#!/usr/bin/env python3
"""vault-mcp-server.py — bounded query surface over obsidian-vault.

This is a small stdlib JSON-RPC/MCP-style server. It does not build or own
memory; it reads the existing vault produced by obsidian-vault-emit.py,
memory-deep-crawler.py, rollups, and tier-1 emitters.

Supported MCP-style methods over stdin/stdout:
  - initialize
  - tools/list
  - tools/call

Direct CLI smoke usage:
  python3 tools/vault-mcp-server.py --self-test
  python3 tools/vault-mcp-server.py --call vault_search --args '{"query":"M14"}'

Goal semantics:
  The top-level auditooor goal is a perpetual capability loop. Tooling may
  return completed iteration artifacts, but the global goal itself should stay
  active unless the operator replaces it.
"""

from __future__ import annotations

