_TELEMETRY_ENV_DISABLE = "AUDITOOOR_MCP_TELEMETRY_DISABLE"
_TELEMETRY_ENV_WORKSPACE = "AUDITOOOR_WORKSPACE"
_TELEMETRY_FALLBACK_LOG = Path(tempfile.gettempdir()) / "mcp_call_log.jsonl"
_TELEMETRY_LOG_FILENAME = "mcp_call_log.jsonl"
_TELEMETRY_AUDITOOOR_SUBDIR = ".auditooor"


def _auditooor_mcp_token_module():
    try:
        import auditooor_mcp_token  # type: ignore
        return auditooor_mcp_token
    except ImportError:
        token_path = Path(__file__).resolve().with_name("auditooor_mcp_token.py")
        spec = importlib.util.spec_from_file_location("auditooor_mcp_token", token_path)
        if spec is None or spec.loader is None:
            raise
        module = importlib.util.module_from_spec(spec)
        sys.modules[spec.name] = module
        spec.loader.exec_module(module)
        return module


def _telemetry_perf_counter_ms() -> int:
    import time as _t
    return int(_t.perf_counter() * 1000)


def _telemetry_args_hash(args: dict[str, Any]) -> str:
    try:
        payload = json.dumps(args, sort_keys=True, default=str, ensure_ascii=False)
    except Exception:
        payload = repr(args)
    return hashlib.sha256(payload.encode("utf-8", errors="ignore")).hexdigest()[:8]


def _telemetry_resolve_workspace(args: dict[str, Any]) -> str | None:
    """Resolve workspace from arguments or env. Returns absolute path or None."""
    raw = None
    for key in ("workspace_path", "workspace"):
        val = args.get(key)
        if isinstance(val, str) and val.strip():
            raw = val.strip()
            break
    if raw is None:
        env_ws = os.environ.get(_TELEMETRY_ENV_WORKSPACE, "").strip()
        if env_ws:
            raw = env_ws
    if not raw:
        return None
    try:
        ws_path = Path(raw).expanduser()
    except Exception:
        return None
    # A workspace MUST be absolute. A bare relative name (e.g. "dydx") would
    # otherwise be resolved against the process CWD -- the tooling repo -- and
    # auto-vivify near-empty stub dirs (auditooor-mcp/dydx/.auditooor/...) on the
    # first MCP call. Do NOT mkdir a stub under the tooling repo from a relative
    # name: no-op (return None) so the caller falls back to the /tmp log.
    if not ws_path.is_absolute():
        return None
    return str(ws_path)


def _telemetry_log_path(workspace: str | None) -> Path:
    # Defense in depth: only ever create the per-workspace log under an ABSOLUTE
    # workspace path. A relative value here would mkdir a stub inside the tooling
    # repo (see _telemetry_resolve_workspace), so fall back to the /tmp log.
    if workspace:
        try:
            ws_path = Path(workspace)
            if ws_path.is_absolute():
                target = ws_path / _TELEMETRY_AUDITOOOR_SUBDIR / _TELEMETRY_LOG_FILENAME
                target.parent.mkdir(parents=True, exist_ok=True)
                return target
        except Exception:
            pass
    return _TELEMETRY_FALLBACK_LOG


def _telemetry_result_verdict(result: Any) -> str:
    if not isinstance(result, dict):
        return "unknown"
    if "error" in result:
        return "error"
    if result.get("degraded") is True:
        return "degraded"
    return "ok"


def _telemetry_result_degraded(result: Any) -> bool:
    if not isinstance(result, dict):
        return False
    return bool(result.get("degraded", False))


def _record_call_telemetry(
    *,
    callable_name: str,
    args: dict[str, Any],
    result: Any,
    duration_ms: int,
    ts: _dt.datetime,
) -> None:
    """Append one JSONL row to the per-workspace MCP call log.

    Kill-switch: `AUDITOOOR_MCP_TELEMETRY_DISABLE=1`. Errors are swallowed.
    """
    if os.environ.get(_TELEMETRY_ENV_DISABLE, "").strip() in {"1", "true", "yes"}:
        return
    try:
        workspace = _telemetry_resolve_workspace(args)
        row = {
            "ts": ts.replace(microsecond=0).isoformat().replace("+00:00", "Z"),
            "workspace": workspace or "",
            "callable": str(callable_name),
            "args_hash": _telemetry_args_hash(args if isinstance(args, dict) else {}),
            "verdict": _telemetry_result_verdict(result),
            "duration_ms": int(duration_ms),
            "degraded": _telemetry_result_degraded(result),
        }
        log_path = _telemetry_log_path(workspace)
        line = json.dumps(row, ensure_ascii=False, sort_keys=True) + "\n"
        with log_path.open("a", encoding="utf-8") as handle:
            handle.write(line)
    except Exception:
        # Never propagate logging failures.
        return



