# Daemon code-revision staleness stamp (wave-3 uplift, 2026-06-18).
# The MCP daemon is a long-lived process: after a `git pull`/merge the on-disk
# tool code can advance while the running process keeps serving the OLD code,
# with no signal to callers. `serverInfo.version` used to be a frozen literal
# "0.1.0" decoupled from the actual revision. We now (1) stamp the running
# process with a code revision computed at start, expose it in
# `serverInfo.version` and a `vault_daemon_version` callable, and (2) on each
# `call()` compare the start-time stamp to the current on-disk stamp; when the
# on-disk code is NEWER we inject a `degraded: true` +
# `daemon_staleness_warning` field into the response envelope so callers know
# the result may be pre-fix. We do NOT hot-reload arbitrary code - we only
# signal "daemon-stale-restart-required".
_DAEMON_VERSION_BASE = "0.1.0"
_DAEMON_STAMP_ENV_OVERRIDE = "AUDITOOOR_MCP_CODE_STAMP"


def _compute_code_revision_stamp(repo_root: Path) -> str:
    """Compute a code-revision stamp for the daemon's tool code.

    Resolution order (first that succeeds wins):
      1. ``AUDITOOOR_MCP_CODE_STAMP`` env override (lets tests inject a stamp).
      2. ``git rev-parse HEAD`` of ``repo_root`` (the canonical revision).
      3. A content hash + max-mtime fingerprint of ``tools/*.py`` (works in a
         detached/exported tree where git is unavailable).
    Always returns a short non-empty string; never raises.
    """
    override = os.environ.get(_DAEMON_STAMP_ENV_OVERRIDE, "").strip()
    if override:
        return override[:40]
    # 2. git rev-parse HEAD
    try:
        import subprocess

        out = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            cwd=str(repo_root),
            capture_output=True,
            text=True,
            timeout=5,
        )
        sha = out.stdout.strip()
        if out.returncode == 0 and sha:
            return f"git:{sha[:12]}"
    except Exception:
        pass
    # 3. content + max-mtime fingerprint of tools/*.py
    try:
        tools_dir = repo_root / "tools"
        digest = hashlib.sha256()
        max_mtime = 0.0
        any_file = False
        for path in sorted(tools_dir.glob("*.py")):
            try:
                st = path.stat()
            except OSError:
                continue
            any_file = True
            max_mtime = max(max_mtime, st.st_mtime)
            digest.update(path.name.encode("utf-8", errors="ignore"))
            digest.update(str(int(st.st_mtime)).encode("ascii"))
            digest.update(str(st.st_size).encode("ascii"))
        if any_file:
            return f"mtime:{int(max_mtime)}:{digest.hexdigest()[:8]}"
    except Exception:
        pass
    return "unknown"


def _daemon_version_string(stamp: str) -> str:
    """Daemon version = frozen base + live code-revision stamp."""
    return f"{_DAEMON_VERSION_BASE}+{stamp}"


