# W5-M2: freshness gate in the recall path. W5-E1 applies a SMOOTH recency
# decay multiplier; M2 adds a DISCRETE FRESH/AGING/STALE label plus a HARD
# demote for STALE notes - they sort below every non-STALE note regardless of
# composite score, so a 200-day-old next-loop note can never out-rank a fresh
# one just because it keyword-matches. The age bands mirror the W4.14
# `mcp-corpus-freshness-monitor.py` model (soft 14d / hard 30d) so the recall
# path and the reactive audit speak the same vocabulary. STALE notes are
# demoted + labelled, never dropped - a stale note still carries signal, the
# consuming session is just told to re-mine before trusting it.
FRESHNESS_SOFT_DAYS = 14.0
FRESHNESS_HARD_DAYS = 30.0
FRESH = "FRESH"
AGING = "AGING"
STALE = "STALE"
