def _argv_has_option(argv: list[str], option: str) -> bool:
    return any(arg == option or arg.startswith(option + "=") for arg in argv)


def _active_vault_candidates() -> list[Path]:
    candidates: list[Path] = []
    for env_name in ("AUDITOOOR_VAULT_DIR", "VAULT", "VAULT_PATH"):
        raw = os.environ.get(env_name)
        if raw:
            candidates.append(Path(raw).expanduser())
    candidates.append(DEFAULT_SHARED_VAULT)
    deduped: list[Path] = []
    seen: set[Path] = set()
    for path in candidates:
        resolved = path.resolve()
        if resolved in seen:
            continue
        seen.add(resolved)
        deduped.append(resolved)
    return deduped


def _vault_has_resume_entrypoints(vault_dir: Path) -> bool:
    return (
        (vault_dir / "INDEX.md").is_file()
        and (vault_dir / "INDEX_active.md").is_file()
        and (vault_dir / "NEXT_LOOP.md").is_file()
    )


def resolve_vault_dir(vault_arg: str, *, argv: list[str]) -> tuple[Path, str | None]:
    """Resolve the vault directory for default CLI/MCP use.

    Worktrees may carry a small generated ``obsidian-vault`` stub that lacks
    the active planning files. If the operator did not explicitly choose a
    non-default vault, prefer the shared Obsidian vault when it has the resume
    entrypoints. Explicit ``--vault-dir`` keeps exact semantics.
    """
    vault = Path(vault_arg).expanduser().resolve()
    raw_vault = Path(vault_arg).expanduser()
    default_like_vault = (
        not _argv_has_option(argv, "--vault-dir")
        or vault == DEFAULT_VAULT.resolve()
        or str(raw_vault) == "obsidian-vault"
    )
    if _vault_has_resume_entrypoints(vault) or not default_like_vault:
        return vault, None
    for fallback in _active_vault_candidates():
        if _vault_has_resume_entrypoints(fallback):
            return (
                fallback,
                (
                    f"default vault {vault} is missing resume entrypoints; "
                    f"using active vault {fallback}"
                ),
            )
    return vault, None


def _clamp_limit(value: Any, default: int = DEFAULT_LIMIT) -> int:
    try:
        limit = int(value)
    except (TypeError, ValueError):
        return default
    return max(1, min(MAX_LIMIT, limit))


def _rel(path: Path, root: Path) -> str:
    return path.relative_to(root).as_posix()


def _frontmatter_and_body(text: str) -> tuple[dict[str, Any], str]:
    lines = text.splitlines()
    if not lines or lines[0].strip() != "---":
        return {}, text
    fm: dict[str, Any] = {}
    end = None
    for idx, line in enumerate(lines[1:], start=1):
        if line.strip() == "---":
            end = idx
            break
        if ":" not in line:
            continue
        key, raw = line.split(":", 1)
        value = raw.strip().strip('"').strip("'")
        if value.lower() == "true":
            fm[key.strip()] = True
        elif value.lower() == "false":
            fm[key.strip()] = False
        else:
            fm[key.strip()] = value
    if end is None:
        return fm, text
    return fm, "\n".join(lines[end + 1 :])


def _title(path: Path, frontmatter: dict[str, Any], body: str) -> str:
    raw = frontmatter.get("title")
    if isinstance(raw, str) and raw:
        return raw
    for line in body.splitlines():
        if line.startswith("#"):
            return line.lstrip("#").strip()
    return path.stem


def _has_secret(text: str) -> bool:
    return any(pattern.search(text) for pattern in SECRET_PATTERNS)


# CAP-GAP-77: advisory doc files whose absence should degrade gracefully.
# These are reference/documentation files referenced from harness reports and
# knowledge-gap ledgers; their absence is cosmetic, not a data integrity fault.
_ADVISORY_DOC_PATTERNS: list[str] = [
    "docs/CONTINUATION_PLAN.md",
    "docs/CONTROL_PLANE_BUILD_STATUS.md",
]


def _detect_missing_doc_paths(message: str) -> list[str]:
    """Return paths of advisory doc files cited in a validation-error message.

    Called by the three CAP-GAP-77 patched callables
    (vault_harness_context, vault_knowledge_gap_context,
    _degraded_exploit_context) to decide whether a degraded verdict should
    be softened to verdict="pass-with-missing-doc".  Returns an empty list
    when the degradation is caused by something other than advisory doc
    absence, preserving the existing hard-degraded path for data-integrity
    faults.
    """
    if not message:
        return []
    found: list[str] = []
    for doc_path in _ADVISORY_DOC_PATTERNS:
        if doc_path in message:
            found.append(doc_path)
    return found


def _has_forbidden_part(path: Path) -> bool:
    return any(part in FORBIDDEN_PARTS or (part not in {".", ".."} and part.startswith(".")) for part in path.parts)


def _excerpt(body: str, query: str, max_chars: int = 280) -> str:
    compact = [line.strip() for line in body.splitlines() if line.strip()]
    if not compact:
        return ""
    q = query.lower().strip()
    if q:
        terms = [term for term in re.split(r"\W+", q) if term]
        for line in compact:
            low = line.lower()
            if any(term in low for term in terms):
                return line[:max_chars]
    return compact[0][:max_chars]


def _search_tokens(value: str) -> list[str]:
    return [term for term in re.split(r"[^a-z0-9_]+", value.lower()) if term]


def _search_score(note: Note, terms: list[str], query: str) -> int:
    if not terms:
        return 1
    metadata = json.dumps(note.frontmatter, sort_keys=True)
    fields = (
        (note.relpath, 32, 8),
        (note.title, 24, 8),
        (metadata, 8, 6),
        (note.body, 1, 16),
    )
    score = 0
    matched_terms: set[str] = set()
    normalized_query = " ".join(terms)
    for text, weight, cap in fields:
        tokens = _search_tokens(text)
        if not tokens:
            continue
        token_counts = {term: tokens.count(term) for term in set(terms)}
        for term, count in token_counts.items():
            if count:
                matched_terms.add(term)
                score += min(count, cap) * weight
        normalized_text = " ".join(tokens)
        if normalized_query and normalized_query in normalized_text:
            score += weight * len(terms) * 3
    rel_title_terms = set(_search_tokens(f"{note.relpath} {note.title}"))
    if set(terms).issubset(rel_title_terms):
        score += 250
    elif matched_terms and matched_terms.issubset(rel_title_terms):
        score += 25 * len(matched_terms)
    return score if matched_terms else 0


# ---------------------------------------------------------------------------
# W5-E1: relevance-ranked context packs.
#
# vault_resume_context historically returned a STATIC default note set on cold
# resume - no relevance ranking, no recency decay. The helpers below turn the
# resume/dispatch pack into a targeted, ranked recall:
#
#   (a) keyword/topic match  - the existing _search_score against an
#       auto-derived workspace query (attack class + workspace name + INTAKE
#       keywords + the explicit `query` arg, if any).
#   (b) recency decay        - frontmatter `date`/`updated` or file mtime,
#       converted to an exponential half-life multiplier.
#   (c) tier                 - status_class -> RANK_TIER_WEIGHTS multiplier.
#
# Everything is deterministic and stdlib-only. The degraded path (no terms,
# no dates) collapses to the static input order, so cold workspaces still get
# a sane checklist.
# ---------------------------------------------------------------------------

_RANK_QUERY_STOPWORDS = frozenset({
    "the", "and", "for", "with", "audit", "audits", "workspace", "repo",
    "main", "src", "test", "tests", "tmp", "new", "old",
})


def _derive_rank_query(workspace_path: Path | None, explicit_query: str) -> str:
    """Auto-derive a ranking query string from a workspace.

    Combines: the explicit `query` arg (if any), the primary asset class via
    _derive_workspace_class, the workspace directory name tokens, and the
    first attack-class-ish keywords from INTAKE_BASELINE.md. Returns a
    space-joined lowercase token string, possibly empty (degraded path).
    """
    parts: list[str] = []
    if explicit_query:
        parts.append(explicit_query.lower())
    if workspace_path is not None:
        try:
            klass = _derive_workspace_class(workspace_path)
        except Exception:  # noqa: BLE001
            klass = ""
        if klass:
            parts.append(klass.replace("-", " "))
        parts.append(workspace_path.name.lower().replace("-", " "))
        intake = workspace_path / "INTAKE_BASELINE.md"
        try:
            if intake.is_file() and not _path_has_symlink(intake, stop_at=workspace_path):
                text = intake.read_text(encoding="utf-8", errors="replace")[:4000]
                # Pull the asset-coverage / attack-class lines.
                for line in text.lower().splitlines():
                    low = line.strip()
                    if any(k in low for k in ("attack", "class", "coverage", "rubric")):
                        parts.append(low)
        except OSError:
            pass
    tokens: list[str] = []
    seen: set[str] = set()
    for term in _search_tokens(" ".join(parts)):
        if term in _RANK_QUERY_STOPWORDS or len(term) < 3:
            continue
        if term in seen:
            continue
        seen.add(term)
        tokens.append(term)
        if len(tokens) >= 24:
            break
    return " ".join(tokens)


def _note_age_days(note: dict[str, Any], now_epoch: float) -> float | None:
    """Best-effort age in days for a context-note dict.

    Prefers frontmatter date-like fields (the authoritative "when was this
    note last updated" anchor). W5-M2 adds `last_validated_at` to the date
    keys checked (it IS on the context-frontmatter whitelist) and a file
    `mtime_epoch` fallback - `_safe_context_frontmatter` strips raw
    `date`/`updated` keys, so without the mtime fallback every emitted pack
    note would be un-dateable. Returns None only when nothing is resolvable,
    so the recency multiplier degrades to a neutral 1.0 and the freshness
    label degrades to the conservative STALE band. `now_epoch` is a UTC
    POSIX timestamp.
    """
    frontmatter = note.get("frontmatter") if isinstance(note.get("frontmatter"), dict) else {}
    for key in ("updated", "date", "last_updated", "last_validated_at",
                "modified", "created"):
        raw = frontmatter.get(key)
        if not raw:
            continue
        match = re.search(r"(\d{4})-(\d{2})-(\d{2})", str(raw))
        if not match:
            continue
        try:
            note_dt = _dt.datetime(
                int(match.group(1)), int(match.group(2)), int(match.group(3)),
                tzinfo=_dt.timezone.utc,
            )
        except (ValueError, OverflowError):
            continue
        age = (now_epoch - note_dt.timestamp()) / 86400.0
        return age if age >= 0 else 0.0
    # W5-M2: file-mtime fallback (signal 2 of the W4.14 freshness model).
    # Floored to whole days so sub-day mtime jitter (e.g. several pack notes
    # written microseconds apart in a temp vault) collapses to a single age
    # bucket - that preserves the W5-E1 stable-input-order floor for
    # same-day notes instead of letting microsecond noise reorder them.
    mtime = note.get("mtime_epoch")
    if isinstance(mtime, (int, float)) and mtime > 0:
        age = (now_epoch - float(mtime)) / 86400.0
        return float(int(age)) if age >= 0 else 0.0
    return None


def _recency_multiplier(age_days: float | None) -> float:
    """Exponential half-life decay. None -> neutral 1.0 (degraded path)."""
    if age_days is None:
        return 1.0
    if age_days <= 0:
        return 1.0
    half_life = RANK_RECENCY_HALF_LIFE_DAYS if RANK_RECENCY_HALF_LIFE_DAYS > 0 else 30.0
    return float(0.5 ** (age_days / half_life))


def _freshness_label(age_days: float | None) -> str:
    """W5-M2: discrete FRESH/AGING/STALE band for a context note.

    Mirrors the W4.14 `mcp-corpus-freshness-monitor.py` `_classify` model so
    the recall path and the reactive freshness audit agree:

      FRESH  age <= FRESHNESS_SOFT_DAYS (default 14d)
      AGING  soft < age <= FRESHNESS_HARD_DAYS (default 30d)
      STALE  age > hard threshold, OR age undeterminable

    `age_days is None` (no date frontmatter, no resolvable mtime) is treated
    as STALE on purpose: an un-dateable note cannot be vouched for as current,
    so the recall path is told to re-mine before trusting it. This is the
    conservative-by-default posture W4.14 also takes.
    """
    if age_days is None:
        return STALE
    if age_days > FRESHNESS_HARD_DAYS:
        return STALE
    if age_days > FRESHNESS_SOFT_DAYS:
        return AGING
    return FRESH


def _rank_context_notes(
    notes: list[dict[str, Any]],
    query: str,
    now_epoch: float | None = None,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    """Rank context-note dicts by relevance; return (ranked_notes, ranking).

    Score = (1 + keyword_score) * recency_multiplier * tier_weight.
    The +1 floor keeps tier/recency meaningful even when keyword_score is 0
    (cold-workspace path). Sort is stable (Python sort) so equal-score notes
    preserve their static input order - that is the backward-compat floor.

    W5-M2 freshness gate: each note is tagged with a discrete
    `freshness` field (FRESH/AGING/STALE) via `_freshness_label`, and that
    field is mutated onto the note dict in place so the consuming session
    sees the label on every emitted note. STALE notes are HARD-DEMOTED: the
    primary sort key is the stale bucket (0 = non-stale, 1 = stale), so a
    stale note can never out-rank a non-stale note no matter how high its
    composite score. Within each bucket the W5-E1 composite ordering holds.
    Stale notes are demoted and labelled, never dropped.

    `ranking` is an auditable, JSON-safe explanation list, one row per note;
    each row carries `freshness` and `is_stale` so the demote is traceable.
    """
    if not notes:
        return [], []
    if now_epoch is None:
        now_epoch = _dt.datetime.now(_dt.timezone.utc).timestamp()
    terms = _search_tokens(query)
    scored: list[tuple[int, float, int, dict[str, Any], dict[str, Any]]] = []
    for idx, note in enumerate(notes):
        # Build a lightweight Note for the existing keyword scorer.
        probe = Note(
            path=Path(str(note.get("path", ""))),
            relpath=str(note.get("path", "")),
            category=str(note.get("category", "")),
            frontmatter=note.get("frontmatter") if isinstance(note.get("frontmatter"), dict) else {},
            body=str(note.get("body", "")),
            title=str(note.get("title", "")),
        )
        kw = _search_score(probe, terms, query) if terms else 0
        age = _note_age_days(note, now_epoch)
        recency = _recency_multiplier(age)
        tier_weight = RANK_TIER_WEIGHTS.get(str(note.get("status_class", "unknown")), 0.5)
        composite = (1.0 + float(kw)) * recency * tier_weight
        # W5-M2: discrete freshness band + hard-demote bucket. STALE -> 1,
        # everything else -> 0; the bucket is the PRIMARY sort key.
        freshness = _freshness_label(age)
        is_stale = freshness == STALE
        # Label the note dict in place so the emitted pack carries it.
        note["freshness"] = freshness
        explain = {
            "path": str(note.get("path", "")),
            "keyword_score": int(kw),
            "age_days": (round(age, 2) if age is not None else None),
            "recency_multiplier": round(recency, 4),
            "tier": str(note.get("status_class", "unknown")),
            "tier_weight": tier_weight,
            "composite_score": round(composite, 4),
            "freshness": freshness,
            "is_stale": is_stale,
        }
        scored.append((1 if is_stale else 0, composite, idx, note, explain))
    # W5-M2: PRIMARY key = stale bucket (non-stale first), then W5-E1
    # composite descending, then idx as the stable tie-breaker.
    scored.sort(key=lambda row: (row[0], -row[1], row[2]))
    ranked_notes = [row[3] for row in scored]
    ranking = []
    for rank, row in enumerate(scored):
        explain = dict(row[4])
        explain["rank"] = rank
        ranking.append(explain)
    return ranked_notes, ranking


# ---------------------------------------------------------------------------
# Synonym map loader + query expansion (plan 09 §5; lane SP-A wiring)
# ---------------------------------------------------------------------------
#
# reference/vault_search_synonyms.yaml maps a canonical phrase ("think like a
# hacker") to a list of synonym phrases ("adversarial", "counter-brief", ...).
# vault_search needs to expand the user's query across these synonyms so that
# a query containing the canonical phrase also fires hits for notes that only
# mention the synonyms.
#
# We avoid the PyYAML dependency (consistent with this file's existing
# minimal-parser style — see _parse_rejection_classifier_history) and parse
# only the ``canonical:`` + ``expands_to:`` slots, ignoring all other fields.

_SYNONYM_CACHE: dict[str, Any] = {"path": None, "mtime": None, "map": None}


def _load_search_synonyms(path: Path | None = None) -> dict[str, list[str]]:
    """Load canonical→synonyms map from the YAML file, mtime-cached.

    Returns ``{}`` if the file is missing or unparseable. The result is a
    plain dict mapping canonical-phrase (str) → list of synonym phrases
    (list[str]). All other YAML fields (artifact_hints, callable_hint,
    context_tags, etc.) are ignored — vault_search only needs the phrase
    substitutions.
    """
    target = (path or SEARCH_SYNONYMS_PATH).resolve()
    try:
        mtime = target.stat().st_mtime
    except OSError:
        return {}
    cached_path = _SYNONYM_CACHE.get("path")
    cached_mtime = _SYNONYM_CACHE.get("mtime")
    cached_map = _SYNONYM_CACHE.get("map")
    if (
        cached_path == str(target)
        and cached_mtime == mtime
        and isinstance(cached_map, dict)
    ):
        return cached_map  # type: ignore[return-value]
    try:
        text = target.read_text(encoding="utf-8")
    except OSError:
        return {}
    result: dict[str, list[str]] = {}
    current_canonical: str | None = None
    in_expands = False
    for raw_line in text.splitlines():
        line = raw_line.rstrip()
        stripped = line.lstrip()
        if not stripped or stripped.startswith("#"):
            continue
        # New row: "- canonical: \"phrase\""  (leading dash optional indent)
        if stripped.startswith("- canonical:"):
            value = stripped[len("- canonical:"):].strip()
            current_canonical = value.strip("'\"")
            if current_canonical:
                result.setdefault(current_canonical, [])
            in_expands = False
            continue
        if current_canonical is None:
            continue
        if stripped.startswith("expands_to:"):
            in_expands = True
            continue
        # Any other top-level-ish key on the same row resets expands_to mode
        if in_expands and stripped.startswith("- "):
            syn = stripped[2:].strip().strip("'\"")
            if syn:
                result[current_canonical].append(syn)
            continue
        # A key like "artifact_hints:" / "callable_hint:" / etc. ends the list
        if in_expands and (stripped.endswith(":") or ":" in stripped) and not stripped.startswith("- "):
            in_expands = False
        # New top-level key beneath a row (artifact_hints, callable_hint, ...)
        # is silently ignored.
    _SYNONYM_CACHE["path"] = str(target)
    _SYNONYM_CACHE["mtime"] = mtime
    _SYNONYM_CACHE["map"] = result
    return result


def _expand_query_with_synonyms(
    query: str,
    synonyms: dict[str, list[str]] | None = None,
    max_variants: int = MAX_SYNONYM_QUERY_VARIANTS,
) -> list[str]:
    """Return query variants generated by synonym substitution.

    The original query is always returned first. Then, for each canonical
    phrase that appears as a case-insensitive substring of the query, we
    emit one variant per synonym substitution (canonical phrase replaced
    by each synonym). Variants are deduped and capped at ``max_variants``.
    """
    if not query or not query.strip():
        return [query]
    variants: list[str] = [query]
    seen: set[str] = {query.lower()}
    table = synonyms if synonyms is not None else _load_search_synonyms()
    if not table:
        return variants
    q_lower = query.lower()
    # Prefer longer canonical phrases first (more specific match).
    canonicals = sorted(table.keys(), key=lambda s: -len(s))
    for canonical in canonicals:
        if len(variants) >= max_variants:
            break
        c_lower = canonical.lower()
        if not c_lower or c_lower not in q_lower:
            continue
        # Substitute one synonym at a time (case-insensitive replacement).
        pattern = re.compile(re.escape(canonical), re.IGNORECASE)
        for synonym in table[canonical]:
            if len(variants) >= max_variants:
                break
            new_q = pattern.sub(synonym, query, count=1)
            key = new_q.lower()
            if key in seen:
                continue
            seen.add(key)
            variants.append(new_q)
    return variants[:max_variants]


def _canonical_json(value: Any) -> str:
    return json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=True)


def _parse_utc_timestamp(value: object) -> _dt.datetime | None:
    raw = str(value if value is not None else "").strip()
    if not raw:
        return None
    try:
        parsed = _dt.datetime.fromisoformat(raw.replace("Z", "+00:00"))
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=_dt.timezone.utc)
    return parsed.astimezone(_dt.timezone.utc)


def _sidecar_generated_at(row: dict[str, Any]) -> str:
    for key in ("generated_at", "generated_at_utc", "_generated_at"):
        value = row.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    return ""


def _sidecar_mtime_utc(path: Path) -> str:
    try:
        return _dt.datetime.fromtimestamp(path.stat().st_mtime, tz=_dt.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )
    except OSError:
        return ""


def _sidecar_freshness_class(
    *,
    exists: bool,
    rows: int,
    generated_at: str,
    mtime_utc: str,
    stale_after_seconds: int,
) -> tuple[str, str]:
    if not exists:
        return "missing", "missing"
    if rows <= 0:
        return "empty", "empty"
    basis = "generated_at" if generated_at else "mtime"
    timestamp = _parse_utc_timestamp(generated_at or mtime_utc)
    if timestamp is None:
        return "unknown", basis
    age_seconds = (_dt.datetime.now(_dt.timezone.utc) - timestamp).total_seconds()
    return ("stale" if age_seconds > stale_after_seconds else "fresh"), basis


_HACKER_BRIEF_GENERATED_LINE_RE = re.compile(r"^\*\*Generated:?\*\*:?\s+.*$", re.MULTILINE)


def _hacker_brief_hash_payload(payload: dict[str, Any]) -> dict[str, Any]:
    hash_payload = dict(payload)
    hash_payload.pop("timestamp_utc", None)
    brief_markdown = hash_payload.get("brief_markdown")
    if isinstance(brief_markdown, str):
        hash_payload["brief_markdown"] = _HACKER_BRIEF_GENERATED_LINE_RE.sub(
            "**Generated**: <generated-at>",
            brief_markdown,
        )
    return hash_payload


def _bounded_text(value: object, max_chars: int = MAX_CONTEXT_NOTE_CHARS) -> str:
    text = str(value if value is not None else "")
    if len(text) <= max_chars:
        return text
    return text[:max_chars] + "\n\n[truncated]"


def _is_public_relpath(relpath: str) -> bool:
    if not relpath or any(ord(ch) < 32 or ch in "`" for ch in relpath):
        return False
    rel = Path(relpath)
    if rel.is_absolute():
        return False
    parts = tuple(part for part in rel.parts if part and part != ".")
    if not parts:
        return False
    return not any(part == ".." or part in FORBIDDEN_PARTS or part.startswith(".") for part in parts)


def _safe_repo_relpath(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or text.startswith("external:") or "://" in text or text.startswith("~"):
        return None
    if not _is_public_relpath(text):
        return None
    return Path(text).as_posix()


def _safe_source_ref(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    if text.startswith("vault://"):
        rel, _, anchor = text.removeprefix("vault://").partition("#")
        if _is_public_relpath(rel):
            if anchor and not re.fullmatch(r"[A-Za-z0-9._/\-]+", anchor):
                return None
            return "vault://" + Path(rel).as_posix() + (f"#{anchor}" if anchor else "")
        return None
    if GITHUB_ARTIFACT_RE.match(text):
        return text
    if not REPO_SOURCE_REF_RE.match(text):
        return None
    rel = _safe_repo_relpath(text)
    if rel:
        return rel
    return None


def _safe_harness_source_ref(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    if not HARNESS_SOURCE_REF_RE.match(text):
        return None
    rel = _safe_repo_relpath(text)
    if rel:
        return rel
    return None


def _safe_knowledge_gap_ref(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    if text.startswith("vault://"):
        parsed = _parse_vault_uri(text)
        if parsed is None:
            return None
        rel, anchor = parsed
        return "vault://" + rel + (f"#{anchor}" if anchor else "")
    if GITHUB_ARTIFACT_RE.match(text):
        return text
    if re.fullmatch(r"commit:[0-9a-fA-F]{7,40}(?::[A-Za-z0-9._/\-]+)?", text):
        return text
    if not KNOWLEDGE_GAP_SOURCE_REF_RE.match(text):
        return None
    rel = _safe_repo_relpath(text)
    if rel:
        return rel
    return None


def _safe_workspace_relpath(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    rel = Path(text)
    if rel.is_absolute():
        return None
    parts = tuple(part for part in rel.parts if part and part != ".")
    if not parts:
        return None
    for idx, part in enumerate(parts):
        if part == ".." or part in FORBIDDEN_PARTS:
            return None
        if part.startswith(".") and not (idx == 0 and part in {".auditooor", ".audit_logs"}):
            return None
    return Path(*parts).as_posix()


def _safe_brief_source_ref(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    match = BRIEF_SOURCE_REF_RE.match(text)
    if not match:
        return None
    prefix, raw_rel, line = match.groups()
    if prefix == "repo":
        if not REPO_SOURCE_REF_RE.match(raw_rel):
            return None
        rel = _safe_repo_relpath(raw_rel)
    else:
        rel = _safe_workspace_relpath(raw_rel)
    if not rel:
        return None
    return f"{prefix}:{rel}" + (f":{line}" if line else "")


def _brief_source_refs(value: object) -> list[str]:
    if isinstance(value, dict):
        refs: list[str] = []
        for nested in value.values():
            refs.extend(_brief_source_refs(nested))
        return refs
    if isinstance(value, list):
        refs = []
        for nested in value:
            refs.extend(_brief_source_refs(nested))
        return refs
    safe = _safe_brief_source_ref(value)
    return [safe] if safe else []


def _looks_like_private_ref(text: str) -> bool:
    if not text:
        return False
    if text.startswith(("~", "/", "external:")):
        return True
    if re.match(r"^[A-Za-z]:[\\/]", text):
        return True
    if re.search(r"(^|[\s\"'])\.\.(/|$)", text):
        return True
    return any(part in text for part in FORBIDDEN_PARTS)


def _safe_context_frontmatter_value(key: str, value: object) -> object | None:
    if key not in CONTEXT_FRONTMATTER_KEYS:
        return None
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return value
    if isinstance(value, str):
        text = _safe_text_item(value, max_chars=240)
        if not text or _has_secret(text) or _looks_like_private_ref(text):
            return None
        if key in {"source_ref", "terminal_artifact"}:
            return _safe_source_ref(text)
        if _safe_source_ref(text):
            return None
        return text
    return None


def _safe_context_frontmatter(frontmatter: dict[str, Any]) -> dict[str, Any]:
    safe: dict[str, Any] = {}
    for raw_key, raw_value in frontmatter.items():
        key = str(raw_key).strip()
        if not re.fullmatch(r"[A-Za-z0-9_\-]+", key):
            continue
        value = _safe_context_frontmatter_value(key, raw_value)
        if value is not None:
            safe[key] = value
    return safe


def _safe_text_item(value: object, max_chars: int = 600) -> str | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    if len(text) > max_chars:
        return text[:max_chars].rstrip() + "..."
    return text


def _parse_vault_uri(value: str) -> tuple[str, str | None] | None:
    if not value.startswith("vault://"):
        return None
    rel, _, anchor = value.removeprefix("vault://").partition("#")
    if not _is_public_relpath(rel):
        return None
    return Path(rel).as_posix(), anchor or None


def _iter_jsonl_objects(path: Path) -> Iterable[dict[str, Any]]:
    if not path.is_file():
        return []
    rows: list[dict[str, Any]] = []
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except OSError:
        return []
    for line in lines:
        if not line.strip():
            continue
        try:
            row = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(row, dict):
            rows.append(row)
    return rows


def _unique_bounded(values: Iterable[str], limit: int) -> list[str]:
    seen: set[str] = set()
    result: list[str] = []
    for value in values:
        if value in seen:
            continue
        seen.add(value)
        result.append(value)
        if len(result) >= limit:
            break
    return result


def _bounded_string_list(values: object, limit: int, *, max_chars: int = 240) -> list[str]:
    if not isinstance(values, list):
        return []
    rows: list[str] = []
    for value in values:
        item = _safe_text_item(value, max_chars=max_chars)
        if item:
            rows.append(item)
        if len(rows) >= limit:
            break
    return rows


def _bounded_brief_refs(values: object, limit: int = MAX_EXPLOIT_REFS) -> list[str]:
    return _unique_bounded(_brief_source_refs(values), limit)


def _safe_worklist_hit_ref(value: object) -> str | None:
    """Sanitize worklist hit refs like `rel/path.rs` or `rel/path.rs:123`."""
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None

    rel = text
    line_suffix = ""
    if ":" in text:
        prefix, _, maybe_line = text.rpartition(":")
        if prefix and maybe_line.isdigit():
            rel = prefix
            line_suffix = f":{maybe_line}"

    safe_rel = _safe_workspace_relpath(rel)
    if not safe_rel:
        return None
    return f"{safe_rel}{line_suffix}"


def _engage_report_workspace_label(value: object, default: str = "spark") -> str:
    """Return a non-absolute workspace label for public engage-report payloads."""
    text = str(value if value is not None else "").strip()
    if not text:
        return default
    try:
        name = Path(text).expanduser().name
    except (OSError, RuntimeError):
        name = ""
    safe = _safe_text_item(name or text, max_chars=120)
    if not safe or _has_secret(safe) or _looks_like_private_ref(safe):
        return default
    return safe


def _safe_engage_report_hit_path(value: object, workspace: Path) -> str:
    """Convert engage_report hit paths to workspace-relative/public labels."""
    text = str(value if value is not None else "").strip().rstrip("`").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text) or _has_secret(text):
        return ""

    line_suffix = ""
    path_text = text
    if ":" in text:
        prefix, _, maybe_line = text.rpartition(":")
        if prefix and maybe_line.isdigit():
            path_text = prefix
            line_suffix = f":{maybe_line}"

    rel_candidate = _safe_workspace_relpath(path_text)
    if rel_candidate:
        return f"{rel_candidate}{line_suffix}"

    try:
        raw_path = Path(path_text).expanduser()
    except (OSError, RuntimeError):
        return ""

    rel_text = ""
    if raw_path.is_absolute():
        try:
            rel_text = raw_path.relative_to(workspace).as_posix()
        except ValueError:
            parts = tuple(part for part in raw_path.parts if part not in {raw_path.anchor, ""})
            workspace_name = workspace.name
            if workspace_name in parts:
                idx = parts.index(workspace_name)
                rel_text = Path(*parts[idx + 1 :]).as_posix() if idx + 1 < len(parts) else ""
            elif len(parts) >= 2:
                rel_text = Path(*parts[-2:]).as_posix()
    safe_rel = _safe_workspace_relpath(rel_text)
    return f"{safe_rel}{line_suffix}" if safe_rel else ""


def _sanitize_engage_report_snippet(value: object, workspace: Path, max_chars: int = 200) -> str:
    """Bound snippets and remove absolute local path fragments."""
    text = str(value if value is not None else "").strip()
    if not text or _has_secret(text):
        return ""
    text = text.replace(str(workspace), f"workspace:{workspace.name}")
    absolute_path_re = re.compile(
        r"(?:/Users/[^\s`'\")\]]+|/home/[^\s`'\")\]]+|/tmp/[^\s`'\")\]]+|"
        r"/private/tmp/[^\s`'\")\]]+|/private/var/[^\s`'\")\]]+|/var/[^\s`'\")\]]+)"
    )
    text = absolute_path_re.sub("[redacted-local-path]", text)
    if any(ord(ch) < 32 for ch in text):
        return ""
    return text[:max_chars]


def _sanitize_worklist_predicates(
    values: object,
    *,
    max_predicates: int = 6,
    max_hit_refs: int = 6,
) -> list[dict[str, Any]]:
    """Bound and sanitize advisory worklist predicates from big-loss verdicts."""
    if not isinstance(values, list):
        return []
    rows: list[dict[str, Any]] = []
    for raw in values:
        if not isinstance(raw, dict):
            continue
        predicate_id = _safe_text_item(raw.get("predicate_id"), max_chars=120)
        if not predicate_id:
            continue
        status = _safe_text_item(raw.get("status"), max_chars=40) or "needs_evidence"
        advisory_only = bool(raw.get("advisory_only"))
        hit_refs = _unique_bounded(
            [
                safe
                for safe in (
                    _safe_worklist_hit_ref(v)
                    for v in (raw.get("hit_refs") if isinstance(raw.get("hit_refs"), list) else [])
                )
                if safe
            ],
            max_hit_refs,
        )
        rows.append(
            {
                "predicate_id": predicate_id,
                "status": status,
                "advisory_only": advisory_only,
                "hit_refs": hit_refs,
            }
        )
        if len(rows) >= max_predicates:
            break
    return rows


def _token_estimate(value: Any) -> int:
    text = _canonical_json(value)
    return max(1, (len(text) + 3) // 4)


def _status_text(value: object) -> str | None:
    text = str(value if value is not None else "").strip().lower().replace(" ", "_").replace("-", "_")
    return text or None


def _status_class(status: str | None) -> str:
    if not status:
        return "unknown"
    if status in TERMINAL_CONTEXT_STATUSES:
        return "terminal"
    if status in LIVE_CONTEXT_STATUSES:
        return "live"
    return "other"


def _extract_status_from_text(text: str) -> str | None:
    match = re.search(r"\bstatus\s*[:=]\s*([A-Za-z0-9_-]+)", text, flags=re.I)
    if not match:
        return None
    return _status_text(match.group(1))


def _context_allows_status(kind: str, status: str | None) -> bool:
    status_kind = _status_class(status)
    if kind in {"dispatch", "resume"}:
        return status_kind != "terminal"
    return True


def _extract_refs(value: object) -> list[str]:
    refs: list[str] = []
    if isinstance(value, dict):
        for nested in value.values():
            refs.extend(_extract_refs(nested))
        return refs
    if isinstance(value, list):
        for nested in value:
            refs.extend(_extract_refs(nested))
        return refs
    text = str(value if value is not None else "")
    for match in CONTEXT_REF_RE.findall(text):
        safe = _safe_source_ref(match)
        if safe:
            refs.append(safe)
    return refs


def _knowledge_gap_refs(value: object) -> list[str]:
    refs: list[str] = []
    values = value if isinstance(value, list) else [value]
    for item in values:
        text = str(item if item is not None else "").strip()
        if KNOWLEDGE_GAP_REF_RE.match(text) and text not in refs:
            refs.append(text)
    return refs[:MAX_CONTEXT_ITEMS]


# L29-Disc-5: case-study + known-patterns recall surface (codified 2026-05-08).
# Returns canonical paths to artifacts every worker brief must consult before
# any source read. Sourced from docs/CASE_STUDIES_AND_PATTERNS_INDEX.md.
_CASE_STUDY_REFS_CACHE: list[str] | None = None
_KNOWN_PATTERNS_REFS_CACHE: list[str] | None = None


def _case_study_refs() -> list[str]:
    """Engagement-derived case-study artifacts (canonical paths).

    Per L29-Disc-5, every worker brief must consult these BEFORE any source
    read. Index document is `docs/CASE_STUDIES_AND_PATTERNS_INDEX.md`.
    """
    global _CASE_STUDY_REFS_CACHE
    if _CASE_STUDY_REFS_CACHE is not None:
        return list(_CASE_STUDY_REFS_CACHE)
    refs = [
        "docs/CASE_STUDIES_AND_PATTERNS_INDEX.md",
        "case_study/litecoin_mweb_dos_plus_protocol_bug.md",
        "case_study/engagement_3_gap_b_composition_fuzz.md",
        "case_study/centrifuge_v3_engagement.md",
        "case_study/polymarket_cantina.md",
        "case_study/R88_closing_the_workflow_gaps.md",
        "case_study/R89_morpho_engagement_and_tool_gaps.md",
        "case_study/R90_flow_refinement_and_morpho_cold_read_saturation.md",
    ]
