def _load_tool_module(tool_name: str) -> Any:
    """Dynamically load a sibling tools/<tool_name>.py module.

    Returns the loaded module, or None on import failure.  Uses importlib so
    vault-mcp-server.py stays self-contained (no top-level imports of the
    sibling tools, which avoids circular-import risk and keeps the server
    start-up cost low for the common path that never touches these builders).
    """
    tool_path = Path(__file__).resolve().parent / f"{tool_name}.py"
    if not tool_path.exists():
        return None
    try:
        module_id = f"_vault_mcp_dynamic_{tool_name.replace('-', '_')}"
        if module_id in sys.modules:
            return sys.modules[module_id]
        spec = importlib.util.spec_from_file_location(module_id, tool_path)
        if spec is None or spec.loader is None:
            return None
        mod = importlib.util.module_from_spec(spec)
        sys.modules[module_id] = mod
        spec.loader.exec_module(mod)  # type: ignore[union-attr]
        return mod
    except Exception:  # noqa: BLE001
        return None


def _derive_workspace_class(workspace_path: Path) -> str:
    """Best-effort derive the primary asset class from a workspace.

    Reads INTAKE_BASELINE.md or SCOPE.md for known class keywords. Returns
    a lowercase class string (e.g. "prediction-market", "bridge", "lending")
    or empty string if undetermined.
    """
    keywords: dict[str, str] = {
        "prediction-market": "prediction-market",
        "prediction market": "prediction-market",
        "polymarket": "prediction-market",
        "bridge": "bridge",
        "cross-chain": "bridge",
        "op-stack": "bridge",
        "lending": "lending",
        "borrow": "lending",
        "aave": "lending",
        "morpho": "lending",
        "statechain": "statechain",
        "spark": "statechain",
        "dlt": "dlt",
        "distributed ledger": "dlt",
        "stablecoin": "stablecoin",
        "amm": "amm",
        "dex": "amm",
        "uniswap": "amm",
    }
    for candidate in ("INTAKE_BASELINE.md", "SCOPE.md", "README.md"):
        fpath = workspace_path / candidate
        if fpath.exists() and not _path_has_symlink(fpath, stop_at=workspace_path):
            try:
                text = fpath.read_text(encoding="utf-8", errors="replace")[:4000].lower()
                for kw, class_ in keywords.items():
                    if kw in text:
                        return class_
            except OSError:
                pass
    # Fallback: use workspace directory name
    name = workspace_path.name.lower()
    for kw, class_ in keywords.items():
        if kw.replace("-", "") in name.replace("-", "_").replace("-", ""):
            return class_
    return ""


# M-J: extracted-LOGIC builder functions for vault_resume_context.
# Each function is workspace-aware: if workspace_path is provided we run the
# corresponding tool against it; otherwise we return static default arrays.

def _case_study_logic_identity(row: dict[str, Any]) -> tuple[Any, ...]:
    """Return a stable semantic identity for deduping case-study logic rows."""
    def _norm_text(value: Any) -> str:
        return re.sub(r"\s+", " ", str(value or "").strip().lower())

    def _norm_list(value: Any) -> tuple[str, ...]:
        if not isinstance(value, list):
            return ()
        return tuple(_norm_text(item) for item in value if _norm_text(item))

    return (
        _norm_text(row.get("case_id")),
        _norm_text(row.get("class")),
        _norm_text(row.get("mechanism")),
        _norm_text(row.get("extracted_lesson")),
        _norm_list(row.get("grep_predicates")),
        _norm_list(row.get("runtime_predicates")),
        _norm_text(row.get("stop_criterion")),
        _norm_text(row.get("workflow_signature")),
        _norm_text(row.get("loop_back_phase")),
    )


def _case_study_logic(workspace_path: Path | None = None) -> list[dict[str, Any]]:
    """Return extracted lesson + predicate objects from case_study/*.md frontmatter.

    Sourced from case-study-class-matcher.py (Phase E).  When workspace_path is
    supplied, matches are filtered by the workspace's primary class; otherwise
    all case studies are returned up to the hard cap (top 8).
    """
    mod = _load_tool_module("case-study-class-matcher")
    if mod is None:
        return []
    try:
        ws_class = _derive_workspace_class(workspace_path) if workspace_path else ""
        if ws_class:
            matches = mod.match_workspace(ws_class, top_n=32)
        else:
            all_studies = mod.load_all_case_studies()
            matches = [
                mod.CaseMatch(
                    case_id=s.case_id,
                    mechanism=s.mechanism,
                    class_=s.class_,
                    severity_class=s.severity_class,
                    score=1.0,
                    grep_predicates=s.grep_predicates,
                    runtime_predicates=s.runtime_predicates,
                    extracted_lesson=s.extracted_lesson,
                    stop_criterion=getattr(s, "stop_criterion", ""),
                    workflow_signature=getattr(s, "workflow_signature", ""),
                    loop_back_phase=getattr(s, "loop_back_phase", ""),
                    source_file=s.source_file,
                    match_reason="no workspace class — returning all",
                )
                for s in all_studies
            ]
        result = []
        seen_identities: set[tuple[Any, ...]] = set()
        for m in matches:
            d = m.as_dict() if hasattr(m, "as_dict") else vars(m)
            # Normalise class_ → class to match JSON output of the CLI
            if "class_" in d:
                d["class"] = d.pop("class_")
            # Keep only the fields the spec asks for
            row = {
                "case_id": d.get("case_id", ""),
                "class": d.get("class", ""),
                "mechanism": d.get("mechanism", ""),
                "extracted_lesson": d.get("extracted_lesson", ""),
                "grep_predicates": d.get("grep_predicates", []),
                "runtime_predicates": d.get("runtime_predicates", []),
                "severity_class": d.get("severity_class", ""),
                "stop_criterion": d.get("stop_criterion", ""),
                "workflow_signature": d.get("workflow_signature", ""),
                "loop_back_phase": d.get("loop_back_phase", ""),
                "score": d.get("score", 0.0),
                "match_reason": d.get("match_reason", ""),
                "source_file": d.get("source_file", ""),
            }
            identity = _case_study_logic_identity(row)
            if identity in seen_identities:
                continue
            seen_identities.add(identity)
            result.append(row)
            if len(result) >= 8:
                break
        return result
    except Exception:  # noqa: BLE001
        return []


def _big_loss_template_actor_sequences(workspace_path: Path | None = None) -> list[dict[str, Any]]:
    """Return per-template actor_sequence verdict arrays from big-loss-template-runner.py.

    Sourced from Phase F.  Runs all templates that match the workspace scope;
    for each returns {template_id, title, workspace_scope_match, actor_sequence_verdicts}.
    Empty list on failure or missing templates dir.

    Note: the runner's human-readable stdout is suppressed via a tempfile redirect so
    it does not contaminate the MCP JSON response on stdout.
    """
    if workspace_path is None:
        return []  # no-op without workspace; templates need a target to evaluate against
    mod = _load_tool_module("big-loss-template-runner")
    if mod is None:
        return []
    try:
        import io as _io
        ws_str = str(workspace_path)
        # Suppress human-readable stdout from run() / _print_human(); capture to devnull.
        _old_stdout = sys.stdout
        sys.stdout = _io.StringIO()
        try:
            results = mod.run(workspace=ws_str, print_json=False, out=None)
        finally:
            sys.stdout = _old_stdout
        if not isinstance(results, list):
            return []
        out = []
        for r in results[:6]:  # cap at 6 templates per recall
            if not isinstance(r, dict):
                continue
            raw_steps = r.get("actor_sequence_verdicts")
            step_rows: list[dict[str, Any]] = []
            for step in (raw_steps if isinstance(raw_steps, list) else [])[:10]:
                if not isinstance(step, dict):
                    continue
                safe_step: dict[str, Any] = {}
                step_no = step.get("step")
                if isinstance(step_no, int):
                    safe_step["step"] = step_no
                elif isinstance(step_no, str) and step_no.isdigit():
                    safe_step["step"] = int(step_no)
                else:
                    safe_step["step"] = 0
                for key, max_chars in (
                    ("actor", 120),
                    ("action", 160),
                    ("target", 240),
                    ("evidence_required", 320),
                    ("actual_state", 240),
                ):
                    text = _safe_text_item(step.get(key), max_chars=max_chars)
                    if text:
                        safe_step[key] = text
                if isinstance(step.get("applicable"), bool):
                    safe_step["applicable"] = step.get("applicable")
                safe_step["worklist_predicates"] = _sanitize_worklist_predicates(
                    step.get("worklist_predicates"),
                    max_predicates=4,
                    max_hit_refs=6,
                )
                step_rows.append(safe_step)

            template_worklist: list[dict[str, Any]] = []
            seen_predicates: set[str] = set()
            for step in step_rows:
                for pred in step.get("worklist_predicates", []):
                    if not isinstance(pred, dict):
                        continue
                    pid = str(pred.get("predicate_id") or "").strip()
                    if not pid or pid in seen_predicates:
                        continue
                    seen_predicates.add(pid)
                    template_worklist.append(pred)
                    if len(template_worklist) >= 12:
                        break
                if len(template_worklist) >= 12:
                    break

            out.append({
                "template_id": r.get("template_id", ""),
                "title": r.get("title", ""),
                "workspace_scope_match": bool(r.get("workspace_scope_match", False)),
                "actor_sequence_verdicts": step_rows,
                "worklist_predicates": template_worklist,
            })
        return out
    except Exception:  # noqa: BLE001
        return []


def _defihack_class_matches(workspace_path: Path | None = None) -> list[dict[str, Any]]:
    """Return DeFiHackLabs catalog rows that fire against the workspace.

    Sourced from defihack-class-matcher.py (Phase G).  Calls _run_matcher
    internally (loading rows from catalog + running grep predicates against
    workspace).  Returns only rows with ≥1 hit, up to 8.
    """
    if workspace_path is None:
        return []  # no-op without workspace; grep predicates need a target tree
    mod = _load_tool_module("defihack-class-matcher")
    if mod is None:
        return []
    try:
        ws = workspace_path
        if not ws.exists():
            return []
        # Safety cap: skip very large workspaces to keep MCP response times bounded.
        # The defihack matcher runs grep for every catalog row × every predicate; on
        # workspaces with >300 source files this can take >60s.  Workers that need
        # full scans should call `python3 tools/defihack-class-matcher.py --workspace <ws>`
        # directly.  Use a fast early-exit counter (stop at cap+1) to avoid scanning
        # the whole tree just to decide whether to skip.
        _SOURCE_EXTS = {".sol", ".go", ".rs", ".py", ".ts", ".js"}
        _FILE_CAP = 300
        _counted = 0
        for _fp in ws.rglob("*"):
            if _fp.is_file() and _fp.suffix in _SOURCE_EXTS:
                _counted += 1
                if _counted > _FILE_CAP:
                    break
        if _counted > _FILE_CAP:
            return [{"id": "skipped", "attack_class": "N/A",
                     "mechanism": f"workspace too large for inline scan (>{_FILE_CAP} source files); run defihack-class-matcher.py --workspace {ws} directly",
                     "detector_status": "skip", "is_candidate": False, "total_hits": 0, "predicates_with_hits": 0}]
        # Locate catalog via the same default the CLI uses (defihacklabs/catalog.yaml).
        catalog_path = REPO_ROOT / "defihacklabs" / "catalog.yaml"
        if not catalog_path.exists():
            return []
        rows = mod._load_catalog(catalog_path)
        if not rows:
            return []
        results, _candidates = mod._run_matcher(rows, ws, quiet=True)
        hits = [r for r in results if r.get("total_hits", 0) > 0][:8]
        out = []
        for r in hits:
            hits_by_pred = r.get("hits_by_pred") or {}
            matched_predicates = []
            for pred, refs in hits_by_pred.items():
                if not pred:
                    continue
                ref_list = refs if isinstance(refs, list) else []
                matched_predicates.append({
                    "predicate": str(pred),
                    "hit_refs": [str(ref) for ref in ref_list[:3]],
                })
            out.append({
                "id": r.get("id", ""),
                "attack_class": r.get("attack_class", ""),
                "mechanism": r.get("mechanism", ""),
                "detector_status": r.get("detector_status", ""),
                "is_candidate": bool(r.get("is_candidate", False)),
                "total_hits": r.get("total_hits", 0),
                "predicates_with_hits": r.get("predicates_with_hits", 0),
                "grep_predicates": [str(pred) for pred in (r.get("grep_predicates") or [])[:4]],
                "matched_predicates": matched_predicates[:4],
            })
        return out
    except Exception:  # noqa: BLE001
        return []


def _safe_make_command(text: str) -> str | None:
    parts = text.split()
    if not parts or parts[0] != "make":
        return None
    if len(parts) < 2 or parts[1] not in CONTEXT_SAFE_MAKE_TARGETS:
        return None
    return text


def _safe_python_tool_command(text: str) -> str | None:
    parts = text.split()
    if len(parts) < 2 or parts[0] != "python3":
        return None
    prefix = "tools/"
    if not parts[1].startswith(prefix):
        return None
    tool_name = parts[1].removeprefix(prefix)
    if tool_name not in CONTEXT_SAFE_PYTHON_TOOLS:
        return None
    return text


def _safe_command(value: object) -> str | None:
    text = str(value if value is not None else "").strip()
    if text.startswith("$ "):
        text = text[2:].strip()
    if not text or len(text) > 240:
        return None
    if any(ord(ch) < 32 for ch in text):
        return None
    if any(part in text for part in ("`", "$(", ";", "&&", "||", "|", ">", "<")):
        return None
    if re.search(r"\b(rm|curl|wget|ssh|scp|sudo)\b", text):
        return None
    if any(part in text for part in ("/.git", "_privacy_quarantine", ".privacy", "_archive", ".archive")):
        return None
    if text.startswith("make "):
        return _safe_make_command(text)
    if text.startswith("python3 tools/"):
        return _safe_python_tool_command(text)
    if text.startswith(("git status", "git diff", "git show", "gh pr ", "gh issue ")):
        return text
    return None


def _extract_commands(body: str, limit: int = MAX_CONTEXT_COMMANDS) -> list[str]:
    commands: list[str] = []
    fence_mode: str | None = None
    for raw_line in body.splitlines():
        line = raw_line.strip()
        if line.startswith("```"):
            fence = line.strip("`").strip().lower()
            if fence_mode is not None:
                fence_mode = None
                continue
            fence_mode = "shell" if not fence or fence in {"bash", "sh", "shell", "zsh"} else "other"
            continue
        candidate = line
        if line.startswith("- "):
            candidate = line[2:].strip()
        if fence_mode == "shell" or candidate.startswith(("$ ", *CONTEXT_COMMAND_PREFIXES)):
            safe = _safe_command(candidate)
            if safe:
                commands.append(safe)
        if len(commands) >= limit:
            break
    return _unique_bounded(commands, limit)


