def _path_has_symlink(path: Path, stop_at: Path | None = None) -> bool:
    stop = stop_at.resolve() if stop_at else None
    for candidate in [path] + list(path.parents):
        try:
            resolved = candidate.resolve()
        except OSError:
            resolved = None
        if stop is not None and resolved == stop:
            break
        if candidate.exists() and candidate.is_symlink():
            return True
    return False


def _safe_workspace_or_brief_path(value: object) -> Path | None:
    text = str(value if value is not None else "").strip()
    if not text or any(ord(ch) < 32 or ch in "`" for ch in text):
        return None
    path = Path(text).expanduser()
    if any(part in FORBIDDEN_PARTS for part in path.parts):
        return None
    return path


def _fileable_signal(value: object, severity: object = "", artifacts: object = "") -> str:
    text = str(value if value is not None else "").strip().lower()
    sev = str(severity if severity is not None else "").strip().lower()
    artifact_text = str(artifacts if artifacts is not None else "").strip().lower()
    if any(term in text for term in ("killed", "superseded", "false_positive", "false positive", "held")):
        return ""
    if "fileable_signal=fileable" in text:
        return "fileable"
    # r36-rebuttal: bugfix-inventory-claude-20260610
    if re.search(r'\bfileable\b', text) and "superseded" not in text:
        return "possible_fileable"
    if any(term in text for term in ("current triager-facing", "triager-facing body", "current submission", "paste-ready")) and any(
        term in sev for term in ("high", "medium")
    ):
        return "candidate"
    if (
        "candidate" in text
        and any(term in sev for term in ("high", "medium"))
        and any(term in artifact_text for term in ("final_cantina_paste", "paste_ready", "packaged"))
    ):
        return "candidate"
    return ""


def _workspace_ref(value: object) -> str | None:
    rel = _safe_workspace_relpath(value)
    return f"workspace:{rel}" if rel else None


def _workspace_artifact_refs(value: object, limit: int = MAX_WORKSPACE_GATE_REFS) -> list[str]:
    text = str(value if value is not None else "")
    candidates = re.findall(r"`([^`]+)`", text)
    if not candidates and text.strip():
        candidates = [part.strip() for part in text.split(",")]
    refs: list[str] = []
    for candidate in candidates:
        ref = _workspace_ref(candidate.strip())
        if ref:
            refs.append(ref)
        if len(refs) >= limit:
            break
    return _unique_bounded(refs, limit)


def _candidate_submission_slugs(source_refs: Iterable[str]) -> list[str]:
    slugs: list[str] = []
    for ref in source_refs:
        if not ref.startswith("workspace:"):
            continue
        rel = ref.removeprefix("workspace:")
        path = Path(rel)
        parts = path.parts
        if len(parts) < 3 or parts[0] != "submissions":
            continue
        if parts[1] not in {"final_cantina_paste", "paste_ready", "hardened"}:
            continue
        if path.suffix != ".md":
            continue
        slug = path.stem
        if re.fullmatch(r"[A-Za-z0-9._-]+", slug):
            slugs.append(slug)
    return _unique_bounded(slugs, MAX_WORKSPACE_SUBMISSIONS)


_ENGAGEMENT_STATUS_RE = re.compile(
    r"^Status\s*[:*]+\s*\*{0,2}\s*(?P<value>[^*\n][^\n]*?)\s*\*{0,2}\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_ENGAGEMENT_INTERNAL_NAME_RE = re.compile(
    r"^Internal\s+name\s*:\s*(?P<value>[^\n]+?)\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_ENGAGEMENT_SEVERITY_RE = re.compile(
    r"^Severity\s*:\s*(?P<value>[A-Za-z]+)\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_ENGAGEMENT_TARGET_RE = re.compile(
    r"^Target\s*:\s*`?(?P<value>[^`\n]+?)`?\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_ENGAGEMENT_TITLE_RE = re.compile(r"^#\s+(?P<value>.+?)\s*$", re.MULTILINE)


def _engagement_status_classify(text: str | None) -> str:
    if not text:
        return "unknown"
    lower = text.lower()
    if "dropped" in lower or "not fileable" in lower or "not_fileable" in lower:
        return "dropped"
    # r36-rebuttal: bugfix-inventory-claude-20260610
    if re.search(r'(?<!de-)escalat', lower):
        return "escalated"
    if "paid" in lower:
        return "paid"
    if "rejected" in lower or "duplicate" in lower:
        return "rejected"
    # r36-rebuttal: bugfix-inventory-claude-20260610
    if "submitted" in lower or re.search(r'\bfiled\b', lower):
        return "submitted"
    if "candidate" in lower or "pending" in lower or "draft" in lower:
        return "candidate"
    return "unknown"


def _engagement_lane_classify(lane_name: str, file_name: str) -> str:
    """Classify the workflow lane an engagement file lives in.

    Maps the directory name (and filename hints) to a stable lane label.
    """
    lane_lower = lane_name.lower()
    name_lower = file_name.lower()
    if lane_lower == "paste_ready":
        return "paste_ready"
    if lane_lower == "packaged":
        return "packaged"
    if lane_lower == "staging":
        if "candidate" in name_lower:
            return "staging_candidate"
        if "dropped" in name_lower:
            return "staging_dropped"
        return "staging"
    if lane_lower == "dropped":
        return "dropped"
    if lane_lower == "llm_review":
        return "llm_review"
    if lane_lower == "superseded":
        return "superseded"
    if lane_lower == "held":
        return "held"
    return lane_lower or "unknown"


def _engagement_extract_header(text: str) -> dict[str, str]:
    """Pull bounded header metadata (title, status, internal name, severity, target).

    Reads only the first ENGAGEMENT_HEADER_LINES lines to keep the surface bounded
    and avoid leaking large finding bodies.
    """
    header = "\n".join(text.splitlines()[:ENGAGEMENT_HEADER_LINES])
    out: dict[str, str] = {}
    title = _ENGAGEMENT_TITLE_RE.search(header)
    if title:
        out["title"] = title.group("value").strip()[:240]
    status = _ENGAGEMENT_STATUS_RE.search(header)
    if status:
        out["status_text"] = status.group("value").strip()[:240]
    internal = _ENGAGEMENT_INTERNAL_NAME_RE.search(header)
    if internal:
        out["internal_name"] = internal.group("value").strip()[:120]
    severity = _ENGAGEMENT_SEVERITY_RE.search(header)
    if severity:
        out["severity"] = severity.group("value").strip().lower()[:40]
    target = _ENGAGEMENT_TARGET_RE.search(header)
    if target:
        out["target"] = target.group("value").strip()[:240]
    return out


def _engagement_safe_relpath(file_path: Path, audits_root: Path) -> str | None:
    """Return audits-root-relative path with no absolute leakage."""
    try:
        rel = file_path.resolve().relative_to(audits_root.resolve())
    except ValueError:
        return None
    text = str(rel)
    if ".." in Path(text).parts:
        return None
    if _has_secret(text):
        return None
    return text


_ENGAGEMENT_ACTIVE_STATUS_WEIGHTS = {
    "escalated": 70,
    "submitted": 60,
    "candidate": 50,
    "unknown": 20,
}
_ENGAGEMENT_TERMINAL_STATUS_CLASSES = {"dropped", "paid", "rejected"}
_ENGAGEMENT_TERMINAL_LANES = {"dropped", "superseded", "staging_dropped"}
_ENGAGEMENT_ACTIVE_LANE_WEIGHTS = {
    "paste_ready": 30,
    "packaged": 25,
    "staging_candidate": 20,
    "staging": 15,
    "llm_review": 15,
    "held": 10,
}


def _engagement_default_scope_score(engagement: dict[str, Any]) -> int:
    """Score active engagements for the no-argument default status snapshot."""
    score = 0
    for item in engagement.get("files", []):
        if not isinstance(item, dict):
            continue
        status = str(item.get("status_class") or "")
        lane = str(item.get("lane") or "")
        if (
            status in _ENGAGEMENT_TERMINAL_STATUS_CLASSES
            or lane in _ENGAGEMENT_TERMINAL_LANES
        ):
            continue
        status_weight = _ENGAGEMENT_ACTIVE_STATUS_WEIGHTS.get(status, 0)
        lane_weight = _ENGAGEMENT_ACTIVE_LANE_WEIGHTS.get(lane, 0)
        if status_weight <= 0 and lane_weight <= 0:
            continue
        score += max(status_weight, lane_weight)
    return score


def _engagement_refs_from_rows(engagements: list[dict[str, Any]]) -> list[str]:
    refs: list[str] = []
    for engagement in engagements:
        for item in engagement.get("files", []):
            if not isinstance(item, dict):
                continue
            rel = item.get("audits_relpath")
            if isinstance(rel, str) and rel:
                refs.append(rel)
    return refs


_LINEAGE_LOOP_RE = re.compile(r"\bL(\d{1,3})\b")
_LINEAGE_WORKER_RE = re.compile(r"\bWorker[-_]([A-Z]{2,5})\b")
_LINEAGE_M14_RE = re.compile(r"\bM14[-_ ]?trap\b", re.IGNORECASE)


def _lineage_extract_from_header(text: str) -> dict[str, Any]:
    """Pull bounded lineage signals out of the header region of a finding markdown.

    Scans the first MAX_LINEAGE_HEADER_CHARS characters for:
      * loop ids (e.g. ``L14``, ``L18``)
      * worker ids (e.g. ``Worker-AAF``, ``Worker-KKK``)
      * M14-trap mentions
      * the ``Surfaced by:`` line
    """
    head = text[:MAX_LINEAGE_HEADER_CHARS]
    loops_seen: list[str] = []
    seen_loops: set[str] = set()
    for m in _LINEAGE_LOOP_RE.finditer(head):
        token = "L" + m.group(1)
        if token in seen_loops:
            continue
        seen_loops.add(token)
        loops_seen.append(token)
        if len(loops_seen) >= MAX_LINEAGE_LOOPS:
            break
    workers_seen: list[str] = []
    seen_workers: set[str] = set()
    for m in _LINEAGE_WORKER_RE.finditer(head):
        token = "Worker-" + m.group(1)
        if token in seen_workers:
            continue
        seen_workers.add(token)
        workers_seen.append(token)
        if len(workers_seen) >= MAX_LINEAGE_WORKERS:
            break
    m14_count = len(_LINEAGE_M14_RE.findall(head))
    surfaced = ""
    for line in head.splitlines():
        stripped = line.strip()
        if stripped.lower().startswith("surfaced by:"):
            surfaced = stripped[len("Surfaced by:"):].strip()[:300]
            break
    return {
        "loops_seen": loops_seen,
        "workers_seen": workers_seen,
        "m14_trap_mentions": m14_count,
        "surfaced_by": surfaced,
    }


def _lineage_match(slug: str, *, internal_name: str, filename: str, title: str) -> bool:
    """Decide whether the bounded slug (lowercased, stripped) matches a finding."""
    slug_lower = slug.lower().strip()
    if not slug_lower:
        return False
    haystacks = (
        (internal_name or "").lower(),
        (filename or "").lower(),
        (title or "").lower(),
    )
    for h in haystacks:
        if not h:
            continue
        if slug_lower in h:
            return True
    # also accept whole-word match against tokens of internal_name (e.g. "LEAD 1")
    return False


def _detector_pattern_dispatch_block(source: str) -> str | None:
    """Extract the pattern_results dispatch literal from go-detector-runner.

    Returns the {…} block text if present, else None.
    """
    marker = re.search(r"pattern_results\s*[:=]\s*\{", source)
    if marker is None:
        return None
    start = source.index("{", marker.start())
    depth = 0
    for idx in range(start, len(source)):
        ch = source[idx]
        if ch == "{":
            depth += 1
        elif ch == "}":
            depth -= 1
            if depth == 0:
                return source[start : idx + 1]
    return None


def _detector_pattern_lookup(source: str, slug: str) -> tuple[str, int] | None:
    """Find the dispatch entry for ``slug``; return (callee_name, source_line)."""
    pattern = re.compile(
        r'"' + re.escape(slug) + r'"\s*:\s*\n?\s*([A-Za-z_][A-Za-z0-9_]*)\s*\(',
    )
    match = pattern.search(source)
    if match is None:
        return None
    callee = match.group(1)
    line = source[: match.start()].count("\n") + 1
    return callee, line


def _detector_function_def_line(source: str, name: str) -> int | None:
    pattern = re.compile(r"^def\s+" + re.escape(name) + r"\s*\(", re.MULTILINE)
    match = pattern.search(source)
    if match is None:
        return None
    return source[: match.start()].count("\n") + 1


def _detector_function_docstring(source: str, name: str) -> str | None:
    """Return the bounded leading docstring of a python function definition."""
    pattern = re.compile(
        r"^def\s+" + re.escape(name) + r"\s*\([^)]*\)[^:]*:\s*\n",
        re.MULTILINE | re.DOTALL,
    )
    match = pattern.search(source)
    if match is None:
        return None
    after = source[match.end():]
    triple = re.match(r"\s*([\"']{3})", after)
    if triple is None:
        return None
    quote = triple.group(1)
    body_start = triple.end()
    end = after.find(quote, body_start)
    if end == -1:
        return None
    text = after[body_start:end].strip()
    return text[:1200] if text else None


def _extract_note_items(note: dict[str, Any], kind: str, limit: int = MAX_CONTEXT_ITEMS) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    path = str(note.get("path", ""))
    for line in str(note.get("body", "")).splitlines():
        stripped = line.strip()
        if not (stripped.startswith("## ") or stripped.startswith("- ")):
            continue
        status = _extract_status_from_text(stripped)
        if not _context_allows_status(kind, status):
            continue
        text = _safe_text_item(stripped.removeprefix("- ").strip())
        if not text:
            continue
        items.append(
            {
                "text": text,
                "source_ref": f"vault://{path}",
                "status": status,
                "status_class": _status_class(status),
            }
        )
        if len(items) >= limit:
            break
    return items


@dataclass(frozen=True)
class Note:
    path: Path
    relpath: str
    category: str
    frontmatter: dict[str, Any]
    body: str
    title: str


class VaultQuery:
    def __init__(self, vault_dir: Path, repo_root: Path | None = None) -> None:
        self.vault_dir = vault_dir.resolve()
        self.repo_root = (repo_root or self._infer_repo_root()).resolve()
        # Stamp the running process with the code revision observed at start.
        # Compared against the live on-disk stamp on every call() to detect a
        # post-merge stale daemon (see _compute_code_revision_stamp).
        self.start_code_stamp = _compute_code_revision_stamp(self.repo_root)

    def daemon_version_info(self) -> dict[str, Any]:
        """Code-revision stamp of the running daemon vs the on-disk code.

        ``stale`` is True when the on-disk tool code has advanced past the
        revision this process started with - i.e. a `git pull`/merge landed a
        tool fix that the running daemon is NOT serving yet. The remedy is a
        daemon restart; we never hot-reload arbitrary code.
        """
        current = _compute_code_revision_stamp(self.repo_root)
        stale = current != self.start_code_stamp
        info: dict[str, Any] = {
            "version": _daemon_version_string(self.start_code_stamp),
            "start_code_stamp": self.start_code_stamp,
            "current_code_stamp": current,
            "stale": stale,
        }
        if stale:
            info["degraded"] = True
            info["warning"] = "daemon-stale-restart-required"
            info["detail"] = (
                "On-disk tool code advanced past the revision this daemon "
                "started with; results may be pre-fix. Restart the MCP daemon "
                "to serve the current code."
            )
        return info

    def _infer_repo_root(self) -> Path:
        if self.vault_dir.name == "obsidian-vault":
            return self.vault_dir.parent
        return REPO_ROOT

    def _safe_path(self, relpath: str) -> Path:
        rel = Path(relpath)
        if rel.is_absolute():
            raise ValueError("path must be relative to vault")
        if _has_forbidden_part(rel):
            raise PermissionError("path is private or archived")
        candidate = self.vault_dir / rel
        current = self.vault_dir
        for part in rel.parts:
            current = current / part
            if current.is_symlink():
                raise PermissionError("symlink paths are not readable through vault MCP")
        path = candidate.resolve()
        if self.vault_dir not in path.parents and path != self.vault_dir:
            raise ValueError("path escapes vault")
        resolved_rel = path.relative_to(self.vault_dir)
        if _has_forbidden_part(resolved_rel):
            raise PermissionError("path is private or archived")
        return path

    def _iter_note_paths(self, category: str | None = None) -> Iterable[Path]:
        if not self.vault_dir.exists():
            return []
        base = self.vault_dir
        if category:
            try:
                candidate = self._safe_path(category)
            except (PermissionError, ValueError):
                return []
            if not candidate.exists() or not candidate.is_dir():
                return []
            base = candidate
        return (
            path
            for path in base.rglob("*.md")
            if not _has_forbidden_part(path.relative_to(self.vault_dir))
        )

    def _project_memory_dir(self) -> Path:
        projects_base = os.environ.get(CLAUDE_PROJECTS_DIR_ENV)
        if projects_base:
            base = Path(projects_base).expanduser()
        else:
            base = Path.home() / ".claude" / "projects"
        slug = str(self.repo_root).replace("/", "-").lstrip("-")
        return (base / slug / "memory").resolve()

    def _safe_project_memory_path(self, relpath: str) -> Path:
        rel = Path(relpath)
        if rel.is_absolute():
            raise ValueError("path must be relative to project memory")
        if _has_forbidden_part(rel):
            raise PermissionError("path is private or archived")
        base = self._project_memory_dir()
        candidate = base / rel
        current = base
        for part in rel.parts:
            current = current / part
            if current.exists() and current.is_symlink():
                raise PermissionError("symlink paths are not readable through vault MCP")
        path = candidate.resolve()
        if base not in path.parents and path != base:
            raise ValueError("path escapes project memory")
        return path

    def _iter_project_memory_note_paths(self, category: str | None = None) -> Iterable[Path]:
        memory_dir = self._project_memory_dir()
        if category:
            category_path = Path(category)
            if category_path.parts[:1] != (PROJECT_MEMORY_CATEGORY,):
                return []
            rel_parts = category_path.parts[1:]
            try:
                base = self._safe_project_memory_path(Path(*rel_parts).as_posix() if rel_parts else ".")
            except (PermissionError, ValueError):
                return []
        else:
            base = memory_dir
        if not base.exists() or not base.is_dir():
            return []
        return (
            path
            for path in base.rglob("*.md")
            if not _has_forbidden_part(path.relative_to(memory_dir))
            and not _path_has_symlink(path, stop_at=memory_dir)
        )

    def _load_note(self, path: Path) -> Note | None:
        if path.is_symlink():
            return None
        try:
            text = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            return None
        if _has_secret(text):
            return None
        frontmatter, body = _frontmatter_and_body(text)
        relpath = _rel(path, self.vault_dir)
        category = relpath.split("/", 1)[0]
        return Note(path, relpath, category, frontmatter, body, _title(path, frontmatter, body))

    def _load_project_memory_note(self, path: Path) -> Note | None:
        memory_dir = self._project_memory_dir()
        if path.is_symlink() or _path_has_symlink(path, stop_at=memory_dir):
            return None
        try:
            text = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            return None
        if _has_secret(text):
            return None
        frontmatter, body = _frontmatter_and_body(text)
        relpath = f"{PROJECT_MEMORY_CATEGORY}/{_rel(path, memory_dir)}"
        return Note(path, relpath, PROJECT_MEMORY_CATEGORY, frontmatter, body, _title(path, frontmatter, body))

    def _iter_repo_search_note_paths(self, category: str | None = None) -> Iterable[tuple[Path, str]]:
        if category:
            category_path = Path(category)
            if category_path.is_absolute() or _has_forbidden_part(category_path):
                return []
            category_parts = category_path.parts
        else:
            category_parts = ()
        results: list[tuple[Path, str]] = []
        for rel in VAULT_SEARCH_REPO_NOTE_SOURCES:
            if category_parts and rel.parts[: len(category_parts)] != category_parts:
                continue
            if _has_forbidden_part(rel):
                continue
            path = (self.repo_root / rel).resolve()
            if not path.is_file() or _path_has_symlink(path, stop_at=self.repo_root):
                continue
            if self.repo_root not in path.parents and path != self.repo_root:
                continue
            results.append((path, rel.as_posix()))
        return results

    def _load_repo_search_note(self, path: Path, relpath: str) -> Note | None:
        try:
            text = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            return None
        if _has_secret(text):
            return None
        frontmatter, body = _frontmatter_and_body(text)
        category = relpath.split("/", 1)[0]
        return Note(path, relpath, category, frontmatter, body, _title(path, frontmatter, body))

    def vault_search(self, query: str = "", category: str | None = None, limit: int = DEFAULT_LIMIT) -> dict[str, Any]:
        limit = _clamp_limit(limit)
        # Plan 09 §5: expand query across canonical→synonym map so notes
        # mentioning only the synonym still fire for queries that use the
        # canonical phrase. Variants are deduped; cap = MAX_SYNONYM_QUERY_VARIANTS.
        variants = _expand_query_with_synonyms(query) if query else [query]
        # Walk the vault once; score each note against every variant; keep
        # the best score per note. This is cheaper than running the full
        # walk per variant (the score function is cheap; the I/O is not).
        per_note_best: dict[str, dict[str, Any]] = {}
        hits_per_variant: dict[str, int] = {v: 0 for v in variants}
        notes: list[Note] = []
        for path in self._iter_note_paths(category):
            note = self._load_note(path)
            if note is None:
                continue
            notes.append(note)
        for path in self._iter_project_memory_note_paths(category):
            note = self._load_project_memory_note(path)
            if note is None:
                continue
            notes.append(note)
        for path, relpath in self._iter_repo_search_note_paths(category):
            note = self._load_repo_search_note(path, relpath)
            if note is None:
                continue
            notes.append(note)
        for note in notes:
            best_score = 0
            best_variant = variants[0]
            for variant in variants:
                terms = _search_tokens(variant)
                score = _search_score(note, terms, variant)
                if score > 0:
                    hits_per_variant[variant] = hits_per_variant.get(variant, 0) + 1
                if score > best_score:
                    best_score = score
                    best_variant = variant
            if best_score <= 0:
                continue
            per_note_best[note.relpath] = {
                "path": note.relpath,
                "title": note.title,
                "category": note.category,
                "score": best_score,
                "excerpt": _excerpt(note.body, best_variant),
                "recommendation": note.frontmatter.get("recommendation"),
                "sample_size": note.frontmatter.get("sample_size"),
                "last_validated_at": note.frontmatter.get("last_validated_at"),
                "confidence": note.frontmatter.get("confidence"),
                "counter_examples": note.frontmatter.get("counter_examples"),
                "matched_variant": best_variant,
            }
        hits = list(per_note_best.values())
        hits.sort(key=lambda row: (-int(row["score"]), row["path"]))
        return {
            "query": query,
            "category": category,
            "limit": limit,
            "hits": hits[:limit],
            "synonym_expansion": {
                "original": query,
                "expanded_variants": variants,
                "hits_per_variant": hits_per_variant,
            },
        }

    def vault_get(self, path: str) -> dict[str, Any]:
        if Path(path).parts[:1] == (PROJECT_MEMORY_CATEGORY,):
            rel_parts = Path(path).parts[1:]
            if not rel_parts:
                return {"error": "invalid_path", "message": "project-memory path must include a file", "path": path}
            try:
                resolved = self._safe_project_memory_path(Path(*rel_parts).as_posix())
            except PermissionError as exc:
                return {"error": "privacy_refusal", "message": str(exc), "path": path}
            except ValueError as exc:
                return {"error": "invalid_path", "message": str(exc), "path": path}
            if not resolved.exists() or not resolved.is_file():
                return {"error": "not_found", "path": path}
            note = self._load_project_memory_note(resolved)
            if note is None:
                return {"error": "privacy_refusal", "message": "note is unreadable or matches secret pattern", "path": path}
            body = note.body
            if len(body) > MAX_NOTE_CHARS:
                body = body[:MAX_NOTE_CHARS] + "\n\n[truncated]"
            return {
                "path": note.relpath,
                "title": note.title,
                "frontmatter": note.frontmatter,
                "body": body,
            }
        try:
            resolved = self._safe_path(path)
        except PermissionError as exc:
            return {"error": "privacy_refusal", "message": str(exc), "path": path}
        except ValueError as exc:
            return {"error": "invalid_path", "message": str(exc), "path": path}
        if not resolved.exists() or not resolved.is_file():
            return {"error": "not_found", "path": path}
        try:
            text = resolved.read_text(encoding="utf-8")
        except PermissionError as exc:
            return {"error": "privacy_refusal", "message": f"unreadable (permission denied): {exc}", "path": path}
        except (OSError, UnicodeDecodeError) as exc:
            return {"error": "unreadable", "message": str(exc), "path": path}
        if _has_secret(text):
            return {"error": "privacy_refusal", "message": "note matches secret pattern", "path": path}
        frontmatter, body = _frontmatter_and_body(text)
        if len(body) > MAX_NOTE_CHARS:
            body = body[:MAX_NOTE_CHARS] + "\n\n[truncated]"
        return {
            "path": _rel(resolved, self.vault_dir),
            "title": _title(resolved, frontmatter, body),
            "frontmatter": frontmatter,
            "body": body,
        }

    def vault_next_loop(self, limit: int = 5) -> dict[str, Any]:
        limit = _clamp_limit(limit, default=5)
        note = self.vault_get("NEXT_LOOP.md")
        if "error" in note:
            return note
        items: list[str] = []
        for line in str(note["body"]).splitlines():
            stripped = line.strip()
            if stripped.startswith("## ") or stripped.startswith("- "):
                items.append(stripped)
            if len(items) >= limit:
                break
        return {"path": "NEXT_LOOP.md", "limit": limit, "items": items, "body": note["body"]}

    def _goal_loop_report_fallback(self, goal_id: str | None = None) -> dict[str, Any] | None:
        if goal_id and goal_id != "current":
            return None
        reports_dir = self.repo_root / "reports"
        if not reports_dir.is_dir():
            return None
        report_paths = sorted(reports_dir.glob("goal_loop_status_*.json"), reverse=True)
        for report_path in report_paths:
            if report_path.is_symlink() or not report_path.is_file():
                continue
            try:
                payload = json.loads(report_path.read_text(encoding="utf-8"))
            except (OSError, UnicodeDecodeError, json.JSONDecodeError):
                continue
            if not isinstance(payload, dict):
                continue
            policy = payload.get("goal_policy") if isinstance(payload.get("goal_policy"), dict) else {}
            goal_status = str(policy.get("status") or "active_continuous_loop")
            loop_back_phase = str(policy.get("loop_back_phase") or "recall_memory")
            next_action = str(
                payload.get("next_operational_rule")
                or "Choose bounded queue items, verify locally, write back memory, and loop back to recall memory."
            )
            report_rel = _rel(report_path, self.repo_root)
            note_path = ""
            for candidate in ("INDEX_active.md", "DASHBOARD.md", "NEXT_LOOP.md"):
                try:
                    resolved = self._safe_path(candidate)
                except (PermissionError, ValueError):
                    continue
                if resolved.exists() and resolved.is_file():
                    note_path = candidate
                    break
            frontmatter: dict[str, Any] = {
                "objective": DEFAULT_PERPETUAL_GOAL_OBJECTIVE,
                "status": goal_status,
                "loop": "perpetual",
                "terminal_condition": "never",
                "completion_scope": "iterations_only",
                "loop_back_phase": loop_back_phase,
                "next_action": next_action,
                "source_report": report_rel,
            }
            if note_path:
                frontmatter["source_note"] = note_path
            body = "\n".join(
                [
                    "# Current Perpetual Goal",
                    "",
                    "Derived from the latest goal-loop status report because no goals/current.md note is present in the vault.",
                    "",
                    f"- Goal status: `{goal_status}`",
                    "- Loop: `perpetual`",
                    "- Terminal condition: `never`",
                    "- Completion scope: `iterations_only`",
                    f"- Loop-back phase: `{loop_back_phase}`",
                    "",
                    "## Next Action",
                    "",
                    next_action,
                    "",
                ]
            )
            return {
                "status": "found",
                "loop_policy": GOAL_LOOP_POLICY,
                "source": "goal_loop_status_report_fallback",
                "goal": {
                    "path": note_path,
                    "title": "Current Perpetual Goal",
                    "frontmatter": frontmatter,
                    "body": body,
                },
            }
        return None

    def vault_goal_state(self, goal_id: str | None = None) -> dict[str, Any]:
        category = "goals"
        if goal_id:
            direct = self.vault_get(f"{category}/{goal_id}.md")
            if "error" not in direct:
                return {"status": "found", "loop_policy": GOAL_LOOP_POLICY, "goal": direct}
        search = self.vault_search("objective status blocker next_action terminal_artifact", category=category, limit=5)
        if search["hits"]:
            return {"status": "found", "loop_policy": GOAL_LOOP_POLICY, "goals": search["hits"]}
        fallback = self._goal_loop_report_fallback(goal_id)
        if fallback:
            return fallback
        return {
            "status": "missing_category",
            "message": "No goals/ notes found. Fall back to INDEX_active.md, NEXT_LOOP.md, and current thread state.",
            "loop_policy": GOAL_LOOP_POLICY,
        }

    # ------------------------------------------------------------------
    # Phase-0 roadmap coordination callables
    # ------------------------------------------------------------------

    _ACTIVE_ROADMAP_DEFAULT_DOC = (
        REPO_ROOT
        / "reports"
        / "v3_iter_2026-05-24"
        / "CONSOLIDATED_ROADMAP_FOR_CODEX_2026-05-24.md"
    )
    _ACTIVE_ROADMAP_DEFAULT_STATE = (
        REPO_ROOT
        / "reports"
        / "v3_iter_2026-05-24"
        / "consolidated_roadmap_state.json"
    )
    _ACTIVE_ROADMAP_TTL_SECONDS = 6 * 60 * 60
    _ACTIVE_ROADMAP_STATUS_ORDER = {
        "PLANNED": 0,
        "CLAIMED": 1,
        "IN-FLIGHT": 2,
        "PARTIAL": 3,
        "LANDED": 4,
        "BLOCKED": 5,
    }
    _ACTIVE_ROADMAP_PHASE_RANK = {
        "PHASE-0": 0,
        "PHASE-I": 1,
        "PHASE-II": 2,
        "PHASE-III": 3,
        "PHASE-IV": 4,
    }

    @staticmethod
    def _active_roadmap_now() -> _dt.datetime:
        return _dt.datetime.now(_dt.timezone.utc).replace(microsecond=0)

    @staticmethod
    def _active_roadmap_iso(ts: _dt.datetime) -> str:
        if ts.tzinfo is None:
            ts = ts.replace(tzinfo=_dt.timezone.utc)
        return ts.astimezone(_dt.timezone.utc).isoformat().replace("+00:00", "Z")

    @staticmethod
    def _active_roadmap_parse_iso(value: Any) -> _dt.datetime | None:
        if not isinstance(value, str) or not value.strip():
            return None
        try:
            parsed = _dt.datetime.fromisoformat(value.strip().replace("Z", "+00:00"))
        except ValueError:
            return None
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=_dt.timezone.utc)
        return parsed.astimezone(_dt.timezone.utc)

    @staticmethod
    def _active_roadmap_owner(raw: str | None, item_id: str) -> str:
        text = (raw or "").strip().lower()
        if text in {"codex", "claude", "either"}:
            return text
        if item_id.startswith("PHASE-0."):
            return "codex"
        if item_id in {"PHASE-I.1", "PHASE-I.2", "PHASE-I.6", "PHASE-I.7"}:
            return "claude"
        if item_id == "PHASE-II.1":
            return "codex"
        if item_id in {"PHASE-II.2", "PHASE-II.3", "PHASE-II.4"}:
            return "claude"
        return "either"

    def _active_roadmap_catalog(self, roadmap_path: Path) -> list[dict[str, Any]]:
        """Parse the consolidated roadmap into ordered lane records.

        The roadmap is markdown, not a rigid manifest. Keep parsing small and
        deterministic: item headings define lane IDs, nearby Owner markers
        define ownership, Phase II.6's numbered subitems are lifted into lane
        records from the same section, and Phase IV's priority list is added as
        explicit generated lanes because that section intentionally uses
        bullets.
        """
        try:
            raw = roadmap_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            raw = ""
        lines = raw.splitlines()
        catalog: list[dict[str, Any]] = []
        phase_label = ""
        phase_title = ""
        current_item_id = ""
        current_item_owner = ""
        for idx, line in enumerate(lines):
            phase_match = re.match(r"^##\s+PHASE\s+([0IVX]+)\s+-\s+(.+?)\s*$", line)
            if phase_match:
                token = phase_match.group(1)
                phase_label = f"PHASE-{token}"
                phase_title = phase_match.group(2).strip()
                current_item_id = ""
                current_item_owner = ""
                continue
            item_match = re.match(r"^###\s+((?:0|I|II|III)\.\d+)\s+(.+?)\s*$", line)
            if not item_match:
                subitem_match = re.match(
                    r"^\s*\d+\.\s+\*\*(II\.6\.[ABC])\s+(.+?)\*\*(?:\s*[:(].*)?$",
                    line,
                )
                if not subitem_match or current_item_id != "PHASE-II.6":
                    continue
                short_id = subitem_match.group(1)
                title = subitem_match.group(2).strip()
                item_id = f"PHASE-{short_id}"
                catalog.append(
                    {
                        "item_id": item_id,
                        "title": title,
                        "description": "",
                        "phase": phase_label or item_id.rsplit(".", 1)[0],
                        "phase_title": phase_title,
                        "preferred_owner": current_item_owner or self._active_roadmap_owner(None, item_id),
                        "source_heading": line.strip(),
                        "source_line": idx + 1,
                    }
                )
                continue
            short_id = item_match.group(1)
            title = re.sub(r"\s{2,}.*$", "", item_match.group(2).strip()).strip()
            item_id = f"PHASE-{short_id}"
            block = "\n".join(lines[idx : idx + 8])
            owner_match = re.search(r"\*\*Owner\*\*:\s*([A-Za-z]+)", block)
            current_item_owner = self._active_roadmap_owner(
                owner_match.group(1) if owner_match else None,
                item_id,
            )
            # Extract first prose paragraph after the heading as description
            # (skip blank lines and metadata lines starting with ** or #)
            desc_parts: list[str] = []
            for desc_line in lines[idx + 1:idx + 20]:
                stripped = desc_line.strip()
                if re.match(r"^#{1,4}\s", stripped):
                    break
                if not stripped or re.match(r"^\*\*[A-Za-z]", stripped):
                    if desc_parts:
                        break
                    continue
                desc_parts.append(stripped)
                # One sentence is enough for identification purposes
                if len(" ".join(desc_parts)) >= 120 or stripped.endswith("."):
                    break
            description = " ".join(desc_parts)[:300].strip()
            current_item_id = item_id
            catalog.append(
                {
                    "item_id": item_id,
                    "title": title,
                    "description": description,
                    "phase": phase_label or item_id.rsplit(".", 1)[0],
                    "phase_title": phase_title,
                    "preferred_owner": current_item_owner,
                    "source_heading": line.strip(),
                    "source_line": idx + 1,
                }
            )

        # Phase IV is represented as an ordered priority list rather than
        # sub-headings. Make those priorities claimable so the callable can
        # coordinate that parallel queue too.
        if "PHASE IV - Capability patch queue burndown" in raw and not any(
            item["item_id"].startswith("PHASE-IV.") for item in catalog
        ):
            phase_iv = [
                ("PHASE-IV.1", "CAP-004/005/006/007 P3 detector precision pass"),
                ("PHASE-IV.2", "CAP-014 P5 ranking tiebreaker"),
                ("PHASE-IV.3", "CAP-018/019 detector false-positive pass"),
                ("PHASE-IV.4", "CAP-008/010/011/013 workspace ergonomics"),
            ]
            for offset, (item_id, title) in enumerate(phase_iv, start=1):
                catalog.append(
                    {
                        "item_id": item_id,
                        "title": title,
                        "description": "",
                        "phase": "PHASE-IV",
                        "phase_title": "Capability patch queue burndown",
                        "preferred_owner": "either",
                        "source_heading": f"{offset}. {title}",
                        "source_line": 0,
                    }
                )

        def sort_key(item: dict[str, Any]) -> tuple[int, int, int]:
            phase = str(item.get("phase") or "")
            item_id = str(item.get("item_id") or "")
            if phase == "PHASE-II":
                phase_two_order: dict[str, tuple[int, int]] = {
                    "PHASE-II.5": (1, 0),
                    "PHASE-II.2": (2, 0),
                    "PHASE-II.3": (3, 0),
                    "PHASE-II.4": (4, 0),
                    "PHASE-II.6": (5, 0),
                    "PHASE-II.6.A": (5, 1),
                    "PHASE-II.6.C": (5, 2),
                    "PHASE-II.6.B": (5, 3),
                    "PHASE-II.7": (6, 0),
                    "PHASE-II.8": (7, 0),
                    "PHASE-II.9": (8, 0),
                    "PHASE-II.10": (9, 0),
                }
                order = phase_two_order.get(item_id)
                if order is not None:
                    return (self._ACTIVE_ROADMAP_PHASE_RANK.get(phase, 99), order[0], order[1])
            tail = item_id.rsplit(".", 1)[-1]
            try:
                ordinal = int(tail)
            except ValueError:
                ordinal = 999
            return (self._ACTIVE_ROADMAP_PHASE_RANK.get(phase, 99), ordinal, 0)

        catalog.sort(key=sort_key)
        return catalog

    def _active_roadmap_dependencies(self, item_id: str, catalog: list[dict[str, Any]]) -> list[str]:
        ids = [str(item["item_id"]) for item in catalog]
        phase0 = [i for i in ids if i.startswith("PHASE-0.")]
        phase1 = [i for i in ids if i.startswith("PHASE-I.")]
        phase2 = [i for i in ids if i.startswith("PHASE-II.")]
        if item_id.startswith("PHASE-0."):
            return []
        if item_id.startswith("PHASE-I."):
            return phase0
        if item_id.startswith("PHASE-II."):
            return phase0 + phase1
        if item_id.startswith("PHASE-III.") or item_id.startswith("PHASE-IV."):
            return phase0 + phase1 + phase2
        return []

    @staticmethod
    def _active_roadmap_merge_state(
        state: dict[str, Any],
        catalog: list[dict[str, Any]],
        now_iso: str,
    ) -> dict[str, Any]:
        items = state.get("items") if isinstance(state.get("items"), dict) else {}
        merged_items: dict[str, Any] = {}
        for item in catalog:
            item_id = str(item["item_id"])
            existing = items.get(item_id) if isinstance(items.get(item_id), dict) else {}
            merged_items[item_id] = {
                "status": str(existing.get("status") or "PLANNED"),
                "owner": existing.get("owner"),
                "claim_token": existing.get("claim_token"),
                "claimed_at": existing.get("claimed_at"),
                "expires_at": existing.get("expires_at"),
                "result": existing.get("result"),
                "result_summary": existing.get("result_summary"),
                "result_remember": existing.get("result_remember"),
                "completed_at": existing.get("completed_at"),
                "completed_by": existing.get("completed_by"),
            }
        for item_id, existing in sorted(items.items()):
            if item_id in merged_items or not isinstance(existing, dict):
                continue
            # Preserve plan-derived state rows that are more granular than the
            # markdown catalog parser, such as Phase II.6.A/B/C acceptance
            # subitems. Dropping them on every claim makes the JSON state less
            # authoritative than the plan audits it was created to track.
            merged_items[str(item_id)] = {
                "status": str(existing.get("status") or "PLANNED"),
                "owner": existing.get("owner"),
                "claim_token": existing.get("claim_token"),
                "claimed_at": existing.get("claimed_at"),
                "expires_at": existing.get("expires_at"),
                "result": existing.get("result"),
                "result_summary": existing.get("result_summary"),
                "result_remember": existing.get("result_remember"),
                "completed_at": existing.get("completed_at"),
                "completed_by": existing.get("completed_by"),
            }
        out = {
            "schema": "auditooor.consolidated_roadmap_state.v1",
            "iter": str(state.get("iter") or "2026-05-24"),
            "updated_at": str(state.get("updated_at") or now_iso),
            "items": merged_items,
        }
        return out

    @staticmethod
    def _active_roadmap_read_state(state_path: Path) -> dict[str, Any]:
        if not state_path.is_file():
            return {}
        try:
            payload = json.loads(state_path.read_text(encoding="utf-8"))
        except (OSError, UnicodeDecodeError, json.JSONDecodeError):
            return {}
        return payload if isinstance(payload, dict) else {}

    @staticmethod
    def _active_roadmap_atomic_write(path: Path, payload: dict[str, Any]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        fd, tmp_name = tempfile.mkstemp(prefix=f".{path.name}.", suffix=".tmp", dir=str(path.parent))
        tmp_path = Path(tmp_name)
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as handle:
                json.dump(payload, handle, indent=2, sort_keys=True)
                handle.write("\n")
            os.replace(tmp_path, path)
        finally:
            if tmp_path.exists():
                try:
                    tmp_path.unlink()
                except OSError:
                    pass

    def _active_roadmap_locked_update(
        self,
        state_path: Path,
        catalog: list[dict[str, Any]],
        mutate,
    ) -> tuple[dict[str, Any], bool]:
        lock_path = state_path.with_suffix(state_path.suffix + ".lock")
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with lock_path.open("a+", encoding="utf-8") as lock_handle:
            fcntl.flock(lock_handle.fileno(), fcntl.LOCK_EX)
            try:
                now = self._active_roadmap_now()
                raw_state = self._active_roadmap_read_state(state_path)
                state = self._active_roadmap_merge_state(
                    raw_state,
                    catalog,
                    self._active_roadmap_iso(now),
                )
                changed = state != raw_state
                # Always call expire_claims unconditionally - do NOT short-circuit
                # via `changed or expire_claims(...)`. If `changed` is already True
                # (because merge_state added catalog items absent from raw_state),
                # the `or` short-circuits and stale IN-FLIGHT items never expire.
                expire_changed = self._active_roadmap_expire_claims(state, now)
                changed = bool(changed or expire_changed)
                mutate_changed = mutate(state, now)
                changed = bool(changed or mutate_changed or not state_path.exists())
                if changed:
                    state["updated_at"] = self._active_roadmap_iso(now)
                    self._active_roadmap_atomic_write(state_path, state)
                return state, changed
            finally:
                fcntl.flock(lock_handle.fileno(), fcntl.LOCK_UN)

    def _active_roadmap_expire_claims(self, state: dict[str, Any], now: _dt.datetime) -> bool:
        changed = False
        items = state.get("items") if isinstance(state.get("items"), dict) else {}
        for row in items.values():
            if not isinstance(row, dict):
                continue
            status = str(row.get("status") or "PLANNED").upper()
            if status not in {"CLAIMED", "IN-FLIGHT"}:
                continue
            expires = self._active_roadmap_parse_iso(row.get("expires_at"))
            if expires is None or expires > now:
                continue
            row["status"] = "PLANNED"
            row["result"] = "expired_claim"
            row["owner"] = None
            row["claim_token"] = None
            row["claimed_at"] = None
            row["expires_at"] = None
            changed = True
        return changed

    def _active_roadmap_deps_met(
        self,
        item_id: str,
        state: dict[str, Any],
        catalog: list[dict[str, Any]],
    ) -> tuple[bool, list[str]]:
        deps = self._active_roadmap_dependencies(item_id, catalog)
        items = state.get("items") if isinstance(state.get("items"), dict) else {}
        missing = [
            dep
            for dep in deps
            if str((items.get(dep) or {}).get("status") or "") != "LANDED"
        ]
        return (not missing, missing)

    @staticmethod
    def _active_roadmap_side(value: Any) -> str:
        side = str(value or "").strip().lower()
        return side if side in {"codex", "claude"} else "codex"

    @staticmethod
    def _active_roadmap_owner_compatible(side: str, preferred_owner: str) -> bool:
        # Owner labels in the roadmap are scheduling hints, not hard access
        # controls. The callable's job is to prevent duplicate claims across
        # Codex/Claude, while the operator may assign all lanes to one side.
        return side in {"codex", "claude"} and preferred_owner in {"codex", "claude", "either"}

    @staticmethod
    def _active_roadmap_result_summary(value: Any, fallback: str = "") -> str:
        text = re.sub(r"\s+", " ", str(value or "").strip())
        if not text:
            text = fallback
        return text[:600]

    @staticmethod
    def _active_roadmap_memory_name(item_id: str) -> str:
        slug = re.sub(r"[^a-z0-9_\-]+", "_", item_id.lower()).strip("_")
        return f"roadmap_{slug}_result"

    def _active_roadmap_prior_outputs(
        self,
        item_id: str,
        state: dict[str, Any],
        catalog: list[dict[str, Any]],
    ) -> list[dict[str, str]]:
        outputs: list[dict[str, str]] = []
        items = state.get("items") if isinstance(state.get("items"), dict) else {}
        titles = {str(item["item_id"]): str(item.get("title") or "") for item in catalog}
        for dep in self._active_roadmap_dependencies(item_id, catalog):
            row = items.get(dep) if isinstance(items.get(dep), dict) else {}
            status = str(row.get("status") or "")
            if status not in {"LANDED", "BLOCKED", "PARTIAL"}:
                continue
            summary = self._active_roadmap_result_summary(row.get("result_summary"))
            if not summary:
                continue
            outputs.append(
                {
                    "item_id": dep,
                    "title": titles.get(dep, ""),
                    "status": status,
                    "summary": summary,
                }
            )
        return outputs

    def _active_roadmap_remember_content(
        self,
        *,
        item_id: str,
        item_title: str,
        result_status: str,
        result_summary: str,
        side: str,
        completed_at: str,
    ) -> str:
        name = self._active_roadmap_memory_name(item_id)
        desc = self._active_roadmap_result_summary(
            f"{item_id} {result_status}: {result_summary}",
            fallback=f"{item_id} {result_status}",
        )
        return "\n".join(
            [
                "---",
                f"name: {name}",
                f"description: {desc}",
                "type: project",
                f"date: {completed_at[:10]}",
                "---",
                "",
                f"# {item_id} result",
                "",
                f"- title: {item_title}",
                f"- status: {result_status}",
                f"- completed_by: {side}",
                f"- completed_at: {completed_at}",
                "",
                "## Result Summary",
                "",
                result_summary,
                "",
            ]
        )

    def _active_roadmap_remember_token(
        self,
        kwargs: dict[str, Any],
        side: str,
    ) -> tuple[str, str]:
        supplied = str(
            kwargs.get("remember_signed_token")
            or kwargs.get("signed_token")
            or ""
        ).strip()
        if supplied:
            return supplied, "provided"
        try:
            token_mod = _auditooor_mcp_token_module()
            token, _payload = token_mod.issue_token(
                workspace_path=str(self.repo_root),
                owner=side,
                scope=["remember"],
                ttl_seconds=10 * 60,
                log=False,
            )
            return token, "issued"
        except Exception as exc:  # noqa: BLE001 - result memory is best-effort.
            return "", f"issue_failed:{exc}"

    def _active_roadmap_record_result_memory(
        self,
        *,
        item: dict[str, Any],
        result_status: str,
        result_summary: str,
        side: str,
        completed_at: str,
        kwargs: dict[str, Any],
    ) -> dict[str, Any]:
        signed_token, token_source = self._active_roadmap_remember_token(kwargs, side)
        if not signed_token:
            return {
                "attempted": False,
                "accepted": False,
                "reason": token_source or "missing_signed_token",
            }
        content = self._active_roadmap_remember_content(
            item_id=str(item["item_id"]),
            item_title=str(item.get("title") or ""),
            result_status=result_status,
            result_summary=result_summary,
            side=side,
            completed_at=completed_at,
        )
        result = self.vault_remember(
            scope=str(kwargs.get("remember_scope") or "project"),
            content=content,
            signed_token=signed_token,
        )
        return {
            "attempted": True,
            "accepted": bool(result.get("accepted")),
            "token_source": token_source,
            "context_pack_id": result.get("context_pack_id", ""),
            "memory_path": result.get("memory_path", ""),
            "derived_filename": result.get("derived_filename", ""),
            "error": result.get("error", ""),
        }

    @staticmethod
    def _active_roadmap_portable_result_remember(
        result_remember: dict[str, Any] | None,
    ) -> dict[str, Any] | None:
        if result_remember is None:
            return None
        portable = dict(result_remember)
        memory_path = str(portable.get("memory_path") or "")
        if memory_path:
            path = Path(memory_path)
            if path.is_absolute():
                filename = str(portable.get("derived_filename") or path.name)
                portable["memory_path"] = f"memory/{filename}"
        return portable

    def _active_roadmap_item_view(
        self,
        item: dict[str, Any],
        state: dict[str, Any],
        catalog: list[dict[str, Any]],
        side: str,
        claim_token: str | None = None,
    ) -> dict[str, Any]:
        item_id = str(item["item_id"])
        row = state.get("items", {}).get(item_id, {})
        deps_met, missing_deps = self._active_roadmap_deps_met(item_id, state, catalog)
        status = str(row.get("status") or "PLANNED")
        owner = row.get("owner") or item.get("preferred_owner")
        prior_outputs = self._active_roadmap_prior_outputs(item_id, state, catalog)
        lane_brief_parts = [
            f"# {item_id} - {item.get('title')}",
            "",
            f"Preferred owner (advisory): {item.get('preferred_owner')}",
            "Operator override: Codex may claim and execute every lane unless explicitly reassigned.",
            f"Current status: {status}",
            f"Requested side: {side}",
        ]
        if prior_outputs:
            lane_brief_parts.extend(["", "prior_lane_output:"])
            for prior in prior_outputs:
                lane_brief_parts.append(
                    f"- {prior['item_id']} [{prior['status']}]: {prior['summary']}"
                )
        lane_brief_parts.extend(
            [
                "",
                "Source: reports/v3_iter_2026-05-24/CONSOLIDATED_ROADMAP_FOR_CODEX_2026-05-24.md",
                "Before edits: run this callable with claim:true and keep the returned claim_token.",
                "On completion: call vault_active_roadmap with result_status=LANDED|BLOCKED|PARTIAL and the claim_token.",
            ]
        )
        lane_brief = "\n".join(lane_brief_parts)
        display_status = status
        if status in {"CLAIMED", "IN-FLIGHT"} and row.get("owner"):
            display_status = f"IN-FLIGHT-BY-{row.get('owner')}"
        view = {
            "next_item_id": item_id,
            "item_id": item_id,
            "title": item.get("title"),
            "description": item.get("description") or "",
            "phase": item.get("phase"),
            "owner": owner,
            "preferred_owner": item.get("preferred_owner"),
            "status": status,
            "display_status": display_status,
            "lane_brief_template": lane_brief,
            "prior_lane_output": prior_outputs,
            "claim_token": claim_token if claim_token is not None else row.get("claim_token"),
            "dependencies_met": deps_met,
            "missing_dependencies": missing_deps,
            "expires_at": row.get("expires_at"),
            "source_line": item.get("source_line"),
        }
        return view

    def _active_roadmap_select_next(
        self,
        side: str,
        state: dict[str, Any],
        catalog: list[dict[str, Any]],
    ) -> dict[str, Any] | None:
        items = state.get("items") if isinstance(state.get("items"), dict) else {}
        for item in catalog:
            item_id = str(item["item_id"])
            preferred = str(item.get("preferred_owner") or "either")
            if not self._active_roadmap_owner_compatible(side, preferred):
                continue
            row = items.get(item_id) if isinstance(items.get(item_id), dict) else {}
            status = str(row.get("status") or "PLANNED")
            if status in {"LANDED", "BLOCKED"}:
                continue
            if status in {"CLAIMED", "IN-FLIGHT"}:
                continue
            deps_met, _missing = self._active_roadmap_deps_met(item_id, state, catalog)
            if not deps_met:
                continue
            return item
        return None

    @staticmethod
    def _active_roadmap_token(side: str, item_id: str, now: _dt.datetime) -> str:
        seed = f"{side}|{item_id}|{now.isoformat()}|".encode("utf-8") + os.urandom(16)
        return hashlib.sha256(seed).hexdigest()[:32]

    def vault_active_roadmap(self, **kwargs: Any) -> dict[str, Any]:
        """Return or claim the next consolidated roadmap item.

        This is the Phase-0 coordination gate for Codex/Claude parallel work.
        It reads the consolidated roadmap markdown plus the JSON state file,
        expires stale claims, and performs claim/result updates under a
        sidecar flock with atomic rename writes.
        """
        side = self._active_roadmap_side(kwargs.get("side"))
        claim = bool(kwargs.get("claim", False))
        item_id_arg = str(kwargs.get("item_id") or "").strip()
        result_status = str(
            kwargs.get("result_status") or kwargs.get("result") or ""
        ).strip().upper()
        claim_token_arg = str(kwargs.get("claim_token") or "").strip()
        result_summary_arg = self._active_roadmap_result_summary(
            kwargs.get("result_summary") or kwargs.get("result_output")
        )
        ttl_seconds = self._ACTIVE_ROADMAP_TTL_SECONDS
        try:
            ttl_seconds = int(kwargs.get("ttl_seconds") or ttl_seconds)
        except (TypeError, ValueError):
            ttl_seconds = self._ACTIVE_ROADMAP_TTL_SECONDS
        ttl_seconds = max(60, min(ttl_seconds, 24 * 60 * 60))

        roadmap_path = Path(
            str(kwargs.get("roadmap_path") or self._ACTIVE_ROADMAP_DEFAULT_DOC)
        ).expanduser()
        state_path = Path(
            str(kwargs.get("state_path") or self._ACTIVE_ROADMAP_DEFAULT_STATE)
        ).expanduser()
        if not roadmap_path.is_absolute():
            roadmap_path = self.repo_root / roadmap_path
        if not state_path.is_absolute():
            state_path = self.repo_root / state_path

        catalog = self._active_roadmap_catalog(roadmap_path)
        catalog_by_id = {str(item["item_id"]): item for item in catalog}

        mutation: dict[str, Any] = {
            "requested_claim": claim,
            "requested_result_status": result_status or None,
            "accepted": False,
            "reason": "",
        }
        selected_item_id: str | None = None
        selected_claim_token: str | None = None
        completed_result_at: str | None = None

        def mutate(state: dict[str, Any], now: _dt.datetime) -> bool:
            nonlocal selected_item_id, selected_claim_token, completed_result_at
            changed = False
            items = state.get("items") if isinstance(state.get("items"), dict) else {}
            if result_status:
                if result_status not in {"LANDED", "BLOCKED", "PARTIAL"}:
                    mutation["reason"] = "invalid_result_status"
                    return changed
                # Allow result recording for catalog items AND ad-hoc items
                # already present in state (previously claimed).
                if not item_id_arg:
                    mutation["reason"] = "unknown_item_id"
                    return changed
                if item_id_arg not in catalog_by_id and item_id_arg not in items:
                    mutation["reason"] = "unknown_item_id"
                    return changed
                row = items.get(item_id_arg) if isinstance(items.get(item_id_arg), dict) else {}
                if not claim_token_arg or claim_token_arg != str(row.get("claim_token") or ""):
                    mutation["reason"] = "claim_token_mismatch"
                    selected_item_id = item_id_arg
                    return changed
                row["status"] = result_status
                row["result"] = result_status
                completed_result_at = self._active_roadmap_iso(now)
                row["completed_at"] = completed_result_at
                row["completed_by"] = side
                row["result_summary"] = self._active_roadmap_result_summary(
                    result_summary_arg,
                    fallback=f"{result_status} by {side}",
                )
                row["owner"] = None
                row["claim_token"] = None
                row["claimed_at"] = None
                row["expires_at"] = None
                selected_item_id = item_id_arg
                mutation["accepted"] = True
                mutation["reason"] = "result_recorded"
                changed = True
                return changed

            target = catalog_by_id.get(item_id_arg) if item_id_arg else None
            if target is None and item_id_arg:
                # Allow ad-hoc claims for well-formed item IDs not yet in the
                # catalog markdown (e.g. meta-fix lanes like
                # PHASE-II.11.1-CLAIM-TOKEN-FIX). These are treated as
                # operator-declared ad-hoc items owned by either side.
                if re.match(r"^PHASE-[A-Z0-9][A-Z0-9._-]{1,60}$", item_id_arg, re.IGNORECASE):
                    target = {
                        "item_id": item_id_arg,
                        "title": item_id_arg,
                        "description": "Ad-hoc lane (not in catalog markdown)",
                        "phase": item_id_arg.rsplit(".", 1)[0] if "." in item_id_arg else item_id_arg,
                        "phase_title": "",
                        "preferred_owner": "either",
                        "source_heading": item_id_arg,
                        "source_line": 0,
                    }
                    # Ensure the ad-hoc item is visible in the state so TTL
                    # expiry and release flows work correctly.
                    if item_id_arg not in items:
                        items[item_id_arg] = {"status": "PLANNED"}
                        if not isinstance(state.get("items"), dict):
                            state["items"] = {}
                        state["items"][item_id_arg] = items[item_id_arg]
                else:
                    mutation["reason"] = "unknown_item_id"
                    return changed
            if target is None:
                target = self._active_roadmap_select_next(side, state, catalog)
            if target is None:
                mutation["reason"] = "no_available_item"
                return changed
            item_id = str(target["item_id"])
            selected_item_id = item_id
            preferred = str(target.get("preferred_owner") or "either")
            if not self._active_roadmap_owner_compatible(side, preferred):
                mutation["reason"] = f"owner_mismatch:{preferred}"
                return changed
            # Ad-hoc items have no catalog dependencies; only catalog items get
            # the normal deps_met check.
            if item_id in catalog_by_id:
                deps_met, _missing = self._active_roadmap_deps_met(item_id, state, catalog)
                if not deps_met:
                    mutation["reason"] = "dependencies_not_met"
                    return changed
            row = items.get(item_id) if isinstance(items.get(item_id), dict) else {}
            status = str(row.get("status") or "PLANNED")
            if status in {"LANDED", "BLOCKED"}:
                mutation["reason"] = f"already_{status.lower()}"
                return changed
            if status in {"CLAIMED", "IN-FLIGHT"}:
                mutation["reason"] = f"in_flight_by:{row.get('owner') or 'unknown'}"
                return changed
            if claim:
                token = self._active_roadmap_token(side, item_id, now)
                row["status"] = "IN-FLIGHT"
                row["owner"] = side
                row["claim_token"] = token
                row["claimed_at"] = self._active_roadmap_iso(now)
                row["expires_at"] = self._active_roadmap_iso(now + _dt.timedelta(seconds=ttl_seconds))
                row["result"] = None
                selected_claim_token = token
                mutation["accepted"] = True
                mutation["reason"] = "claim_recorded"
                changed = True
            else:
                mutation["accepted"] = True
                mutation["reason"] = "preview"
            return changed

        state, state_changed = self._active_roadmap_locked_update(
            state_path,
            catalog,
            mutate,
        )
        selected_item = catalog_by_id.get(selected_item_id or "")
        # For ad-hoc items not in the catalog, reconstruct a minimal item dict
        # so the view/remember paths can function correctly. This fires both
        # for accepted mutations (claim, result) AND for rejected ones where
        # the item_id was explicitly requested (e.g. in_flight_by rejection).
        if selected_item is None and selected_item_id and (
            selected_item_id in state.get("items", {}) or mutation.get("accepted")
        ):
            row = state.get("items", {}).get(selected_item_id, {})
            selected_item = {
                "item_id": selected_item_id,
                "title": selected_item_id,
                "description": "Ad-hoc lane (not in catalog markdown)",
                "phase": selected_item_id.rsplit(".", 1)[0] if "." in selected_item_id else selected_item_id,
                "phase_title": "",
                "preferred_owner": row.get("owner") or side,
                "source_heading": selected_item_id,
                "source_line": 0,
            }
        result_remember: dict[str, Any] | None = None
        if (
            result_status
            and mutation.get("accepted")
            and selected_item is not None
            and completed_result_at
        ):
            row = state.get("items", {}).get(str(selected_item["item_id"]), {})
            summary_for_memory = self._active_roadmap_result_summary(
                row.get("result_summary"),
                fallback=f"{result_status} by {side}",
            )
            result_remember = self._active_roadmap_record_result_memory(
                item=selected_item,
                result_status=result_status,
                result_summary=summary_for_memory,
                side=side,
                completed_at=completed_result_at,
                kwargs=kwargs,
            )

            def remember_mutate(next_state: dict[str, Any], _now: _dt.datetime) -> bool:
                items = next_state.get("items") if isinstance(next_state.get("items"), dict) else {}
                next_item_id = str(selected_item["item_id"])
                next_row = (
                    items.get(next_item_id)
                    if isinstance(items.get(next_item_id), dict)
                    else None
                )
                if next_row is None:
                    return False
                next_row["result_remember"] = (
                    self._active_roadmap_portable_result_remember(result_remember)
                )
                return True

            state, remember_state_changed = self._active_roadmap_locked_update(
                state_path,
                catalog,
                remember_mutate,
            )
            state_changed = bool(state_changed or remember_state_changed)
        if selected_item is None:
            selected_item = self._active_roadmap_select_next(side, state, catalog)
        next_view = (
            self._active_roadmap_item_view(
                selected_item,
                state,
                catalog,
                side,
                claim_token=selected_claim_token,
            )
            if selected_item is not None
            else None
        )
        counts: dict[str, int] = {}
        for row in state.get("items", {}).values():
            if isinstance(row, dict):
                status = str(row.get("status") or "PLANNED")
                counts[status] = counts.get(status, 0) + 1
        payload = {
            "schema": ACTIVE_ROADMAP_SCHEMA,
            "kind": "active_roadmap",
            "side": side,
            "claim": claim,
            "mutation": mutation,
            "result_remember": result_remember,
            "state_changed": state_changed,
            "next_item_id": next_view.get("item_id") if next_view else None,
            "lane_brief_template": next_view.get("lane_brief_template") if next_view else "",
            "claim_token": selected_claim_token
            if selected_claim_token is not None
            else (next_view.get("claim_token") if next_view else None),
            "owner": next_view.get("owner") if next_view else None,
            "dependencies_met": next_view.get("dependencies_met") if next_view else False,
            "expires_at": next_view.get("expires_at") if next_view else None,
            "next_item": next_view,
            "status_counts": dict(sorted(counts.items())),
            "catalog_count": len(catalog),
            "state_path": str(state_path),
            "roadmap_path": str(roadmap_path),
            "source_refs": [
                _rel(roadmap_path, self.repo_root) if roadmap_path.is_relative_to(self.repo_root) else str(roadmap_path),
                _rel(state_path, self.repo_root) if state_path.is_relative_to(self.repo_root) else str(state_path),
            ],
            "generated_at_utc": self._active_roadmap_iso(self._active_roadmap_now()),
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{ACTIVE_ROADMAP_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_known_dead_ends(self, **kwargs: Any) -> dict[str, Any]:
        """Return known futile workflows matching a candidate query."""
        ts = self._active_roadmap_iso(self._active_roadmap_now())
        path = Path(str(kwargs.get("dead_ends_path") or self.repo_root / "reports" / "known_dead_ends.jsonl")).expanduser()
        if not path.is_absolute():
            path = self.repo_root / path
        workspace = str(kwargs.get("workspace") or kwargs.get("workspace_path") or "").strip().lower()
        attack_class = str(kwargs.get("attack_class") or "").strip().lower()
        candidate = str(kwargs.get("candidate_pattern") or kwargs.get("pattern") or "").strip().lower()
        limit = _clamp_limit(kwargs.get("limit"), default=10)

        rows: list[dict[str, Any]] = []
        bad_lines = 0
        if path.is_file() and not _path_has_symlink(path, stop_at=self.repo_root):
            try:
                for line in path.read_text(encoding="utf-8").splitlines():
                    if not line.strip():
                        continue
                    try:
                        row = json.loads(line)
                    except json.JSONDecodeError:
                        bad_lines += 1
                        continue
                    if isinstance(row, dict):
                        rows.append(row)
            except (OSError, UnicodeDecodeError):
                rows = []

        def field_text(row: dict[str, Any], *names: str) -> str:
            parts: list[str] = []
            for name in names:
                value = row.get(name)
                if isinstance(value, list):
                    parts.extend(str(v) for v in value)
                elif value not in (None, ""):
                    parts.append(str(value))
            return "\n".join(parts).lower()

        def matches(row: dict[str, Any]) -> bool:
            if workspace:
                hay = field_text(row, "workspace", "workspace_path", "engagement", "target")
                if workspace not in hay:
                    return False
            if attack_class:
                hay = field_text(row, "attack_class", "bug_class", "category", "tags")
                if attack_class not in hay:
                    return False
            if candidate:
                hay = field_text(row, "candidate_pattern", "pattern", "title", "summary", "reason", "evidence")
                if candidate not in hay:
                    return False
            return True

        matched = [row for row in rows if matches(row)]
        capped = matched[:limit]

        # Optional group_by: an operator-auditable histogram over the MATCHED rows.
        # group_by in {drop_class, rule_cited}. drop_class is derived via
        # lib/dead_end_classify when a row lacks it. Default (no group_by) leaves
        # the flat `dead_ends` output unchanged (back-compat).
        group_by = str(kwargs.get("group_by") or "").strip().lower()
        group_histogram: dict[str, Any] | None = None
        if group_by in ("drop_class", "rule_cited"):
            _dec = None
            try:
                import importlib.util as _ilu
                _sp = _ilu.spec_from_file_location(
                    "dead_end_classify",
                    str(Path(__file__).resolve().parent / "lib" / "dead_end_classify.py"))
                _dec = _ilu.module_from_spec(_sp)
                _sp.loader.exec_module(_dec)  # type: ignore[union-attr]
            except Exception:  # noqa: BLE001 - degrade gracefully
                _dec = None
            hist: dict[str, Any] = {}
            for row in matched:
                reason_txt = str(row.get("reason") or row.get("kill_reason")
                                 or row.get("why_dropped") or "")
                excerpt = str(row.get("code_excerpt") or row.get("evidence_code_excerpt") or "")
                if group_by == "drop_class":
                    dc = row.get("drop_class")
                    if not dc and _dec is not None:
                        try:
                            dc = _dec.classify(reason_txt, excerpt)
                        except Exception:  # noqa: BLE001
                            dc = None
                    keys = [str(dc or "ruled-out-other")]
                else:  # rule_cited
                    rc = row.get("rule_cited")
                    if isinstance(rc, list) and rc:
                        keys = [str(x) for x in rc]
                    elif isinstance(rc, str) and rc.strip():
                        keys = [rc.strip()]
                    elif _dec is not None:
                        try:
                            parsed = _dec.parse_rule_codes(reason_txt, excerpt)
                        except Exception:  # noqa: BLE001
                            parsed = []
                        keys = [str(x) for x in parsed] or ["none"]
                    else:
                        keys = ["none"]
                fl = str(row.get("file_line") or row.get("evidence_file_line")
                         or row.get("file") or "")
                for k in keys:
                    bucket = hist.setdefault(k, {"count": 0, "samples": []})
                    bucket["count"] += 1
                    if fl and len(bucket["samples"]) < 5:
                        bucket["samples"].append(fl)
            group_histogram = dict(sorted(hist.items(), key=lambda kv: -kv[1]["count"]))

        payload = {
            "schema": KNOWN_DEAD_ENDS_SCHEMA,
            "kind": "known_dead_ends",
            "degraded": not path.is_file(),
            "degraded_reason": "" if path.is_file() else "known_dead_ends_jsonl_missing",
            "query": {
                "workspace": workspace,
                "attack_class": attack_class,
                "candidate_pattern": candidate,
                "group_by": group_by,
                "limit": limit,
            },
            "total_records": len(rows),
            "matching_records": len(matched),
            "returned_count": len(capped),
            "bad_jsonl_lines": bad_lines,
            "group_by": group_by or None,
            "group_histogram": group_histogram,
            "dead_ends": capped,
            "source_refs": [_rel(path, self.repo_root) if path.is_relative_to(self.repo_root) else str(path)],
            "generated_at_utc": ts,
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{KNOWN_DEAD_ENDS_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    # r36-rebuttal: lane mimo-corpus-mining-wave-2026-05-28 - corpus-miner output surface
    def vault_mimo_corpus_intelligence(self, **kwargs: Any) -> dict[str, Any]:
        """Surface the mimo-corpus-miner.py output products to workers.

        Returns the observed yield matrix (per workspace x attack_class),
        the per-question signal scores, the cross-class chain candidates,
        the MAYBE-survivor predicate queue, and the hallucination class
        distribution. This is the read-side of the learning loop:
        workers picking up a workspace can see what classes work / fail /
        hallucinate on this target before drilling.

        Added 2026-05-28 (mimo-corpus-mining-wave). Schema:
        auditooor.vault_mimo_corpus_intelligence.v1.
        """
        SCHEMA_RET = "auditooor.vault_mimo_corpus_intelligence.v1"
        workspace = str(kwargs.get("workspace") or kwargs.get("workspace_path") or "").strip()
        ws_name = Path(workspace).name if workspace else ""
        limit = _clamp_limit(kwargs.get("limit"), default=20)

        derived = self.repo_root / "audit/corpus_tags/derived"

        def _read_json(p: Path) -> dict | None:
            if not p.is_file():
                return None
            try:
                return json.loads(p.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                return None

        def _read_jsonl(p: Path, limit: int = 50) -> list:
            if not p.is_file():
                return []
            rows = []
            try:
                with p.open(encoding="utf-8") as fh:
                    for i, line in enumerate(fh):
                        if i >= limit:
                            break
                        line = line.strip()
                        if not line:
                            continue
                        try:
                            rows.append(json.loads(line))
                        except json.JSONDecodeError:
                            continue
            except OSError:
                pass
            return rows

        observed_yield = _read_json(derived / "mimo_observed_yield.json") or {}
        ws_yield = observed_yield.get("by_workspace", {}).get(ws_name, {}) if ws_name else {}

        signal_scores = _read_jsonl(derived / "hacker_q_signal_scores.jsonl", limit=limit)
        # Sort by signal_score descending for top-N
        signal_scores.sort(key=lambda r: r.get("signal_score", 0), reverse=True)
        signal_top = signal_scores[:limit]

        chain_candidates = _read_jsonl(derived / "chain_candidates_from_mimo.jsonl", limit=limit)
        if ws_name:
            chain_candidates = [c for c in chain_candidates if c.get("workspace") == ws_name][:limit]

        predicate_maybes = _read_jsonl(derived / "exploit_predicates_from_mimo_maybes.jsonl", limit=50)
        if ws_name:
            predicate_maybes = [p for p in predicate_maybes if p.get("workspace") == ws_name][:limit]

        hallu_class = _read_jsonl(derived / "mimo_hallucination_classification.jsonl", limit=limit)

        workspace_oos = _read_json(
            derived / f"workspace_oos_extension_{ws_name}.json"
        ) if ws_name else None
        oos_rows_count = len(workspace_oos.get("rows", [])) if workspace_oos else 0

        payload = {
            "schema": SCHEMA_RET,
            "kind": "mimo_corpus_intelligence",
            "workspace": workspace,
            "ws_name": ws_name,
            "observed_yield_for_workspace": ws_yield,
            "observed_yield_global_total_sidecars": observed_yield.get("sidecars_scanned", 0),
            "top_signal_questions": signal_top,
            "chain_candidates_for_workspace": chain_candidates,
            "maybe_predicates_for_workspace_sample": predicate_maybes[:limit],
            "hallucination_class_distribution": hallu_class[:limit],
            "workspace_oos_extension_rows": oos_rows_count,
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{SCHEMA_RET}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    # r36-rebuttal: registered lane mimo-harness-build-2026-05-27
    def vault_mining_health(self, **kwargs: Any) -> dict[str, Any]:
        """Mining-loop telemetry for a workspace: coverage heatmap summary,
        hacker-q reweight ledger snapshot, KDE record count, R75 hallucination
        scan count. Added 2026-05-27 (mimo-harness-build wave).

        Schema: auditooor.vault_mining_health.v1.
        """
        SCHEMA = "auditooor.vault_mining_health.v1"
        workspace = str(kwargs.get("workspace") or kwargs.get("workspace_path") or "").strip()
        ws_name = Path(workspace).name if workspace else ""

        # 1. Coverage heatmap: latest reports/coverage_heatmap_<ws>_*.md
        heatmap_summary: dict[str, Any] = {"present": False, "path": None}
        if ws_name:
            heatmap_glob = list((self.repo_root / "reports").glob(
                f"coverage_heatmap_{ws_name}_*.md"
            ))
            if heatmap_glob:
                latest = sorted(heatmap_glob)[-1]
                try:
                    txt = latest.read_text(encoding="utf-8", errors="replace")[:4000]
                    heatmap_summary = {
                        "present": True,
                        "path": str(latest.relative_to(self.repo_root)),
                        "excerpt": txt,
                    }
                except OSError:
                    pass

        # 2. Hacker-q reweight ledger: latest hacker_q_reweight_*.jsonl
        reweight_summary: dict[str, Any] = {"present": False, "path": None, "record_count": 0}
        rew_glob = list((self.repo_root / "audit/corpus_tags/derived").glob(
            "hacker_q_reweight_*.jsonl"
        ))
        if rew_glob:
            latest = sorted(rew_glob)[-1]
            try:
                count = sum(1 for _ in latest.open(encoding="utf-8"))
                reweight_summary = {
                    "present": True,
                    "path": str(latest.relative_to(self.repo_root)),
                    "record_count": count,
                }
            except OSError:
                pass

        # 3. Known-dead-ends record count
        kde_count = 0
        kde_path = self.repo_root / "reports" / "known_dead_ends.jsonl"
        if kde_path.is_file():
            try:
                kde_count = sum(
                    1 for line in kde_path.open(encoding="utf-8")
                    if line.strip()
                )
            except OSError:
                pass

        # 4. R75 hallucination scan (count CONFIRMED+conceptual signals
        # in active mimo_harness dirs for this workspace)
        hallucination_count = 0
        if ws_name:
            for sidecar_dir in (self.repo_root / "audit/corpus_tags/derived").glob(
                f"mimo_harness_{ws_name}*"
            ):
                if not sidecar_dir.is_dir():
                    continue
                for f in sidecar_dir.glob("*.json"):
                    try:
                        d = json.loads(f.read_text(encoding="utf-8"))
                    except (OSError, json.JSONDecodeError):
                        continue
                    r = d.get("result", "")
                    if not isinstance(r, str):
                        continue
                    if "CONFIRMED" in r and (
                        "conceptual" in r.lower()
                        or "n/a" in r.lower()[:200]
                    ):
                        hallucination_count += 1

        payload = {
            "schema": SCHEMA,
            "kind": "mining_health",
            "workspace": workspace,
            "ws_name": ws_name,
            "coverage_heatmap": heatmap_summary,
            "hacker_q_reweight": reweight_summary,
            "known_dead_end_count": kde_count,
            "hallucination_signal_count": hallucination_count,
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_aggregated_learning(self, **kwargs):
        """Cross-workspace aggregated agent-learning corpus.

        Reads audit/corpus_tags/derived/agent_learning_ledger_aggregated.jsonl
        (the 13+-workspace aggregate; today vault_agent_learning_context only
        reads ONE workspace). Returns a cross-workspace summary (total rows,
        distinct workspaces, distinct attack_classes) plus the top matching
        rows, filterable by optional attack_class / workspace / terminal_kind.

        Honest: relays the aggregated rows verbatim, no fabrication; degrades
        to an empty result if the aggregate file is absent.

        Schema: auditooor.vault_aggregated_learning.v1.
        """
        SCHEMA = "auditooor.vault_aggregated_learning.v1"
        attack_class = str(kwargs.get("attack_class") or "").strip()
        workspace = str(kwargs.get("workspace") or kwargs.get("workspace_path") or "").strip()
        terminal_kind = str(kwargs.get("terminal_kind") or "").strip()
        try:
            limit = int(kwargs.get("limit") or 25)
        except (TypeError, ValueError):
            limit = 25
        limit = max(1, min(limit, 500))

        agg_path = (
            self.repo_root
            / "audit/corpus_tags/derived/agent_learning_ledger_aggregated.jsonl"
        )

        def _row_attack_class(row):
            # The aggregate carries no first-class attack_class field; surface the
            # nearest impact-classifier signals so the attack_class filter and the
            # distinct-attack_classes summary have something honest to bind to.
            for key in ("attack_class", "primary_for", "selected_impact"):
                val = row.get(key)
                if isinstance(val, str) and val.strip():
                    return val.strip()
            return ""

        rows = []
        all_workspaces = set()
        all_attack_classes = set()
        total_rows = 0
        file_present = agg_path.is_file()
        if file_present:
            ac_lower = attack_class.lower()
            tk_lower = terminal_kind.lower()
            ws_lower = workspace.lower()
            try:
                with agg_path.open(encoding="utf-8") as fh:
                    for line in fh:
                        line = line.strip()
                        if not line:
                            continue
                        try:
                            row = json.loads(line)
                        except json.JSONDecodeError:
                            continue
                        if not isinstance(row, dict):
                            continue
                        total_rows += 1
                        r_ws = str(row.get("workspace") or "")
                        r_tk = str(row.get("terminal_kind") or "")
                        r_ac = _row_attack_class(row)
                        if r_ws:
                            all_workspaces.add(r_ws)
                        if r_ac:
                            all_attack_classes.add(r_ac)
                        # Apply filters (substring / case-insensitive, honest best-effort).
                        if ws_lower and ws_lower not in r_ws.lower():
                            continue
                        if tk_lower and tk_lower not in r_tk.lower():
                            continue
                        if ac_lower and ac_lower not in r_ac.lower():
                            continue
                        if len(rows) < limit:
                            rows.append(row)
            except OSError:
                file_present = False

        payload = {
            "schema": SCHEMA,
            "kind": "aggregated_learning",
            "file_present": file_present,
            "aggregate_path": str(agg_path.relative_to(self.repo_root)),
            "filters": {
                "attack_class": attack_class or None,
                "workspace": workspace or None,
                "terminal_kind": terminal_kind or None,
                "limit": limit,
            },
            "summary": {
                "total_rows": total_rows,
                "distinct_workspaces": len(all_workspaces),
                "distinct_attack_classes": len(all_attack_classes),
                "returned_rows": len(rows),
            },
            "rows": rows,
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_auto_coverage_closer(self, **kwargs: Any) -> dict[str, Any]:
        """Run (or read) the auto-coverage-closer for a workspace and return its
        verdict + residual-queue summary.  <!-- r36-rebuttal: lane auto-coverage-closer-extend registered in .auditooor/agent_pathspec.json -->

        Drives BOTH coverage axes (SURFACE units + RUBRIC impact classes) to a
        bounded fixpoint via tools/auto-coverage-closer.py, then surfaces the
        run verdict, stop reason, final coverage fraction, and the residual
        worker-dispatch queue summary so a worker can see what still needs an
        LLM-depth lane without re-running the heavy closer.

        Honest: the closer attaches NO attack_class/severity/claim to a
        no-finding verdict (R76/R80 safe); this callable only relays its
        bounded telemetry. When ``read_only`` is true (or the closer import
        fails) it returns the last on-disk run snapshot instead of re-running.

        Schema: auditooor.vault_auto_coverage_closer.v1.
        """
        SCHEMA = "auditooor.vault_auto_coverage_closer.v1"
        workspace = str(
            kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        ).strip()
        ws_path = Path(os.path.expanduser(workspace)) if workspace else None
        ws_name = ws_path.name if ws_path else ""
        read_only = bool(kwargs.get("read_only", False))
        try:
            max_iters = int(kwargs.get("max_iters", 3))
        except (TypeError, ValueError):
            max_iters = 3
        try:
            coverage_threshold = float(kwargs.get("coverage_threshold", 1.0))
        except (TypeError, ValueError):
            coverage_threshold = 1.0
        try:
            unit_cap = int(kwargs.get("unit_cap", 400))
        except (TypeError, ValueError):
            unit_cap = 400
        run_id = str(kwargs.get("run_id") or "")

        snapshot_rel = os.path.join(
            ".auditooor", "auto_coverage_closer_last_result.json"
        )
        residual_rel = os.path.join(
            ".auditooor", "coverage_residual_worker_queue.json"
        )

        result: dict[str, Any] | None = None
        source = "none"
        error: str | None = None

        if ws_path is None or not ws_path.is_dir():
            error = "workspace path not found or not a directory: %s" % workspace
        else:
            closer_path = self.repo_root / "tools" / "auto-coverage-closer.py"
            if not read_only and closer_path.is_file():
                try:
                    spec = importlib.util.spec_from_file_location(
                        "_vault_acc", closer_path
                    )
                    mod = importlib.util.module_from_spec(spec)
                    spec.loader.exec_module(mod)  # type: ignore[union-attr]
                    result = mod.run(
                        ws_path,
                        max_iters=max_iters,
                        coverage_threshold=coverage_threshold,
                        unit_cap=unit_cap,
                        run_id=run_id,
                    )
                    source = "ran"
                except Exception as exc:  # noqa: BLE001 - degrade to snapshot
                    error = "closer run failed: %s" % exc
                    result = None
            if result is None:
                # read_only mode OR run failed: fall back to the last snapshot.
                snap = ws_path / snapshot_rel
                if snap.is_file():
                    try:
                        result = json.loads(snap.read_text(encoding="utf-8"))
                        source = "snapshot" if source != "ran" else source
                    except (OSError, ValueError) as exc:
                        error = error or "snapshot read failed: %s" % exc

        residual_summary: dict[str, Any] = {
            "present": False,
            "path": None,
            "residual_surface_units": 0,
            "residual_rubric_classes": 0,
            "total_residual": 0,
        }
        if ws_path is not None:
            rq = ws_path / residual_rel
            if rq.is_file():
                try:
                    rqd = json.loads(rq.read_text(encoding="utf-8"))
                    residual_summary = {
                        "present": True,
                        "path": str(rq),
                        "residual_surface_units": int(
                            rqd.get("residual_surface_units") or 0
                        ),
                        "residual_rubric_classes": int(
                            rqd.get("residual_rubric_classes") or 0
                        ),
                        "total_residual": int(rqd.get("total_residual") or 0),
                    }
                except (OSError, ValueError):
                    pass

        res = result if isinstance(result, dict) else {}
        payload = {
            "schema": SCHEMA,
            "kind": "auto_coverage_closer",
            "workspace": workspace,
            "ws_name": ws_name,
            "source": source,
            "error": error,
            "verdict": res.get("verdict"),
            "stop_reason": res.get("stop_reason"),
            "iters_run": res.get("iters_run"),
            # final_coverage_fraction is the STRICT-reconciled value (never 1.0
            # while strict-uncovered > 0; None when the strict axis is
            # unresolved). The raw heatmap value is relayed separately for
            # transparency so a consumer can see the over-credited enumeration
            # notion without mistaking it for genuine coverage.
            "final_coverage_fraction": res.get("final_coverage_fraction"),
            "final_heatmap_coverage_fraction": res.get(
                "final_heatmap_coverage_fraction"
            ),
            "final_effective_uncovered": res.get("final_effective_uncovered"),
            # The authoritative strict L37 axis: a non-zero count or a non-ok
            # status means coverage is NOT genuinely closed regardless of the
            # heatmap fraction. Surfaced so the MCP consumer never reads a
            # closed verdict without the strict residual that contradicts it.
            "final_strict_uncovered_count": res.get(
                "final_strict_uncovered_count"
            ),
            "final_strict_uncovered_status": res.get(
                "final_strict_uncovered_status"
            ),
            "final_strict_residual": res.get("final_strict_residual"),
            "final_rubric_rows_uncovered": res.get("final_rubric_rows_uncovered"),
            "residual_worker_queue": residual_summary,
            "run_snapshot_path": (
                str(ws_path / snapshot_rel) if ws_path is not None else None
            ),
        }
        digest = hashlib.sha256(
            _canonical_json(payload).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_outcome_context(self, workspace: str | None = None, platform: str | None = None, limit: int = DEFAULT_LIMIT) -> dict[str, Any]:
        # Gap #44 + #47 resilience: even on missing/empty corpus, emit a recognizable
        # schema envelope with top-level context_pack_id and context_pack_hash so
        # downstream consumers (memory-context-load + parity checks) can detect drift
        # rather than treat the result as "degraded with no pack identity".
        # R36 pathspec compliance: GAP-FIX-2-44 in .auditooor/agent_pathspec.json via tools/agent-pathspec-register.py.
        limit = _clamp_limit(limit)
        outcomes = self.repo_root / "reference" / "outcomes.jsonl"
        rows: list[dict[str, Any]] = []
        outcomes_exists = outcomes.exists()
        if outcomes_exists:
            for line in outcomes.read_text(encoding="utf-8").splitlines():
                if not line.strip():
                    continue
                try:
                    row = json.loads(line)
                except json.JSONDecodeError:
                    continue
                row_workspace = row.get("workspace") or row.get("engagement")
                row_platform = row.get("platform")
                if workspace and row_workspace != workspace:
                    continue
                if platform and row_platform != platform:
                    continue
                rows.append(row)
        # new_rule_codified is canonically a STRING per outcome-ledger-gate.py
        # ("none" | "deferred" | "<rule-id>"); legacy boolean True/False is also
        # accepted. Count string-codified rows (incl. "none"/"deferred"/rule-id)
        # AND legacy bool True as codified; only null/missing/False is uncodified.
        def _is_codified(v: Any) -> bool:
            if v is True:
                return True
            if isinstance(v, str) and v.strip():
                return True
            return False
        codified_true = sum(1 for row in rows if _is_codified(row.get("new_rule_codified")))
        codified_false = sum(
            1 for row in rows if row.get("new_rule_codified") is False
        )
        base = {
            "schema": "auditooor.vault_outcome_context.v1",
            "kind": "outcome",
            "workspace": workspace,
            "platform": platform,
            "limit": limit,
            "rows": rows[-limit:],
            "source_refs": ["reference/outcomes.jsonl"],
            "summary": {
                "row_count": len(rows),
                "returned_count": min(limit, len(rows)),
                "outcomes_corpus_present": outcomes_exists,
            },
            "new_rule_codified_summary": {
                "true": codified_true,
                "false": codified_false,
                "missing": len(rows) - codified_true - codified_false,
            },
            "policy": "Unknown-reason declines affect base-rate calibration only; do not infer rejection classes without triager text.",
        }
        if not outcomes_exists:
            base["degraded"] = True
            base["degraded_reason"] = "outcomes_corpus_missing"
            base["degraded_message"] = (
                f"reference/outcomes.jsonl not present at repo root {self.repo_root}; emitting empty-but-valid pack."
            )
            base["next_action"] = (
                "Bootstrap reference/outcomes.jsonl (or rerun "
                "`python3 tools/memory-context-load.py --workspace <ws> --refresh` to "
                "rebuild the receipt). Pack still emitted with empty-but-valid envelope."
            )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"auditooor.vault_outcome_context.v1:outcome:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def _context_default_paths(self, kind: str) -> list[str]:
        if kind == "dispatch":
            return [
                "INDEX.md",
                "INDEX_active.md",
                "NEXT_LOOP.md",
                "dispatch/next_dispatch_manifest.md",
            ]
        if kind == "resume":
            return [
                "INDEX_active.md",
                "NEXT_LOOP.md",
                "goals/current.md",
            ]
        if kind == "finalization":
            return [
                "INDEX_active.md",
                "NEXT_LOOP.md",
                "goals/current.md",
                "finalization/current.md",
            ]
        raise ValueError(f"unknown context pack kind: {kind}")

    def _context_note_paths(self, kind: str, args: dict[str, Any], limit: int) -> tuple[list[str], list[dict[str, str]]]:
        requested: list[str] = []
        refusals: list[dict[str, str]] = []
        raw_paths = args.get("paths")
        if isinstance(raw_paths, list):
            for value in raw_paths:
                rel = _safe_repo_relpath(value)
                if rel:
                    requested.append(rel)
                else:
                    refusals.append({"path": str(value), "reason": "invalid_or_private_path"})
        else:
            requested.extend(self._context_default_paths(kind))

        # W4.12: cross-session memory carry. When a workspace_path is given,
        # include that workspace's session-memory carry note so the next
        # resume / finalization pack picks up the prior session's NEGATIVE
        # verdicts, dropped lanes, harness deltas and lane cooldowns. The note
        # is written by tools/audit/session-memory-carry.py at session end.
        if kind in {"resume", "finalization"}:
            ws_arg = args.get("workspace_path") or args.get("workspace")
            if ws_arg:
                # The carry tool slugs the workspace basename (ws.name).
                ws_name = Path(str(ws_arg)).name
                ws_slug = re.sub(r"[^a-z0-9]+", "-", ws_name.lower()).strip("-")
                if ws_slug:
                    requested.append(f"session-memory/{ws_slug}.md")

        query = _safe_text_item(args.get("query", ""), max_chars=160) or ""
        category = args.get("category")
        if query:
            search = self.vault_search(query, str(category) if category else None, limit=limit)
            requested.extend(str(hit["path"]) for hit in search.get("hits", []))

        safe_paths: list[str] = []
        for rel in requested:
            if not _is_public_relpath(rel):
                refusals.append({"path": rel, "reason": "invalid_or_private_path"})
                continue
            safe_paths.append(Path(rel).as_posix())
        return _unique_bounded(safe_paths, limit), refusals

    def _context_note(self, relpath: str, kind: str) -> tuple[dict[str, Any] | None, dict[str, str] | None]:
        note = self.vault_get(relpath)
        if "error" in note:
            return None, {"path": relpath, "reason": str(note.get("error", "read_refused"))}
        status = _status_text(note.get("frontmatter", {}).get("status"))
        if not _context_allows_status(kind, status):
            return None, {"path": relpath, "reason": f"filtered_{_status_class(status)}_status", "status": status or ""}
        raw_frontmatter = note.get("frontmatter") if isinstance(note.get("frontmatter"), dict) else {}
        frontmatter = _safe_context_frontmatter(raw_frontmatter)
        body = _bounded_text(note.get("body", ""), MAX_CONTEXT_NOTE_CHARS)
        # W5-M2: carry the note file's mtime so `_note_age_days` has a second
        # freshness signal. `_safe_context_frontmatter` drops `date`/`updated`
        # frontmatter (not on the context whitelist), so without an mtime
        # fallback every pack note would be un-dateable and therefore STALE.
        # This mirrors signal-2 ("newest record mtime") of the W4.14
        # `mcp-corpus-freshness-monitor.py` model.
        mtime_epoch: float | None = None
        try:
            mtime_epoch = self._safe_path(relpath).stat().st_mtime
        except (OSError, PermissionError, ValueError):
            mtime_epoch = None
        return (
            {
                "path": note["path"],
                "title": note["title"],
                "category": str(note["path"]).split("/", 1)[0],
                "status": status,
                "status_class": _status_class(status),
                "frontmatter": frontmatter,
                "body": body,
                "mtime_epoch": mtime_epoch,
            },
            None,
        )

    def _context_json_items(self, kind: str, limit: int) -> list[dict[str, Any]]:
        if kind != "dispatch":
            return []
        items: list[dict[str, Any]] = []
        for relpath in ("dispatch/next_dispatch_manifest.json", "dispatch/next_dispatch_manifest.preview.json"):
            try:
                path = self._safe_path(relpath)
            except (PermissionError, ValueError):
                continue
            if not path.is_file() or path.is_symlink():
                continue
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, UnicodeDecodeError, json.JSONDecodeError):
                continue
            if isinstance(payload, list):
                rows = payload
            elif isinstance(payload, dict):
                rows = []
                for key in ("slots", "workpacks", "items"):
                    value = payload.get(key)
                    if isinstance(value, list) and value:
                        rows = value
                        break
            else:
                rows = []
            if not isinstance(rows, list):
                continue
            for row in rows:
                if not isinstance(row, dict):
                    continue
                status = _status_text(row.get("status"))
                if not _context_allows_status(kind, status):
                    continue
                text = _safe_text_item(row.get("title") or row.get("id") or row.get("gap_id") or row)
                if not text:
                    continue
                refs = _unique_bounded(_extract_refs(row), MAX_CONTEXT_ITEMS)
                items.append(
                    {
                        "text": text,
                        "source_ref": f"vault://{relpath}",
                        "status": status,
                        "status_class": _status_class(status),
                        "source_refs": refs,
                    }
                )
                if len(items) >= limit:
                    return items
        return items

    def _context_next_loop_summary(self) -> dict[str, Any]:
        note = self.vault_next_loop(limit=5)
        if "error" in note:
            return {
                "status": "missing",
                "path": "NEXT_LOOP.md",
                "error": _safe_text_item(note.get("error"), max_chars=80) or "not_found",
                "message": _safe_text_item(note.get("message"), max_chars=200) or "",
                "items": [],
            }
        return {
            "status": "found",
            "path": "NEXT_LOOP.md",
            "source_ref": "vault://NEXT_LOOP.md",
            "items": [
                item
                for item in (_safe_text_item(row, max_chars=180) for row in note.get("items", []))
                if item
            ][:5],
        }

    def _context_current_goal_summary(self) -> dict[str, Any]:
        state = self.vault_goal_state("current")
        summary: dict[str, Any] = {
            "status": _safe_text_item(state.get("status"), max_chars=80) or "missing",
            "loop_policy": GOAL_LOOP_POLICY,
        }
        goal = state.get("goal") if isinstance(state.get("goal"), dict) else None
        if goal:
            frontmatter = goal.get("frontmatter") if isinstance(goal.get("frontmatter"), dict) else {}
            safe_frontmatter = _safe_context_frontmatter(frontmatter)
            goal_status = _status_text(safe_frontmatter.get("status"))
            summary.update(
                {
                    "path": goal.get("path"),
                    "source_ref": f"vault://{goal.get('path')}",
                    "title": _safe_text_item(goal.get("title"), max_chars=160) or "",
                    "objective": _safe_text_item(safe_frontmatter.get("objective"), max_chars=240) or "",
                    "next_action": _safe_text_item(safe_frontmatter.get("next_action"), max_chars=240) or "",
                    "goal_status": goal_status,
                    "status_class": _status_class(goal_status),
                    "terminal_condition": _safe_text_item(safe_frontmatter.get("terminal_condition"), max_chars=120) or "",
                }
            )
            return summary
        if isinstance(state.get("goals"), list):
            summary["goals"] = [
                {
                    "path": _safe_text_item(row.get("path"), max_chars=160) or "",
                    "title": _safe_text_item(row.get("title"), max_chars=160) or "",
                    "excerpt": _safe_text_item(row.get("excerpt"), max_chars=240) or "",
                }
                for row in state["goals"][:3]
                if isinstance(row, dict)
            ]
            return summary
        summary["message"] = _safe_text_item(state.get("message"), max_chars=240) or ""
        return summary

    def _workspace_gate_refs(self, workspace_path: Path, row_id: str, source: str) -> list[str]:
        gates_dir = workspace_path / "gates"
        if not gates_dir.is_dir() or gates_dir.is_symlink():
            return []
        source_stem = Path(source).stem
        stems = [row_id, source_stem]
        match = re.fullmatch(r"(.+)-([0-9]{4}-[0-9]{2}-[0-9]{2})", row_id)
        if match:
            slug, date = match.groups()
            stems.insert(0, f"{date}.{slug}")
        stems.extend([stem.lower() for stem in list(stems)])
        refs: list[str] = []
        for stem in stems:
            if not re.fullmatch(r"[A-Za-z0-9._-]+", stem):
                continue
            for path in sorted(gates_dir.glob(f"{stem}*")):
                if path.is_symlink() or not path.is_file():
                    continue
                try:
                    rel = path.relative_to(workspace_path).as_posix()
                except ValueError:
                    continue
                ref = _workspace_ref(rel)
                if ref:
                    refs.append(ref)
                if len(refs) >= MAX_WORKSPACE_GATE_REFS:
                    return _unique_bounded(refs, MAX_WORKSPACE_GATE_REFS)
        return _unique_bounded(refs, MAX_WORKSPACE_GATE_REFS)

    def _workspace_existing_ref(self, workspace_path: Path, relpath: str) -> str | None:
        rel = _safe_workspace_relpath(relpath)
        if not rel:
            return None
        path = workspace_path / rel
        if _path_has_symlink(path, stop_at=workspace_path):
            return None
        if not path.is_file():
            return None
        return _workspace_ref(rel)

    def _workspace_package_refs(self, workspace_path: Path, source_refs: list[str]) -> list[str]:
        refs: list[str] = []
        slugs = _candidate_submission_slugs(source_refs)
        packaged_root = workspace_path / "submissions" / "packaged"
        for slug in slugs:
            for rel in (
                f"submissions/packaged/{slug}/manifest.json",
                f"submissions/packaged/{slug}/source-draft.md",
                f"submissions/packaged/{slug}/pre-submit.log",
                f"submissions/packaged/{slug}/poc.t.sol",
                f"submissions/packaged/{slug}/package_index.json",
                f"submissions/packaged/{slug}/README.md",
                f"poc_execution/{slug}/execution_manifest.json",
            ):
                ref = self._workspace_existing_ref(workspace_path, rel)
                if ref:
                    refs.append(ref)
                if len(refs) >= MAX_WORKSPACE_SUBMISSION_REFS:
                    return _unique_bounded(refs, MAX_WORKSPACE_SUBMISSION_REFS)
        if packaged_root.is_dir() and not _path_has_symlink(packaged_root, stop_at=workspace_path):
            for package_dir in sorted(p for p in packaged_root.iterdir() if p.is_dir()):
                if _path_has_symlink(package_dir, stop_at=workspace_path):
                    continue
                manifest_path = package_dir / "manifest.json"
                draft_stem = ""
                if manifest_path.is_file() and not manifest_path.is_symlink():
                    try:
                        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
                        draft_stem = Path(str(payload.get("draft", ""))).stem
                    except (OSError, UnicodeDecodeError, json.JSONDecodeError):
                        draft_stem = ""
                if draft_stem not in slugs and package_dir.name not in slugs:
                    continue
                for name in (
                    "manifest.json",
                    "source-draft.md",
                    "pre-submit.log",
                    "poc.t.sol",
                    "package_index.json",
                    "README.md",
                ):
                    rel = f"submissions/packaged/{package_dir.name}/{name}"
                    ref = self._workspace_existing_ref(workspace_path, rel)
                    if ref:
                        refs.append(ref)
                    if len(refs) >= MAX_WORKSPACE_SUBMISSION_REFS:
                        return _unique_bounded(refs, MAX_WORKSPACE_SUBMISSION_REFS)
        return _unique_bounded(refs, MAX_WORKSPACE_SUBMISSION_REFS)

    def _workspace_submission_lane_refs(self, workspace_path: Path, source: object, row_id: object) -> list[str]:
        names: list[str] = []
        raw = str(source if source is not None else "")
        for token in re.findall(r"`([^`]+)`", raw) or [part.strip() for part in raw.split(",")]:
            token = token.strip().strip("`")
            if not token:
                continue
            path = Path(token)
            if path.suffix == ".md":
                names.append(path.name)
        row_text = str(row_id if row_id is not None else "").strip()
        if row_text and re.fullmatch(r"[A-Za-z0-9._-]+", row_text):
            names.append(f"{row_text}.md")

        refs: list[str] = []
        for name in _unique_bounded(names, MAX_WORKSPACE_SUBMISSIONS * 2):
            if not re.fullmatch(r"[A-Za-z0-9._-]+\.md", name):
                continue
            for lane in (
                "final_cantina_paste",
                "paste_ready",
                "staging",
                "hardened",
                "cantina_paste",
                "paste_ready_full",
            ):
                ref = self._workspace_existing_ref(workspace_path, f"submissions/{lane}/{name}")
                if ref:
                    refs.append(ref)
                if len(refs) >= MAX_WORKSPACE_SUBMISSION_REFS:
                    return _unique_bounded(refs, MAX_WORKSPACE_SUBMISSION_REFS)
        return _unique_bounded(refs, MAX_WORKSPACE_SUBMISSION_REFS)

    def _workspace_fileable_submissions(self, workspace_path: Path) -> tuple[list[dict[str, Any]], list[dict[str, str]], list[str]]:
        submissions_path = workspace_path / "submissions" / "SUBMISSIONS.md"
        if not submissions_path.is_file() or submissions_path.is_symlink():
            return [], [{"path": "submissions/SUBMISSIONS.md", "reason": "not_found"}], []
        try:
            text = submissions_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as exc:
            return [], [{"path": "submissions/SUBMISSIONS.md", "reason": f"read_error:{exc}"}], []
        if _has_secret(text):
            return [], [{"path": "submissions/SUBMISSIONS.md", "reason": "privacy_refusal"}], []

        rows: list[dict[str, Any]] = []
        submission_refs: list[str] = ["workspace:submissions/SUBMISSIONS.md"]
        gate_refs_all: list[str] = []
        for raw_line in text.splitlines():
            line = raw_line.strip()
            if not line.startswith("|") or "---" in line:
                continue
            cells = [cell.strip() for cell in line.strip("|").split("|")]
            if len(cells) < 5 or cells[0].lower() == "id":
                continue
            if len(cells) >= 6:
                row_id, date, severity, status, title, source = cells[:6]
            else:
                row_id, severity, status, title, source = cells[:5]
                date = ""
            signal = _fileable_signal(status, severity, source)
            if not signal:
                continue
            source_refs = []
            for ref in _workspace_artifact_refs(source):
                if not ref.startswith("workspace:"):
                    continue
                existing_ref = self._workspace_existing_ref(workspace_path, ref.removeprefix("workspace:"))
                if existing_ref:
                    source_refs.append(existing_ref)
            lane_refs = self._workspace_submission_lane_refs(workspace_path, source, row_id)
            source_refs = _unique_bounded(
                [*lane_refs, *source_refs],
                MAX_WORKSPACE_SUBMISSION_REFS,
            )
            source_refs = _unique_bounded(
                [*source_refs, *self._workspace_package_refs(workspace_path, source_refs)],
                MAX_WORKSPACE_SUBMISSION_REFS,
            )
            source_ref = source_refs[0] if source_refs else (_workspace_ref(source.strip().strip("`")) or "")
            gate_refs = self._workspace_gate_refs(workspace_path, row_id, source)
            for ref in source_refs:
                submission_refs.append(ref)
                gate_refs.extend(self._workspace_gate_refs(workspace_path, row_id, ref.removeprefix("workspace:")))
            gate_refs = _unique_bounded(gate_refs, MAX_WORKSPACE_GATE_REFS)
            if source_ref and not source_refs:
                submission_refs.append(source_ref)
            gate_refs_all.extend(gate_refs)
            rows.append(
                {
                    "id": _safe_text_item(row_id, max_chars=80) or "",
                    "date": _safe_text_item(date, max_chars=32) or "",
                    "severity": _safe_text_item(severity, max_chars=32) or "",
                    "fileable_signal": signal,
                    "status": _safe_text_item(status, max_chars=160) or "",
                    "title": _safe_text_item(title, max_chars=200) or "",
                    "source_ref": source_ref,
                    "source_refs": source_refs[:MAX_WORKSPACE_SUBMISSION_REFS],
                    "gate_refs": gate_refs[:6],
                    "local_only": True,
                }
            )
            if len(rows) >= MAX_WORKSPACE_SUBMISSIONS:
                break
        return rows, [], _unique_bounded([*submission_refs, *gate_refs_all], MAX_WORKSPACE_GATE_REFS)

    def _workspace_closeout_summary(self, workspace_path: Path) -> tuple[dict[str, Any], list[dict[str, str]], list[str]]:
        manifest_rel = ".audit_logs/audit_closeout_manifest.json"
        manifest_path = workspace_path / manifest_rel
        manifest_ref = _workspace_ref(manifest_rel)
        if _path_has_symlink(manifest_path, stop_at=workspace_path):
            return (
                {"status": "privacy_refusal", "manifest_ref": manifest_ref or ""},
                [{"path": manifest_rel, "reason": "symlink_refusal"}],
                [],
            )
        if not manifest_path.is_file():
            return {"status": "missing", "manifest_ref": manifest_ref or ""}, [], []
        try:
            text = manifest_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as exc:
            return (
                {"status": "unavailable", "manifest_ref": manifest_ref or "", "message": f"read_error:{exc}"},
                [{"path": manifest_rel, "reason": "read_error"}],
                [],
            )
        if _has_secret(text):
            return (
                {"status": "privacy_refusal", "manifest_ref": manifest_ref or ""},
                [{"path": manifest_rel, "reason": "privacy_refusal"}],
                [],
            )
        try:
            doc = json.loads(text)
        except json.JSONDecodeError:
            return (
                {"status": "invalid_json", "manifest_ref": manifest_ref or ""},
                [{"path": manifest_rel, "reason": "invalid_json"}],
                [manifest_ref] if manifest_ref else [],
            )
        if not isinstance(doc, dict):
            return (
                {"status": "invalid_shape", "manifest_ref": manifest_ref or ""},
                [{"path": manifest_rel, "reason": "invalid_shape"}],
                [manifest_ref] if manifest_ref else [],
            )

        raw_summary = doc.get("summary") if isinstance(doc.get("summary"), dict) else {}
        pass_count = int(raw_summary.get("pass", 0) or 0)
        warn_count = int(raw_summary.get("warn", 0) or 0)
        fail_count = int(raw_summary.get("fail", 0) or 0)
        if fail_count:
            status = "fail"
        elif warn_count:
            status = "warn"
        else:
            status = "pass"

        unresolved: list[dict[str, str]] = []
        checks = doc.get("checks") if isinstance(doc.get("checks"), list) else []
        for check in checks:
            if not isinstance(check, dict):
                continue
            check_status = str(check.get("status") or "").strip().upper()
            if check_status == "PASS":
                continue
            name = _safe_text_item(check.get("check"), max_chars=120) or ""
            reason = _safe_text_item(check.get("reason"), max_chars=300) or ""
            if not name and not reason:
                continue
            unresolved.append({"check": name, "status": check_status.lower(), "reason": reason})
            if len(unresolved) >= MAX_WORKSPACE_CLOSEOUT_ROWS:
                break

        return (
            {
                "status": status,
                "summary": {"pass": pass_count, "warn": warn_count, "fail": fail_count},
                "manifest_ref": manifest_ref or "",
                "unresolved": unresolved,
            },
            [],
            [manifest_ref] if manifest_ref else [],
        )

    def _workspace_finalization_manifest_summary(self, workspace_path: Path) -> tuple[dict[str, Any], list[str]]:
        payload = self.vault_finalization_manifest_context(workspace_path=str(workspace_path))

        mcp_update_payload = payload.get("mcp_update") if isinstance(payload.get("mcp_update"), dict) else {}
        mcp_update = {
            "status": _safe_text_item(mcp_update_payload.get("status"), max_chars=40) or "missing",
            "mcp_path_count": int(mcp_update_payload.get("mcp_path_count", 0) or 0),
            "task_update_path_count": int(mcp_update_payload.get("task_update_path_count", 0) or 0),
            "note_count": int(mcp_update_payload.get("note_count", 0) or 0),
        }

        errors = []
        raw_errors = payload.get("errors")
        if isinstance(raw_errors, list):
            errors = [_bounded_text(item, max_chars=240) for item in raw_errors[:8]]

        summary = {
            "manifest_found": bool(payload.get("manifest_found")),
            "status": _safe_text_item(payload.get("status"), max_chars=40) or "missing",
            "manifest_path": _safe_text_item(payload.get("manifest_path"), max_chars=240) or "",
            "tool_schema": _safe_text_item(payload.get("tool_schema"), max_chars=120) or "",
            "artifact_count": int(payload.get("artifact_count", 0) or 0),
            "agent_output_count": int(payload.get("agent_output_count", 0) or 0),
            "tests_count": int(payload.get("tests_count", 0) or 0),
            "mcp_update": mcp_update,
            "errors": errors,
        }
        source_refs: list[str] = []
        for raw_ref in payload.get("source_refs", []) if isinstance(payload.get("source_refs"), list) else []:
            text = str(raw_ref if raw_ref is not None else "").strip()
            if not text:
                continue
            if text.startswith("workspace:"):
                rel = _safe_workspace_relpath(text.removeprefix("workspace:"))
                safe = f"workspace:{rel}" if rel else None
            elif text.startswith("repo:"):
                rel = _safe_repo_relpath(text.removeprefix("repo:"))
                safe = f"repo:{rel}" if rel else None
            else:
                safe = _safe_source_ref(text)
            if safe:
                source_refs.append(safe)
        source_refs = _unique_bounded(source_refs, MAX_CONTEXT_ITEMS)
        return summary, source_refs

    def _finalization_manifest_first_state(
        self, workspace_context: dict[str, Any]
    ) -> tuple[dict[str, Any] | None, dict[str, Any] | None]:
        if not isinstance(workspace_context, dict):
            return None, None
        if workspace_context.get("status") != "found":
            return None, None
        manifest = workspace_context.get("finalization_manifest")
        if not isinstance(manifest, dict) or not bool(manifest.get("manifest_found")):
            return None, None

        manifest_status = (_safe_text_item(manifest.get("status"), max_chars=40) or "error").lower()
        mcp_update = manifest.get("mcp_update") if isinstance(manifest.get("mcp_update"), dict) else {}
        mcp_update_status = (_safe_text_item(mcp_update.get("status"), max_chars=40) or "missing").lower()
        artifact_count = int(manifest.get("artifact_count", 0) or 0)
        tests_count = int(manifest.get("tests_count", 0) or 0)
        errors_count = len(manifest.get("errors", [])) if isinstance(manifest.get("errors"), list) else 0

        if manifest_status == "pass":
            state_class = "ready"
            item_status = "ready_for_operator_review"
        elif manifest_status == "fail":
            state_class = "blocked"
            item_status = "failed_gate"
        else:
            state_class = "error"
            item_status = "failed"

        manifest_state = {
            "source": "canonical_finalization_manifest",
            "status": manifest_status,
            "state_class": state_class,
            "mcp_update_status": mcp_update_status,
            "artifact_count": artifact_count,
            "tests_count": tests_count,
            "errors_count": errors_count,
            "manifest_path": _safe_text_item(manifest.get("manifest_path"), max_chars=240) or "",
        }
        manifest_item = {
            "text": (
                f"Canonical finalization manifest state: {manifest_status} "
                f"(class={state_class}, mcp_update={mcp_update_status}, "
                f"artifacts={artifact_count}, tests={tests_count}, errors={errors_count})"
            ),
            "source_ref": "tools/finalization-manifest.py",
            "status": item_status,
            "status_class": _status_class(item_status),
            "source_refs": ["tools/finalization-manifest.py"],
        }
        return manifest_state, manifest_item

    def _context_workspace_summary(self, args: dict[str, Any], *, include_finalization_manifest: bool = False) -> dict[str, Any]:
        workspace_arg = args.get("workspace_path")
        if not workspace_arg:
            return {"status": "not_requested"}
        raw_workspace = _safe_workspace_or_brief_path(workspace_arg)
        if raw_workspace is None:
            return {"status": "invalid_path", "message": "invalid workspace_path"}
        workspace_path = raw_workspace.resolve()
        if _path_has_symlink(workspace_path):
            return {"status": "privacy_refusal", "message": "symlink paths are not readable through vault workspace context"}
        if not workspace_path.is_dir():
            return {"status": "not_found", "message": f"workspace not found: {workspace_path}"}

        submissions, filtered, submission_refs = self._workspace_fileable_submissions(workspace_path)
        closeout, closeout_filtered, closeout_refs = self._workspace_closeout_summary(workspace_path)
        filtered.extend(closeout_filtered)
        exploit = self.vault_exploit_context(workspace_path=str(workspace_path), limit=3)
        if "error" in exploit:
            exploit_summary = {
                "status": "unavailable",
                "error": _safe_text_item(exploit.get("error"), max_chars=80) or "",
                "message": _safe_text_item(exploit.get("message"), max_chars=240) or "",
            }
            exploit_refs: list[str] = []
        else:
            run_policy = exploit.get("run_policy") if isinstance(exploit.get("run_policy"), dict) else {}
            summary = exploit.get("summary") if isinstance(exploit.get("summary"), dict) else {}
            exploit_summary = {
                "status": _safe_text_item(summary.get("status"), max_chars=40) or "",
                "brief_hash": _safe_text_item(exploit.get("brief_hash"), max_chars=80) or "",
                "generated_at": _safe_text_item(exploit.get("generated_at"), max_chars=80) or "",
                "protocol_family": _safe_text_item(summary.get("protocol_family"), max_chars=80) or "",
                "recommended_angle_count": summary.get("recommended_angle_count", 0),
                "submission_ready": bool(run_policy.get("submission_ready")),
                "advisory_boundary": _safe_text_item(exploit.get("advisory_boundary"), max_chars=240) or "",
            }
            exploit_refs = [
                ref
                for ref in (_safe_brief_source_ref(row) for row in exploit.get("source_refs", []))
                if ref
            ][:MAX_CONTEXT_ITEMS]

        finalization_manifest = None
        manifest_refs: list[str] = []
        if include_finalization_manifest:
            finalization_manifest, manifest_refs = self._workspace_finalization_manifest_summary(workspace_path)

        return {
            "status": "found",
            "workspace": workspace_path.name,
            "workspace_path": str(workspace_path),
            "exploit_brief": exploit_summary,
            "audit_closeout": closeout,
            "finalization_manifest": finalization_manifest,
            "fileable_submissions": submissions,
            "hardened_fileable_submissions": submissions,
            "source_refs": _unique_bounded([*manifest_refs, *submission_refs, *closeout_refs, *exploit_refs], MAX_CONTEXT_ITEMS),
            "filtered": filtered,
            "advisory_boundary": (
                "Fileable signals are local hardening/pre-submit signals only; do not infer Cantina filing, "
                "acceptance, rejection, or duplicate status."
            ),
        }

    def _context_pack(self, kind: str, args: dict[str, Any] | None = None) -> dict[str, Any]:
        args = args or {}
        limit = _clamp_limit(args.get("limit", MAX_CONTEXT_ITEMS), default=MAX_CONTEXT_ITEMS)
        note_limit = MAX_CONTEXT_NOTES
        item_limit = max(1, min(MAX_CONTEXT_ITEMS, limit))
        command_limit = max(1, min(MAX_CONTEXT_COMMANDS, limit))
        paths, refusals = self._context_note_paths(kind, args, note_limit)
        notes: list[dict[str, Any]] = []
        items: list[dict[str, Any]] = []
        commands: list[str] = []
        source_refs: list[str] = []
        knowledge_gap_refs = _knowledge_gap_refs(args.get("knowledge_gap_refs"))
        filtered: list[dict[str, str]] = list(refusals)
        next_loop = self._context_next_loop_summary()
        current_goal = self._context_current_goal_summary()
        workspace_context = self._context_workspace_summary(args, include_finalization_manifest=(kind == "finalization"))
        manifest_state, manifest_first_item = (None, None)
        if kind == "finalization":
            manifest_state, manifest_first_item = self._finalization_manifest_first_state(workspace_context)
            if manifest_state is not None:
                workspace_context["finalization_state"] = manifest_state
            if manifest_first_item is not None:
                items.append(manifest_first_item)

        for relpath in paths:
            note, refusal = self._context_note(relpath, kind)
            if refusal:
                filtered.append(refusal)
                continue
            if note is None:
                continue
            notes.append(note)
            source_refs.append(f"vault://{note['path']}")
            source_refs.extend(_extract_refs(note.get("frontmatter", {})))
            source_refs.extend(_extract_refs(note.get("body", "")))
            items.extend(_extract_note_items(note, kind, item_limit))
            commands.extend(_extract_commands(str(note.get("body", "")), command_limit))
            if len(notes) >= note_limit:
                break

        # M-J: resolve workspace_path for extracted-LOGIC fields.
        # Only runs when workspace_path is explicitly provided and valid.
        # W5-E1 also reuses this resolved path to auto-derive the rank query.
        _ws_logic_path: Path | None = None
        _ws_arg = args.get("workspace_path") or args.get("workspace")
        if _ws_arg:
            _ws_raw = _safe_workspace_or_brief_path(_ws_arg)
            if _ws_raw is not None:
                _ws_resolved = _ws_raw.resolve()
                if _ws_resolved.is_dir() and not _path_has_symlink(_ws_resolved):
                    _ws_logic_path = _ws_resolved

        # W5-E1: relevance-rank the note set before emission. This converts
        # cold resume from a static default digest into a targeted recall.
        # The ranking is deterministic + stdlib-only and degrades to the
        # static input order when no query terms / dates are derivable.
        _rank_query = _derive_rank_query(
            _ws_logic_path,
            _safe_text_item(args.get("query", ""), max_chars=160) or "",
        )
        notes, ranking = _rank_context_notes(notes, _rank_query)

        items.extend(self._context_json_items(kind, item_limit))
        source_refs.extend(_extract_refs(args.get("source_refs", [])))
        source_refs.extend(_extract_refs(next_loop))
        source_refs.extend(_extract_refs(current_goal))
        source_refs.extend(_extract_refs(workspace_context))
        items = items[:item_limit]
        commands = _unique_bounded(commands, command_limit)
        source_refs = _unique_bounded(source_refs, MAX_CONTEXT_ITEMS)

        base = {
            "schema": CONTEXT_PACK_SCHEMA,
            "kind": kind,
            "limits": {
                "max_notes": MAX_CONTEXT_NOTES,
                "max_items": MAX_CONTEXT_ITEMS,
                "max_commands": MAX_CONTEXT_COMMANDS,
                "max_note_chars": MAX_CONTEXT_NOTE_CHARS,
            },
            "status_filter": {
                "terminal_statuses": sorted(TERMINAL_CONTEXT_STATUSES),
                "live_statuses": sorted(LIVE_CONTEXT_STATUSES),
                "mode": "exclude_terminal" if kind in {"dispatch", "resume"} else "classify_terminal_and_live",
            },
            "privacy_guards": {
                "vault_relative_paths_only": True,
                "hidden_archive_and_quarantine_paths_blocked": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "source_refs_sanitized": True,
                "knowledge_gap_refs_sanitized": True,
            },
            "notes_read": len(notes),
            "source_refs": source_refs,
            "knowledge_gap_refs": knowledge_gap_refs,
            "case_study_refs": _case_study_refs(),
            "known_patterns_refs": _known_patterns_refs(),
            # M-J: extracted LOGIC fields (additive, backward-compatible empty defaults).
            "case_study_logic": _case_study_logic(_ws_logic_path),
            "big_loss_template_actor_sequences": _big_loss_template_actor_sequences(_ws_logic_path),
            "defihack_class_matches": _defihack_class_matches(_ws_logic_path),
            "next_loop": next_loop,
            "current_goal": current_goal,
            "workspace_context": workspace_context,
            "filtered": filtered,
            "notes": notes,
            "items": items,
            "commands": commands,
            # W5-E1: auditable relevance-ranking block. `ranking` is one row
            # per emitted note (rank, keyword_score, recency, tier, composite)
            # so the session can see WHY each note ranked where it did.
            # W5-M2: each row also carries `freshness` + `is_stale`, and the
            # block carries a pack-level `freshness` summary so the consuming
            # session sees at a glance whether recall is degrading.
            "ranking": {
                "model": "composite = (1 + keyword_score) * recency_multiplier * tier_weight",
                "recency_half_life_days": RANK_RECENCY_HALF_LIFE_DAYS,
                "tier_weights": dict(RANK_TIER_WEIGHTS),
                "derived_query": _rank_query,
                "notes": ranking,
                "freshness": {
                    "model": (
                        "FRESH age<=%gd / AGING soft<age<=%gd / STALE age>%gd "
                        "or un-dateable; STALE notes are hard-demoted below all "
                        "non-STALE notes" % (
                            FRESHNESS_SOFT_DAYS, FRESHNESS_HARD_DAYS,
                            FRESHNESS_HARD_DAYS,
                        )
                    ),
                    "soft_days": FRESHNESS_SOFT_DAYS,
                    "hard_days": FRESHNESS_HARD_DAYS,
                    "fresh_note_count": sum(
                        1 for r in ranking if r.get("freshness") == FRESH
                    ),
                    "aging_note_count": sum(
                        1 for r in ranking if r.get("freshness") == AGING
                    ),
                    "stale_note_count": sum(
                        1 for r in ranking if r.get("freshness") == STALE
                    ),
                    "recall_degraded": any(
                        r.get("freshness") == STALE for r in ranking
                    ),
                    "advisory": (
                        "STALE notes are demoted + labelled, not dropped - "
                        "re-mine the backing source before trusting them."
                    ),
                },
            },
        }
        base["token_estimate"] = _token_estimate(
            {
                "notes": notes,
                "items": items,
                "commands": commands,
                "source_refs": source_refs,
                "knowledge_gap_refs": knowledge_gap_refs,
                "next_loop": next_loop,
                "current_goal": current_goal,
                "workspace_context": workspace_context,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{CONTEXT_PACK_SCHEMA}:{kind}:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_dispatch_context(self, **kwargs: Any) -> dict[str, Any]:
        return self._context_pack("dispatch", kwargs)

    def vault_resume_context(self, **kwargs: Any) -> dict[str, Any]:
        return self._context_pack("resume", kwargs)

    def vault_finalization_context(self, **kwargs: Any) -> dict[str, Any]:
        return self._context_pack("finalization", kwargs)

    def vault_route(self, **kwargs: Any) -> dict[str, Any]:
        """Route a request to one of the 4 recall packs based on intent /
        keywords / artifact extensions. Returns:
            {schema, routed_pack, reasoning, inputs_seen, pack_payload}

        Routing precedence (first match wins):
          1. explicit ``intent`` (when not "auto")
          2. ``task_keywords`` matching one of the 4 keyword sets
          3. ``recent_artifacts`` extensions hinting at exploit work
          4. default → ``vault_resume_context``
        """
        workspace_path = kwargs.get("workspace_path") or kwargs.get("workspace")
        intent_raw = kwargs.get("intent")
        intent = (str(intent_raw).strip().lower() if intent_raw is not None else "")
        keywords_raw = kwargs.get("task_keywords") or []
        artifacts_raw = kwargs.get("recent_artifacts") or []

        # Normalize / bound inputs.
        keywords: list[str] = []
        if isinstance(keywords_raw, (list, tuple)):
            for item in keywords_raw[:ROUTE_MAX_KEYWORDS]:
                if isinstance(item, str) and item.strip():
                    keywords.append(item.strip().lower())
        artifacts: list[str] = []
        if isinstance(artifacts_raw, (list, tuple)):
            for item in artifacts_raw[:ROUTE_MAX_ARTIFACTS]:
                if isinstance(item, str) and item.strip():
                    artifacts.append(item.strip())

        inputs_seen = {
            "workspace_path": str(workspace_path) if workspace_path else "",
            "intent": intent,
            "task_keywords": keywords,
            "recent_artifacts": artifacts,
        }

        routed_pack: str | None = None
        reasoning: str = ""

        # 1. Explicit intent passthrough (skip "auto" — fall through to keyword/artifact logic).
        if intent and intent != "auto":
            if intent in ROUTE_INTENT_TO_PACK:
                routed_pack = ROUTE_INTENT_TO_PACK[intent]
                reasoning = f"explicit intent={intent!r} → {routed_pack}"
            else:
                return {
                    "schema": ROUTE_SCHEMA,
                    "error": "invalid_intent",
                    "message": f"intent must be one of {list(ROUTE_VALID_INTENTS)}; got {intent!r}",
                    "inputs_seen": inputs_seen,
                }

        # 2. Keyword-based routing — union ROUTE_KEYWORDS with SPARK_DOMAIN_KEYWORDS
        #    so spark/frost/coop_exit/chain_watcher/permafreeze/etc. route to
        #    vault_exploit_context instead of falling through to the default.
        if routed_pack is None and keywords:
            kw_set = set(keywords)
            for pack, hints in ROUTE_KEYWORDS.items():
                merged_hints = tuple(set(hints).union(SPARK_DOMAIN_KEYWORDS.get(pack, ())))
                hit = sorted(kw_set.intersection(merged_hints))
                if hit:
                    routed_pack = pack
                    reasoning = f"task_keywords {hit!r} → {pack}"
                    break

        # 3. Artifact-extension routing.
        if routed_pack is None and artifacts:
            for art in artifacts:
                lower = art.lower()
                if (
                    lower.endswith(ROUTE_EXPLOIT_EXTENSIONS)
                    or lower.endswith(ROUTE_EXPLOIT_SUFFIXES)
                    or (lower.endswith(".rs") and any(h in lower for h in ROUTE_RUST_TEST_HINTS))
                ):
                    routed_pack = "vault_exploit_context"
                    reasoning = f"recent_artifact {art!r} matches exploit-test extension → vault_exploit_context"
                    break

        # 4. Default.
        if routed_pack is None:
            routed_pack = "vault_resume_context"
            reasoning = "no explicit intent / keyword / artifact match → default vault_resume_context"

        # Re-dispatch to the chosen pack with the safe args we received.
        # Only forward the keys that the underlying packs accept.
        forward_args: dict[str, Any] = {}
        if workspace_path:
            forward_args["workspace_path"] = str(workspace_path)
        # Exploit / harness / gap packs accept extra filters but those aren't
        # part of the router contract; we always pass workspace_path-only and
        # let the pack apply its own defaults.
        try:
            pack_payload = self.call(routed_pack, forward_args)
        except Exception as exc:  # noqa: BLE001 — surface routing errors as data
            pack_payload = {"error": "pack_call_failed", "message": str(exc), "pack": routed_pack}

        return {
            "schema": ROUTE_SCHEMA,
            "routed_pack": routed_pack,
            "reasoning": reasoning,
            "inputs_seen": inputs_seen,
            "pack_payload": pack_payload,
        }

    def _harness_report_path(self) -> Path:
        return self.repo_root / "reports" / "harness_failures.jsonl"

    def _load_validated_harness_rows(self) -> tuple[Path, list[dict[str, Any]]] | dict[str, Any]:
        # R36 pathspec compliance: tools/agent-pathspec-register.py registered
        # GAP-FIX-2-44 with this file in .auditooor/agent_pathspec.json.
        report_path = self._harness_report_path()
        if _path_has_symlink(report_path, stop_at=self.repo_root):
            return {"error": "privacy_refusal", "message": "symlink paths are not readable through vault harness context"}
        if not report_path.is_file():
            return {"error": "not_found", "message": f"harness failure report not found: {_rel(report_path, self.repo_root)}"}
        try:
            text = report_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as exc:
            return {"error": "read_error", "message": str(exc), "report_path": _rel(report_path, self.repo_root)}
        if _has_secret(text):
            return {
                "error": "privacy_refusal",
                "message": "harness failure report matches secret pattern",
                "report_path": _rel(report_path, self.repo_root),
            }
        try:
            module = _harness_failure_module()
            errors = module.validate_report(report_path, repo=self.repo_root)
            if errors:
                # Gap #44 resilience: emit empty-but-valid pack downstream so
                # consumers receive a recognizable schema envelope with
                # context_pack_id/hash, not a bare error dict. Best-effort
                # normalization; tolerate per-row normalization failures.
                try:
                    rows = [module.normalize_row(row) for row in module.read_jsonl(report_path)]
                except Exception:  # noqa: BLE001 - tolerate normalisation failures.
                    rows = []
                return {
                    "_degraded_with_rows": True,
                    "report_path_obj": report_path,
                    "rows": rows,
                    "error": "invalid_report",
                    "message": "; ".join(str(error) for error in errors[:5]),
                    "report_path": _rel(report_path, self.repo_root),
                }
            rows = [module.normalize_row(row) for row in module.read_jsonl(report_path)]
        except Exception as exc:  # noqa: BLE001 - report validator failures as data.
            # Gap #44 resilience: emit empty-but-valid pack downstream rather
            # than a bare error envelope. R36 pathspec compliance via
            # tools/agent-pathspec-register.py / .auditooor/agent_pathspec.json.
            return {
                "_degraded_with_rows": True,
                "report_path_obj": report_path,
                "rows": [],
                "error": "invalid_report",
                "message": str(exc),
                "report_path": _rel(report_path, self.repo_root),
            }
        return report_path, rows

    def _harness_row_context(self, row: dict[str, Any]) -> dict[str, Any]:
        source_paths = _unique_bounded(
            (ref for ref in (_safe_harness_source_ref(value) for value in row.get("source_paths", [])) if ref),
            MAX_CONTEXT_ITEMS,
        )
        counter_examples = _unique_bounded(
            (ref for ref in (_safe_harness_source_ref(value) for value in row.get("counter_example_links", [])) if ref),
            MAX_CONTEXT_ITEMS,
        )
        return {
            "root_cause_id": _safe_text_item(row.get("root_cause_id"), max_chars=90) or "",
            "title": _safe_text_item(row.get("title"), max_chars=180) or "",
            "status": _safe_text_item(row.get("status"), max_chars=40) or "",
            "severity": _safe_text_item(row.get("severity"), max_chars=40) or "",
            "symptom": _safe_text_item(row.get("symptom"), max_chars=360) or "",
            "known_fix": _safe_text_item(row.get("known_fix"), max_chars=360) or "",
            "guard": _safe_text_item(row.get("guard"), max_chars=240) or "",
            "occurrence_count": row.get("occurrence_count", 0),
            "tools_affected": _bounded_string_list(row.get("tools_affected"), MAX_CONTEXT_ITEMS, max_chars=120),
            "counter_example_links": counter_examples,
            "source_paths": source_paths,
            "first_seen": _safe_text_item(row.get("first_seen"), max_chars=16) or "",
            "last_seen": _safe_text_item(row.get("last_seen"), max_chars=16) or "",
            "last_validated_at": _safe_text_item(row.get("last_validated_at"), max_chars=16) or "",
        }

    def vault_harness_context(self, **kwargs: Any) -> dict[str, Any]:
        # R36 pathspec compliance: this callable is in GAP-FIX-2-44 pathspec
        # (tools/agent-pathspec-register.py / .auditooor/agent_pathspec.json).
        loaded = self._load_validated_harness_rows()
        degraded_info: dict[str, Any] | None = None
        if isinstance(loaded, dict):
            # Gap #44: detect tolerant-degraded mode and continue with empty/best-effort rows.
            if loaded.get("_degraded_with_rows"):
                degraded_info = {
                    "error": loaded.get("error"),
                    "message": loaded.get("message"),
                    "report_path": loaded.get("report_path"),
                }
                report_path = loaded["report_path_obj"]
                rows = loaded.get("rows") or []
            else:
                return loaded
        else:
            report_path, rows = loaded
        limit = min(MAX_HARNESS_ROOT_CAUSES, _clamp_limit(kwargs.get("limit", 8), default=8))
        status_filter = _safe_text_item(kwargs.get("status"), max_chars=40)
        severity_filter = _safe_text_item(kwargs.get("severity"), max_chars=40)
        tool_filter = _safe_text_item(kwargs.get("tool"), max_chars=120)
        root_cause_filter = _safe_text_item(kwargs.get("root_cause_id"), max_chars=90)
        if status_filter:
            status_filter = status_filter.lower().replace(" ", "_").replace("-", "_")
            # "all"/"any" are sentinels meaning "no status filter"; the row schema
            # only enumerates active|mitigated|watch, so a literal "all" comparison
            # would otherwise drop every row.
            if status_filter in {"all", "any"}:
                status_filter = ""
        if severity_filter:
            severity_filter = severity_filter.lower().replace(" ", "_").replace("-", "_")
            if severity_filter in {"all", "any"}:
                severity_filter = ""
        if root_cause_filter:
            root_cause_filter = root_cause_filter.lower().replace(" ", "-").replace("_", "-")
        tool_filter_lc = tool_filter.lower() if tool_filter else None

        filtered_rows: list[dict[str, Any]] = []
        for row in rows:
            status = str(row.get("status", "")).lower()
            severity = str(row.get("severity", "")).lower()
            root_cause_id = str(row.get("root_cause_id", "")).lower()
            tools = [str(value).lower() for value in row.get("tools_affected", [])]
            if root_cause_filter and root_cause_id != root_cause_filter:
                continue
            if status_filter and status != status_filter:
                continue
            if severity_filter and severity != severity_filter:
                continue
            if tool_filter_lc and not any(tool_filter_lc in tool for tool in tools):
                continue
            filtered_rows.append(row)
        filtered_rows.sort(
            key=lambda row: (
                HARNESS_STATUS_ORDER.get(str(row.get("status", "")), 99),
                HARNESS_SEVERITY_ORDER.get(str(row.get("severity", "")), 99),
                -int(row.get("occurrence_count", 0) or 0),
                str(row.get("root_cause_id", "")),
            )
        )
        root_causes = [self._harness_row_context(row) for row in filtered_rows[:limit]]
        source_refs = _unique_bounded(
            [
                "reports/harness_failures.jsonl",
                *[
                    ref
                    for root in root_causes
                    for ref in [*root.get("source_paths", []), *root.get("counter_example_links", [])]
                ],
            ],
            MAX_HARNESS_REFS,
        )
        status_counts: dict[str, int] = {}
        severity_counts: dict[str, int] = {}
        for row in rows:
            status = str(row.get("status", "unknown"))
            severity = str(row.get("severity", "unknown"))
            status_counts[status] = status_counts.get(status, 0) + 1
            severity_counts[severity] = severity_counts.get(severity, 0) + 1
        base = {
            "schema": HARNESS_CONTEXT_SCHEMA,
            "kind": "harness",
            "report_path": _rel(report_path, self.repo_root),
            "limits": {
                "max_root_causes": MAX_HARNESS_ROOT_CAUSES,
                "max_refs": MAX_HARNESS_REFS,
            },
            "filters": {
                "status": status_filter or "",
                "severity": severity_filter or "",
                "tool": tool_filter or "",
                "root_cause_id": root_cause_filter or "",
            },
            # R36 pathspec compliance: GAP-FIX-2-44 lane in .auditooor/agent_pathspec.json via tools/agent-pathspec-register.py.
            "validation": {
                "report_validated": degraded_info is None,
                "validator": "tools/harness-failure-memory.py",
                "row_schema": "auditooor.harness_failure_root.v1",
            },
            "privacy_guards": {
                "exact_report_path_only": True,
                "repo_relative_refs_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "raw_harness_logs_not_returned": True,
            },
            "summary": {
                "root_cause_count": len(rows),
                "returned_count": len(root_causes),
                "status_counts": status_counts,
                "severity_counts": severity_counts,
                "active_or_watch_count": sum(1 for row in rows if row.get("status") in {"active", "watch"}),
            },
            "source_refs": source_refs,
            "root_causes": root_causes,
            "advisory_boundary": "Harness context identifies recurring tool/proof failure modes and guards; it is not exploit evidence or a substitute for project-specific proof execution.",
        }
        # Gap #44 resilience: when validation flagged invalid refs, attach a
        # honest-degraded marker so consumers can detect drift while still
        # receiving a recognizable schema envelope with context_pack_id/hash.
        # CAP-GAP-77: when the degradation is caused by missing advisory doc
        # files (CONTINUATION_PLAN.md / CONTROL_PLANE_BUILD_STATUS.md) rather
        # than actual data corruption, emit verdict="pass-with-missing-doc" so
        # callers do not treat this as a hard failure.
        if degraded_info is not None:
            base["degraded"] = True
            base["degraded_reason"] = degraded_info.get("error") or "invalid_report"
            base["degraded_message"] = degraded_info.get("message") or ""
            missing_doc_paths = _detect_missing_doc_paths(degraded_info.get("message") or "")
            if missing_doc_paths:
                base["missing_doc"] = True
                base["missing_doc_paths"] = missing_doc_paths
                base["verdict"] = "pass-with-missing-doc"
                base["next_action"] = (
                    "Advisory doc files are missing from reports/harness_failures.jsonl "
                    "source_paths refs. Pack still returned with full advisory content. "
                    "Provide missing docs, then rerun `python3 tools/memory-context-load.py "
                    "--workspace <ws> --refresh` to clear verdict=pass-with-missing-doc."
                )
            else:
                base["next_action"] = (
                    "Re-validate reports/harness_failures.jsonl source_paths refs (or rerun "
                    "`python3 tools/memory-context-load.py --workspace <ws> --refresh` to "
                    "rebuild the receipt). Pack still emitted with empty-but-valid envelope."
                )
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "filters": base["filters"],
                "root_causes": root_causes,
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{HARNESS_CONTEXT_SCHEMA}:harness:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def _knowledge_gap_ledger_path(self) -> Path:
        return self.repo_root / "reports" / "knowledge_gaps.jsonl"

    def _load_validated_knowledge_gap_states(self) -> tuple[Path, list[dict[str, Any]]] | dict[str, Any]:
        # R36 pathspec compliance: GAP-FIX-2-44 in .auditooor/agent_pathspec.json (tools/agent-pathspec-register.py).
        ledger_path = self._knowledge_gap_ledger_path()
        if _path_has_symlink(ledger_path, stop_at=self.repo_root):
            return {"error": "privacy_refusal", "message": "symlink paths are not readable through vault knowledge-gap context"}
        if not ledger_path.is_file():
            return {"error": "not_found", "message": f"knowledge-gap ledger not found: {_rel(ledger_path, self.repo_root)}"}
        try:
            text = ledger_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as exc:
            return {"error": "read_error", "message": str(exc), "ledger_path": _rel(ledger_path, self.repo_root)}
        if _has_secret(text):
            return {
                "error": "privacy_refusal",
                "message": "knowledge-gap ledger matches secret pattern",
                "ledger_path": _rel(ledger_path, self.repo_root),
            }
        try:
            module = _knowledge_gap_module()
            errors = module.validate_ledger(ledger_path, repo=self.repo_root)
            if errors:
                # Gap #44 resilience: emit empty-but-valid pack downstream even
                # when validation flags invalid refs. tools/agent-pathspec-register.py
                # registered GAP-FIX-2-44 (R36) for this file. Best-effort state
                # extraction; tolerate per-row failures.
                try:
                    states = list(module.latest_states(ledger_path, repo=self.repo_root).values())
                except Exception:  # noqa: BLE001 - tolerate state-extraction failures.
                    states = []
                return {
                    "_degraded_with_states": True,
                    "ledger_path_obj": ledger_path,
                    "states": states,
                    "error": "invalid_ledger",
                    "message": "; ".join(str(error) for error in errors[:5]),
                    "ledger_path": _rel(ledger_path, self.repo_root),
                }
            states = list(module.latest_states(ledger_path, repo=self.repo_root).values())
        except Exception as exc:  # noqa: BLE001 - report validator failures as data.
            # Gap #44 resilience: emit empty-but-valid pack downstream rather
            # than a bare error envelope. R36 pathspec compliance via
            # tools/agent-pathspec-register.py / .auditooor/agent_pathspec.json.
            return {
                "_degraded_with_states": True,
                "ledger_path_obj": ledger_path,
                "states": [],
                "error": "invalid_ledger",
                "message": str(exc),
                "ledger_path": _rel(ledger_path, self.repo_root),
            }
        return ledger_path, states

    def _knowledge_gap_refs(self, row: dict[str, Any]) -> list[str]:
        refs: list[str] = []
        for key in (
            "blocked_by_artifacts",
            "source_paths",
            "analyzer_target_paths",
            "resolution_evidence_paths",
        ):
            for value in row.get(key, []):
                ref = _safe_knowledge_gap_ref(value)
                if ref:
                    refs.append(ref)
        terminal = _safe_knowledge_gap_ref(row.get("terminal_artifact"))
        if terminal:
            refs.append(terminal)
        return _unique_bounded(refs, MAX_CONTEXT_ITEMS)

    def _knowledge_gap_context_row(self, row: dict[str, Any]) -> dict[str, Any]:
        verification = row.get("verification") if isinstance(row.get("verification"), dict) else {}
        commands = []
        for item in verification.get("commands", []):
            if not isinstance(item, dict):
                continue
            command = _safe_text_item(item.get("command"), max_chars=180)
            exit_code = item.get("exit_code")
            if command and type(exit_code) is int:
                commands.append({"command": command, "exit_code": exit_code})
            if len(commands) >= 5:
                break
        return {
            "gap_id": _safe_text_item(row.get("gap_id"), max_chars=80) or "",
            "candidate_gap_id": _safe_text_item(row.get("candidate_gap_id"), max_chars=90) or "",
            "status": _safe_text_item(row.get("status"), max_chars=32) or "",
            "event_type": _safe_text_item(row.get("event_type"), max_chars=32) or "",
            "area": _safe_text_item(row.get("area"), max_chars=80) or "",
            "gap_type": _safe_text_item(row.get("gap_type"), max_chars=80) or "",
            "severity": _safe_text_item(row.get("severity"), max_chars=32) or "",
            "yield_estimate": _safe_text_item(row.get("yield_estimate"), max_chars=32) or "",
            "effort_estimate": _safe_text_item(row.get("effort_estimate"), max_chars=32) or "",
            "title": _safe_text_item(row.get("title"), max_chars=180) or "",
            "question": _safe_text_item(row.get("question"), max_chars=240) or "",
            "description": _safe_text_item(row.get("description"), max_chars=360) or "",
            "evidence": _safe_text_item(row.get("evidence"), max_chars=360) or "",
            "remediation": _safe_text_item(row.get("remediation"), max_chars=320) or "",
            "blocked_by_artifacts": _unique_bounded(
                (ref for ref in (_safe_knowledge_gap_ref(value) for value in row.get("blocked_by_artifacts", [])) if ref),
                MAX_CONTEXT_ITEMS,
            ),
            "downstream_blocked_tasks": _bounded_string_list(row.get("downstream_blocked_tasks"), MAX_CONTEXT_ITEMS, max_chars=120),
            "source_paths": _unique_bounded(
                (ref for ref in (_safe_knowledge_gap_ref(value) for value in row.get("source_paths", [])) if ref),
                MAX_CONTEXT_ITEMS,
            ),
            "analyzer_target_paths": _unique_bounded(
                (ref for ref in (_safe_knowledge_gap_ref(value) for value in row.get("analyzer_target_paths", [])) if ref),
                MAX_CONTEXT_ITEMS,
            ),
            "heuristic_fp_risk": _safe_text_item(row.get("heuristic_fp_risk"), max_chars=240) or "",
            "heuristic_fn_risk": _safe_text_item(row.get("heuristic_fn_risk"), max_chars=240) or "",
            "resolution_summary": _safe_text_item(row.get("resolution_summary"), max_chars=320) or "",
            "resolution_evidence_paths": _unique_bounded(
                (ref for ref in (_safe_knowledge_gap_ref(value) for value in row.get("resolution_evidence_paths", [])) if ref),
                MAX_CONTEXT_ITEMS,
            ),
            "terminal_artifact": _safe_knowledge_gap_ref(row.get("terminal_artifact")) or "",
            "verification": {
                "passed": verification.get("passed") is True,
                "commands": commands,
            },
            "occurred_at": _safe_text_item(row.get("occurred_at"), max_chars=40) or "",
            "actor": _safe_text_item(row.get("actor"), max_chars=80) or "",
            "reopen_reason": _safe_text_item(row.get("reopen_reason"), max_chars=240) or "",
        }

    def vault_knowledge_gap_context(self, **kwargs: Any) -> dict[str, Any]:
        # R36 pathspec compliance: GAP-FIX-2-44 in .auditooor/agent_pathspec.json via tools/agent-pathspec-register.py.
        loaded = self._load_validated_knowledge_gap_states()
        degraded_info: dict[str, Any] | None = None
        if isinstance(loaded, dict):
            # Gap #44: detect tolerant-degraded mode and continue with best-effort states.
            if loaded.get("_degraded_with_states"):
                degraded_info = {
                    "error": loaded.get("error"),
                    "message": loaded.get("message"),
                    "ledger_path": loaded.get("ledger_path"),
                }
                ledger_path = loaded["ledger_path_obj"]
                states = loaded.get("states") or []
            else:
                return loaded
        else:
            ledger_path, states = loaded
        limit = min(MAX_KNOWLEDGE_GAPS, _clamp_limit(kwargs.get("limit", 8), default=8))
        status_filter = _safe_text_item(kwargs.get("status", "open"), max_chars=32) or "open"
        area_filter = _safe_text_item(kwargs.get("area"), max_chars=80)
        gap_type_filter = _safe_text_item(kwargs.get("gap_type"), max_chars=80)
        severity_filter = _safe_text_item(kwargs.get("severity"), max_chars=32)
        gap_id_filter = _safe_text_item(kwargs.get("gap_id"), max_chars=80)
        candidate_gap_id_filter = _safe_text_item(kwargs.get("candidate_gap_id"), max_chars=90)
        status_filter = status_filter.lower().replace(" ", "_").replace("-", "_")
        area_filter = area_filter.lower() if area_filter else None
        gap_type_filter = gap_type_filter.lower() if gap_type_filter else None
        severity_filter = severity_filter.lower() if severity_filter else None

        filtered_states: list[dict[str, Any]] = []
        for row in states:
            status = str(row.get("status", "")).lower()
            area = str(row.get("area", "")).lower()
            gap_type = str(row.get("gap_type", "")).lower()
            severity = str(row.get("severity", "")).lower()
            gap_id = str(row.get("gap_id", ""))
            candidate_gap_id = str(row.get("candidate_gap_id", ""))
            if status_filter != "all" and status != status_filter:
                continue
            if area_filter and area != area_filter:
                continue
            if gap_type_filter and gap_type != gap_type_filter:
                continue
            if severity_filter and severity != severity_filter:
                continue
            if gap_id_filter and gap_id != gap_id_filter:
                continue
            if candidate_gap_id_filter and candidate_gap_id != candidate_gap_id_filter:
                continue
            filtered_states.append(row)
        filtered_states.sort(
            key=lambda row: (
                KNOWLEDGE_GAP_STATUS_ORDER.get(str(row.get("status", "")), 99),
                HARNESS_SEVERITY_ORDER.get(str(row.get("severity", "")), 99),
                ESTIMATE_ORDER.get(str(row.get("yield_estimate", "")), 99),
                ESTIMATE_ORDER.get(str(row.get("effort_estimate", "")), 99),
                str(row.get("gap_id", "")),
            )
        )
        gaps = [self._knowledge_gap_context_row(row) for row in filtered_states[:limit]]
        status_counts: dict[str, int] = {}
        severity_counts: dict[str, int] = {}
        area_counts: dict[str, int] = {}
        for row in states:
            status = str(row.get("status", "unknown"))
            severity = str(row.get("severity", "unknown"))
            area = str(row.get("area", "unknown"))
            status_counts[status] = status_counts.get(status, 0) + 1
            severity_counts[severity] = severity_counts.get(severity, 0) + 1
            area_counts[area] = area_counts.get(area, 0) + 1
        source_refs = _unique_bounded(
            [
                "reports/knowledge_gaps.jsonl",
                *[ref for gap in gaps for ref in self._knowledge_gap_refs(gap)],
            ],
            MAX_KNOWLEDGE_GAP_REFS,
        )
        base = {
            "schema": KNOWLEDGE_GAP_CONTEXT_SCHEMA,
            "kind": "knowledge_gap",
            "ledger_path": _rel(ledger_path, self.repo_root),
            "limits": {
                "max_gaps": MAX_KNOWLEDGE_GAPS,
                "max_refs": MAX_KNOWLEDGE_GAP_REFS,
            },
            "filters": {
                "status": status_filter,
                "area": area_filter or "",
                "gap_type": gap_type_filter or "",
                "severity": severity_filter or "",
                "gap_id": gap_id_filter or "",
                "candidate_gap_id": candidate_gap_id_filter or "",
            },
            # R36 pathspec compliance: GAP-FIX-2-44 lane via tools/agent-pathspec-register.py.
            "validation": {
                "ledger_validated": degraded_info is None,
                "validator": "tools/knowledge-gap-log.py",
                "row_schema": "auditooor.knowledge_gap_event.v2",
                "latest_state_only": True,
            },
            "privacy_guards": {
                "exact_ledger_path_only": True,
                "repo_relative_refs_only": True,
                "vault_uri_refs_sanitized": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "raw_transcripts_not_returned": True,
            },
            "summary": {
                "gap_count": len(states),
                "returned_count": len(gaps),
                "open_count": status_counts.get("open", 0),
                "resolved_count": status_counts.get("resolved", 0),
                "status_counts": status_counts,
                "severity_counts": severity_counts,
                "area_counts": area_counts,
            },
            "source_refs": source_refs,
            "knowledge_gap_refs": [gap["gap_id"] for gap in gaps if gap.get("gap_id")],
            "gaps": gaps,
            "advisory_boundary": "Knowledge-gap context records missing truth and resolved provenance; open rows should trigger evidence collection, not inference.",
        }
        # Gap #44 resilience: surface degraded marker on ledger-validation failure.
        # CAP-GAP-77: when the degradation is caused by missing advisory doc
        # files (CONTINUATION_PLAN.md / CONTROL_PLANE_BUILD_STATUS.md) rather
        # than actual data corruption, emit verdict="pass-with-missing-doc".
        if degraded_info is not None:
            base["degraded"] = True
            base["degraded_reason"] = degraded_info.get("error") or "invalid_ledger"
            base["degraded_message"] = degraded_info.get("message") or ""
            missing_doc_paths = _detect_missing_doc_paths(degraded_info.get("message") or "")
            if missing_doc_paths:
                base["missing_doc"] = True
                base["missing_doc_paths"] = missing_doc_paths
                base["verdict"] = "pass-with-missing-doc"
                base["next_action"] = (
                    "Advisory doc files are missing from reports/knowledge_gaps.jsonl "
                    "source_paths refs. Pack still returned with full advisory content. "
                    "Provide missing docs, then rerun `python3 tools/memory-context-load.py "
                    "--workspace <ws> --refresh` to clear verdict=pass-with-missing-doc."
                )
            else:
                base["next_action"] = (
                    "Re-validate reports/knowledge_gaps.jsonl source_paths refs (or rerun "
                    "`python3 tools/memory-context-load.py --workspace <ws> --refresh` to "
                    "rebuild the receipt). Pack still emitted with empty-but-valid envelope."
                )
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "filters": base["filters"],
                "gaps": gaps,
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{KNOWLEDGE_GAP_CONTEXT_SCHEMA}:knowledge_gap:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def _resolve_exploit_brief_path(self, args: dict[str, Any], *, require_brief: bool = True) -> tuple[Path, Path]:
        brief_arg = args.get("brief_path")
        workspace_arg = args.get("workspace_path") or args.get("workspace")
        if brief_arg:
            raw_brief = _safe_workspace_or_brief_path(brief_arg)
            if raw_brief is None:
                raise ValueError("invalid brief_path")
            brief_path = raw_brief.resolve()
            if brief_path.name != "exploit_memory_brief.json" or brief_path.parent.name != ".auditooor":
                raise ValueError("brief_path must point to <workspace>/.auditooor/exploit_memory_brief.json")
            workspace_path = brief_path.parent.parent.resolve()
        elif workspace_arg:
            raw_workspace = _safe_workspace_or_brief_path(workspace_arg)
            if raw_workspace is None:
                raise ValueError("invalid workspace_path")
            workspace_path = raw_workspace.resolve()
            brief_path = workspace_path / ".auditooor" / "exploit_memory_brief.json"
        else:
            raise ValueError("workspace_path or brief_path is required")

        if _path_has_symlink(workspace_path) or _path_has_symlink(brief_path, stop_at=workspace_path):
            raise PermissionError("symlink paths are not readable through vault exploit context")
        if not workspace_path.is_dir():
            raise FileNotFoundError(f"workspace not found: {workspace_path}")
        if require_brief and not brief_path.is_file():
            raise FileNotFoundError(f"exploit memory brief not found: {brief_path}")
        try:
            brief_path.relative_to(workspace_path)
        except ValueError as exc:
            raise ValueError("brief_path must be inside workspace_path") from exc
        if brief_path.parent != workspace_path / ".auditooor":
            raise ValueError("brief_path must be the workspace .auditooor exploit brief")
        return workspace_path, brief_path

    def _build_missing_exploit_brief(self, workspace_path: Path, brief_path: Path) -> dict[str, Any] | None:
        try:
            module = _exploit_brief_module()
            payload = module.build_brief(self.repo_root, workspace_path)
            module.emit(payload, workspace_path / ".auditooor" / "exploit_memory_brief.md", brief_path)
        except Exception as exc:  # noqa: BLE001 - return fail-closed blocker data to the MCP caller.
            message = str(exc)
            if self._is_missing_live_topology_requirements(message):
                return self._degraded_exploit_context(
                    workspace_path,
                    brief_path,
                    code="missing_live_topology_proof_requirements",
                    missing_artifact=".auditooor/live_topology_proof_requirements.json",
                    message=message,
                    next_action=(
                        f"Run `make -C {self.repo_root} live-topology-proof-requirements "
                        f"WS={workspace_path}` when live-proof requirements are needed. "
                        "Until then, vault_exploit_context returns an empty advisory pack."
                    ),
                )
            return {
                "error": "brief_blocked",
                "message": message,
                "workspace_path": str(workspace_path),
                "brief_path": str(brief_path),
                "next_action": (
                    "Provide the missing artifact named in message, then rerun vault_exploit_context. "
                    "This MCP path only builds offline advisory exploit-memory briefs and never marks a finding submission-ready."
                ),
            }
        return None

    def _is_missing_live_topology_requirements(self, message: str) -> bool:
        return (
            "missing required artifact: live topology proof requirements" in message
            and ".auditooor/live_topology_proof_requirements.json" in message
        )

    def _degraded_exploit_context(
        self,
        workspace_path: Path,
        brief_path: Path,
        *,
        code: str,
        missing_artifact: str,
        message: str,
        next_action: str,
    ) -> dict[str, Any]:
        warning = {
            "code": code,
            "severity": "warning",
            "missing_artifact": missing_artifact,
            "message": _safe_text_item(message, max_chars=360) or "",
            "next_action": _safe_text_item(next_action, max_chars=360) or "",
        }
        base = {
            "schema": EXPLOIT_CONTEXT_SCHEMA,
            "kind": "exploit",
            "workspace": workspace_path.name,
            "workspace_path": str(workspace_path),
            "brief_path": str(brief_path),
            "workspace_posture": "degraded_missing_input",
            "generated_at": "",
            "brief_hash": "",
            "limits": {
                "max_angles": MAX_EXPLOIT_ANGLES,
                "max_proof_requirements": MAX_EXPLOIT_PROOF_REQUIREMENTS,
                "max_risks": MAX_EXPLOIT_RISKS,
                "max_refs": MAX_EXPLOIT_REFS,
            },
            "validation": {
                "brief_validated": False,
                "validator": "tools/exploit-memory-brief.py",
                "brief_schema": "",
            },
            "privacy_guards": {
                "exact_brief_path_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "brief_refs_sanitized": True,
                "raw_workspace_source_not_returned": True,
            },
            "run_policy": {
                "offline_only": True,
                "llm_used": False,
                "network_used": False,
                "submission_ready": False,
                "unknown_reason_declines": code,
            },
            "summary": {
                "status": "degraded_empty_brief",
                "protocol_family": "",
                "recommended_angle_count": 0,
                "base_rate_only_rejections": 0,
            },
            "source_refs": [],
            "knowledge_gap_refs": [],
            "angles": [],
            "proof_requirements": [],
            "duplicate_risks": [],
            "oos_risks": [],
            "local_kill_risks": [],
            "warnings": [warning],
            "advisory_boundary": (
                "This degraded context pack is an empty advisory recall surface. "
                "It is not submission-ready evidence; generate the missing proof requirements "
                "before filing or routing live-proof work."
            ),
        }
        # CAP-GAP-77: if the missing artifact is an advisory doc file rather
        # than a required input, surface verdict="pass-with-missing-doc" so
        # callers can distinguish doc-gap from hard-blocking missing inputs.
        missing_doc_paths = _detect_missing_doc_paths(missing_artifact)
        if missing_doc_paths:
            base["missing_doc"] = True
            base["missing_doc_paths"] = missing_doc_paths
            base["verdict"] = "pass-with-missing-doc"
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "warnings": base["warnings"],
                "angles": [],
                "proof_requirements": [],
                "duplicate_risks": [],
                "oos_risks": [],
                "local_kill_risks": [],
                "source_refs": [],
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{EXPLOIT_CONTEXT_SCHEMA}:exploit:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def _read_exploit_brief_payload(self, workspace_path: Path, brief_path: Path) -> tuple[dict[str, Any] | None, dict[str, Any] | None]:
        try:
            text = brief_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as exc:
            return None, {"error": "read_error", "message": str(exc), "brief_path": str(brief_path)}
        if _has_secret(text):
            return None, {"error": "privacy_refusal", "message": "brief matches secret pattern", "brief_path": str(brief_path)}
        try:
            payload = json.loads(text)
        except json.JSONDecodeError as exc:
            return None, {"error": "invalid_brief", "message": f"invalid JSON: {exc}", "brief_path": str(brief_path)}
        if not isinstance(payload, dict):
            return None, {"error": "invalid_brief", "message": "brief must be a JSON object", "brief_path": str(brief_path)}
        try:
            _exploit_brief_module().validate_payload(payload, workspace_path, self.repo_root)
        except Exception as exc:  # noqa: BLE001 - expose validator failure as data, not server crash.
            return None, {"error": "invalid_brief", "message": str(exc), "brief_path": str(brief_path)}
        return payload, None

    def _load_validated_exploit_brief(self, args: dict[str, Any]) -> tuple[Path, Path, dict[str, Any]] | dict[str, Any]:
        try:
            workspace_path, brief_path = self._resolve_exploit_brief_path(args, require_brief=False)
        except PermissionError as exc:
            return {"error": "privacy_refusal", "message": str(exc)}
        except ValueError as exc:
            return {"error": "invalid_path", "message": str(exc)}
        except FileNotFoundError as exc:
            return {"error": "not_found", "message": str(exc)}
        if not brief_path.is_file():
            if args.get("brief_path"):
                return {"error": "not_found", "message": f"exploit memory brief not found: {brief_path}"}
            blocked = self._build_missing_exploit_brief(workspace_path, brief_path)
            if blocked is not None:
                return blocked

        payload, error = self._read_exploit_brief_payload(workspace_path, brief_path)
        if error is None and payload is not None:
            return workspace_path, brief_path, payload
        if (
            not args.get("brief_path")
            and error
            and error.get("error") == "invalid_brief"
            and "source snapshot hash mismatch" in str(error.get("message"))
        ):
            blocked = self._build_missing_exploit_brief(workspace_path, brief_path)
            if blocked is not None:
                return blocked
            payload, error = self._read_exploit_brief_payload(workspace_path, brief_path)
            if error is None and payload is not None:
                return workspace_path, brief_path, payload
        assert error is not None
        return error

    def _exploit_angle_context(self, angle: dict[str, Any]) -> dict[str, Any]:
        duplicate_guard = angle.get("duplicate_guard") if isinstance(angle.get("duplicate_guard"), dict) else {}
        oos_guard = angle.get("oos_guard") if isinstance(angle.get("oos_guard"), dict) else {}
        outcome_semantics = angle.get("outcome_semantics") if isinstance(angle.get("outcome_semantics"), dict) else {}
        return {
            "angle_id": _safe_text_item(angle.get("angle_id"), max_chars=32) or "",
            "title": _safe_text_item(angle.get("title"), max_chars=160) or "",
            "recommendation_status": _safe_text_item(angle.get("recommendation_status"), max_chars=64) or "",
            "bug_class_id": _safe_text_item(angle.get("bug_class_id"), max_chars=80) or "",
            "confidence": _safe_text_item(angle.get("confidence"), max_chars=32) or "",
            "source_signal_score": angle.get("source_signal_score", 0),
            "detector_saturation": angle.get("detector_saturation", 0),
            "target_files": [
                rel for rel in (_safe_workspace_relpath(path) for path in angle.get("target_files", []))
                if rel
            ][:MAX_CONTEXT_ITEMS],
            "source_refs": _bounded_brief_refs(angle.get("source_refs"), MAX_CONTEXT_ITEMS),
            "evidence_chain": _bounded_brief_refs(angle.get("evidence_chain"), MAX_CONTEXT_ITEMS),
            "ranking_rationale": _safe_text_item(angle.get("ranking_rationale"), max_chars=240) or "",
            "duplicate_guard": {
                "status": _safe_text_item(duplicate_guard.get("status"), max_chars=64) or "",
                "material_distinction": _safe_text_item(duplicate_guard.get("material_distinction"), max_chars=240) or "",
                "evidence_chain": _bounded_brief_refs(duplicate_guard.get("evidence_chain"), MAX_CONTEXT_ITEMS),
            },
            "oos_guard": {
                "status": _safe_text_item(oos_guard.get("status"), max_chars=80) or "",
                "rationale": _safe_text_item(oos_guard.get("rationale"), max_chars=280) or "",
                "clause_refs": _bounded_brief_refs(oos_guard.get("clause_refs"), MAX_CONTEXT_ITEMS),
            },
            "outcome_semantics": {
                "unknown_reason_declines_learning_scope": _safe_text_item(
                    outcome_semantics.get("unknown_reason_declines_learning_scope"),
                    max_chars=80,
                )
                or "",
                "cause_learning_allowed": bool(outcome_semantics.get("cause_learning_allowed")),
            },
            "proof_prerequisites": [
                self._exploit_requirement_context(row)
                for row in angle.get("proof_prerequisites", [])
                if isinstance(row, dict)
            ][:5],
            "not_submit_ready_until": _bounded_string_list(angle.get("not_submit_ready_until"), 8, max_chars=120),
        }

    def _exploit_requirement_context(self, row: dict[str, Any]) -> dict[str, Any]:
        return {
            "artifact": _safe_text_item(row.get("artifact"), max_chars=120) or "",
            "status": _safe_text_item(row.get("status"), max_chars=80) or "",
            "summary": _safe_text_item(row.get("summary"), max_chars=240) or "",
            "source_ref": _safe_brief_source_ref(row.get("source_ref")) or "",
        }

    def _exploit_risk_context(self, row: dict[str, Any]) -> dict[str, Any]:
        return {
            "bug_class_id": _safe_text_item(row.get("bug_class_id"), max_chars=80) or "",
            "status": _safe_text_item(row.get("status"), max_chars=80) or "",
            "duplicate_count": row.get("duplicate_count", 0),
            "rejected_count": row.get("rejected_count", 0),
            "local_kill_count": row.get("local_kill_count", 0),
            "rationale": _safe_text_item(row.get("rationale") or row.get("material_distinction_required"), max_chars=280) or "",
            "evidence_chain": _bounded_brief_refs(row.get("evidence_chain"), MAX_CONTEXT_ITEMS),
        }

    def vault_exploit_context(self, **kwargs: Any) -> dict[str, Any]:
        loaded = self._load_validated_exploit_brief(kwargs)
        if isinstance(loaded, dict):
            return loaded
        workspace_path, brief_path, payload = loaded
        limit = min(MAX_EXPLOIT_ANGLES, _clamp_limit(kwargs.get("limit", 5), default=5))
        raw_angles = payload.get("angles") if isinstance(payload.get("angles"), list) else []
        angles = [
            self._exploit_angle_context(angle)
            for angle in raw_angles[:limit]
            if isinstance(angle, dict)
        ]
        proof_requirements = [
            self._exploit_requirement_context(row)
            for row in (payload.get("proof_requirements") or [])
            if isinstance(row, dict)
        ][:MAX_EXPLOIT_PROOF_REQUIREMENTS]
        duplicate_risks = [
            self._exploit_risk_context(row)
            for row in (payload.get("duplicate_risks") or [])
            if isinstance(row, dict)
        ][:MAX_EXPLOIT_RISKS]
        oos_risks = [
            self._exploit_risk_context(row)
            for row in (payload.get("oos_risks") or [])
            if isinstance(row, dict)
        ][:MAX_EXPLOIT_RISKS]
        local_kill_risks = [
            self._exploit_risk_context(row)
            for row in (payload.get("local_kill_risks") or [])
            if isinstance(row, dict)
        ][:MAX_EXPLOIT_RISKS]
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        run_policy = payload.get("run_policy") if isinstance(payload.get("run_policy"), dict) else {}
        source_refs = _bounded_brief_refs(
            {
                "source_snapshot": payload.get("source_snapshot"),
                "angles": angles,
                "proof_requirements": proof_requirements,
                "duplicate_risks": duplicate_risks,
                "oos_risks": oos_risks,
                "local_kill_risks": local_kill_risks,
            }
        )
        base = {
            "schema": EXPLOIT_CONTEXT_SCHEMA,
            "kind": "exploit",
            "workspace": _safe_text_item(payload.get("workspace"), max_chars=120) or workspace_path.name,
            "workspace_path": str(workspace_path),
            "brief_path": str(brief_path),
            "workspace_posture": _safe_text_item(payload.get("workspace_posture"), max_chars=80) or "",
            "generated_at": _safe_text_item(payload.get("generated_at"), max_chars=80) or "",
            "brief_hash": _safe_text_item(payload.get("brief_hash"), max_chars=80) or "",
            "limits": {
                "max_angles": MAX_EXPLOIT_ANGLES,
                "max_proof_requirements": MAX_EXPLOIT_PROOF_REQUIREMENTS,
                "max_risks": MAX_EXPLOIT_RISKS,
                "max_refs": MAX_EXPLOIT_REFS,
            },
            "validation": {
                "brief_validated": True,
                "validator": "tools/exploit-memory-brief.py",
                "brief_schema": _safe_text_item(payload.get("schema"), max_chars=80) or "",
            },
            "privacy_guards": {
                "exact_brief_path_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "brief_refs_sanitized": True,
                "raw_workspace_source_not_returned": True,
            },
            "run_policy": {
                "offline_only": bool(run_policy.get("offline_only")),
                "llm_used": bool(run_policy.get("llm_used")),
                "network_used": bool(run_policy.get("network_used")),
                "submission_ready": bool(run_policy.get("submission_ready")),
                "unknown_reason_declines": _safe_text_item(run_policy.get("unknown_reason_declines"), max_chars=120) or "",
            },
            "summary": {
                "status": _safe_text_item(summary.get("status"), max_chars=40) or "",
                "protocol_family": _safe_text_item(summary.get("protocol_family"), max_chars=80) or "",
                "recommended_angle_count": summary.get("recommended_angle_count", 0),
                "base_rate_only_rejections": summary.get("base_rate_only_rejections", 0),
            },
            "source_refs": source_refs,
            "knowledge_gap_refs": _bounded_string_list(payload.get("knowledge_gap_refs"), MAX_CONTEXT_ITEMS, max_chars=40),
            "angles": angles,
            "proof_requirements": proof_requirements,
            "duplicate_risks": duplicate_risks,
            "oos_risks": oos_risks,
            "local_kill_risks": local_kill_risks,
            "advisory_boundary": "This context pack is not submission-ready evidence; run source-proof, OOS, duplicate, pre-submit, and PoC/live-proof gates before filing.",
        }
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "angles": angles,
                "proof_requirements": proof_requirements,
                "duplicate_risks": duplicate_risks,
                "oos_risks": oos_risks,
                "local_kill_risks": local_kill_risks,
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{EXPLOIT_CONTEXT_SCHEMA}:exploit:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_engagement_status(self, **kwargs: Any) -> dict[str, Any]:
        """Walk ``audits/<engagement>/submissions/`` and return bounded per-file state.

        Inputs (all optional):
          * ``engagement_path``: explicit absolute path to a single engagement
            (e.g. ``/Users/wolf/audits/spark``). Filename + lane only — no body.
          * ``audits_root``: override the default ``~/audits`` root.
          * ``engagement``: name filter (substring match against engagement dir name).
          * ``limit``: max files surfaced per engagement (default 12, max 50).
          * No explicit scope: active engagements only, capped to reduce recall noise.

        Output schema: ``auditooor.vault_engagement_status.v1`` — engagements list
        with per-file status text, status_class, lane, severity, internal_name,
        and audits-root-relative path. Privacy guards: no absolute paths returned,
        secret-bearing files are dropped, ``.bak`` and dotfiles are skipped.
        """
        limit = min(MAX_ENGAGEMENT_FILES, _clamp_limit(kwargs.get("limit", 12), default=12))
        explicit_path = kwargs.get("engagement_path")
        audits_root_arg = kwargs.get("audits_root")
        engagement_filter = _safe_text_item(kwargs.get("engagement"), max_chars=80)
        engagement_filter = engagement_filter.lower() if engagement_filter else None
        default_scoped = not bool(explicit_path or audits_root_arg or engagement_filter)

        if audits_root_arg:
            try:
                audits_root = Path(str(audits_root_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                return {"error": "invalid_audits_root"}
        else:
            audits_root = DEFAULT_AUDITS_ROOT.resolve()

        if not audits_root.exists() or not audits_root.is_dir():
            return {"error": "audits_root_not_found", "audits_root": str(audits_root)}

        if explicit_path:
            try:
                target = Path(str(explicit_path)).expanduser().resolve()
            except (OSError, RuntimeError):
                return {"error": "invalid_engagement_path"}
            if audits_root not in target.parents and target != audits_root:
                return {"error": "engagement_path_escapes_audits_root"}
            engagement_dirs = [target]
        else:
            engagement_dirs = sorted(
                p for p in audits_root.iterdir()
                if p.is_dir() and not p.name.startswith(".") and not p.name.startswith("_")
            )

        engagements: list[dict[str, Any]] = []
        all_refs: list[str] = []
        total_files_scanned = 0
        engagements_with_submissions = 0

        for eng_dir in engagement_dirs:
            if engagement_filter and engagement_filter not in eng_dir.name.lower():
                continue
            submissions_dir = eng_dir / "submissions"
            if not submissions_dir.exists() or not submissions_dir.is_dir():
                continue
            engagements_with_submissions += 1
            files: list[dict[str, Any]] = []
            status_class_counts: dict[str, int] = {}
            lane_counts: dict[str, int] = {}
            for lane_dir in ENGAGEMENT_LANE_DIRS:
                lane_path = submissions_dir / lane_dir
                if not lane_path.exists() or not lane_path.is_dir():
                    continue
                for md_file in sorted(lane_path.rglob("*.md")):
                    if md_file.name.startswith(".") or md_file.name.endswith(".bak"):
                        continue
                    if md_file.is_symlink():
                        continue
                    total_files_scanned += 1
                    try:
                        text = md_file.read_text(encoding="utf-8", errors="replace")
                    except OSError:
                        continue
                    if _has_secret(text[:8000]):
                        continue
                    header = _engagement_extract_header(text)
                    rel = _engagement_safe_relpath(md_file, audits_root)
                    if rel is None:
                        continue
                    lane = _engagement_lane_classify(lane_dir, md_file.name)
                    status_text = header.get("status_text")
                    status_class = _engagement_status_classify(status_text)
                    status_class_counts[status_class] = status_class_counts.get(status_class, 0) + 1
                    lane_counts[lane] = lane_counts.get(lane, 0) + 1
                    files.append(
                        {
                            "audits_relpath": rel,
                            "filename": md_file.name,
                            "lane": lane,
                            "status_text": status_text or "",
                            "status_class": status_class,
                            "title": header.get("title", ""),
                            "internal_name": header.get("internal_name", ""),
                            "severity": header.get("severity", ""),
                            "target": header.get("target", ""),
                        }
                    )
                    all_refs.append(rel)
                    if len(files) >= limit:
                        break
                if len(files) >= limit:
                    break
            engagements.append(
                {
                    "engagement": eng_dir.name,
                    "submissions_relpath": eng_dir.name + "/submissions",
                    "file_count": len(files),
                    "status_class_counts": status_class_counts,
                    "lane_counts": lane_counts,
                    "files": files,
                }
            )

        default_scope_scores: dict[str, int] = {}
        if default_scoped:
            scoped: list[dict[str, Any]] = []
            for engagement in engagements:
                score = _engagement_default_scope_score(engagement)
                if score <= 0:
                    continue
                default_scope_scores[engagement["engagement"]] = score
                scoped.append(engagement)
            scoped.sort(
                key=lambda e: (
                    -default_scope_scores.get(e["engagement"], 0),
                    e["engagement"],
                )
            )
            engagements = scoped[:MAX_DEFAULT_ENGAGEMENT_STATUS_ENGAGEMENTS]
            source_refs = _unique_bounded(
                _engagement_refs_from_rows(engagements),
                MAX_ENGAGEMENT_REFS,
            )
        else:
            engagements.sort(key=lambda e: (-e["file_count"], e["engagement"]))
            source_refs = _unique_bounded(all_refs, MAX_ENGAGEMENT_REFS)
        base = {
            "schema": ENGAGEMENT_STATUS_SCHEMA,
            "kind": "engagement_status",
            "audits_root_name": audits_root.name,
            "limits": {
                "max_files_per_engagement": MAX_ENGAGEMENT_FILES,
                "max_refs": MAX_ENGAGEMENT_REFS,
                "header_lines_read": ENGAGEMENT_HEADER_LINES,
                "default_max_engagements": MAX_DEFAULT_ENGAGEMENT_STATUS_ENGAGEMENTS,
            },
            "filters": {
                "engagement": engagement_filter or "",
                "engagement_path": str(explicit_path) if explicit_path else "",
                "default_scoped": default_scoped,
                "default_scope_rule": (
                    "active_status_or_lane_cap"
                    if default_scoped
                    else ""
                ),
            },
            "privacy_guards": {
                "audits_root_relative_only": True,
                "absolute_paths_blocked": True,
                "header_only_no_body": True,
                "secret_patterns_blocked": True,
                "symlinks_blocked": True,
                "bak_and_dotfiles_skipped": True,
            },
            "summary": {
                "engagements_scanned": len(engagement_dirs),
                "engagements_with_submissions": engagements_with_submissions,
                "engagements_returned": len(engagements),
                "total_files_returned": sum(len(e["files"]) for e in engagements),
                "total_files_scanned": total_files_scanned,
                "default_scope_filtered_engagements": (
                    engagements_with_submissions - len(engagements)
                    if default_scoped
                    else 0
                ),
            },
            "engagements": engagements,
            "source_refs": source_refs,
            "advisory_boundary": "Engagement status reflects filesystem ground truth from submissions/ tree headers; do NOT infer triager-side state beyond what the in-file Status line records.",
        }
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "engagements": engagements,
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{ENGAGEMENT_STATUS_SCHEMA}:engagement_status:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_spark_engagement_context(self, **kwargs: Any) -> dict[str, Any]:
        """Surface Spark engagement state into MCP recall.

        Inputs (all optional):
          * ``workspace_path``: absolute path to a Spark workspace (e.g.
            ``~/audits/spark``). Defaults to ``~/audits/spark`` when omitted.
          * ``limit``: max lead files returned (default 5, max 20).

        Output schema: ``auditooor.vault_spark_engagement_context.v1.1``

        Returns:
          * ``leads``: list of paste-ready/packaged/staging .md files with
            filename, severity (parsed from ``Severity:`` header or filename
            suffix CRITICAL/HIGH/MEDIUM), file_path.
          * ``originality_sha_range``: contents of
            ``<workspace>/.auditooor/originality_sha_range.json`` or null.
          * ``submissions_index_path``: path to
            ``<workspace>/submissions/SUBMISSIONS.md`` if it exists, else null.
          * ``engagement_status``: contents of
            ``<workspace>/.auditooor/engagement_status.json`` if it exists,
            else ``{"status": "unknown"}``.
          * ``latest_filed_lead`` (v1.1): highest-severity row in
            ``submissions/SUBMISSIONS.md`` with status "filed", "submitted", or
            "escalated". Keys: id, date, severity, status_text, title. null when
            no matching row found.
          * ``closed_dupes_count`` (v1.1): count of .md files under
            ``submissions/superseded/``.
          * ``pending_originality_check`` (v1.1): true when any paste_ready lead
            has status_text containing "ESCALATED" (but not "STATUS-CHECKED") and
            the file was modified within the last 7 days.
          * ``context_pack_id`` and ``context_pack_hash``: always present for
            pr-hygiene-check.py.
        """
        limit = min(20, _clamp_limit(kwargs.get("limit", 5), default=5))
        workspace_path_arg = kwargs.get("workspace_path")

        if workspace_path_arg:
            try:
                workspace = Path(str(workspace_path_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                workspace = None
        else:
            workspace = (Path.home() / "audits" / "spark").resolve()

        # Graceful empty payload when workspace does not exist.
        if workspace is None or not workspace.exists() or not workspace.is_dir():
            payload: dict[str, Any] = {
                "schema": SPARK_ENGAGEMENT_CONTEXT_SCHEMA,
                "kind": "spark_engagement_context",
                "workspace_path": str(workspace_path_arg) if workspace_path_arg else "",
                "error": "workspace_not_found",
                "leads": [],
                "originality_sha_range": None,
                "submissions_index_path": None,
                "engagement_status": {"status": "unknown"},
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{SPARK_ENGAGEMENT_CONTEXT_SCHEMA}:spark_engagement:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        # Walk submissions/{paste_ready,packaged,staging}/*.md
        lead_lanes = ("paste_ready", "packaged", "staging")
        _SEVERITY_SUFFIX_RE = re.compile(
            r"[-_](CRITICAL|HIGH|MEDIUM|LOW)(?:\.md)?$", re.IGNORECASE
        )
        leads: list[dict[str, Any]] = []
        submissions_dir = workspace / "submissions"

        if submissions_dir.exists() and submissions_dir.is_dir():
            for lane in lead_lanes:
                lane_path = submissions_dir / lane
                if not lane_path.exists() or not lane_path.is_dir():
                    continue
                for md_file in sorted(lane_path.rglob("*.md")):
                    if md_file.name.startswith(".") or md_file.name.endswith(".bak"):
                        continue
                    if md_file.is_symlink():
                        continue
                    try:
                        text = md_file.read_text(encoding="utf-8", errors="replace")
                    except OSError:
                        continue
                    if _has_secret(text[:8000]):
                        continue
                    # Determine severity: parse header first, then fall back to filename suffix.
                    header = _engagement_extract_header(text)
                    severity = header.get("severity", "").strip().lower()
                    if not severity:
                        m = _SEVERITY_SUFFIX_RE.search(md_file.stem)
                        if m:
                            severity = m.group(1).lower()
                    leads.append(
                        {
                            "filename": md_file.name,
                            "severity": severity,
                            "file_path": str(md_file),
                            "lane": lane,
                            "title": header.get("title", ""),
                            "status_text": header.get("status_text", ""),
                        }
                    )
                    if len(leads) >= limit:
                        break
                if len(leads) >= limit:
                    break

        # originality_sha_range
        originality_path = workspace / ".auditooor" / "originality_sha_range.json"
        originality_sha_range: Any = None
        if originality_path.exists():
            try:
                raw = originality_path.read_text(encoding="utf-8", errors="replace")
                originality_sha_range = json.loads(raw)
            except (OSError, json.JSONDecodeError):
                originality_sha_range = None

        # submissions index
        submissions_index = workspace / "submissions" / "SUBMISSIONS.md"
        submissions_index_path: str | None = str(submissions_index) if submissions_index.exists() else None

        # engagement_status
        engagement_status_path = workspace / ".auditooor" / "engagement_status.json"
        engagement_status: Any = {"status": "unknown"}
        if engagement_status_path.exists():
            try:
                raw = engagement_status_path.read_text(encoding="utf-8", errors="replace")
                engagement_status = json.loads(raw)
            except (OSError, json.JSONDecodeError):
                engagement_status = {"status": "unknown"}

        # --- v1.1 derived keys ---

        # latest_filed_lead: parse SUBMISSIONS.md for highest-severity SUBMITTED row.
        # Severity order: critical > high > medium > low (descending priority).
        latest_filed_lead: dict[str, Any] | None = None
        _SUBS_ROW_RE = re.compile(
            r"\|\s*(?P<id>[^|]*?)\s*\|\s*(?P<date>[^|]*?)\s*\|\s*(?P<sev>[^|]*?)\s*\|"
            r"\s*(?P<status>[^|]*?)\s*\|\s*(?P<title>[^|]+?)\s*\|",
            re.IGNORECASE,
        )
        _SEVERITY_ORDER = {"critical": 0, "high": 1, "medium": 2, "low": 3}
        if submissions_index is not None and submissions_index.exists():
            try:
                subs_text = submissions_index.read_text(encoding="utf-8", errors="replace")
                best_rank = 999
                for m in _SUBS_ROW_RE.finditer(subs_text):
                    status_cell = m.group("status").strip().lower()
                    # Row must describe a filed/submitted/escalated submission.
                    if not any(kw in status_cell for kw in ("filed", "submitted", "escalated")):
                        continue
                    sev = m.group("sev").strip().lower()
                    rank = _SEVERITY_ORDER.get(sev, 99)
                    if rank < best_rank:
                        best_rank = rank
                        latest_filed_lead = {
                            "id": m.group("id").strip() or None,
                            "date": m.group("date").strip(),
                            "severity": sev,
                            "status_text": m.group("status").strip(),
                            "title": m.group("title").strip()[:240],
                        }
            except OSError:
                pass

        # closed_dupes_count: count .md files in submissions/superseded/ (exclude .hash sidecars).
        closed_dupes_count = 0
        superseded_dir = submissions_dir / "superseded" if submissions_dir.exists() else None
        if superseded_dir is not None and superseded_dir.exists() and superseded_dir.is_dir():
            closed_dupes_count = sum(
                1
                for f in superseded_dir.iterdir()
                if f.is_file() and f.suffix == ".md" and not f.name.startswith(".")
            )

        # pending_originality_check: True when any paste_ready lead's status_text contains
        # "ESCALATED" (case-insensitive) but NOT "STATUS-CHECKED", AND the file was
        # modified within the last 7 days (proxy for still-active check window).
        import time as _time
        _7_DAYS_S = 7 * 24 * 3600
        _now = _time.time()
        pending_originality_check = False
        paste_ready_path = submissions_dir / "paste_ready" if submissions_dir.exists() else None
        if paste_ready_path is not None and paste_ready_path.exists():
            for lead in leads:
                if lead.get("lane") != "paste_ready":
                    continue
                st = lead.get("status_text", "")
                if "escalated" in st.lower() and "status-checked" not in st.lower():
                    try:
                        mtime = Path(lead["file_path"]).stat().st_mtime
                        if (_now - mtime) < _7_DAYS_S:
                            pending_originality_check = True
                            break
                    except OSError:
                        pass

        base: dict[str, Any] = {
            "schema": SPARK_ENGAGEMENT_CONTEXT_SCHEMA,
            "kind": "spark_engagement_context",
            "workspace_path": str(workspace),
            "leads": leads,
            "leads_returned": len(leads),
            "limit": limit,
            "originality_sha_range": originality_sha_range,
            "submissions_index_path": submissions_index_path,
            "engagement_status": engagement_status,
            # v1.1 derived keys
            "latest_filed_lead": latest_filed_lead,
            "closed_dupes_count": closed_dupes_count,
            "pending_originality_check": pending_originality_check,
        }
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{SPARK_ENGAGEMENT_CONTEXT_SCHEMA}:spark_engagement:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_brain_prime_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded brain-prime receipt state for a workspace."""
        limit = min(
            MAX_BRAIN_PRIME_LANES,
            _clamp_limit(
                kwargs.get("limit", DEFAULT_BRAIN_PRIME_LANES),
                default=DEFAULT_BRAIN_PRIME_LANES,
            ),
        )
        workspace_path_arg = kwargs.get("workspace_path")
        receipt_path_arg = kwargs.get("receipt_path")

        def _finalize(payload: dict[str, Any]) -> dict[str, Any]:
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{BRAIN_PRIME_CONTEXT_SCHEMA}:brain_prime:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _workspace_ref(base: Path, candidate: Path | None) -> str | None:
            if candidate is None:
                return None
            try:
                rel = candidate.resolve().relative_to(base.resolve()).as_posix()
            except (OSError, RuntimeError, ValueError):
                return None
            safe_rel = _safe_workspace_relpath(rel)
            return f"workspace:{safe_rel}" if safe_rel else None

        def _empty(
            *,
            workspace_label: str,
            error: str,
            receipt_ref: str | None = None,
            degraded_reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": BRAIN_PRIME_CONTEXT_SCHEMA,
                "kind": "brain_prime_context",
                "workspace": workspace_label,
                "receipt_found": False,
                "receipt_path": receipt_ref,
                "report_path": None,
                "report_present": False,
                "generated_at": "",
                "audit_pin": "",
                "target_repo": "",
                "summary": {
                    "functions_extracted": 0,
                    "phase_d_files": 0,
                    "phase_e_sources": 0,
                    "phase_f_lanes": 0,
                    "strict_ready": False,
                    "top_functions_per_file": 0,
                    "min_confidence": 0,
                    "max_files": 0,
                },
                "scope": {
                    "language": "",
                    "auto_detected": False,
                    "candidate_dir_count": 0,
                    "scope_globs_hash": "",
                },
                "mcp": {
                    "skipped": False,
                    "callables_attempted": 0,
                    "callables_succeeded": 0,
                    "callables_failed_count": 0,
                    "duration_seconds": 0,
                    "phase_a_context_pack_id": "",
                    "phase_a_context_pack_hash": "",
                },
                "integrity": {
                    "receipt_schema_valid": False,
                    "receipt_hash_valid": False,
                    "report_sha256_valid": False,
                    "report_mtime_valid": False,
                },
                "dispatch_ready": False,
                "top_phase_f_lanes": [],
                "lanes_returned": 0,
                "limit": limit,
                "degraded": True,
                "error": error,
                "degraded_reason": degraded_reason or error,
                "privacy_guards": [
                    "no_raw_receipt_body",
                    "no_raw_report_body",
                    "workspace_relative_refs_only",
                ],
                "source_refs": [
                    ref
                    for ref in [receipt_ref, "tools/brain-prime.py", "docs/BRAIN_PRIMING.md"]
                    if ref
                ],
            }
            return _finalize(payload)

        if not workspace_path_arg:
            return _empty(workspace_label="", error="missing_workspace_path")
        try:
            workspace = Path(str(workspace_path_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            label = _engage_report_workspace_label(workspace_path_arg, default="")
            return _empty(
                workspace_label=label,
                error="invalid_workspace_path",
            )
        workspace_label = _engage_report_workspace_label(workspace.name, default=workspace.name)
        if not workspace.exists() or not workspace.is_dir():
            return _empty(workspace_label=workspace_label, error="workspace_not_found")

        receipt_path = workspace / ".auditooor" / "brain_prime_receipt.json"
        if receipt_path_arg:
            try:
                candidate = Path(str(receipt_path_arg)).expanduser()
            except (OSError, RuntimeError):
                return _empty(
                    workspace_label=workspace_label,
                    error="invalid_receipt_path",
                    degraded_reason="receipt_path_unparseable",
                )
            receipt_path = candidate if candidate.is_absolute() else workspace / candidate
            try:
                receipt_path.resolve().relative_to(workspace.resolve())
            except (OSError, RuntimeError, ValueError):
                return _empty(
                    workspace_label=workspace_label,
                    error="invalid_receipt_path",
                    degraded_reason="receipt_path_outside_workspace",
                )

        receipt_ref = _workspace_ref(workspace, receipt_path)
        if not receipt_path.is_file():
            return _empty(
                workspace_label=workspace_label,
                error="receipt_not_found",
                receipt_ref=receipt_ref,
            )
        try:
            raw = json.loads(receipt_path.read_text(encoding="utf-8", errors="replace"))
        except (OSError, json.JSONDecodeError):
            return _empty(
                workspace_label=workspace_label,
                error="receipt_read_error",
                receipt_ref=receipt_ref,
            )
        if not isinstance(raw, dict):
            return _empty(
                workspace_label=workspace_label,
                error="receipt_not_object",
                receipt_ref=receipt_ref,
            )

        receipt_hash_expected = str(raw.get("receipt_hash") or "")
        receipt_hash_valid = False
        if receipt_hash_expected:
            receipt_hash_actual = hashlib.sha256(
                _canonical_json({k: v for k, v in raw.items() if k != "receipt_hash"}).encode("utf-8")
            ).hexdigest()
            receipt_hash_valid = receipt_hash_actual == receipt_hash_expected

        report_path = None
        report_value = str(raw.get("report_path") or "").strip()
        if report_value:
            try:
                candidate = Path(report_value).expanduser()
                if candidate.is_absolute():
                    try:
                        candidate.resolve().relative_to(workspace.resolve())
                    except (OSError, RuntimeError, ValueError):
                        candidate = None
                else:
                    candidate = workspace / candidate
                report_path = candidate.resolve() if candidate is not None else None
            except (OSError, RuntimeError):
                report_path = None
        report_ref = _workspace_ref(workspace, report_path)
        report_present = bool(report_path and report_path.is_file())
        report_sha256_valid = False
        report_mtime_valid = False
        if report_present and report_path is not None:
            try:
                report_text = report_path.read_text(encoding="utf-8", errors="replace")
                report_sha256_valid = hashlib.sha256(report_text.encode("utf-8")).hexdigest() == str(
                    raw.get("report_sha256") or ""
                )
                stored_mtime = raw.get("report_mtime_epoch")
                if isinstance(stored_mtime, (int, float)):
                    report_mtime_valid = abs(report_path.stat().st_mtime - float(stored_mtime)) < 1e-6
            except OSError:
                report_present = False

        summary_raw = raw.get("summary") if isinstance(raw.get("summary"), dict) else {}
        scope_raw = raw.get("scope") if isinstance(raw.get("scope"), dict) else {}
        mcp_raw = raw.get("mcp") if isinstance(raw.get("mcp"), dict) else {}
        lanes_raw = raw.get("top_phase_f_lanes") if isinstance(raw.get("top_phase_f_lanes"), list) else []

        top_lanes: list[dict[str, Any]] = []
        for lane in lanes_raw[:limit]:
            if not isinstance(lane, dict):
                continue
            try:
                confidence = float(lane.get("max_confidence", 0) or 0)
            except (TypeError, ValueError):
                confidence = 0.0
            top_lanes.append(
                {
                    "lane_id": _safe_text_item(lane.get("lane_id"), max_chars=120) or "",
                    "attack_class": _safe_text_item(lane.get("attack_class"), max_chars=120) or "",
                    "max_confidence": round(confidence, 6),
                    "severity_guess": _safe_text_item(lane.get("severity_guess"), max_chars=40) or "",
                    "provenance": _safe_text_item(lane.get("provenance"), max_chars=240) or "",
                }
            )

        callables_failed = mcp_raw.get("callables_failed")
        payload = {
            "schema": BRAIN_PRIME_CONTEXT_SCHEMA,
            "kind": "brain_prime_context",
            "workspace": workspace_label,
            "receipt_found": True,
            "receipt_path": receipt_ref,
            "report_path": report_ref,
            "report_present": report_present,
            "generated_at": _safe_text_item(raw.get("generated_at"), max_chars=64) or "",
            "audit_pin": _safe_text_item(raw.get("audit_pin"), max_chars=80) or "",
            "target_repo": _safe_text_item(raw.get("target_repo"), max_chars=160) or "",
            "summary": {
                "functions_extracted": int(summary_raw.get("functions_extracted") or 0),
                "phase_d_files": int(summary_raw.get("phase_d_files") or 0),
                "phase_e_sources": int(summary_raw.get("phase_e_sources") or 0),
                "phase_f_lanes": int(summary_raw.get("phase_f_lanes") or 0),
                "strict_ready": bool(summary_raw.get("strict_ready", False)),
                "top_functions_per_file": int(summary_raw.get("top_functions_per_file") or 0),
                "min_confidence": summary_raw.get("min_confidence", 0),
                "max_files": int(summary_raw.get("max_files") or 0),
            },
            "scope": {
                "language": _safe_text_item(scope_raw.get("language"), max_chars=32) or "",
                "auto_detected": bool(scope_raw.get("auto_detected", False)),
                "candidate_dir_count": len(scope_raw.get("candidate_dirs"))
                if isinstance(scope_raw.get("candidate_dirs"), list)
                else 0,
                "scope_globs_hash": _safe_text_item(raw.get("scope_globs_hash"), max_chars=80) or "",
            },
            "mcp": {
                "skipped": bool(mcp_raw.get("skipped", False)),
                "callables_attempted": int(mcp_raw.get("callables_attempted") or 0),
                "callables_succeeded": int(mcp_raw.get("callables_succeeded") or 0),
                "callables_failed_count": len(callables_failed) if isinstance(callables_failed, list) else 0,
                "duration_seconds": mcp_raw.get("duration_seconds", 0),
                "phase_a_context_pack_id": _safe_text_item(raw.get("context_pack_id"), max_chars=200) or "",
                "phase_a_context_pack_hash": _safe_text_item(raw.get("context_pack_hash"), max_chars=80) or "",
            },
            "integrity": {
                "receipt_schema_valid": raw.get("schema") == "auditooor.brain_prime_receipt.v1",
                "receipt_hash_valid": receipt_hash_valid,
                "report_sha256_valid": report_sha256_valid,
                "report_mtime_valid": report_mtime_valid,
            },
            "dispatch_ready": bool(summary_raw.get("strict_ready", False))
            and receipt_hash_valid
            and report_sha256_valid
            and report_mtime_valid,
            "top_phase_f_lanes": top_lanes,
            "lanes_returned": len(top_lanes),
            "limit": limit,
            "degraded": False,
            "privacy_guards": [
                "no_raw_receipt_body",
                "no_raw_report_body",
                "workspace_relative_refs_only",
                "candidate_dirs_count_only",
            ],
            "source_refs": [
                ref
                for ref in [receipt_ref, report_ref, "tools/brain-prime.py", "docs/BRAIN_PRIMING.md"]
                if ref
            ],
        }
        return _finalize(payload)

    def vault_engage_report_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return a bounded typed context pack from a workspace's engage_report.md.

        Inputs (all optional):
          * ``workspace_path``: absolute path to an audit workspace (e.g.
            ``~/audits/spark``). Defaults to ``~/audits/spark`` when omitted.
          * ``limit``: max detector clusters returned (default 10, max 20).

        Output schema: ``auditooor.vault_engage_report_context.v1``

        Returns:
          * ``workspace_path``: non-absolute workspace label.
          * ``report_path``: workspace source-ref label for engage_report.md (or null when
            not found).
          * ``report_found``: bool.
          * ``total_hits``: integer (0 when report missing or unparseable).
          * ``distinct_detectors``: integer.
          * ``analogical_clusters``: integer.
          * ``severity_summary``: dict with HIGH/MEDIUM/LOW counts.
          * ``actionable_next_steps``: dict with triage/dupe_check/mine counts.
          * ``clusters``: list of cluster dicts, each with
            ``detector_slug``, ``hit_count``, ``hits`` (bounded list), each hit
            having ``severity``, ``file_path``, ``snippet`` (first 200 chars).
          * ``privacy_guards``: list of redacted-field notices.
          * ``context_pack_id`` and ``context_pack_hash``: always present.

        Graceful empty envelope when workspace or engage_report.md is missing.
        """
        limit = min(MAX_ENGAGE_REPORT_CLUSTERS, _clamp_limit(kwargs.get("limit", 10), default=10))
        workspace_path_arg = kwargs.get("workspace_path")

        if workspace_path_arg:
            try:
                workspace = Path(str(workspace_path_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                workspace = None
        else:
            workspace = (Path.home() / "audits" / "spark").resolve()

        _EMPTY_ENVELOPE_KEYS: dict[str, Any] = {
            "schema": ENGAGE_REPORT_CONTEXT_SCHEMA,
            "kind": "engage_report_context",
            "report_found": False,
            "report_path": None,
            "total_hits": 0,
            "distinct_detectors": 0,
            "analogical_clusters": 0,
            "severity_summary": {"HIGH": 0, "MEDIUM": 0, "LOW": 0},
            "actionable_next_steps": {"triage": 0, "dupe_check": 0, "mine": 0},
            "clusters": [],
            "limit": limit,
            "clusters_returned": 0,
            "privacy_guards": [],
        }

        def _make_empty(ws_label: str, error: str | None = None) -> dict[str, Any]:
            payload: dict[str, Any] = {
                **_EMPTY_ENVELOPE_KEYS,
                "workspace_path": ws_label,
            }
            if error:
                payload["error"] = error
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{ENGAGE_REPORT_CONTEXT_SCHEMA}:engage_report:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        ws_label = _engage_report_workspace_label(workspace_path_arg)
        if workspace is None or not workspace.exists() or not workspace.is_dir():
            return _make_empty(ws_label, "workspace_not_found")

        ws_label = _engage_report_workspace_label(workspace.name)

        report_path = workspace / "engage_report.md"
        sidecar_path = workspace / "engage_report.json"
        if (
            (not report_path.exists() or not report_path.is_file())
            and (not sidecar_path.exists() or not sidecar_path.is_file())
        ):
            return _make_empty(ws_label, "engage_report_not_found")

        def _coerce_int(value: object, default: int = 0) -> int:
            try:
                return int(value)  # type: ignore[arg-type]
            except (TypeError, ValueError):
                return default

        def _finalize(payload: dict[str, Any]) -> dict[str, Any]:
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{ENGAGE_REPORT_CONTEXT_SCHEMA}:engage_report:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _parse_sidecar(path: Path) -> dict[str, Any] | None:
            try:
                raw = json.loads(path.read_text(encoding="utf-8", errors="replace"))
            except (OSError, json.JSONDecodeError):
                return None
            if not isinstance(raw, dict):
                return None

            privacy_guards: list[str] = []
            clusters: list[dict[str, Any]] = []
            raw_clusters = raw.get("clusters")
            if isinstance(raw_clusters, list):
                for c in raw_clusters:
                    if len(clusters) >= limit:
                        break
                    if not isinstance(c, dict):
                        continue
                    slug = _safe_text_item(c.get("detector_slug"), max_chars=180)
                    if not slug:
                        continue
                    raw_hits = c.get("hits")
                    hits: list[dict[str, Any]] = []
                    if isinstance(raw_hits, list):
                        for h in raw_hits:
                            if len(hits) >= MAX_ENGAGE_REPORT_CLUSTER_HITS:
                                break
                            if not isinstance(h, dict):
                                continue
                            severity = (_safe_text_item(h.get("severity"), max_chars=16) or "UNKNOWN").upper()
                            file_path_raw = str(h.get("file_path", "") or "")
                            if _has_secret(file_path_raw):
                                privacy_guards.append(f"cluster:{slug}:hit:secret_redacted")
                                continue
                            file_path = _safe_engage_report_hit_path(file_path_raw, workspace)
                            if not file_path:
                                privacy_guards.append(f"cluster:{slug}:hit:path_redacted")
                                continue
                            snippet = _sanitize_engage_report_snippet(h.get("snippet"), workspace)
                            hits.append(
                                {
                                    "severity": severity,
                                    "file_path": file_path,
                                    "snippet": snippet,
                                }
                            )
                    hit_count = _coerce_int(c.get("hit_count"), len(hits))
                    clusters.append(
                        {
                            "detector_slug": slug,
                            "hit_count": hit_count,
                            "hits": hits,
                        }
                    )

            severity_raw = raw.get("severity_summary")
            severity_summary = {"HIGH": 0, "MEDIUM": 0, "LOW": 0}
            if isinstance(severity_raw, dict):
                severity_summary = {
                    "HIGH": _coerce_int(severity_raw.get("HIGH")),
                    "MEDIUM": _coerce_int(severity_raw.get("MEDIUM")),
                    "LOW": _coerce_int(severity_raw.get("LOW")),
                }
            next_steps_raw = raw.get("actionable_next_steps")
            next_steps = {"triage": 0, "dupe_check": 0, "mine": 0}
            if isinstance(next_steps_raw, dict):
                next_steps = {
                    "triage": _coerce_int(next_steps_raw.get("triage")),
                    "dupe_check": _coerce_int(next_steps_raw.get("dupe_check")),
                    "mine": _coerce_int(next_steps_raw.get("mine")),
                }

            return {
                "schema": ENGAGE_REPORT_CONTEXT_SCHEMA,
                "kind": "engage_report_context",
                "workspace_path": ws_label,
                "report_path": "workspace:engage_report.json",
                "report_found": True,
                "total_hits": _coerce_int(raw.get("total_hits")),
                "distinct_detectors": _coerce_int(raw.get("distinct_detectors")),
                "analogical_clusters": _coerce_int(raw.get("analogical_clusters"), len(clusters)),
                "severity_summary": severity_summary,
                "actionable_next_steps": next_steps,
                "clusters": clusters,
                "limit": limit,
                "clusters_returned": len(clusters),
                "privacy_guards": privacy_guards,
            }

        def _parse_markdown(path: Path) -> dict[str, Any] | None:
            try:
                raw_text = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                return None

            _SEVERITY_LINE_RE = re.compile(
                r"Severity:\s*HIGH=(\d+)\s+MEDIUM=(\d+)\s+LOW=(\d+)", re.IGNORECASE
            )
            _DETECTORS_RE = re.compile(
                r"Distinct detectors:\s*(?:\*\*)?(\d+)(?:\*\*)?",
                re.IGNORECASE,
            )
            _CLUSTERS_RE = re.compile(
                r"Analogical clusters:\s*(?:\*\*)?(\d+)(?:\*\*)?",
                re.IGNORECASE,
            )
            _TRIAGE_RE = re.compile(r"Triage.*?:\s*\*\*(\d+)\*\*", re.IGNORECASE)
            _DUPE_RE = re.compile(r"Dupe-check.*?:\s*\*\*(\d+)\*\*", re.IGNORECASE)
            _MINE_RE = re.compile(r"Mine for novelty.*?:\s*\*\*(\d+)\*\*", re.IGNORECASE)
            _TOTAL_HITS_RE = re.compile(r"Total hits:\s*\*\*(\d+)\*\*", re.IGNORECASE)

            def _parse_int(pattern: re.Pattern[str], text: str, default: int = 0) -> int:
                m = pattern.search(text)
                return int(m.group(1)) if m else default

            total_hits = _parse_int(_TOTAL_HITS_RE, raw_text)
            sev_m = _SEVERITY_LINE_RE.search(raw_text)
            severity_summary: dict[str, int] = {"HIGH": 0, "MEDIUM": 0, "LOW": 0}
            if sev_m:
                severity_summary = {
                    "HIGH": int(sev_m.group(1)),
                    "MEDIUM": int(sev_m.group(2)),
                    "LOW": int(sev_m.group(3)),
                }
            distinct_detectors = _parse_int(_DETECTORS_RE, raw_text)
            analogical_clusters = _parse_int(_CLUSTERS_RE, raw_text)
            triage_count = _parse_int(_TRIAGE_RE, raw_text)
            dupe_count = _parse_int(_DUPE_RE, raw_text)
            mine_count = _parse_int(_MINE_RE, raw_text)

            # A cluster block starts with: ### Cluster: `<slug>` (<N> hits)
            # Each hit line:  - **[SEV] `slug`** — `path:line`
            _CLUSTER_HEADER_RE = re.compile(
                r"^###\s+Cluster:\s+`([^`]+)`\s+\((\d+)\s+hits?\)", re.MULTILINE
            )
            _SNIPPET_RE = re.compile(r"snippet:\s+`([^`\n]{1,300})`", re.IGNORECASE)
            _FILE_RE = re.compile(
                r"^\s*-\s+\*\*\[[A-Z]+\]\s+`[^`]+`\*\*\s+[—\-]+\s+`?([^`\n]+)`?",
                re.MULTILINE,
            )

            privacy_guards: list[str] = []
            clusters: list[dict[str, Any]] = []
            cluster_splits = list(_CLUSTER_HEADER_RE.finditer(raw_text))
            for idx, m in enumerate(cluster_splits):
                if len(clusters) >= limit:
                    break
                slug = m.group(1).strip()
                header_hit_count = int(m.group(2))
                block_start = m.end()
                block_end = cluster_splits[idx + 1].start() if idx + 1 < len(cluster_splits) else len(raw_text)
                block = raw_text[block_start:block_end]

                hits: list[dict[str, Any]] = []
                for line_m in _FILE_RE.finditer(block):
                    if len(hits) >= MAX_ENGAGE_REPORT_CLUSTER_HITS:
                        break
                    line_text = line_m.group(0)
                    sev_hit = re.search(r"\[([A-Z]+)\]", line_text)
                    severity_str = sev_hit.group(1) if sev_hit else "UNKNOWN"
                    file_path_raw = line_m.group(1).strip().rstrip("`").strip()
                    if _has_secret(file_path_raw):
                        privacy_guards.append(f"cluster:{slug}:hit:secret_redacted")
                        continue
                    file_path = _safe_engage_report_hit_path(file_path_raw, workspace)
                    if not file_path:
                        privacy_guards.append(f"cluster:{slug}:hit:path_redacted")
                        continue
                    hit_pos = line_m.start()
                    next_lines = block[hit_pos:hit_pos + 400]
                    snip_m = _SNIPPET_RE.search(next_lines)
                    snippet = _sanitize_engage_report_snippet(snip_m.group(1), workspace) if snip_m else ""
                    hits.append({"severity": severity_str, "file_path": file_path, "snippet": snippet})

                clusters.append(
                    {
                        "detector_slug": slug,
                        "hit_count": header_hit_count,
                        "hits": hits,
                    }
                )

            return {
                "schema": ENGAGE_REPORT_CONTEXT_SCHEMA,
                "kind": "engage_report_context",
                "workspace_path": ws_label,
                "report_path": "workspace:engage_report.md",
                "report_found": True,
                "total_hits": total_hits,
                "distinct_detectors": distinct_detectors,
                "analogical_clusters": analogical_clusters,
                "severity_summary": severity_summary,
                "actionable_next_steps": {
                    "triage": triage_count,
                    "dupe_check": dupe_count,
                    "mine": mine_count,
                },
                "clusters": clusters,
                "limit": limit,
                "clusters_returned": len(clusters),
                "privacy_guards": privacy_guards,
            }

        if sidecar_path.exists() and sidecar_path.is_file():
            payload = _parse_sidecar(sidecar_path)
            if payload is not None:
                return _finalize(payload)

        if report_path.exists() and report_path.is_file():
            payload = _parse_markdown(report_path)
            if payload is not None:
                return _finalize(payload)

        return _make_empty(ws_label, "engage_report_read_error")

    def vault_detector_provenance(self, **kwargs: Any) -> dict[str, Any]:
        """Resolve a Go detector pattern slug to its source provenance.

        Inputs:
          * ``pattern_slug`` (required): e.g.
            ``go.spark.coop_exit.coordinator_confirmation_guard_asymmetry``.
          * ``runner_path`` (optional): override the default
            ``tools/go-detector-runner.py``.

        Output schema: ``auditooor.vault_detector_provenance.v1`` — pattern slug,
        callee function name, runner-relative paths, dispatch line, def line, and
        bounded leading docstring. Returns ``error: not_found`` for unknown slugs.
        """
        slug = _safe_text_item(kwargs.get("pattern_slug"), max_chars=200) or ""
        slug = slug.strip()
        if not slug:
            return {"error": "missing_pattern_slug"}
        if not DETECTOR_PATTERN_SLUG_RE.match(slug):
            return {"error": "invalid_pattern_slug", "pattern_slug": slug}

        runner_arg = kwargs.get("runner_path")
        if runner_arg:
            runner_rel = _safe_repo_relpath(runner_arg)
            if runner_rel is None:
                return {"error": "invalid_runner_path"}
            runner_path = self.repo_root / runner_rel
        else:
            runner_rel = "tools/go-detector-runner.py"
            runner_path = self.repo_root / runner_rel

        if not runner_path.exists() or not runner_path.is_file():
            return {"error": "runner_not_found", "runner_path": runner_rel}
        if runner_path.is_symlink():
            return {"error": "runner_is_symlink"}

        try:
            source = runner_path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            return {"error": "runner_read_failed"}

        dispatch_block = _detector_pattern_dispatch_block(source)
        lookup = _detector_pattern_lookup(source, slug)
        if lookup is None:
            return {
                "error": "not_found",
                "pattern_slug": slug,
                "runner_path": runner_rel,
                "dispatch_block_present": dispatch_block is not None,
            }
        callee, dispatch_line = lookup
        def_line = _detector_function_def_line(source, callee)
        docstring = _detector_function_docstring(source, callee)

        # Cross-reference: search go-detector-runner tests for the slug too.
        test_rel = "tools/tests/test_go_detector_runner.py"
        test_path = self.repo_root / test_rel
        test_hits: list[int] = []
        if test_path.exists() and test_path.is_file() and not test_path.is_symlink():
            try:
                test_source = test_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                test_source = ""
            for match in re.finditer(re.escape(slug), test_source):
                test_hits.append(test_source[: match.start()].count("\n") + 1)
                if len(test_hits) >= MAX_PROVENANCE_REFS:
                    break

        # Cross-reference: search docs/next-loop/ for any markdown that mentions slug.
        doc_refs: list[str] = []
        next_loop_dir = self.repo_root / "docs" / "next-loop"
        if next_loop_dir.exists() and next_loop_dir.is_dir():
            for md_file in sorted(next_loop_dir.glob("*.md")):
                if md_file.is_symlink():
                    continue
                try:
                    text = md_file.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                if slug in text:
                    rel = _rel(md_file, self.repo_root)
                    if rel and not _has_forbidden_part(Path(rel)):
                        doc_refs.append(rel)
                if len(doc_refs) >= MAX_PROVENANCE_REFS:
                    break

        source_refs = _unique_bounded(
            [runner_rel, *(test_rel for _ in test_hits if test_hits), *doc_refs],
            MAX_PROVENANCE_REFS,
        )
        base = {
            "schema": DETECTOR_PROVENANCE_SCHEMA,
            "kind": "detector_provenance",
            "pattern_slug": slug,
            "runner_path": runner_rel,
            "callee": callee,
            "dispatch_line": dispatch_line,
            "def_line": def_line,
            "docstring": docstring or "",
            "test_path": test_rel if test_hits else "",
            "test_hit_lines": test_hits,
            "doc_refs": doc_refs,
            "limits": {"max_refs": MAX_PROVENANCE_REFS, "max_docstring_chars": 1200},
            "privacy_guards": {
                "repo_relative_refs_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "no_full_function_body_returned": True,
            },
            "source_refs": source_refs,
            "advisory_boundary": "Detector provenance reflects runner source ground truth; cross-ref refs are best-effort discovery and may include unrelated mentions.",
        }
        base["token_estimate"] = _token_estimate(
            {
                "pattern_slug": slug,
                "callee": callee,
                "docstring": base["docstring"],
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{DETECTOR_PROVENANCE_SCHEMA}:detector_provenance:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_detector_provenance_v2(self, **kwargs: Any) -> dict[str, Any]:
        """Resolve Solidity/Rust detector provenance through the v2 resolver.

        Inputs:
          * ``detector_id`` (required): Solidity detector ARGUMENT, Rust
            runner pattern id, Rust wave2 canonical id, or Rust wave2 raw
            detector id.

        Output schema: ``auditooor.vault_detector_provenance_v2.v1`` wrapping
        the v2 resolver payload. Returns ``error: not_found`` for unknown ids
        and never returns raw function bodies or absolute local paths.
        """
        detector_id = _safe_text_item(kwargs.get("detector_id"), max_chars=240) or ""
        detector_id = detector_id.strip()
        if not detector_id:
            return {"error": "missing_detector_id"}
        if not DETECTOR_PROVENANCE_V2_ID_RE.match(detector_id):
            return {"error": "invalid_detector_id", "detector_id": detector_id}

        def _scrub_local_paths(value: Any) -> Any:
            if isinstance(value, dict):
                return {str(k): _scrub_local_paths(v) for k, v in value.items()}
            if isinstance(value, list):
                return [_scrub_local_paths(v) for v in value[:MAX_PROVENANCE_REFS]]
            if not isinstance(value, str):
                return value
            text = value.replace(str(self.repo_root), "repo_root")
            if _has_secret(text):
                return "[redacted-secret]"
            if text.startswith("repo_root/"):
                return text.removeprefix("repo_root/")
            if _looks_like_private_ref(text):
                return "[redacted-local-path]"
            return text

        resolver = _load_tool_module("detector-provenance-v2")
        if resolver is None or not hasattr(resolver, "resolve"):
            return {
                "schema": DETECTOR_PROVENANCE_V2_SCHEMA,
                "kind": "detector_provenance_v2",
                "error": "resolver_unavailable",
                "detector_id": detector_id,
            }

        try:
            resolved = resolver.resolve(self.repo_root, detector_id)
        except Exception as exc:  # noqa: BLE001
            return {
                "schema": DETECTOR_PROVENANCE_V2_SCHEMA,
                "kind": "detector_provenance_v2",
                "error": "resolver_failed",
                "detector_id": detector_id,
                "message": _safe_text_item(
                    str(_scrub_local_paths(str(exc))), max_chars=200
                ) or "",
            }

        if not isinstance(resolved, dict):
            resolved = {"error": "resolver_invalid_response", "detector_id": detector_id}

        base = _scrub_local_paths(dict(resolved))
        base.pop("context_pack_id", None)
        base.pop("context_pack_hash", None)
        base["resolver_schema"] = _safe_text_item(base.get("schema"), max_chars=120) or ""
        base["schema"] = DETECTOR_PROVENANCE_V2_SCHEMA
        base["kind"] = "detector_provenance_v2"
        base.setdefault("detector_id", detector_id)
        base.setdefault("advisory_boundary", "advisory_only_local_metadata_no_impact_claim")
        base["limits"] = {"max_refs": MAX_PROVENANCE_REFS, "max_detector_id_chars": 240}
        base["privacy_guards"] = {
            "repo_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "no_full_function_body_returned": True,
        }
        base["token_estimate"] = _token_estimate(base)
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{DETECTOR_PROVENANCE_V2_SCHEMA}:detector_provenance_v2:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_detector_action_graph_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return advisory attacker actions and proof obligations for one detector hit.

        This is a bounded MCP wrapper around ``tools/detector-hit-action-graph.py``.
        It turns a detector hit (usually from ``engage_report.json`` produced by
        ``make audit``) into ranked attack-class hypotheses, attacker-action
        graph nodes, chain candidates, and proof obligations. It does not prove
        exploitability, impact, severity, duplicate status, or submission readiness.
        """
        resolver_schema = "auditooor.detector_hit_action_graph.v1"
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace: Path | None = None
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        privacy_guards = {
            "repo_relative_refs_only": True,
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "advisory_only": True,
        }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", DETECTOR_ACTION_GRAPH_CONTEXT_SCHEMA)
            base.setdefault("kind", "detector_action_graph_context")
            base.setdefault("resolver_schema", resolver_schema)
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "advisory_boundary",
                "advisory_action_graph_only_no_exploitability_or_submission_readiness_claim",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{DETECTOR_ACTION_GRAPH_CONTEXT_SCHEMA}:detector_action_graph:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _error(code: str, message: str = "") -> dict[str, Any]:
            base: dict[str, Any] = {
                "error": code,
                "message": _safe_text_item(message, max_chars=240) or "",
                "degraded": True,
                "advisory_only": True,
                "submission_posture": "NOT_SUBMIT_READY",
            }
            return _finalize(base)

        if workspace_arg:
            try:
                workspace = Path(str(workspace_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                return _error("invalid_workspace_path")
            workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
            if not workspace.is_dir():
                return _error("workspace_not_found", workspace_label)

        engage_report_arg = kwargs.get("engage_report_path") or kwargs.get("engage_report") or ""
        engage_report_path: Path | None = None
        if engage_report_arg:
            if workspace is None:
                return _error("workspace_path_required_for_engage_report_path")
            try:
                engage_report_path = Path(str(engage_report_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                return _error("invalid_engage_report_path")
            try:
                engage_report_path.relative_to(workspace)
            except ValueError:
                return _error("engage_report_path_outside_workspace")
            if not engage_report_path.is_file():
                return _error("engage_report_not_found")

        detector_slug = _safe_text_item(kwargs.get("detector_slug"), max_chars=240) or ""
        file_path_arg = str(kwargs.get("file_path") or "").strip()
        if not detector_slug and workspace is None and engage_report_path is None:
            return _error(
                "missing_selector",
                "provide detector_slug, or workspace_path with engage_report.json / hit_index",
            )
        if workspace is None and _looks_like_private_ref(file_path_arg):
            return _error("workspace_path_required_for_private_file_path")

        resolver = _load_tool_module("detector-hit-action-graph")
        if resolver is None or not hasattr(resolver, "build_parser") or not hasattr(resolver, "build_payload"):
            return _error("resolver_unavailable")

        def _cli_text(value: object, max_chars: int = 800) -> str:
            text = re.sub(r"[\x00-\x08\x0b\x0c\x0e-\x1f]", " ", str(value if value is not None else ""))
            text = re.sub(r"\s+", " ", text).strip()
            if _has_secret(text):
                return ""
            return text[:max_chars]

        def _int_arg(value: object, default: int = 0) -> int:
            try:
                return int(value)  # type: ignore[arg-type]
            except (TypeError, ValueError):
                return default

        def _relative_workspace_ref(path: Path) -> str:
            if workspace is None:
                return path.name
            try:
                return path.relative_to(workspace).as_posix()
            except ValueError:
                return path.name

        def _chain_plan_freshness(chain_count: int) -> dict[str, Any]:
            if workspace is None:
                return {
                    "status": "not_checked",
                    "reason": "workspace_path_not_provided",
                    "chain_candidate_count": chain_count,
                    "freshness_basis": "workspace_required",
                    "safe_to_treat_as_current": False,
                }
            chain_path = workspace / "swarm" / "chained_attack_plans.json"
            report_path = engage_report_path if engage_report_path is not None else workspace / "engage_report.json"
            row: dict[str, Any] = {
                "status": "absent",
                "chain_candidate_count": chain_count,
                "chain_plan_ref": _relative_workspace_ref(chain_path),
                "engage_report_ref": _relative_workspace_ref(report_path),
                "freshness_basis": "mtime_vs_engage_report",
                "safe_to_treat_as_current": False,
            }
            if not chain_path.is_file():
                row["reason"] = "chained_attack_plans_json_missing"
                return row
            if not report_path.is_file():
                row["status"] = "not_checked"
                row["reason"] = "engage_report_missing"
                row["freshness_basis"] = "engage_report_required"
                return row
            try:
                chain_mtime = chain_path.stat().st_mtime
                report_mtime = report_path.stat().st_mtime
            except OSError:
                row["status"] = "not_checked"
                row["reason"] = "stat_failed"
                row["freshness_basis"] = "stat_failed"
                return row
            row["chain_plan_mtime_utc"] = _dt.datetime.fromtimestamp(chain_mtime, tz=_dt.timezone.utc).isoformat()
            row["engage_report_mtime_utc"] = _dt.datetime.fromtimestamp(report_mtime, tz=_dt.timezone.utc).isoformat()
            if chain_mtime < report_mtime:
                row["status"] = "stale"
                row["reason"] = "chained_attack_plans_older_than_engage_report"
            else:
                row["status"] = "fresh"
                row["reason"] = "chained_attack_plans_not_older_than_engage_report"
                row["safe_to_treat_as_current"] = True
            return row

        top_n = max(
            1,
            min(MAX_DETECTOR_ACTION_GRAPH_TOP_N, _int_arg(kwargs.get("top_n"), default=3)),
        )
        argv = ["--repo-root", str(self.repo_root), "--top-n", str(top_n)]
        if workspace is not None:
            argv.extend(["--workspace", str(workspace)])
        if engage_report_path is not None:
            argv.extend(["--engage-report", str(engage_report_path)])
        hit_index = max(0, _int_arg(kwargs.get("hit_index"), default=0))
        argv.extend(["--hit-index", str(hit_index)])
        for key, option, max_chars in (
            ("detector_slug", "--detector-slug", 240),
            ("severity", "--severity", 32),
            ("file_path", "--file-path", 300),
            ("function_signature", "--function-signature", 500),
            ("function_name", "--function-name", 200),
            ("language", "--language", 40),
            ("snippet", "--snippet", 800),
            ("context", "--context", 1200),
        ):
            value = _cli_text(kwargs.get(key), max_chars=max_chars)
            if value:
                argv.extend([option, value])

        def _scrub(value: Any) -> Any:
            if isinstance(value, dict):
                return {str(k): _scrub(v) for k, v in value.items()}
            if isinstance(value, list):
                return [_scrub(v) for v in value[:MAX_CONTEXT_ITEMS * 10]]
            if not isinstance(value, str):
                return value
            text = re.sub(r"[\x00-\x08\x0b\x0c\x0e-\x1f]", " ", value)
            text = text.replace(str(self.repo_root), "repo_root")
            if workspace is not None:
                text = text.replace(str(workspace), "workspace")
            if _has_secret(text):
                return "[redacted-secret]"
            if text.startswith("repo_root/"):
                text = text.removeprefix("repo_root/")
            if re.search(r"/(?:Users|private|tmp|var/folders)/", text) or _looks_like_private_ref(text):
                return "[redacted-local-path]"
            return text[:2000] + ("..." if len(text) > 2000 else "")

        try:
            parsed_args = resolver.build_parser().parse_args(argv)
            raw_payload = resolver.build_payload(parsed_args)
        except SystemExit as exc:
            return _error("resolver_input_error", str(exc))
        except Exception as exc:  # noqa: BLE001
            return _error("resolver_failed", str(exc))

        if not isinstance(raw_payload, dict):
            return _error("resolver_invalid_response")

        payload = _scrub(raw_payload)
        ranked_attack_classes = list(payload.get("ranked_attack_classes", []) or [])[:top_n]
        hacker_questions = list(payload.get("hacker_questions", []) or [])[:MAX_CONTEXT_ITEMS]
        chain_candidates = list(payload.get("chain_candidates", []) or [])[:MAX_DETECTOR_ACTION_GRAPH_TOP_N]
        proof_obligations = list(payload.get("proof_obligations", []) or [])[:MAX_CONTEXT_ITEMS]
        raw_action_graph = payload.get("action_graph")
        if isinstance(raw_action_graph, dict):
            action_graph = {
                "nodes": list(raw_action_graph.get("nodes", []) or [])[:MAX_CONTEXT_ITEMS],
                "edges": list(raw_action_graph.get("edges", []) or [])[:MAX_CONTEXT_ITEMS],
            }
        else:
            action_graph = {"nodes": [], "edges": []}
        summary = dict(payload.get("summary", {}) or {})
        summary.update(
            {
                "ranked_attack_class_count": len(ranked_attack_classes),
                "chain_candidate_count": len(chain_candidates),
                "action_node_count": len(action_graph["nodes"]),
                "action_edge_count": len(action_graph["edges"]),
                "hacker_question_count": len(hacker_questions),
                "proof_obligation_count": len(proof_obligations),
            }
        )
        limits = {
            "max_ranked_attack_classes": top_n,
            "max_chain_candidates": MAX_DETECTOR_ACTION_GRAPH_TOP_N,
            "max_action_graph_nodes": MAX_CONTEXT_ITEMS,
            "max_action_graph_edges": MAX_CONTEXT_ITEMS,
            "max_hacker_questions": MAX_CONTEXT_ITEMS,
            "max_proof_obligations": MAX_CONTEXT_ITEMS,
        }
        freshness = {"chained_attack_plans": _chain_plan_freshness(len(chain_candidates))}
        chain_freshness_status = str(freshness["chained_attack_plans"].get("status") or "")
        chain_freshness_safe = bool(freshness["chained_attack_plans"].get("safe_to_treat_as_current"))
        for candidate in chain_candidates:
            if isinstance(candidate, dict):
                candidate["artifact_freshness_status"] = chain_freshness_status
                candidate["derived_from_stale_artifact"] = chain_freshness_status == "stale"
                candidate["safe_to_treat_as_current"] = chain_freshness_safe
        limitations = list(payload.get("limitations", []) or [])
        if chain_candidates and freshness["chained_attack_plans"].get("status") == "stale":
            limitations.append(
                "Stale chain_candidates: attached chain candidates came from a chained_attack_plans.json older than engage_report.json; "
                "rerun make chained-attack-plans or make audit-hacker-logic-bridge before using them as current work."
            )
        source_refs = ["tools/detector-hit-action-graph.py", "tools/attack-class-ranker.py"]
        if workspace is not None:
            if engage_report_path is not None:
                source_refs.append(f"{workspace.name}/{engage_report_path.name}")
            elif (workspace / "engage_report.json").is_file():
                source_refs.append(f"{workspace.name}/engage_report.json")

        base = {
            "schema": DETECTOR_ACTION_GRAPH_CONTEXT_SCHEMA,
            "kind": "detector_action_graph_context",
            "resolver_schema": _safe_text_item(payload.get("schema"), max_chars=120) or resolver_schema,
            "resolver_context_pack_id": payload.get("context_pack_id", ""),
            "resolver_context_pack_hash": payload.get("context_pack_hash", ""),
            "workspace_path": workspace_label,
            "degraded": False,
            "advisory_only": True,
            "claim_scope": payload.get("claim_scope", "attacker_worklist_only"),
            "submission_posture": payload.get("submission_posture", "NOT_SUBMIT_READY"),
            "proof_boundary": payload.get("proof_boundary", ""),
            "hacker_question_schema": payload.get("hacker_question_schema", ""),
            "detector_hit": payload.get("detector_hit", {}),
            "ranked_attack_classes": ranked_attack_classes,
            "hacker_questions": hacker_questions,
            "action_graph": action_graph,
            "chain_candidates": chain_candidates,
            "proof_obligations": proof_obligations,
            "summary": summary,
            "limits": limits,
            "freshness": freshness,
            "limitations": limitations,
            "source_refs": source_refs,
        }
        return _finalize(base)

    def vault_chained_attack_plan_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded advisory context from ``swarm/chained_attack_plans.json``.

        The chained-attack planner is a worklist generator. This MCP context pack
        deliberately preserves that boundary: returned rows are candidate chains
        with open proof obligations, not exploitability, impact, severity, OOS,
        duplicate, or submission-readiness claims.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        max_plans = min(
            MAX_CONTEXT_ITEMS,
            _clamp_limit(kwargs.get("max_plans", kwargs.get("limit")), default=5),
        )
        privacy_guards = {
            "repo_relative_refs_only": True,
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "advisory_only": True,
        }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", CHAINED_ATTACK_PLAN_CONTEXT_SCHEMA)
            base.setdefault("kind", "chained_attack_plan_context")
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("degraded", False)
            base.setdefault("advisory_only", True)
            base.setdefault("submission_posture", "NOT_SUBMIT_READY")
            base.setdefault("plans", [])
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "advisory_boundary",
                "advisory_chain_plan_only_no_exploitability_or_submission_readiness_claim",
            )
            base.setdefault(
                "proof_boundary",
                "candidate chains require runnable PoC evidence, duplicate/OOS review, and pre-submit gates before filing",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{CHAINED_ATTACK_PLAN_CONTEXT_SCHEMA}:chained_attack_plan:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _empty(error: str, *, degraded: bool = True, reason: str = "") -> dict[str, Any]:
            base: dict[str, Any] = {
                "error": error,
                "degraded": degraded,
                "degraded_reason": error if degraded else "",
                "advisory_only": True,
                "submission_posture": "NOT_SUBMIT_READY",
                "plans": [],
                "summary": {
                    "total_plans_available": 0,
                    "plan_count": 0,
                    "plans_returned": 0,
                    "candidate_not_submit_ready_count": 0,
                    "advisory_only_count": 0,
                },
                "limits": {
                    "max_plans": max_plans,
                    "max_primitives_per_plan": 4,
                    "max_chain_steps_per_plan": 5,
                    "max_blockers_per_plan": 6,
                    "max_proof_steps_per_plan": 6,
                    "max_source_refs_per_plan": 8,
                },
                "freshness": {
                    "chained_attack_plans": {
                        "status": "absent" if error == "chained_attack_plans_json_missing" else "not_checked",
                        "reason": reason or error,
                        "safe_to_treat_as_current": False,
                    }
                },
                "source_refs": ["tools/chained-attack-planner.py"],
            }
            return _finalize(base)

        if not workspace_arg:
            return _empty("workspace_path_required", reason="workspace_path_required")
        try:
            workspace = Path(str(workspace_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return _empty("invalid_workspace_path")
        workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
        if not workspace.is_dir():
            return _empty("workspace_not_found")

        def _workspace_ref(path: Path) -> str:
            try:
                return path.relative_to(workspace).as_posix()
            except ValueError:
                return path.name

        plan_arg = kwargs.get("chain_plan_path") or kwargs.get("plan_path") or ""
        if plan_arg:
            try:
                raw_plan_path = Path(str(plan_arg)).expanduser()
                plan_path = (raw_plan_path if raw_plan_path.is_absolute() else workspace / raw_plan_path).resolve()
            except (OSError, RuntimeError):
                return _empty("invalid_chain_plan_path")
            try:
                plan_path.relative_to(workspace)
            except ValueError:
                return _empty("chain_plan_path_outside_workspace")
        else:
            plan_path = workspace / "swarm" / "chained_attack_plans.json"

        def _scrub_text(value: object, max_chars: int = 360) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 for ch in text):
                return ""
            text = text.replace(str(workspace), "workspace")
            text = text.replace(str(self.repo_root), "repo_root")
            if _has_secret(text):
                return "[redacted-secret]"
            text = re.sub(
                r"(?:/Users|/home|/tmp|/private|/var)(?:/[^\s,;:'\")\]}]+)+",
                "[redacted-local-path]",
                text,
            )
            text = re.sub(r"\s+", " ", text).strip()
            if len(text) > max_chars:
                return text[:max_chars].rstrip() + "..."
            return text

        def _scrub_list(values: object, limit: int, max_chars: int = 240) -> list[str]:
            if not isinstance(values, list):
                return []
            rows: list[str] = []
            for value in values:
                item = _scrub_text(value, max_chars=max_chars)
                if item:
                    rows.append(item)
                if len(rows) >= limit:
                    break
            return rows

        def _declared_source_paths(payload: dict[str, Any]) -> list[Path]:
            sources = payload.get("sources")
            if not isinstance(sources, dict):
                return []
            rows: list[Path] = []
            for value in sources.values():
                if not isinstance(value, str) or not value.strip():
                    continue
                try:
                    candidate = Path(value).expanduser()
                    candidate = (candidate if candidate.is_absolute() else workspace / candidate).resolve()
                    candidate.relative_to(workspace)
                except (OSError, RuntimeError, ValueError):
                    continue
                if candidate != plan_path and candidate not in rows:
                    rows.append(candidate)
            return rows[:MAX_CONTEXT_ITEMS]

        def _mtime_utc(path: Path) -> str:
            return _dt.datetime.fromtimestamp(path.stat().st_mtime, tz=_dt.timezone.utc).isoformat()

        def _freshness(payload: dict[str, Any], total_plans: int) -> dict[str, Any]:
            row: dict[str, Any] = {
                "status": "not_checked",
                "reason": "declared_source_artifacts_missing",
                "chain_candidate_count": total_plans,
                "chain_plan_ref": _workspace_ref(plan_path),
                "freshness_basis": "declared_source_artifact_mtime",
                "safe_to_treat_as_current": False,
            }
            try:
                plan_mtime = plan_path.stat().st_mtime
                row["chain_plan_mtime_utc"] = _dt.datetime.fromtimestamp(
                    plan_mtime,
                    tz=_dt.timezone.utc,
                ).isoformat()
            except OSError:
                row["status"] = "absent"
                row["reason"] = "chained_attack_plans_json_missing"
                row["freshness_basis"] = "plan_file_missing"
                return row

            source_paths = _declared_source_paths(payload)
            if not source_paths:
                row["freshness_basis"] = "declared_sources_unavailable"
                return row

            rows: list[dict[str, Any]] = []
            missing = 0
            newer = 0
            for source_path in source_paths:
                source_row: dict[str, Any] = {"ref": _workspace_ref(source_path)}
                if not source_path.exists():
                    source_row["exists"] = False
                    missing += 1
                else:
                    source_row["exists"] = True
                    try:
                        source_mtime = source_path.stat().st_mtime
                        source_row["mtime_utc"] = _mtime_utc(source_path)
                        if source_mtime > plan_mtime:
                            newer += 1
                    except OSError:
                        source_row["exists"] = False
                        missing += 1
                rows.append(source_row)
            row["declared_sources"] = rows
            if missing:
                row["reason"] = "declared_source_artifact_missing"
                return row
            if newer:
                row["status"] = "stale"
                row["reason"] = "declared_source_artifact_newer_than_plan"
                row["safe_to_treat_as_current"] = False
                return row
            row["status"] = "fresh"
            row["reason"] = "plan_not_older_than_declared_source_artifacts"
            row["safe_to_treat_as_current"] = True
            return row

        def _bounded_primitives(values: object) -> list[dict[str, Any]]:
            if not isinstance(values, list):
                return []
            rows: list[dict[str, Any]] = []
            for raw in values:
                if not isinstance(raw, dict):
                    continue
                item = {
                    "primitive_id": _scrub_text(raw.get("primitive_id"), max_chars=120),
                    "source_kind": _scrub_text(raw.get("source_kind"), max_chars=80),
                    "title": _scrub_text(raw.get("title"), max_chars=180),
                    "source_refs": _scrub_list(raw.get("source_refs"), 4, max_chars=180),
                }
                rows.append({key: value for key, value in item.items() if value not in ("", [])})
                if len(rows) >= 4:
                    break
            return rows

        def _bounded_chain_steps(values: object) -> list[dict[str, Any]]:
            if not isinstance(values, list):
                return []
            rows: list[dict[str, Any]] = []
            for raw in values:
                if not isinstance(raw, dict):
                    continue
                item = {
                    "step_id": _scrub_text(raw.get("step_id"), max_chars=80),
                    "source_kind": _scrub_text(raw.get("source_kind"), max_chars=80),
                    "title": _scrub_text(raw.get("title"), max_chars=160),
                    "summary": _scrub_text(raw.get("summary"), max_chars=240),
                    "advisory_only": True,
                    "source_refs": _scrub_list(raw.get("source_refs"), 4, max_chars=180),
                }
                rows.append({key: value for key, value in item.items() if value not in ("", [])})
                if len(rows) >= 5:
                    break
            return rows

        def _guard_statuses(value: object) -> list[str]:
            if not isinstance(value, dict):
                return []
            return _scrub_list(value.get("statuses"), 4, max_chars=80)

        def _plan_row(raw: dict[str, Any], safe_to_treat_as_current: bool) -> dict[str, Any]:
            blockers = _scrub_list(raw.get("blockers") or raw.get("kill_conditions"), 6, max_chars=220)
            proof_steps = _scrub_list(raw.get("proof_steps"), 6, max_chars=220)
            source_refs = _scrub_list(raw.get("source_refs"), 8, max_chars=180)
            shared_evidence = _scrub_list(raw.get("shared_evidence"), 6, max_chars=200)
            row: dict[str, Any] = {
                "chain_id": _scrub_text(raw.get("chain_id"), max_chars=80),
                "status": "candidate_not_submit_ready",
                "advisory_only": True,
                "candidate_not_submit_ready": True,
                "does_not_claim_exploitability": True,
                "causal_hypothesis_only": True,
                "safe_to_treat_as_current": safe_to_treat_as_current,
                "causal_evidence_level": _scrub_text(raw.get("causal_evidence_level"), max_chars=120),
                "metadata_overlap_only": bool(raw.get("metadata_overlap_only")),
                "title": _scrub_text(raw.get("title"), max_chars=160),
                "composition_rationale": _scrub_text(raw.get("composition_rationale"), max_chars=320),
                "material_distinction_required": _scrub_text(
                    raw.get("material_distinction_required"),
                    max_chars=260,
                ),
                "primitives": _bounded_primitives(raw.get("primitives")),
                "chain_steps": _bounded_chain_steps(raw.get("chain_steps")),
                "proof_steps": proof_steps,
                "proof_obligations": [
                    {"status": "open", "description": proof_step}
                    for proof_step in proof_steps
                ],
                "shared_evidence": shared_evidence,
                "duplicate_guard": {"statuses": _guard_statuses(raw.get("duplicate_guard")) or ["manual_review_required"]},
                "oos_guard": {"statuses": _guard_statuses(raw.get("oos_guard")) or ["manual_review_required"]},
                "blockers": blockers,
                "escalation_result": _scrub_text(raw.get("escalation_result"), max_chars=220),
                "recommended_next_step": _scrub_text(raw.get("recommended_next_step"), max_chars=220),
                "source_refs": source_refs,
            }
            score = raw.get("score")
            if isinstance(score, (int, float)):
                row["score"] = score
            omitted = {
                "source_refs": max(0, len(raw.get("source_refs", [])) - len(source_refs))
                if isinstance(raw.get("source_refs"), list)
                else 0,
                "proof_steps": max(0, len(raw.get("proof_steps", [])) - len(proof_steps))
                if isinstance(raw.get("proof_steps"), list)
                else 0,
                "blockers": max(0, len((raw.get("blockers") or raw.get("kill_conditions") or [])) - len(blockers))
                if isinstance(raw.get("blockers") or raw.get("kill_conditions"), list)
                else 0,
            }
            if any(omitted.values()):
                row["omitted_counts"] = omitted
            return {key: value for key, value in row.items() if value not in ("", [], {})}

        if not plan_path.is_file():
            return _empty(
                "chained_attack_plans_json_missing",
                reason="swarm/chained_attack_plans.json not found",
            )
        try:
            payload = json.loads(plan_path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            return _empty("chained_attack_plans_json_invalid")
        except OSError:
            return _empty("chained_attack_plans_json_unreadable")
        if not isinstance(payload, dict):
            return _empty("chained_attack_plans_json_invalid_schema")
        raw_plans = payload.get("plans")
        if not isinstance(raw_plans, list):
            return _empty("chained_attack_plans_json_missing_plans")

        freshness = {"chained_attack_plans": _freshness(payload, len(raw_plans))}
        safe_to_treat_as_current = bool(freshness["chained_attack_plans"].get("safe_to_treat_as_current"))
        plans = [
            _plan_row(raw, safe_to_treat_as_current)
            for raw in raw_plans[:max_plans]
            if isinstance(raw, dict)
        ]
        blocker_count = sum(len(plan.get("blockers", [])) for plan in plans if isinstance(plan.get("blockers"), list))
        summary = {
            "source_schema_version": _scrub_text(payload.get("schema_version"), max_chars=120),
            "total_plans_available": len(raw_plans),
            "plan_count": len(plans),
            "plans_returned": len(plans),
            "candidate_not_submit_ready_count": len(plans),
            "advisory_only_count": len(plans),
            "unresolved_blocker_count": blocker_count,
            "freshness_status": freshness["chained_attack_plans"].get("status", "not_checked"),
        }
        limitations = [
            "Chained attack plans are advisory hypotheses; they do not prove exploitability, impact, severity, duplicate status, OOS status, or submission readiness.",
            "Every returned proof obligation remains open until a runnable PoC and pre-submit evidence close it.",
        ]
        if not safe_to_treat_as_current:
            limitations.append(
                "Freshness is not fully current; rerun make audit, make hacker-brief, and make chained-attack-plans before treating this as the latest worklist."
            )

        base = {
            "schema": CHAINED_ATTACK_PLAN_CONTEXT_SCHEMA,
            "kind": "chained_attack_plan_context",
            "workspace_path": workspace_label,
            "plan_ref": _workspace_ref(plan_path),
            "plan_schema": _scrub_text(payload.get("schema_version"), max_chars=120),
            "degraded": False,
            "advisory_only": True,
            "claim_scope": "candidate_chain_worklist_only",
            "submission_posture": "NOT_SUBMIT_READY",
            "plans": plans,
            "summary": summary,
            "limits": {
                "max_plans": max_plans,
                "max_primitives_per_plan": 4,
                "max_chain_steps_per_plan": 5,
                "max_blockers_per_plan": 6,
                "max_proof_steps_per_plan": 6,
                "max_source_refs_per_plan": 8,
                "max_shared_evidence_per_plan": 6,
            },
            "freshness": freshness,
            "limitations": limitations,
            "source_refs": ["tools/chained-attack-planner.py", _workspace_ref(plan_path)],
        }

        # r36-rebuttal: lane LIFT-28-PER-FUNCTION-CAPABILITY declared in .auditooor/agent_pathspec.json
        # LIFT-28 (2026-05-26): per-contract / per-function plan filtering.
        # ADDITIVE - default behavior preserved when both args absent.
        lift28_contract = str(kwargs.get("target_contract_path") or "").strip()
        lift28_function = str(kwargs.get("target_function_name") or "").strip()
        lift28_kind = str(kwargs.get("contract_kind_hint") or "").strip()
        if lift28_contract or lift28_function or lift28_kind:
            haystack_needle = (
                f"{lift28_contract} {lift28_function} {lift28_kind}"
            ).lower()
            keep_plans: list[dict[str, Any]] = []
            for plan in plans:
                if not isinstance(plan, dict):
                    continue
                # Soft per-function filter: a plan whose title / primitives
                # / chain_steps / source_refs mentions the contract path,
                # function name, or contract kind is kept; legacy plans
                # without any of those signals fall through.
                plan_blob_parts: list[str] = []
                for k in ("title", "kind", "summary"):
                    v = plan.get(k)
                    if isinstance(v, str) and v:
                        plan_blob_parts.append(v)
                for k in ("primitives", "chain_steps", "source_refs",
                          "blockers", "proof_steps"):
                    v = plan.get(k)
                    if isinstance(v, list):
                        for item in v:
                            if isinstance(item, str):
                                plan_blob_parts.append(item)
                            elif isinstance(item, dict):
                                for vv in item.values():
                                    if isinstance(vv, str):
                                        plan_blob_parts.append(vv)
                plan_blob = " ".join(plan_blob_parts).lower()
                if not plan_blob:
                    keep_plans.append(plan)
                    continue
                hit = False
                if lift28_contract and lift28_contract.lower() in plan_blob:
                    hit = True
                if not hit and lift28_function and lift28_function.lower() in plan_blob:
                    hit = True
                if not hit and lift28_kind and lift28_kind.lower() in plan_blob:
                    hit = True
                if hit:
                    keep_plans.append(plan)
            base["plans"] = keep_plans
            base["summary"]["plans_returned"] = len(keep_plans)
            base["summary"]["plan_count"] = len(keep_plans)
            base["summary"]["candidate_not_submit_ready_count"] = len(keep_plans)
            base["summary"]["advisory_only_count"] = len(keep_plans)
            base["summary"]["lift28_filter_applied"] = {
                "target_contract_path": lift28_contract or None,
                "target_function_name": lift28_function or None,
                "contract_kind_hint": lift28_kind or None,
            }

        # LIFT-25 Phase 3.3 closure (2026-05-26): wire the
        # `seed_from_global_templates` kwarg that LIFT-21 declared but
        # silently discarded. When True, augment the response with
        # `global_template_seeds` (rows of GCT-* templates whose
        # member_invariant_ids intersect the workspace's broken-invariant
        # set) and a `global_template_seeds_summary` aggregate row. When
        # False or absent (default), response shape is unchanged.
        # r36-rebuttal: lane LIFT-25-PHASE-3-3-CLOSURE registered via
        # tools/agent-pathspec-register.py.
        if bool(kwargs.get("seed_from_global_templates")):
            seeds_payload = self._compute_global_template_seeds(
                workspace=workspace,
                workspace_label=workspace_label,
                max_seeds=max_plans,
                kwargs=kwargs,
            )
            base["global_template_seeds"] = seeds_payload["seeds"]
            base["global_template_seeds_summary"] = seeds_payload["summary"]
            if seeds_payload.get("degraded_reason"):
                base["global_template_seeds_summary"][
                    "degraded_reason"
                ] = seeds_payload["degraded_reason"]
            extra_source = seeds_payload.get("templates_path_ref")
            if extra_source and extra_source not in base["source_refs"]:
                base["source_refs"] = list(base["source_refs"]) + [
                    extra_source,
                    "tools/lib/global_chain_templates_seed.py",
                ]
        return _finalize(base)

    def _compute_global_template_seeds(
        self,
        *,
        workspace: Path,
        workspace_label: str,
        max_seeds: int,
        kwargs: dict[str, Any],
    ) -> dict[str, Any]:
        """LIFT-25 Phase 3.3 helper. Compute GCT-* seed rows whose
        member_invariant_ids intersect the workspace's broken-invariant
        set.

        Source order for broken-invariant resolution:
          1. Explicit ``broken_invariant_ids`` kwarg (list[str]).
          2. ``tools/lib/global_chain_templates_seed.load_workspace_broken_invariants``
             (which itself reads invariant_ledger.json, semantic_predicate_gate.json,
             or falls back to a regex sweep of ``<ws>/.auditooor/``).

        Templates JSONL path resolution:
          1. Explicit ``templates_jsonl_path`` kwarg.
          2. ``<repo_root>/audit/corpus_tags/derived/global_chain_templates.jsonl``.

        Returns ``{"seeds": list[dict], "summary": dict,
        "templates_path_ref": str|None, "degraded_reason": str|None}``.
        Returns an empty seed list with a degraded reason on missing
        templates file or missing broken-invariant set; never raises.
        """
        empty_summary = {
            "total_seeds_matched": 0,
            "max_density": 0.0,
            "avg_density": 0.0,
            "evidence_incidents_count": 0,
            "broken_invariant_id_count": 0,
            "broken_invariant_source": "none",
            "templates_scanned": 0,
        }

        # --- broken_invariant_ids resolution ---
        explicit_ids = kwargs.get("broken_invariant_ids")
        broken_ids: list[str] = []
        broken_source = "none"
        if isinstance(explicit_ids, (list, tuple, set)):
            broken_ids = sorted({
                str(x) for x in explicit_ids
                if isinstance(x, str) and x.strip()
            })
            if broken_ids:
                broken_source = "explicit_kwarg"
        if not broken_ids:
            try:
                import importlib.util as _ilu
                seed_mod_path = (
                    self.repo_root / "tools" / "lib"
                    / "global_chain_templates_seed.py"
                )
                spec = _ilu.spec_from_file_location(
                    "_lift25_global_chain_templates_seed",
                    seed_mod_path,
                )
                if spec is not None and spec.loader is not None:
                    seed_mod = _ilu.module_from_spec(spec)
                    spec.loader.exec_module(seed_mod)
                    res = seed_mod.load_workspace_broken_invariants(workspace)
                    broken_ids = sorted({
                        str(x) for x in res.get("invariant_ids", set())
                        if isinstance(x, str) and x.strip()
                    })
                    broken_source = str(res.get("source") or "none")
            except Exception:  # noqa: BLE001 - degrade gracefully
                broken_ids = []
                broken_source = "none"

        broken_set = set(broken_ids)

        # --- templates jsonl path ---
        templates_path_arg = kwargs.get("templates_jsonl_path") or ""
        if templates_path_arg:
            try:
                templates_path = Path(
                    str(templates_path_arg)
                ).expanduser().resolve()
            except (OSError, RuntimeError, ValueError):
                templates_path = (
                    self.repo_root
                    / "audit" / "corpus_tags" / "derived"
                    / "global_chain_templates.jsonl"
                )
        else:
            templates_path = (
                self.repo_root
                / "audit" / "corpus_tags" / "derived"
                / "global_chain_templates.jsonl"
            )

        templates_path_ref = self._safe_local_path_label(templates_path)

        if not templates_path.is_file():
            summary = dict(empty_summary)
            summary["broken_invariant_id_count"] = len(broken_ids)
            summary["broken_invariant_source"] = broken_source
            return {
                "seeds": [],
                "summary": summary,
                "templates_path_ref": templates_path_ref,
                "degraded_reason": "global_chain_templates_jsonl_missing",
            }

        if not broken_set:
            summary = dict(empty_summary)
            summary["broken_invariant_id_count"] = 0
            summary["broken_invariant_source"] = broken_source
            return {
                "seeds": [],
                "summary": summary,
                "templates_path_ref": templates_path_ref,
                "degraded_reason": "broken_invariant_set_empty",
            }

        # --- scan jsonl + collect matches ---
        candidates: list[dict[str, Any]] = []
        total_scanned = 0
        try:
            with templates_path.open("r", encoding="utf-8") as fh:
                for line in fh:
                    line = line.strip()
                    if not line:
                        continue
                    total_scanned += 1
                    try:
                        rec = json.loads(line)
                    except Exception:  # noqa: BLE001 - skip malformed
                        continue
                    if not isinstance(rec, dict):
                        continue
                    member_raw = rec.get("member_invariant_ids") or []
                    if not isinstance(member_raw, list):
                        continue
                    member_ids = sorted({
                        str(m) for m in member_raw if isinstance(m, str)
                    })
                    if not member_ids:
                        continue
                    tuple_size_raw = rec.get("tuple_size")
                    try:
                        tuple_size = int(
                            tuple_size_raw
                            if tuple_size_raw is not None
                            else len(member_ids)
                        )
                    except (TypeError, ValueError):
                        tuple_size = len(member_ids)
                    if tuple_size < 1:
                        tuple_size = 1
                    matched = sorted(set(member_ids) & broken_set)
                    if not matched:
                        continue
                    density = len(matched) / float(tuple_size)
                    candidates.append({
                        "chain_template_id": str(
                            rec.get("chain_template_id") or ""
                        ),
                        "member_invariant_ids": member_ids,
                        "matched_invariant_ids": matched,
                        "match_density": density,
                        "tuple_size": tuple_size,
                        "evidence_incidents": [
                            str(e)
                            for e in (rec.get("evidence_incidents") or [])
                            if isinstance(e, str)
                        ][:8],
                        "composition_rationale": str(
                            rec.get("composition_rationale") or ""
                        )[:480],
                        "verification_tier": str(
                            rec.get("verification_tier") or ""
                        ),
                        "advisory_only": True,
                        "submission_posture": "NOT_SUBMIT_READY",
                    })
        except Exception as exc:  # noqa: BLE001 - bounded I/O
            summary = dict(empty_summary)
            summary["broken_invariant_id_count"] = len(broken_ids)
            summary["broken_invariant_source"] = broken_source
            summary["templates_scanned"] = total_scanned
            return {
                "seeds": [],
                "summary": summary,
                "templates_path_ref": templates_path_ref,
                "degraded_reason": f"templates_scan_error: {exc}",
            }

        # --- sort + cap ---
        candidates.sort(
            key=lambda r: (
                -r["match_density"],
                -r["tuple_size"],
                r["chain_template_id"],
            )
        )
        returned = candidates[:max_seeds]

        densities = [c["match_density"] for c in candidates]
        evidence_count = sum(
            len(c.get("evidence_incidents") or []) for c in returned
        )
        summary = {
            "total_seeds_matched": len(candidates),
            "total_seeds_returned": len(returned),
            "max_density": max(densities) if densities else 0.0,
            "avg_density": (
                sum(densities) / len(densities) if densities else 0.0
            ),
            "evidence_incidents_count": evidence_count,
            "broken_invariant_id_count": len(broken_ids),
            "broken_invariant_source": broken_source,
            "templates_scanned": total_scanned,
        }
        return {
            "seeds": returned,
            "summary": summary,
            "templates_path_ref": templates_path_ref,
            "degraded_reason": None,
        }

    def vault_high_impact_execution_bridge_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded advisory context from ``high_impact_execution_bridge.json``.

        The high-impact execution bridge is an execution-readiness worklist. This
        context pack reads the existing artifact only; it does not run scaffold,
        compile, or PoC-record commands, and it never promotes scaffold readiness
        into exploit proof or submission readiness.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        row_limit = min(
            MAX_HIGH_IMPACT_BRIDGE_ROWS,
            _clamp_limit(kwargs.get("limit"), default=8),
        )
        command_limit = MAX_HIGH_IMPACT_BRIDGE_COMMANDS
        row_id_filter = str(kwargs.get("row_id") or "").strip()
        status_filter = str(kwargs.get("status") or "").strip().lower().replace("-", "_").replace(" ", "_")
        runnable_only = bool(kwargs.get("runnable_only"))
        privacy_guards = {
            "repo_relative_refs_only": True,
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "raw_harness_logs_not_returned": True,
            "commands_are_advisory_not_executed": True,
            "advisory_only": True,
        }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", HIGH_IMPACT_EXECUTION_BRIDGE_CONTEXT_SCHEMA)
            base.setdefault("kind", "high_impact_execution_bridge_context")
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("degraded", False)
            base.setdefault("advisory_only", True)
            base.setdefault("claim_scope", "execution_readiness_only")
            base.setdefault("submission_posture", "NOT_SUBMIT_READY")
            base.setdefault("promotion_allowed", False)
            base.setdefault("dispatch_ready", False)
            base.setdefault("rows", [])
            base.setdefault("runnable_rows", [])
            base.setdefault("blocked_rows", [])
            base.setdefault("queue_next_commands", [])
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "advisory_boundary",
                "execution_readiness_only_not_exploit_proof_or_submission_readiness",
            )
            base.setdefault(
                "proof_boundary",
                "Bridge rows are scaffold readiness only; a separate poc-execution-record with RESULT=proved and IMPACT=exploit_impact is required before impact claims.",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{HIGH_IMPACT_EXECUTION_BRIDGE_CONTEXT_SCHEMA}:high_impact_execution_bridge:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _limits() -> dict[str, int]:
            return {
                "max_rows": row_limit,
                "max_commands": command_limit,
                "max_refs": MAX_HIGH_IMPACT_BRIDGE_REFS,
                "max_command_chars": MAX_HIGH_IMPACT_BRIDGE_COMMAND_CHARS,
            }

        def _empty(error: str, *, degraded: bool = True, reason: str = "") -> dict[str, Any]:
            return _finalize(
                {
                    "error": error,
                    "degraded": degraded,
                    "degraded_reason": error if degraded else "",
                    "bridge_ref": ".auditooor/high_impact_execution_bridge.json",
                    "source_schema_version": "",
                    "summary": {
                        "high_impact_missing": 0,
                        "processed_rows": 0,
                        "total_rows_available": 0,
                        "rows_matched": 0,
                        "rows_returned": 0,
                        "runnable_harness_rows": 0,
                        "blocked_missing_impact_contract": 0,
                        "blocked_other": 0,
                        "queue_commands_returned": 0,
                    },
                    "limits": _limits(),
                    "freshness": {
                        "bridge_report": {
                            "status": "absent" if error == "high_impact_execution_bridge_json_missing" else "not_checked",
                            "reason": reason or error,
                            "safe_to_treat_as_current": False,
                        }
                    },
                    "filters": {
                        "row_id": row_id_filter,
                        "status": status_filter,
                        "runnable_only": runnable_only,
                    },
                    "source_refs": ["tools/high-impact-execution-bridge.py"],
                }
            )

        if not workspace_arg:
            return _empty("workspace_path_required", reason="workspace_path_required")
        try:
            workspace = Path(str(workspace_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return _empty("invalid_workspace_path")
        workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
        if not workspace.is_dir():
            return _empty("workspace_not_found")

        bridge_arg = kwargs.get("bridge_path") or ""
        if bridge_arg:
            try:
                raw_bridge_path = Path(str(bridge_arg)).expanduser()
                bridge_path = (raw_bridge_path if raw_bridge_path.is_absolute() else workspace / raw_bridge_path).resolve()
            except (OSError, RuntimeError):
                return _empty("invalid_bridge_path")
            try:
                bridge_path.relative_to(workspace)
            except ValueError:
                return _empty("bridge_path_outside_workspace")
        else:
            bridge_path = workspace / ".auditooor" / "high_impact_execution_bridge.json"

        def _workspace_ref(value: object) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 or ch in "`" for ch in text) or _has_secret(text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            if text.startswith("<workspace>/"):
                rel = text.removeprefix("<workspace>/")
                safe = _safe_workspace_relpath(rel)
                return safe or ""
            try:
                path = Path(text).expanduser()
                if path.is_absolute():
                    resolved = path.resolve()
                    try:
                        return resolved.relative_to(workspace).as_posix()
                    except ValueError:
                        return "[redacted-local-path]"
            except (OSError, RuntimeError):
                return ""
            safe = _safe_workspace_relpath(text)
            return safe or ""

        def _scrub_text(value: object, max_chars: int = 360) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 for ch in text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            text = text.replace(str(self.repo_root), "repo_root")
            text = re.sub(
                r"(?:/Users|/home|/tmp|/private|/var)(?:/[^\s,;:'\")\]}]+)+",
                "[redacted-local-path]",
                text,
            )
            if _has_secret(text):
                return "[redacted-secret]"
            text = re.sub(r"\s+", " ", text).strip()
            if len(text) > max_chars:
                return text[:max_chars].rstrip() + "..."
            return text

        def _command(value: object) -> str:
            return _scrub_text(value, max_chars=MAX_HIGH_IMPACT_BRIDGE_COMMAND_CHARS)

        def _status(value: object) -> str:
            return str(value if value is not None else "").strip().lower().replace("-", "_").replace(" ", "_")

        def _bounded_commands(values: list[str]) -> list[str]:
            rows: list[str] = []
            for value in values:
                item = _command(value)
                if item and item not in rows:
                    rows.append(item)
                if len(rows) >= command_limit:
                    break
            return rows

        def _row(raw: dict[str, Any]) -> dict[str, Any]:
            row: dict[str, Any] = {
                "row_id": _scrub_text(raw.get("row_id"), max_chars=120),
                "queue_item_id": _scrub_text(raw.get("queue_item_id"), max_chars=120),
                "harness_family": _scrub_text(raw.get("harness_family"), max_chars=120),
                "severity": _scrub_text(raw.get("severity"), max_chars=40),
                "invariant_family": _scrub_text(raw.get("invariant_family"), max_chars=160),
                "impact_contract_status": _scrub_text(raw.get("impact_contract_status"), max_chars=120),
                "bridge_status": _scrub_text(raw.get("bridge_status"), max_chars=120),
                "runnable_harness": bool(raw.get("runnable_harness")),
                "attempt_status": _scrub_text(raw.get("attempt_status"), max_chars=120),
                "compile_command_present": bool(str(raw.get("compile_command") or "").strip()),
                "attempt_manifest": _workspace_ref(raw.get("attempt_manifest")),
                "scaffold_dir": _workspace_ref(raw.get("scaffold_dir")),
                "handoff_brief": _workspace_ref(raw.get("handoff_brief")),
                "impact_contract_skeleton_path": _workspace_ref(raw.get("impact_contract_skeleton_path")),
                "proof_boundary": _scrub_text(raw.get("proof_boundary"), max_chars=240),
                "advisory_only": True,
                "submission_posture": "NOT_SUBMIT_READY",
                "promotion_allowed": False,
            }
            next_commands = _bounded_commands(
                [
                    str(raw.get("poc_execution_record_command") or ""),
                    str(raw.get("impact_contract_command") or ""),
                    str(raw.get("impact_contract_skeleton_command") or ""),
                ]
            )
            if next_commands:
                row["next_commands"] = next_commands
            if raw.get("runnable_harness") and raw.get("poc_execution_record_command"):
                row["poc_execution_record_command"] = next_commands[0] if next_commands else ""
            if raw.get("impact_contract_command"):
                row["impact_contract_command"] = _command(raw.get("impact_contract_command"))
            if raw.get("impact_contract_skeleton_command"):
                row["impact_contract_skeleton_command"] = _command(raw.get("impact_contract_skeleton_command"))
            return {key: value for key, value in row.items() if value not in ("", [], None)}

        def _matches(row: dict[str, Any]) -> bool:
            if row_id_filter and row.get("row_id") != row_id_filter:
                return False
            if runnable_only and not row.get("runnable_harness"):
                return False
            if status_filter:
                statuses = {
                    _status(row.get("bridge_status")),
                    _status(row.get("attempt_status")),
                    _status(row.get("impact_contract_status")),
                }
                if status_filter not in statuses:
                    return False
            return True

        if not bridge_path.is_file():
            return _empty(
                "high_impact_execution_bridge_json_missing",
                reason=".auditooor/high_impact_execution_bridge.json not found",
            )
        try:
            payload = json.loads(bridge_path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            return _empty("high_impact_execution_bridge_json_invalid")
        except OSError:
            return _empty("high_impact_execution_bridge_json_unreadable")
        if not isinstance(payload, dict):
            return _empty("high_impact_execution_bridge_json_invalid_schema")

        declared_workspace = str(payload.get("workspace") or "").strip()
        workspace_match = "not_declared"
        if declared_workspace and declared_workspace not in {"<workspace>", "workspace"}:
            try:
                declared_path = Path(declared_workspace).expanduser().resolve()
                workspace_match = "matched" if declared_path == workspace else "mismatched"
            except (OSError, RuntimeError):
                workspace_match = "unresolved"
            if workspace_match == "mismatched":
                return _empty(
                    "high_impact_execution_bridge_workspace_mismatch",
                    reason="bridge artifact declares a different workspace",
                )

        raw_rows = payload.get("rows")
        if not isinstance(raw_rows, list):
            return _empty("high_impact_execution_bridge_json_missing_rows")
        all_rows = [_row(raw) for raw in raw_rows if isinstance(raw, dict)]
        matched_rows = [row for row in all_rows if _matches(row)]
        rows = matched_rows[:row_limit]
        runnable_rows = [row for row in rows if row.get("runnable_harness")]
        blocked_rows = [row for row in rows if not row.get("runnable_harness")]
        queue_next_commands = _bounded_commands(
            [str(command) for command in (payload.get("queue_next_commands") or []) if isinstance(command, str)]
        )
        source_summary = dict(payload.get("summary", {}) or {})
        summary = {
            "source_schema_version": _scrub_text(payload.get("schema_version"), max_chars=120),
            "high_impact_missing": int(payload.get("high_impact_missing") or 0),
            "processed_rows": int(payload.get("processed_rows") or len(all_rows)),
            "total_rows_available": len(all_rows),
            "rows_matched": len(matched_rows),
            "rows_returned": len(rows),
            "runnable_harness_rows": int(source_summary.get("runnable_harness_rows") or 0),
            "runnable_rows_returned": len(runnable_rows),
            "blocked_rows_returned": len(blocked_rows),
            "scaffold_attempts": int(source_summary.get("scaffold_attempts") or 0),
            "blocked_missing_impact_contract": int(source_summary.get("blocked_missing_impact_contract") or 0),
            "blocked_other": int(source_summary.get("blocked_other") or 0),
            "queue_commands_returned": len(queue_next_commands),
        }
        freshness = {
            "bridge_report": {
                "status": "present",
                "reason": "loaded_existing_high_impact_execution_bridge_json",
                "bridge_ref": _workspace_ref(bridge_path),
                "workspace_match": workspace_match,
                "ledger_generated_at": _scrub_text(payload.get("ledger_generated_at"), max_chars=80),
                "freshness_basis": "artifact_presence_and_ledger_generated_at",
                "safe_to_treat_as_current": bool(payload.get("ledger_generated_at")) and workspace_match != "mismatched",
            }
        }
        limitations = [
            "This pack reports execution readiness only; it does not prove exploitability, impact, severity, duplicate status, OOS status, or submission readiness.",
            "Returned commands are advisory next actions and were not executed by this MCP callable.",
        ]
        if not freshness["bridge_report"]["safe_to_treat_as_current"]:
            limitations.append("Bridge freshness is incomplete; rerun make high-impact-execution-bridge after the latest invariant ledger before using it as the current worklist.")

        base = {
            "schema": HIGH_IMPACT_EXECUTION_BRIDGE_CONTEXT_SCHEMA,
            "kind": "high_impact_execution_bridge_context",
            "workspace_path": workspace_label,
            "bridge_ref": _workspace_ref(bridge_path),
            "source_schema_version": _scrub_text(payload.get("schema_version"), max_chars=120),
            "degraded": False,
            "advisory_only": True,
            "claim_scope": "execution_readiness_only",
            "submission_posture": "NOT_SUBMIT_READY",
            "promotion_allowed": False,
            "dispatch_ready": False,
            "proof_boundary": _scrub_text(payload.get("proof_boundary"), max_chars=260)
            or "Bridge rows are scaffold readiness only; execution records are required before impact claims.",
            "summary": summary,
            "rows": rows,
            "runnable_rows": runnable_rows,
            "blocked_rows": blocked_rows,
            "queue_next_commands": queue_next_commands,
            "limits": _limits(),
            "freshness": freshness,
            "filters": {
                "row_id": row_id_filter,
                "status": status_filter,
                "runnable_only": runnable_only,
            },
            "limitations": limitations,
            "privacy_guards": privacy_guards,
            "source_refs": ["tools/high-impact-execution-bridge.py", _workspace_ref(bridge_path)],
        }
        return _finalize(base)

    def vault_poc_execution_record_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded context from ``poc_execution/**/execution_manifest.json``.

        PoC execution manifests are stronger than scaffold readiness, but they
        still do not by themselves make a candidate submission-ready. This
        callable exposes the existing execution-record truth with strict path
        scrubbing and explicit proof boundaries.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        row_limit = min(
            MAX_POC_EXECUTION_RECORD_ROWS,
            _clamp_limit(kwargs.get("limit"), default=8),
        )
        candidate_filter = str(kwargs.get("candidate_id") or kwargs.get("candidate") or "").strip()
        final_result_filter = str(kwargs.get("final_result") or "").strip().lower()
        impact_filter = str(kwargs.get("impact_assertion") or "").strip().lower()
        status_filter = str(kwargs.get("status") or "").strip().lower().replace("-", "_").replace(" ", "_")
        proof_only = bool(kwargs.get("proof_only"))
        privacy_guards = {
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "repo_relative_refs_only": True,
            "secret_patterns_blocked": True,
            "raw_stdout_stderr_not_returned": True,
            "commands_are_summarized_not_executed": True,
            "submission_readiness_not_inferred": True,
        }

        def _limits() -> dict[str, int]:
            return {
                "max_rows": row_limit,
                "max_commands": MAX_POC_EXECUTION_RECORD_COMMANDS,
                "max_refs": MAX_POC_EXECUTION_RECORD_REFS,
                "max_chars": MAX_POC_EXECUTION_RECORD_CHARS,
            }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", POC_EXECUTION_RECORD_CONTEXT_SCHEMA)
            base.setdefault("kind", "poc_execution_record_context")
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("degraded", False)
            base.setdefault("advisory_only", True)
            base.setdefault("claim_scope", "execution_record_truth_only")
            base.setdefault("submission_posture", "NOT_SUBMIT_READY")
            base.setdefault("promotion_allowed", False)
            base.setdefault("rows", [])
            base.setdefault("records", base.get("rows", []))
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "proof_boundary",
                "A proved PoC execution record is proof evidence only when final_result=proved, impact_assertion=exploit_impact, evidence_class=executed_with_manifest, and at least one structured command row has non-empty command, status=pass, and exit_code=0; submission still requires scope/OOS/duplicate/pre-submit review.",
            )
            base.setdefault(
                "advisory_boundary",
                "execution_manifest_context_only_not_submission_readiness",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{POC_EXECUTION_RECORD_CONTEXT_SCHEMA}:poc_execution_record:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _empty(error: str, *, degraded: bool = True, reason: str = "") -> dict[str, Any]:
            return _finalize(
                {
                    "error": error,
                    "degraded": degraded,
                    "degraded_reason": error if degraded else "",
                    "summary": {
                        "total_manifests_available": 0,
                        "records_total": 0,
                        "records_matched": 0,
                        "records_returned": 0,
                        "proved_exploit_impact_count": 0,
                        "proved_impact_evidence_count": 0,
                        "control_plane_proof_counted_count": 0,
                    },
                    "records": [],
                    "rows": [],
                    "filters": {
                        "candidate_id": candidate_filter,
                        "final_result": final_result_filter,
                        "impact_assertion": impact_filter,
                        "status": status_filter,
                        "proof_only": proof_only,
                    },
                    "freshness": {
                        "poc_execution_manifests": {
                            "status": "absent" if error == "poc_execution_manifests_missing" else "not_checked",
                            "reason": reason or error,
                            "safe_to_treat_as_current": False,
                        }
                    },
                    "limits": _limits(),
                    "source_refs": ["tools/poc-execution-record.py", "tools/control/runs.py"],
                }
            )

        if not workspace_arg:
            return _empty("workspace_path_required", reason="workspace_path_required")
        try:
            workspace = Path(str(workspace_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return _empty("invalid_workspace_path")
        workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
        if not workspace.is_dir():
            return _empty("workspace_not_found")

        def _workspace_ref(value: object) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 or ch in "`" for ch in text) or _has_secret(text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            if text.startswith("<workspace>/"):
                safe = _safe_workspace_relpath(text.removeprefix("<workspace>/"))
                return safe or ""
            try:
                candidate = Path(text).expanduser()
                if candidate.is_absolute():
                    resolved = candidate.resolve()
                    try:
                        return resolved.relative_to(workspace).as_posix()
                    except ValueError:
                        return "[redacted-local-path]"
            except (OSError, RuntimeError):
                return ""
            safe = _safe_workspace_relpath(text)
            return safe or ""

        def _scrub_text(value: object, max_chars: int = MAX_POC_EXECUTION_RECORD_CHARS) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 for ch in text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            text = text.replace(str(self.repo_root), "repo_root")
            text = re.sub(
                r"(?:/Users|/home|/tmp|/private|/var)(?:/[^\s,;:'\")\]}]+)+",
                "[redacted-local-path]",
                text,
            )
            if _has_secret(text):
                return "[redacted-secret]"
            text = re.sub(r"\s+", " ", text).strip()
            if len(text) > max_chars:
                return text[:max_chars].rstrip() + "..."
            return text

        def _load_control_rows() -> dict[str, dict[str, Any]]:
            module_path = self.repo_root / "tools" / "control" / "runs.py"
            if not module_path.is_file():
                return {}
            try:
                module_id = "_vault_mcp_control_runs"
                if module_id in sys.modules:
                    mod = sys.modules[module_id]
                else:
                    spec = importlib.util.spec_from_file_location(module_id, module_path)
                    if spec is None or spec.loader is None:
                        return {}
                    mod = importlib.util.module_from_spec(spec)
                    sys.modules[module_id] = mod
                    spec.loader.exec_module(mod)  # type: ignore[union-attr]
                rows = mod.discover_run_rows(workspace)  # type: ignore[attr-defined]
            except Exception:  # noqa: BLE001
                return {}
            result: dict[str, dict[str, Any]] = {}
            if isinstance(rows, list):
                for row in rows:
                    if not isinstance(row, dict) or row.get("tool") != "poc-execution":
                        continue
                    path = str(row.get("artifact_path") or "")
                    if path:
                        result[path] = row
            return result

        def _manifest_paths() -> list[Path]:
            poc_root = workspace / "poc_execution"
            if not poc_root.is_dir():
                return []
            return sorted(poc_root.glob("**/execution_manifest.json"))

        def _read_manifest(path: Path) -> tuple[dict[str, Any] | None, str]:
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except json.JSONDecodeError:
                return None, "invalid_json"
            except OSError:
                return None, "unreadable"
            if not isinstance(payload, dict):
                return None, "invalid_schema"
            return payload, ""

        def _is_zero_exit_code(value: object) -> bool:
            if isinstance(value, bool):
                return False
            if isinstance(value, int):
                return value == 0
            if isinstance(value, str):
                return value.strip() == "0"
            return False

        def _command_rows(commands: object) -> tuple[list[dict[str, Any]], dict[str, int], int, int, int]:
            rows: list[dict[str, Any]] = []
            status_counts: dict[str, int] = {}
            passing_count = 0
            structured_count = 0
            total = len(commands) if isinstance(commands, list) else 0
            if not isinstance(commands, list):
                return [], {}, 0, 0, 0
            for raw in commands[:MAX_POC_EXECUTION_RECORD_COMMANDS]:
                if isinstance(raw, dict):
                    structured_count += 1
                    status = (_scrub_text(raw.get("status"), max_chars=80) or "unknown").lower()
                    command_text = _scrub_text(raw.get("command"))
                    exit_code = raw.get("exit_code")
                    if status == "pass" and _is_zero_exit_code(exit_code) and command_text:
                        passing_count += 1
                    status_counts[status] = status_counts.get(status, 0) + 1
                    row: dict[str, Any] = {
                        "status": status,
                        "exit_code": exit_code
                        if isinstance(exit_code, int) and not isinstance(exit_code, bool)
                        else _scrub_text(exit_code, max_chars=20),
                        "command": command_text,
                        "cwd": _workspace_ref(raw.get("cwd")),
                        "stdout_ref": _workspace_ref(raw.get("stdout_path")),
                        "stderr_ref": _workspace_ref(raw.get("stderr_path")),
                    }
                    rows.append({key: value for key, value in row.items() if value not in ("", [], None)})
                else:
                    status_counts["legacy_recorded_command"] = status_counts.get("legacy_recorded_command", 0) + 1
                    rows.append({"status": "legacy_recorded_command", "command": _scrub_text(raw)})
            return rows, dict(sorted(status_counts.items())), total, structured_count, passing_count

        def _proof_blockers(
            final_result: str,
            impact_assertion: str,
            evidence_class: str,
            command_count: int,
            structured_command_count: int,
            passing_command_count: int,
        ) -> list[str]:
            blockers: list[str] = []
            if final_result != "proved":
                blockers.append("final_result_not_proved")
            if impact_assertion != "exploit_impact":
                blockers.append("impact_assertion_not_exploit_impact")
            if evidence_class != "executed_with_manifest":
                blockers.append("evidence_class_not_executed_with_manifest")
            if command_count <= 0:
                blockers.append("commands_attempted")
            elif structured_command_count <= 0:
                blockers.append("commands_attempted_structured")
                blockers.append("commands_attempted_pass_exit_0")
            elif passing_command_count <= 0:
                blockers.append("commands_attempted_pass_exit_0")
            return blockers

        def _proof_status(
            final_result: str,
            impact_assertion: str,
            evidence_class: str,
            passing_command_count: int,
        ) -> tuple[str, bool]:
            if (
                final_result == "proved"
                and impact_assertion == "exploit_impact"
                and evidence_class == "executed_with_manifest"
                and passing_command_count > 0
            ):
                return "proved_impact_evidence", True
            if final_result == "proved" and impact_assertion == "exploit_impact":
                return "claimed_proved_missing_execution_evidence", False
            if final_result in {"blocked_env", "blocked_path"}:
                return "blocked", False
            if final_result == "disproved":
                return "disproved", False
            if final_result == "needs_human":
                return "needs_human", False
            return "unknown", False

        control_rows = _load_control_rows()
        paths = _manifest_paths()
        if not paths:
            return _empty(
                "poc_execution_manifests_missing",
                reason="poc_execution/**/execution_manifest.json not found",
            )

        rows: list[dict[str, Any]] = []
        invalid_rows = 0
        for path in paths:
            rel = _workspace_ref(path)
            payload, error = _read_manifest(path)
            control_row = control_rows.get(rel, {})
            if payload is None:
                invalid_rows += 1
                row = {
                    "candidate_id": path.parent.name,
                    "manifest_ref": rel,
                    "manifest_valid": False,
                    "proof_status": "invalid_manifest",
                    "proof_counted": False,
                    "control_plane_proof_counted": bool(control_row.get("proof_counted")),
                    "execution_state": _scrub_text(control_row.get("execution_state"), max_chars=80) or "blocked",
                    "blockers": [error],
                    "submission_posture": "NOT_SUBMIT_READY",
                    "promotion_allowed": False,
                }
                rows.append(row)
                continue
            candidate_id = _scrub_text(payload.get("candidate_id"), max_chars=160) or path.parent.name
            final_result = _scrub_text(payload.get("final_result") or payload.get("result"), max_chars=80).lower()
            impact_assertion = _scrub_text(payload.get("impact_assertion"), max_chars=80).lower()
            evidence_class = _scrub_text(payload.get("evidence_class"), max_chars=120)
            (
                command_rows,
                command_status_counts,
                command_total,
                structured_command_count,
                passing_command_count,
            ) = _command_rows(
                payload.get("commands_attempted")
            )
            proof_status, proved_impact = _proof_status(
                final_result,
                impact_assertion,
                evidence_class,
                passing_command_count,
            )
            proof_blockers = _proof_blockers(
                final_result,
                impact_assertion,
                evidence_class,
                command_total,
                structured_command_count,
                passing_command_count,
            )
            refs = _unique_bounded(
                [
                    ref
                    for ref in (
                        _workspace_ref(payload.get("brief_path")),
                        _workspace_ref(payload.get("source_graph_path")),
                        *(_workspace_ref(value) for value in (payload.get("artifact_paths") or []) if isinstance(value, str)),
                    )
                    if ref
                ],
                MAX_POC_EXECUTION_RECORD_REFS,
            )
            control_warnings = control_row.get("warnings") if isinstance(control_row, dict) else []
            control_blockers = control_row.get("blockers") if isinstance(control_row, dict) else []
            row = {
                "candidate_id": candidate_id,
                "manifest_ref": rel,
                "manifest_valid": True,
                "schema_version": _scrub_text(payload.get("schema_version"), max_chars=120),
                "proof_task_id": _scrub_text(
                    payload.get("proof_task_id") or payload.get("proof_queue_task_id"),
                    max_chars=120,
                ),
                "proof_queue_relationship": _scrub_text(payload.get("proof_queue_relationship"), max_chars=120),
                "detector_slug": _scrub_text(payload.get("detector_slug"), max_chars=160),
                "detector_obligation": _scrub_text(
                    payload.get("detector_obligation") or payload.get("detector_action_graph_obligation"),
                    max_chars=120,
                ),
                "detector_action_graph": _workspace_ref(
                    payload.get("detector_action_graph") or payload.get("detector_action_graph_path")
                ),
                "detector_action_graph_sha256": _scrub_text(payload.get("detector_action_graph_sha256"), max_chars=80),
                "final_result": final_result,
                "impact_assertion": impact_assertion,
                "evidence_class": evidence_class,
                "proof_status": proof_status,
                "proof_counted": proved_impact,
                "control_plane_proof_counted": bool(control_row.get("proof_counted")),
                "execution_state": _scrub_text(control_row.get("execution_state"), max_chars=80),
                "assigned_model": _scrub_text(payload.get("assigned_model"), max_chars=120),
                "workspace_commit": _scrub_text(payload.get("workspace_commit"), max_chars=80),
                "source_graph_sha256": _scrub_text(payload.get("source_graph_sha256"), max_chars=80),
                "commands_attempted_count": command_total,
                "structured_command_count": structured_command_count,
                "passing_command_count": passing_command_count,
                "commands_returned": len(command_rows),
                "command_status_counts": command_status_counts,
                "commands": command_rows,
                "artifact_refs": refs,
                "warnings": [str(v) for v in control_warnings[:8]] if isinstance(control_warnings, list) else [],
                "blockers": [str(v) for v in control_blockers[:8]] if isinstance(control_blockers, list) else [],
                "proof_blockers": proof_blockers,
                "updated_at_unix": payload.get("updated_at_unix") if isinstance(payload.get("updated_at_unix"), int) else None,
                "submission_posture": "NOT_SUBMIT_READY",
                "promotion_allowed": False,
            }
            rows.append({key: value for key, value in row.items() if value not in ("", [], {}, None)})

        def _mark_ambiguous_linkage(rows_to_mark: list[dict[str, Any]]) -> None:
            duplicate_fields = (
                ("proof_task_id", "ambiguous_proof_task_manifest_linkage"),
                ("detector_obligation", "ambiguous_detector_obligation_manifest_linkage"),
            )
            for field, blocker in duplicate_fields:
                grouped: dict[str, list[dict[str, Any]]] = {}
                for row in rows_to_mark:
                    value = str(row.get(field) or "").strip()
                    if not value:
                        continue
                    grouped.setdefault(value, []).append(row)
                for linked_rows in grouped.values():
                    if len(linked_rows) < 2:
                        continue
                    for row in linked_rows:
                        proof_blockers = row.setdefault("proof_blockers", [])
                        if isinstance(proof_blockers, list) and blocker not in proof_blockers:
                            proof_blockers.append(blocker)
                            proof_blockers.sort()
                        if row.get("proof_counted") is True:
                            row["proof_counted"] = False
                            row["proof_status"] = "claimed_proved_missing_execution_evidence"

        _mark_ambiguous_linkage(rows)

        def _matches(row: dict[str, Any]) -> bool:
            if candidate_filter and row.get("candidate_id") != candidate_filter:
                return False
            if final_result_filter and row.get("final_result") != final_result_filter:
                return False
            if impact_filter and row.get("impact_assertion") != impact_filter:
                return False
            if proof_only and row.get("proof_counted") is not True:
                return False
            if status_filter:
                statuses = {
                    str(row.get("final_result") or "").lower(),
                    str(row.get("impact_assertion") or "").lower(),
                    str(row.get("evidence_class") or "").lower(),
                    str(row.get("proof_status") or "").lower(),
                    str(row.get("execution_state") or "").lower(),
                }
                if status_filter not in statuses:
                    return False
            return True

        matched = [row for row in rows if _matches(row)]
        returned = matched[:row_limit]
        final_counts: dict[str, int] = {}
        impact_counts: dict[str, int] = {}
        proof_status_counts: dict[str, int] = {}
        execution_state_counts: dict[str, int] = {}
        for row in rows:
            for bucket, key in (
                (final_counts, "final_result"),
                (impact_counts, "impact_assertion"),
                (proof_status_counts, "proof_status"),
                (execution_state_counts, "execution_state"),
            ):
                value = str(row.get(key) or "unknown")
                bucket[value] = bucket.get(value, 0) + 1

        base = {
            "schema": POC_EXECUTION_RECORD_CONTEXT_SCHEMA,
            "kind": "poc_execution_record_context",
            "workspace_path": workspace_label,
            "degraded": False,
            "claim_scope": "execution_record_truth_only",
            "submission_posture": "NOT_SUBMIT_READY",
            "promotion_allowed": False,
            "proof_boundary": (
                "Only rows with proof_status=proved_impact_evidence have explicit proved impact execution evidence "
                "(final_result=proved, impact_assertion=exploit_impact, evidence_class=executed_with_manifest, "
                "and at least one structured command with status=pass and exit_code=0); "
                "even those still require scope, OOS, duplicate, and pre-submit review before filing."
            ),
            "records": returned,
            "rows": returned,
            "summary": {
                "total_manifests_available": len(rows),
                "records_total": len(rows),
                "records_matched": len(matched),
                "records_returned": len(returned),
                "rows_matched": len(matched),
                "rows_returned": len(returned),
                "invalid_manifest_count": invalid_rows,
                "proved_exploit_impact_count": sum(1 for row in rows if row.get("proof_counted") is True),
                "proved_impact_evidence_count": sum(1 for row in rows if row.get("proof_counted") is True),
                "control_plane_proof_counted_count": sum(
                    1 for row in rows if row.get("control_plane_proof_counted") is True
                ),
                "final_result_counts": dict(sorted(final_counts.items())),
                "impact_assertion_counts": dict(sorted(impact_counts.items())),
                "proof_status_counts": dict(sorted(proof_status_counts.items())),
                "execution_state_counts": dict(sorted(execution_state_counts.items())),
            },
            "filters": {
                "candidate_id": candidate_filter,
                "final_result": final_result_filter,
                "impact_assertion": impact_filter,
                "status": status_filter,
                "proof_only": proof_only,
            },
            "freshness": {
                "poc_execution_manifests": {
                    "status": "present",
                    "manifest_count": len(rows),
                    "safe_to_treat_as_current": True,
                    "freshness_basis": "workspace_poc_execution_manifest_inventory",
                }
            },
            "limits": _limits(),
            "privacy_guards": privacy_guards,
            "source_refs": ["tools/poc-execution-record.py", "tools/control/runs.py", "poc_execution/**/execution_manifest.json"],
        }
        return _finalize(base)

    def vault_cosmos_evidence_pack_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return a compact summary from a Cosmos harness exec record."""
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        row_limit = min(
            MAX_COSMOS_EVIDENCE_PACK_ROWS,
            _clamp_limit(kwargs.get("limit"), default=MAX_COSMOS_EVIDENCE_PACK_ROWS),
        )
        exec_record_arg = str(
            kwargs.get("exec_record_path")
            or kwargs.get("exec_record")
            or kwargs.get("record_path")
            or ""
        ).strip()
        privacy_guards = {
            "raw_stdout_stderr_not_returned": True,
            "runtime_event_payloads_summarized": True,
            "absolute_local_paths_labelled": True,
            "secret_patterns_blocked": True,
            "submission_readiness_not_inferred": True,
        }

        def _finalize(payload: dict[str, Any]) -> dict[str, Any]:
            payload.setdefault("schema", COSMOS_EVIDENCE_PACK_CONTEXT_SCHEMA)
            payload.setdefault("kind", "cosmos_evidence_pack_context")
            payload.setdefault("degraded", False)
            payload.setdefault("advisory_only", True)
            payload.setdefault("claim_scope", "runtime_marker_evidence_pack_summary_only")
            payload.setdefault("submission_posture", "NOT_SUBMIT_READY")
            payload.setdefault("promotion_allowed", False)
            payload.setdefault("privacy_guards", privacy_guards)
            payload.setdefault("source_refs", ["tools/cosmos-production-harness-evidence-pack.py"])
            payload.setdefault("generated_at_utc", ts)
            payload["token_estimate"] = _token_estimate(payload)
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{COSMOS_EVIDENCE_PACK_CONTEXT_SCHEMA}:cosmos_evidence_pack:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _degraded(reason: str) -> dict[str, Any]:
            return _finalize(
                {
                    "degraded": True,
                    "degraded_reason": reason,
                    "reason": reason,
                    "exec_record": {"path": self._safe_local_path_label(exec_record_arg) if exec_record_arg else ""},
                    "verdict": "unavailable",
                    "failed_required_rows": [],
                    "triager_rows": [],
                    "summary": {
                        "triager_rows_total": 0,
                        "triager_rows_returned": 0,
                        "pass_count": 0,
                        "missing_count": 0,
                        "not_applicable_count": 0,
                    },
                    "limits": {
                        "max_triager_rows": row_limit,
                        "max_chars": MAX_COSMOS_EVIDENCE_PACK_CHARS,
                    },
                }
            )

        if not exec_record_arg:
            return _degraded("exec_record_path_required")
        try:
            exec_record_path = Path(exec_record_arg).expanduser().resolve()
        except (OSError, RuntimeError, ValueError):
            return _degraded("invalid_exec_record_path")
        if not exec_record_path.is_file():
            return _degraded("exec_record_not_found")

        try:
            module_path = self.repo_root / "tools" / "cosmos-production-harness-evidence-pack.py"
            spec = importlib.util.spec_from_file_location(
                "_vault_cosmos_production_harness_evidence_pack",
                module_path,
            )
            if spec is None or spec.loader is None:
                return _degraded("cosmos_evidence_pack_module_unavailable")
            mod = importlib.util.module_from_spec(spec)
            sys.modules[spec.name] = mod
            spec.loader.exec_module(mod)  # type: ignore[union-attr]
            pack, exit_code = mod.build_evidence_pack(exec_record_path)
        except Exception as exc:  # noqa: BLE001 - MCP read path must degrade.
            return _degraded(f"evidence_pack_build_failed: {_bounded_text(str(exc), max_chars=180)}")
        if not isinstance(pack, dict):
            return _degraded("evidence_pack_invalid_schema")

        def _safe_path(value: object) -> str:
            text = str(value if value is not None else "").strip()
            if not text:
                return ""
            if _has_secret(text):
                return "[redacted-secret]"
            return self._safe_local_path_label(text)

        def _scrub_value(value: object, max_chars: int = MAX_COSMOS_EVIDENCE_PACK_CHARS) -> Any:
            if isinstance(value, dict):
                out: dict[str, Any] = {}
                for key, item in value.items():
                    key_text = _safe_text_item(key, max_chars=80) or ""
                    if not key_text:
                        continue
                    if key_text in {"path", "stdout_path", "stderr_path", "events_path", "cwd", "data_dir"}:
                        out[key_text] = _safe_path(item)
                    elif key_text == "sha256":
                        out[key_text] = _safe_text_item(item, max_chars=80) or ""
                    else:
                        out[key_text] = _scrub_value(item, max_chars=max_chars)
                return out
            if isinstance(value, list):
                return [_scrub_value(item, max_chars=max_chars) for item in value[:8]]
            if isinstance(value, (int, float, bool)) or value is None:
                return value
            text = str(value)
            if _has_secret(text):
                return "[redacted-secret]"
            if "/" in text or text.startswith("~"):
                return _safe_path(text)
            return _safe_text_item(text, max_chars=max_chars) or ""

        raw_rows = pack.get("triager_rows") if isinstance(pack.get("triager_rows"), list) else []
        triager_rows: list[dict[str, Any]] = []
        status_counts: dict[str, int] = {}
        for row in raw_rows:
            if not isinstance(row, dict):
                continue
            status = _safe_text_item(row.get("status"), max_chars=40) or "unknown"
            status_counts[status] = status_counts.get(status, 0) + 1
            if len(triager_rows) >= row_limit:
                continue
            evidence = row.get("evidence") if isinstance(row.get("evidence"), dict) else {}
            triager_rows.append(
                {
                    "id": _safe_text_item(row.get("id"), max_chars=120) or "",
                    "status": status,
                    "summary": _safe_text_item(row.get("summary"), max_chars=240) or "",
                    "evidence_summary": _scrub_value(evidence),
                }
            )

        runtime_events = pack.get("runtime_events") if isinstance(pack.get("runtime_events"), dict) else {}
        failed_rows = pack.get("failed_required_rows") if isinstance(pack.get("failed_required_rows"), list) else []
        exec_record = pack.get("exec_record") if isinstance(pack.get("exec_record"), dict) else {}
        payload = {
            "schema": COSMOS_EVIDENCE_PACK_CONTEXT_SCHEMA,
            "kind": "cosmos_evidence_pack_context",
            "degraded": False,
            "advisory_only": True,
            "claim_scope": "runtime_marker_evidence_pack_summary_only",
            "submission_posture": "NOT_SUBMIT_READY",
            "promotion_allowed": False,
            "exec_record": {
                "path": _safe_path(exec_record.get("path") or exec_record_path),
                "sha256": _safe_text_item(exec_record.get("sha256"), max_chars=80) or "",
            },
            "candidate_id": _safe_text_item(pack.get("candidate_id"), max_chars=160) or "",
            "workspace": _safe_path(pack.get("workspace")),
            "workspace_commit": _safe_text_item(pack.get("workspace_commit"), max_chars=80) or "",
            "tool_schema": _safe_text_item(pack.get("schema"), max_chars=120) or "",
            "source_tool": _safe_text_item(pack.get("tool"), max_chars=120) or "",
            "builder_exit_code": exit_code,
            "verdict": _safe_text_item(pack.get("verdict"), max_chars=80) or "",
            "runtime_proof_claimed": bool(pack.get("runtime_proof_claimed")),
            "failed_required_rows": [
                _safe_text_item(item, max_chars=120) or "" for item in failed_rows
            ][:MAX_COSMOS_EVIDENCE_PACK_ROWS],
            "triager_rows": triager_rows,
            "summary": {
                "triager_rows_total": len([row for row in raw_rows if isinstance(row, dict)]),
                "triager_rows_returned": len(triager_rows),
                "status_counts": dict(sorted(status_counts.items())),
                "pass_count": status_counts.get("pass", 0),
                "missing_count": status_counts.get("missing", 0),
                "not_applicable_count": status_counts.get("not_applicable", 0),
                "failed_required_count": len(failed_rows),
            },
            "runtime_events": {
                "path": _safe_path(runtime_events.get("path")),
                "sha256": _safe_text_item(runtime_events.get("sha256"), max_chars=80) or "",
                "events_seen": [
                    _safe_text_item(item, max_chars=80) or ""
                    for item in (
                        runtime_events.get("events_seen")
                        if isinstance(runtime_events.get("events_seen"), list)
                        else []
                    )
                ][:MAX_COSMOS_EVIDENCE_PACK_ROWS],
            },
            "proof_boundary": _safe_text_item(pack.get("advisory_boundary"), max_chars=360) or "",
            "advisory_boundary": _safe_text_item(pack.get("advisory_boundary"), max_chars=360) or "",
            "limits": {
                "max_triager_rows": row_limit,
                "max_chars": MAX_COSMOS_EVIDENCE_PACK_CHARS,
            },
            "privacy_guards": privacy_guards,
            "source_refs": ["tools/cosmos-production-harness-evidence-pack.py"],
            "generated_at_utc": ts,
        }
        return _finalize(payload)

    def vault_solidity_detector_proof_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return a Solidity detector-to-proof worklist with execution overlay.

        This joins existing detector/action-graph and proof-queue artifacts to
        existing PoC execution manifests. It is a routing surface for Foundry
        proof work, not an exploitability, impact, severity, duplicate/OOS, or
        submission-readiness verdict.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        row_limit = min(
            MAX_SOLIDITY_DETECTOR_PROOF_ROWS,
            _clamp_limit(kwargs.get("limit"), default=8),
        )
        detector_filter = str(kwargs.get("detector_slug") or kwargs.get("detector") or "").strip()
        status_filter = str(kwargs.get("status") or "").strip().lower().replace("-", "_").replace(" ", "_")
        proof_only = bool(kwargs.get("proof_only"))
        privacy_guards = {
            "repo_relative_refs_only": True,
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "raw_harness_logs_not_returned": True,
            "generated_poc_bodies_not_returned": True,
            "no_full_function_body_returned": True,
            "commands_are_advisory_not_executed": True,
        }

        def _limits() -> dict[str, int]:
            return {
                "max_rows": row_limit,
                "max_refs": MAX_SOLIDITY_DETECTOR_PROOF_REFS,
                "max_chars": MAX_SOLIDITY_DETECTOR_PROOF_CHARS,
            }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", SOLIDITY_DETECTOR_PROOF_CONTEXT_SCHEMA)
            base.setdefault("kind", "solidity_detector_proof_context")
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("degraded", False)
            base.setdefault("advisory_only", True)
            base.setdefault("claim_scope", "solidity_detector_fixture_evidence_only")
            base.setdefault("submission_posture", "NOT_SUBMIT_READY")
            base.setdefault("candidate_not_submit_ready", True)
            base.setdefault("promotion_allowed", False)
            base.setdefault("does_not_claim_exploitability", True)
            base.setdefault("does_not_claim_impact", True)
            base.setdefault("does_not_claim_severity", True)
            base.setdefault("does_not_claim_duplicate_clearance", True)
            base.setdefault("does_not_claim_oos_clearance", True)
            base.setdefault("does_not_claim_submission_readiness", True)
            base.setdefault("rows", [])
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "proof_boundary",
                "Detector hits, proof queues, templates, and generated PoC scaffolds are worklist artifacts only; a separate runnable PoC execution record with proved exploit impact, plus scope/OOS/duplicate/pre-submit review, is required before filing.",
            )
            base.setdefault(
                "claim_guard",
                "Do NOT infer exploitability, impact, severity, duplicate/OOS clearance, or submission readiness from detector hits, action graphs, proof queues, templates, manifests, or generated scaffolds.",
            )
            base.setdefault(
                "advisory_boundary",
                "solidity_detector_proof_worklist_only_not_submission_readiness",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{SOLIDITY_DETECTOR_PROOF_CONTEXT_SCHEMA}:solidity_detector_proof:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _empty(error: str, *, degraded: bool = True, reason: str = "") -> dict[str, Any]:
            return _finalize(
                {
                    "error": error,
                    "degraded": degraded,
                    "degraded_reason": error if degraded else "",
                    "summary": {
                        "queue_rows_seen": 0,
                        "non_solidity_rows_filtered": 0,
                        "rows_matched": 0,
                        "rows_returned": 0,
                        "ready_for_foundry_poc_count": 0,
                        "executed_with_manifest_count": 0,
                        "proved_impact_evidence_count": 0,
                    },
                    "filters": {
                        "detector_slug": detector_filter,
                        "status": status_filter,
                        "proof_only": proof_only,
                    },
                    "freshness": {
                        "detector_artifacts": {
                            "status": "absent" if "missing" in error or "not_found" in error else "not_checked",
                            "reason": reason or error,
                            "safe_to_treat_as_current": False,
                        }
                    },
                    "limits": _limits(),
                    "source_refs": [
                        "tools/detector-hit-action-graph.py",
                        "tools/proof-obligation-queue.py",
                        "tools/poc-execution-record.py",
                    ],
                }
            )

        if not workspace_arg:
            return _empty("workspace_path_required", reason="workspace_path_required")
        try:
            workspace = Path(str(workspace_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return _empty("invalid_workspace_path")
        workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
        if not workspace.is_dir():
            return _empty("workspace_not_found")

        execution_manifest_proof = _load_tool_module("execution_manifest_proof")
        shared_command_evidence_counts = getattr(
            execution_manifest_proof, "command_evidence_counts", None
        )
        shared_is_strict_proved_execution_manifest = getattr(
            execution_manifest_proof, "is_strict_proved_execution_manifest", None
        )

        def _manifest_command_evidence_counts(payload: dict[str, Any]) -> dict[str, int]:
            if callable(shared_command_evidence_counts):
                try:
                    counts = shared_command_evidence_counts(payload)
                except Exception:  # noqa: BLE001
                    counts = {}
                if isinstance(counts, dict):
                    total = counts.get("commands_attempted_count", 0)
                    structured = counts.get("structured_command_count", 0)
                    passing = counts.get("passing_command_count", 0)
                    return {
                        "commands_attempted_count": total if isinstance(total, int) and total >= 0 else 0,
                        "structured_command_count": structured
                        if isinstance(structured, int) and structured >= 0
                        else 0,
                        "passing_command_count": passing if isinstance(passing, int) and passing >= 0 else 0,
                    }
            # Integration fallback when tools/execution_manifest_proof.py is unavailable.
            commands = payload.get("commands_attempted")
            if not isinstance(commands, list):
                return {
                    "commands_attempted_count": 0,
                    "structured_command_count": 0,
                    "passing_command_count": 0,
                }
            structured_count = 0
            passing_count = 0
            for command in commands:
                if not isinstance(command, dict):
                    continue
                structured_count += 1
                command_text = _scrub_text(command.get("command"))
                status = _scrub_text(command.get("status"), max_chars=80).lower()
                exit_code = command.get("exit_code")
                is_zero_exit = (
                    (isinstance(exit_code, int) and not isinstance(exit_code, bool) and exit_code == 0)
                    or (isinstance(exit_code, str) and exit_code.strip() == "0")
                )
                if command_text and status == "pass" and is_zero_exit:
                    passing_count += 1
            return {
                "commands_attempted_count": len(commands),
                "structured_command_count": structured_count,
                "passing_command_count": passing_count,
            }

        def _is_strict_proved_execution_manifest(payload: dict[str, Any]) -> bool:
            if callable(shared_is_strict_proved_execution_manifest):
                try:
                    return bool(shared_is_strict_proved_execution_manifest(payload))
                except Exception:  # noqa: BLE001
                    pass
            counts = _manifest_command_evidence_counts(payload)
            return (
                _scrub_text(payload.get("final_result") or payload.get("result"), max_chars=80).lower() == "proved"
                and _scrub_text(payload.get("impact_assertion"), max_chars=80).lower() == "exploit_impact"
                and _scrub_text(payload.get("evidence_class"), max_chars=120) == "executed_with_manifest"
                and counts.get("passing_command_count", 0) > 0
            )

        def _slug(value: object) -> str:
            return re.sub(r"[^a-z0-9]+", "-", str(value if value is not None else "").strip().lower()).strip("-")

        def _workspace_ref(value: object) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 or ch in "`" for ch in text) or _has_secret(text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            if text.startswith("<workspace>/"):
                raw = text.removeprefix("<workspace>/")
                line = ""
                if ":" in raw:
                    prefix, _, maybe_line = raw.rpartition(":")
                    if prefix and maybe_line.isdigit():
                        raw = prefix
                        line = f":{maybe_line}"
                safe = _safe_workspace_relpath(raw)
                return f"{safe}{line}" if safe else ""
            try:
                candidate = Path(text).expanduser()
                if candidate.is_absolute():
                    line = ""
                    raw_candidate = text
                    if ":" in text:
                        prefix, _, maybe_line = text.rpartition(":")
                        if prefix and maybe_line.isdigit():
                            raw_candidate = prefix
                            line = f":{maybe_line}"
                            candidate = Path(raw_candidate).expanduser()
                    resolved = candidate.resolve()
                    try:
                        rel = resolved.relative_to(workspace).as_posix()
                        return f"{rel}{line}"
                    except ValueError:
                        return "[redacted-local-path]"
            except (OSError, RuntimeError):
                return ""
            raw = text
            line = ""
            if ":" in raw:
                prefix, _, maybe_line = raw.rpartition(":")
                if prefix and maybe_line.isdigit():
                    raw = prefix
                    line = f":{maybe_line}"
            safe = _safe_workspace_relpath(raw)
            return f"{safe}{line}" if safe else ""

        def _repo_ref(path: Path) -> str:
            try:
                return path.resolve().relative_to(self.repo_root.resolve()).as_posix()
            except ValueError:
                return path.name

        def _scrub_text(value: object, max_chars: int = MAX_SOLIDITY_DETECTOR_PROOF_CHARS) -> str:
            text = str(value if value is not None else "").strip()
            if not text or any(ord(ch) < 32 for ch in text):
                return ""
            text = text.replace(str(workspace), "<workspace>")
            text = text.replace(str(self.repo_root), "repo_root")
            text = re.sub(
                r"(?:/Users|/home|/tmp|/private|/var)(?:/[^\s,;:'\")\]}]+)+",
                "[redacted-local-path]",
                text,
            )
            if _has_secret(text):
                return "[redacted-secret]"
            text = re.sub(r"\s+", " ", text).strip()
            if len(text) > max_chars:
                return text[:max_chars].rstrip() + "..."
            return text

        def _load_json(path: Path) -> dict[str, Any] | None:
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                return None
            return payload if isinstance(payload, dict) else None

        def _sha256_file(path: Path) -> str:
            try:
                h = hashlib.sha256()
                with path.open("rb") as fh:
                    for chunk in iter(lambda: fh.read(1024 * 1024), b""):
                        h.update(chunk)
                return h.hexdigest()
            except OSError:
                return ""

        def _graph_paths() -> tuple[list[Path], list[str]]:
            summary = workspace / ".auditooor" / "audit_hacker_logic_bridge.json"
            warnings: list[str] = []
            paths: list[Path] = []
            if summary.is_file():
                payload = _load_json(summary)
                graphs = payload.get("graphs") if isinstance(payload, dict) else None
                if isinstance(graphs, list):
                    for graph in graphs:
                        if not isinstance(graph, dict):
                            continue
                        raw = str(graph.get("graph_path") or "").strip()
                        if not raw:
                            continue
                        candidate = (workspace / raw).resolve() if not Path(raw).is_absolute() else Path(raw).resolve()
                        try:
                            candidate.relative_to(workspace)
                        except ValueError:
                            warnings.append("bridge_graph_path_outside_workspace")
                            continue
                        paths.append(candidate)
                    if paths:
                        return _unique_path_list(paths), warnings
            graph_dir = workspace / ".auditooor" / "detector_action_graphs"
            if graph_dir.is_dir():
                paths.extend(sorted(graph_dir.glob("*.json")))
            for candidate in (
                workspace / ".auditooor" / "detector_action_graph.json",
                workspace / ".auditooor" / "detector_action_graph_context.json",
            ):
                if candidate.is_file():
                    paths.append(candidate)
            return _unique_path_list(paths), warnings

        def _unique_path_list(paths: list[Path]) -> list[Path]:
            out: list[Path] = []
            seen: set[str] = set()
            for path in paths:
                key = str(path)
                if key in seen:
                    continue
                seen.add(key)
                out.append(path)
            return out

        def _load_graphs() -> tuple[dict[str, dict[str, Any]], list[str], list[str]]:
            graphs: dict[str, dict[str, Any]] = {}
            refs: list[str] = []
            paths, warnings = _graph_paths()
            for path in paths:
                payload = _load_json(path)
                if not isinstance(payload, dict):
                    continue
                hit = payload.get("detector_hit") if isinstance(payload.get("detector_hit"), dict) else {}
                detector = str(hit.get("detector_slug") or "").strip()
                key = _slug(detector)
                if not key:
                    continue
                refs.append(_workspace_ref(path))
                graph_summary = {
                    "graph_ref": _workspace_ref(path),
                    "graph_sha256": _sha256_file(path),
                    "detector_hit": {
                        "detector_slug": _scrub_text(detector, max_chars=160),
                        "severity": _scrub_text(hit.get("severity"), max_chars=40),
                        "file_path": _workspace_ref(hit.get("file_path")) or _scrub_text(hit.get("file_path"), max_chars=220),
                        "snippet": _scrub_text(hit.get("snippet"), max_chars=220),
                    },
                    "ranked_attack_classes": [
                        {
                            "attack_class": _scrub_text(item.get("attack_class"), max_chars=120),
                            "score": item.get("score") if isinstance(item.get("score"), (int, float)) else None,
                            "confidence": _scrub_text(item.get("confidence"), max_chars=40),
                        }
                        for item in (payload.get("ranked_attack_classes") or [])[:3]
                        if isinstance(item, dict)
                    ],
                    "proof_obligations": [
                        {
                            "id": _scrub_text(item.get("id"), max_chars=80),
                            "kind": _scrub_text(item.get("kind"), max_chars=120),
                            "status": _scrub_text(item.get("status"), max_chars=80),
                            "title": _scrub_text(item.get("title"), max_chars=180),
                        }
                        for item in (payload.get("proof_obligations") or [])[:8]
                        if isinstance(item, dict)
                    ],
                }
                graphs[key] = graph_summary
            return graphs, refs, warnings

        def _queue_payload() -> tuple[dict[str, Any] | None, str, str]:
            for rel in (
                ".auditooor/proof_obligation_queue.json",
                ".auditooor/detector_proof_gap_queue.json",
            ):
                path = workspace / rel
                if path.is_file():
                    payload = _load_json(path)
                    if payload is not None:
                        return payload, rel, _workspace_ref(path)
                    return None, rel, _workspace_ref(path)
            return None, "", ""

        def _queue_freshness_marker(queue_rel: str, queue_ref: str) -> dict[str, Any]:
            marker_path = workspace / ".auditooor" / "proof_obligation_queue.freshness.json"
            marker_ref = _workspace_ref(marker_path)
            if not marker_path.is_file():
                return {
                    "status": "missing_freshness_marker",
                    "reason": "proof queue freshness marker missing",
                    "marker_ref": marker_ref,
                    "queue_ref": queue_ref,
                    "stale": True,
                    "safe_to_treat_as_current": False,
                    "freshness_basis": "missing_proof_obligation_queue_freshness_marker",
                }
            payload = _load_json(marker_path)
            if not isinstance(payload, dict):
                return {
                    "status": "invalid_freshness_marker",
                    "reason": "proof queue freshness marker is not valid JSON object",
                    "marker_ref": marker_ref,
                    "queue_ref": queue_ref,
                    "stale": True,
                    "safe_to_treat_as_current": False,
                    "freshness_basis": "invalid_proof_obligation_queue_freshness_marker",
                }
            proof_queue = payload.get("proof_queue") if isinstance(payload.get("proof_queue"), dict) else {}
            marker_queue_ref = _workspace_ref(proof_queue.get("path")) or _scrub_text(
                proof_queue.get("path"), max_chars=220
            )
            normalized_marker_queue = marker_queue_ref.removeprefix("<workspace>/").lstrip("/")
            normalized_loaded_queue = (queue_ref or queue_rel).removeprefix("<workspace>/").lstrip("/")
            queue_ref_matches = bool(
                normalized_marker_queue
                and normalized_loaded_queue
                and normalized_marker_queue == normalized_loaded_queue
            )
            status = _scrub_text(payload.get("status"), max_chars=80) or "unknown_freshness_status"
            stale = bool(payload.get("stale", status != "fresh_bridge_completed"))
            queue_exists = bool(proof_queue.get("exists"))
            queue_json_valid = bool(proof_queue.get("json_valid"))
            safe = (
                status == "fresh_bridge_completed"
                and not stale
                and queue_exists
                and queue_json_valid
                and queue_ref_matches
            )
            warnings: list[str] = []
            if stale:
                warnings.append("proof_queue_marker_stale")
            if status != "fresh_bridge_completed":
                warnings.append("proof_queue_marker_not_fresh_bridge_completed")
            if not queue_exists:
                warnings.append("proof_queue_marker_queue_missing")
            if not queue_json_valid:
                warnings.append("proof_queue_marker_queue_json_invalid")
            if not queue_ref_matches:
                warnings.append("proof_queue_marker_queue_ref_mismatch")
            return {
                "status": status,
                "reason": _scrub_text(payload.get("reason"), max_chars=180),
                "marker_ref": marker_ref,
                "marker_schema": _scrub_text(payload.get("schema"), max_chars=100),
                "queue_ref": queue_ref,
                "queue_source": queue_rel,
                "marker_queue_ref": marker_queue_ref,
                "queue_ref_matches_loaded_queue": queue_ref_matches,
                "queue_exists": queue_exists,
                "queue_json_valid": queue_json_valid,
                "queue_task_count": proof_queue.get("task_count"),
                "generated_at_utc": _scrub_text(payload.get("generated_at_utc"), max_chars=80),
                "stale": stale,
                "safe_to_treat_as_current": safe,
                "warnings": warnings,
                "freshness_basis": "proof_obligation_queue_freshness_marker",
            }

        def _queue_rows(payload: dict[str, Any]) -> list[dict[str, Any]]:
            if isinstance(payload.get("tasks"), list):
                rows = []
                for task in payload.get("tasks") or []:
                    if not isinstance(task, dict):
                        continue
                    detector = str(task.get("detector") or task.get("scanner_id") or "").strip()
                    rows.append(
                        {
                            "detector_slug": detector,
                            "language": str(task.get("language") or task.get("backend") or ""),
                            "proof_needed": task.get("proof_needed"),
                            "blockers": [task.get("blocker")] if task.get("blocker") else [],
                            "source_refs": task.get("source_refs") if isinstance(task.get("source_refs"), list) else [],
                            "file_hints": task.get("file_hints") if isinstance(task.get("file_hints"), list) else [],
                            "task_id": task.get("task_id"),
                            "detector_action_graph_obligation": task.get("detector_action_graph_obligation"),
                            "queue_ref": task.get("source_ref"),
                            "suggested_test_command": task.get("suggested_test_command") or "",
                            "raw": task,
                        }
                    )
                return rows
            rows = []
            seen: set[str] = set()
            candidates: list[dict[str, Any]] = []
            sections = payload.get("sections")
            if isinstance(sections, dict):
                for section_name, section in sections.items():
                    if isinstance(section, dict) and isinstance(section.get("rows"), list):
                        for row in section.get("rows") or []:
                            if isinstance(row, dict):
                                item = dict(row)
                                item.setdefault("section", section_name)
                                candidates.append(item)
            full = payload.get("full_throttle")
            if isinstance(full, dict) and isinstance(full.get("rows"), list):
                for row in full.get("rows") or []:
                    if isinstance(row, dict):
                        candidates.append(row)
            for row in candidates:
                detector = str(row.get("scanner_id") or row.get("detector") or row.get("queue_id") or "").strip()
                key = f"{detector}:{row.get('section') or ''}:{row.get('proof_status') or ''}"
                if key in seen:
                    continue
                seen.add(key)
                rows.append(
                    {
                        "detector_slug": detector,
                        "language": str(row.get("language") or row.get("backend") or ""),
                        "proof_needed": row.get("claim_guard") or row.get("proof_needed") or row.get("proof_status"),
                        "blockers": row.get("blockers") if isinstance(row.get("blockers"), list) else [],
                        "source_refs": row.get("source_refs") if isinstance(row.get("source_refs"), list) else [],
                        "file_hints": row.get("source_paths") if isinstance(row.get("source_paths"), list) else [],
                        "task_id": row.get("task_id") or row.get("queue_id"),
                        "detector_action_graph_obligation": row.get("detector_action_graph_obligation")
                        or row.get("obligation_id"),
                        "queue_ref": "",
                        "suggested_test_command": row.get("suggested_test_command") or "",
                        "raw": row,
                    }
                )
            return rows

        def _template_refs() -> list[str]:
            refs: list[str] = []
            for root in (self.repo_root / "reference" / "poc_templates", self.repo_root / "templates"):
                if root.is_dir():
                    refs.extend(_repo_ref(path) for path in sorted(root.glob("*.t.sol*")))
            return _unique_bounded(refs, MAX_SOLIDITY_DETECTOR_PROOF_REFS)

        def _select_template(detector: str, graph: dict[str, Any] | None, templates: list[str]) -> str:
            if not templates:
                return ""
            text = " ".join(
                [
                    detector,
                    json.dumps(graph or {}, sort_keys=True),
                ]
            ).lower()
            preferences = [
                ("reentr", "reentrancy"),
                ("oracle", "oracle"),
                ("price", "oracle"),
                ("role", "role"),
                ("access", "role"),
                ("pause", "pause"),
                ("slippage", "slippage"),
                ("liquidation", "liquidation"),
                ("underflow", "underflow"),
                ("account", "accounting"),
                ("share", "accounting"),
                ("bridge", "cross-chain"),
                ("cross", "cross-chain"),
                ("init", "init"),
            ]
            for needle, template_hint in preferences:
                if needle in text:
                    for template in templates:
                        if template_hint in template.lower():
                            return template
            return templates[0]

        def _manifest_rows() -> tuple[dict[str, list[dict[str, Any]]], list[dict[str, Any]]]:
            out: dict[str, list[dict[str, Any]]] = {}
            rows: list[dict[str, Any]] = []
            poc_root = workspace / "poc_execution"
            if not poc_root.is_dir():
                return out, rows
            def _path_inside_workspace(raw: object) -> bool | None:
                text = str(raw if raw is not None else "").strip()
                if not text:
                    return None
                try:
                    candidate = Path(text).expanduser()
                    resolved = candidate.resolve() if candidate.is_absolute() else (workspace / candidate).resolve()
                    resolved.relative_to(workspace)
                    return True
                except (OSError, RuntimeError, ValueError):
                    return False
            for path in sorted(poc_root.glob("**/execution_manifest.json")):
                payload = _load_json(path)
                if not isinstance(payload, dict):
                    continue
                candidate_id = _scrub_text(payload.get("candidate_id"), max_chars=160) or path.parent.name
                commands = payload.get("commands_attempted") if isinstance(payload.get("commands_attempted"), list) else []
                final_result = _scrub_text(payload.get("final_result") or payload.get("result"), max_chars=80).lower()
                impact_assertion = _scrub_text(payload.get("impact_assertion"), max_chars=80).lower()
                evidence_class = _scrub_text(payload.get("evidence_class"), max_chars=120)
                command_evidence_counts = _manifest_command_evidence_counts(payload)
                command_count = command_evidence_counts.get("commands_attempted_count", 0)
                structured_command_count = command_evidence_counts.get("structured_command_count", 0)
                passing_command_count = command_evidence_counts.get("passing_command_count", 0)
                command_status_counts: dict[str, int] = {}
                command_cwd_workspace_matches = True
                for command in commands:
                    if isinstance(command, dict):
                        status = _scrub_text(command.get("status"), max_chars=80) or "unknown"
                        command_status_counts[status] = command_status_counts.get(status, 0) + 1
                        cwd_inside = _path_inside_workspace(command.get("cwd"))
                        if cwd_inside is False:
                            command_cwd_workspace_matches = False
                manifest_workspace_inside = _path_inside_workspace(payload.get("workspace"))
                canonical_execution_class = evidence_class == "executed_with_manifest"
                proved = _is_strict_proved_execution_manifest(payload)
                if proved:
                    execution_evidence = "proved_impact_evidence"
                elif canonical_execution_class and structured_command_count > 0:
                    execution_evidence = "executed_with_manifest"
                elif command_count > 0:
                    execution_evidence = "manifest_present_unproved"
                else:
                    execution_evidence = "missing_command_evidence"
                row = {
                    "candidate_id": candidate_id,
                    "manifest_ref": _workspace_ref(path),
                    "proof_task_id": _scrub_text(
                        payload.get("proof_task_id") or payload.get("proof_queue_task_id"),
                        max_chars=120,
                    ),
                    "proof_queue_relationship": _scrub_text(payload.get("proof_queue_relationship"), max_chars=120),
                    "detector_slug": _scrub_text(payload.get("detector_slug"), max_chars=160),
                    "detector_obligation": _scrub_text(
                        payload.get("detector_obligation") or payload.get("detector_action_graph_obligation"),
                        max_chars=120,
                    ),
                    "detector_action_graph": _workspace_ref(
                        payload.get("detector_action_graph") or payload.get("detector_action_graph_path")
                    ),
                    "detector_action_graph_sha256": _scrub_text(payload.get("detector_action_graph_sha256"), max_chars=80),
                    "manifest_workspace_ref": _workspace_ref(payload.get("workspace")),
                    "manifest_workspace_matches": True if manifest_workspace_inside is None else manifest_workspace_inside,
                    "command_cwd_workspace_matches": command_cwd_workspace_matches,
                    "final_result": final_result,
                    "impact_assertion": impact_assertion,
                    "evidence_class": evidence_class,
                    "commands_attempted_count": command_count,
                    "structured_command_count": structured_command_count,
                    "passing_command_count": passing_command_count,
                    "command_status_counts": dict(sorted(command_status_counts.items())),
                    "execution_evidence": execution_evidence,
                    "proof_counted": proved,
                }
                rows.append(row)
                for key in (
                    candidate_id,
                    path.parent.name,
                    row.get("proof_task_id"),
                    row.get("detector_slug"),
                    f"{row.get('detector_slug')}:{row.get('detector_obligation')}"
                    if row.get("detector_slug") and row.get("detector_obligation")
                    else "",
                ):
                    slugged = _slug(key)
                    if slugged:
                        out.setdefault(slugged, []).append(row)
            return out, rows

        def _repo_or_workspace_ref(path: Path) -> str:
            try:
                return path.resolve().relative_to(workspace).as_posix()
            except ValueError:
                pass
            try:
                return path.resolve().relative_to(self.repo_root.resolve()).as_posix()
            except ValueError:
                return path.name

        def _fixture_smoke_int(payload: dict[str, Any], *keys: str) -> int | None:
            for key in keys:
                if key not in payload:
                    continue
                value = payload.get(key)
                if isinstance(value, bool):
                    return None
                try:
                    return int(value)
                except (TypeError, ValueError):
                    return None
            return None

        def _fixture_smoke_status_ok(payload: dict[str, Any]) -> bool:
            status = str(payload.get("status") or payload.get("result") or "").strip().lower()
            return status in {
                "pass",
                "passed",
                "ok",
                "success",
                "clean",
                "smoke_pass",
                "passed_smoke",
                "passed_vulnerable_clean_smoke",
            }

        def _fixture_smoke_is_graveyard(path: Path) -> bool:
            parts = {part.lower() for part in path.parts}
            return "wave_graveyard" in parts or any(part.endswith("_broken") for part in parts)

        def _fixture_ref(payload: dict[str, Any], smoke_path: Path, *keys: str) -> str:
            for key in keys:
                raw = payload.get(key)
                if not isinstance(raw, str) or not raw.strip():
                    continue
                candidate = Path(raw.strip()).expanduser()
                candidates = [candidate.resolve()] if candidate.is_absolute() else [
                    (self.repo_root / candidate).resolve(),
                    (workspace / candidate).resolve(),
                    (smoke_path.parent / candidate).resolve(),
                ]
                for resolved in candidates:
                    try:
                        resolved.relative_to(self.repo_root.resolve())
                    except ValueError:
                        try:
                            resolved.relative_to(workspace)
                        except ValueError:
                            continue
                    if resolved.exists():
                        return _repo_or_workspace_ref(resolved)
            return ""

        def _fixture_smoke_command(payload: dict[str, Any], key: str) -> str:
            commands = payload.get("commands") if isinstance(payload.get("commands"), dict) else {}
            direct = payload.get(f"{key}_command")
            nested = commands.get(key) if isinstance(commands, dict) else ""
            fallback = payload.get("command") if key == "combined" else ""
            return _scrub_text(direct or nested or fallback, max_chars=260)

        def _fixture_smoke_detector_binding_blockers(
            payload: dict[str, Any],
            detector_key: str,
        ) -> list[str]:
            expected = _slug(detector_key)
            if not expected:
                return []
            observed: set[str] = set()
            for key in ("detector_slug", "suggested_detector_slug", "pattern", "pattern_id", "argument"):
                value = str(payload.get(key) or "").strip()
                if value:
                    observed.add(_slug(value))
            detector_path_text = str(payload.get("detector_path") or "").strip()
            if detector_path_text:
                observed.add(_slug(Path(detector_path_text).stem))
            observed.discard("")
            if observed and expected not in observed:
                return [
                    "fixture_smoke_detector_binding_mismatch: "
                    + ",".join(_unique_bounded(sorted(observed), 5))
                ]
            return []

        def _fixture_smoke_evidence(smoke_path: Path, payload: dict[str, Any], detector_key: str) -> dict[str, Any]:
            schema = _scrub_text(payload.get("schema"), max_chars=120)
            status = _scrub_text(payload.get("status") or payload.get("result"), max_chars=80)
            detector_path_text = str(payload.get("detector_path") or "").strip()
            detector_path_is_graveyard = _fixture_smoke_is_graveyard(smoke_path)
            if detector_path_text:
                detector_path_is_graveyard = detector_path_is_graveyard or any(
                    part in detector_path_text.lower()
                    for part in ("wave_graveyard", "_broken/")
                )
            positive_hits = _fixture_smoke_int(payload, "positive_hits", "vulnerable_hits", "positive_match_count")
            clean_hits = _fixture_smoke_int(payload, "clean_hits", "negative_hits", "clean_match_count")
            positive_fixture = _fixture_ref(
                payload,
                smoke_path,
                "positive_fixture",
                "positive_fixture_path",
                "vulnerable_fixture",
                "vulnerable_fixture_path",
            )
            clean_fixture = _fixture_ref(
                payload,
                smoke_path,
                "clean_fixture",
                "clean_fixture_path",
                "negative_fixture",
                "negative_fixture_path",
            )
            blockers: list[str] = []
            if schema not in {
                "auditooor.canonical_detector_fixture_smoke.v1",
                "auditooor.scanner_wiring_row_smoke.v1",
            }:
                blockers.append("fixture_smoke_schema_unrecognized")
            if detector_path_is_graveyard:
                blockers.append("fixture_smoke_detector_path_graveyard_or_broken")
            if not _fixture_smoke_status_ok(payload):
                blockers.append("fixture_smoke_status_not_pass")
            if positive_hits is None or clean_hits is None:
                blockers.append("fixture_smoke_hit_counts_missing_or_invalid")
            elif positive_hits <= 0:
                blockers.append("fixture_smoke_positive_hits_missing")
            elif clean_hits != 0:
                blockers.append("fixture_smoke_clean_hits_nonzero")
            blockers.extend(_fixture_smoke_detector_binding_blockers(payload, detector_key))
            if not positive_fixture:
                blockers.append("fixture_smoke_positive_fixture_missing")
            if not clean_fixture:
                blockers.append("fixture_smoke_clean_fixture_missing")
            passed = not blockers
            return {
                "status": "fixture_smoke_passed" if passed else "fixture_smoke_not_valid",
                "smoke_status": status,
                "schema": schema,
                "smoke_ref": _repo_or_workspace_ref(smoke_path),
                "detector_slug": _scrub_text(
                    payload.get("detector_slug") or payload.get("fixture_id") or detector_key,
                    max_chars=160,
                ),
                "pattern": _scrub_text(payload.get("pattern") or payload.get("pattern_id"), max_chars=160),
                "detector_path": _workspace_ref(detector_path_text)
                or _scrub_text(detector_path_text, max_chars=220),
                "positive_fixture": positive_fixture,
                "clean_fixture": clean_fixture,
                "positive_hits": positive_hits,
                "clean_hits": clean_hits,
                "coverage_claim": _scrub_text(
                    payload.get("coverage_claim") or "detector_fixture_smoke_only",
                    max_chars=120,
                ),
                "promotion_allowed": False,
                "source_promotion_allowed": bool(payload.get("promotion_allowed")),
                "submission_posture": "NOT_SUBMIT_READY",
                "commands": {
                    key: value
                    for key, value in {
                        "positive": _fixture_smoke_command(payload, "positive"),
                        "clean": _fixture_smoke_command(payload, "clean"),
                        "combined": _fixture_smoke_command(payload, "combined"),
                    }.items()
                    if value
                },
                "blockers": blockers,
                "advisory_only": True,
                "evidence_class": "fixture_smoke_only",
                "does_not_prove_exploit_impact": True,
            }

        def _fixture_smoke_index() -> dict[str, list[dict[str, Any]]]:
            roots = _unique_path_list(
                [
                    self.repo_root / "detectors" / "fixtures",
                    workspace / "detectors" / "fixtures",
                ]
            )
            index: dict[str, list[dict[str, Any]]] = {}
            seen_paths: set[str] = set()
            for root in roots:
                if not root.is_dir():
                    continue
                for smoke_path in sorted(root.rglob("*.json")):
                    if smoke_path.name != "smoke.json" and not smoke_path.name.endswith("_smoke.json"):
                        continue
                    if str(smoke_path) in seen_paths:
                        continue
                    seen_paths.add(str(smoke_path))
                    payload = _load_json(smoke_path)
                    if not isinstance(payload, dict):
                        continue
                    keys: set[str] = set()
                    for candidate in (
                        payload.get("detector_slug"),
                        payload.get("fixture_id"),
                        payload.get("pattern"),
                        payload.get("pattern_id"),
                        payload.get("argument"),
                        smoke_path.parent.name,
                    ):
                        key = _slug(candidate)
                        if key:
                            keys.add(key)
                    detector_path_text = str(payload.get("detector_path") or "").strip()
                    if detector_path_text:
                        detector_key = _slug(Path(detector_path_text).stem)
                        if detector_key:
                            keys.add(detector_key)
                    for key in keys:
                        index.setdefault(key, []).append(_fixture_smoke_evidence(smoke_path, payload, key))
            for key, values in index.items():
                values.sort(
                    key=lambda item: (
                        0 if item.get("status") == "fixture_smoke_passed" else 1,
                        str(item.get("smoke_ref") or ""),
                    )
                )
            return index

        graphs_by_detector, graph_refs, graph_warnings = _load_graphs()
        queue_payload, queue_rel, queue_ref = _queue_payload()
        queue_marker_freshness = (
            _queue_freshness_marker(queue_rel, queue_ref)
            if queue_payload is not None
            else {
                "status": "missing_proof_queue",
                "reason": "proof queue missing",
                "marker_ref": _workspace_ref(workspace / ".auditooor" / "proof_obligation_queue.freshness.json"),
                "queue_ref": queue_ref,
                "stale": True,
                "safe_to_treat_as_current": False,
                "warnings": ["proof_queue_missing"],
                "freshness_basis": "missing_proof_queue",
            }
        )
        queue_marker_safe = bool(queue_marker_freshness.get("safe_to_treat_as_current"))
        if queue_payload is None and not graphs_by_detector:
            return _empty(
                "detector_proof_artifacts_missing",
                reason="missing proof_obligation_queue.json / detector_proof_gap_queue.json and detector action graph artifacts",
            )
        if queue_payload is None:
            return _empty(
                "detector_proof_queue_missing",
                reason="missing proof_obligation_queue.json or detector_proof_gap_queue.json",
            )
        raw_queue_rows = _queue_rows(queue_payload)
        manifests, manifest_records = _manifest_rows()
        templates = _template_refs()
        smoke_by_detector = _fixture_smoke_index()
        non_solidity = 0
        rows: list[dict[str, Any]] = []

        def _unique_manifest_rows(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
            out: list[dict[str, Any]] = []
            seen: set[str] = set()
            for item in items:
                key = str(item.get("manifest_ref") or item.get("candidate_id") or "")
                if not key or key in seen:
                    continue
                seen.add(key)
                out.append(item)
            return out

        def _manifest_match_summary(item: dict[str, Any]) -> dict[str, Any]:
            return {
                key: value
                for key, value in {
                    "candidate_id": item.get("candidate_id"),
                    "manifest_ref": item.get("manifest_ref"),
                    "proof_task_id": item.get("proof_task_id"),
                    "detector_slug": item.get("detector_slug"),
                    "detector_obligation": item.get("detector_obligation"),
                    "execution_evidence": item.get("execution_evidence"),
                    "proof_counted": item.get("proof_counted"),
                }.items()
                if value not in ("", [], {}, None)
            }

        def _manifest_binding_conflicts(
            raw_row: dict[str, Any],
            detector: str,
            obligation: str,
            graph: dict[str, Any] | None,
            manifest: dict[str, Any],
        ) -> list[str]:
            if not manifest:
                return []
            conflicts: list[str] = []
            expected_task = _scrub_text(raw_row.get("task_id"), max_chars=120)
            observed_task = _scrub_text(manifest.get("proof_task_id"), max_chars=120)
            if observed_task and expected_task and _slug(observed_task) != _slug(expected_task):
                conflicts.append("execution_manifest_proof_task_id_conflict")

            expected_detector = _slug(detector)
            observed_detector = _slug(manifest.get("detector_slug"))
            if observed_detector and expected_detector and observed_detector != expected_detector:
                conflicts.append("execution_manifest_detector_slug_conflict")

            expected_obligation = _slug(obligation)
            observed_obligation = _slug(manifest.get("detector_obligation"))
            if observed_obligation and expected_obligation and observed_obligation != expected_obligation:
                conflicts.append("execution_manifest_detector_obligation_conflict")

            expected_graph = str((graph or {}).get("graph_ref") or "").strip()
            observed_graph = str(manifest.get("detector_action_graph") or "").strip()
            if observed_graph and expected_graph:
                normalized_observed = observed_graph.removeprefix("<workspace>/").lstrip("/")
                normalized_expected = expected_graph.removeprefix("<workspace>/").lstrip("/")
                if normalized_observed and normalized_expected and normalized_observed != normalized_expected:
                    conflicts.append("execution_manifest_detector_action_graph_conflict")
            expected_graph_sha = str((graph or {}).get("graph_sha256") or "").strip()
            observed_graph_sha = str(manifest.get("detector_action_graph_sha256") or "").strip()
            if observed_graph_sha and expected_graph_sha and observed_graph_sha != expected_graph_sha:
                conflicts.append("execution_manifest_detector_action_graph_sha256_conflict")
            if manifest.get("manifest_workspace_matches") is False:
                conflicts.append("execution_manifest_workspace_conflict")
            if manifest.get("command_cwd_workspace_matches") is False:
                conflicts.append("execution_manifest_command_cwd_conflict")
            return conflicts

        def _resolve_manifest_match(
            explicit_candidates: list[object],
            fallback_candidates: list[object],
        ) -> tuple[dict[str, Any], str, str, list[dict[str, Any]]]:
            explicit_matches: list[dict[str, Any]] = []
            explicit_keys: list[str] = []
            for candidate in explicit_candidates:
                candidate_key = _slug(candidate)
                if not candidate_key:
                    continue
                matched = manifests.get(candidate_key, [])
                if matched:
                    explicit_matches.extend(matched)
                    explicit_keys.append(candidate_key)
            unique_explicit = _unique_manifest_rows(explicit_matches)
            if len(unique_explicit) == 1:
                return (
                    unique_explicit[0],
                    explicit_keys[0] if explicit_keys else "",
                    "explicit_proof_task_or_detector_metadata",
                    [],
                )
            if len(unique_explicit) > 1:
                return (
                    {},
                    ",".join(_unique_bounded(explicit_keys, 6)),
                    "ambiguous_execution_manifest_link",
                    unique_explicit,
                )

            for candidate in fallback_candidates:
                candidate_key = _slug(candidate)
                if not candidate_key:
                    continue
                unique_fallback = _unique_manifest_rows(manifests.get(candidate_key, []))
                if len(unique_fallback) == 1:
                    return unique_fallback[0], candidate_key, "candidate_id_or_detector_slug_fallback", []
                if len(unique_fallback) > 1:
                    return (
                        {},
                        candidate_key,
                        "ambiguous_execution_manifest_link",
                        unique_fallback,
                    )
            return {}, "", "missing", []

        for raw_row in raw_queue_rows:
            detector = str(raw_row.get("detector_slug") or "").strip()
            detector_key = _slug(detector)
            if detector_filter and detector_key != _slug(detector_filter):
                continue
            graph = graphs_by_detector.get(detector_key)
            file_hints = [
                _workspace_ref(item) or _scrub_text(item, max_chars=220)
                for item in (raw_row.get("file_hints") or [])
                if str(item or "").strip()
            ][:8]
            language_text = str(raw_row.get("language") or "").lower()
            graph_file = ""
            if graph:
                graph_file = str((graph.get("detector_hit") or {}).get("file_path") or "")
            is_solidity = (
                "solidity" in language_text
                or language_text in {"sol", "evm"}
                or any(".sol" in str(item).lower() for item in file_hints)
                or ".sol" in graph_file.lower()
            )
            if not is_solidity:
                non_solidity += 1
                continue
            template = _select_template(detector, graph, templates)
            obligation = str(raw_row.get("detector_action_graph_obligation") or "").strip()
            explicit_manifest_candidates = [raw_row.get("task_id")]
            if obligation:
                explicit_manifest_candidates.append(f"{detector}:{obligation}")
            fallback_manifest_candidates = [detector]
            manifest, manifest_join_key, manifest_join, ambiguous_manifest_matches = _resolve_manifest_match(
                explicit_manifest_candidates,
                fallback_manifest_candidates,
            )
            manifest_binding_conflicts = _manifest_binding_conflicts(
                raw_row,
                detector,
                obligation,
                graph,
                manifest,
            )
            smoke_records = smoke_by_detector.get(detector_key, [])
            smoke_record = smoke_records[0] if smoke_records else {}
            fixture_smoke_status = str(smoke_record.get("status") or "missing")
            execution_evidence = str(manifest.get("execution_evidence") or "missing")
            if ambiguous_manifest_matches:
                execution_evidence = "ambiguous_execution_manifest_link"
            if manifest_binding_conflicts:
                execution_evidence = "execution_manifest_metadata_conflict"
            weak_fallback_manifest = bool(
                manifest
                and manifest_join == "candidate_id_or_detector_slug_fallback"
                and (raw_row.get("task_id") or obligation)
            )
            if weak_fallback_manifest:
                execution_evidence = "fallback_manifest_unbound"
            blockers = [
                _scrub_text(item, max_chars=160)
                for item in (raw_row.get("blockers") or [])
                if _scrub_text(item, max_chars=160)
            ][:8]
            if not queue_marker_safe:
                blockers.append("proof_queue_freshness_not_current")
            if fixture_smoke_status != "fixture_smoke_passed":
                blockers.append("fixture_smoke_evidence_missing_or_invalid")
            if not graph:
                blockers.append("missing_detector_action_graph")
            if not template:
                blockers.append("missing_solidity_poc_template")
            if ambiguous_manifest_matches:
                blockers.append("ambiguous_execution_manifest_link")
            elif not manifest:
                blockers.append("missing_execution_manifest")
            elif manifest_binding_conflicts:
                blockers.extend(manifest_binding_conflicts)
            elif weak_fallback_manifest:
                blockers.append("execution_manifest_fallback_not_proof_task_bound")
            elif manifest.get("proof_counted"):
                blockers.append("advisory_not_submission_ready")
            elif execution_evidence == "executed_with_manifest":
                blockers.append("execution_manifest_not_proved_impact")
            elif execution_evidence == "manifest_present_unproved":
                blockers.append("execution_manifest_not_canonical_executed_evidence")
            else:
                blockers.append("execution_manifest_missing_command_evidence")
            blockers.append("advisory_not_submission_ready")
            blockers = _unique_bounded([item for item in blockers if item], 12)
            if ambiguous_manifest_matches:
                proof_readiness = "blocked"
            elif manifest_binding_conflicts:
                proof_readiness = "blocked"
            elif manifest.get("proof_counted") and not weak_fallback_manifest:
                proof_readiness = "proved_impact_evidence"
            elif manifest:
                proof_readiness = "executed_with_manifest" if execution_evidence == "executed_with_manifest" else "blocked"
            elif graph and template:
                proof_readiness = "ready_for_foundry_poc"
            else:
                proof_readiness = "blocked"
            underlying_proof_readiness = proof_readiness
            if not queue_marker_safe:
                proof_readiness = "blocked"
            next_command = _scrub_text(raw_row.get("suggested_test_command"), max_chars=300)
            if not next_command:
                next_command = "forge test --match-test testExploitImpact"
            source_refs = _unique_bounded(
                [
                    ref
                    for ref in [
                        queue_ref,
                        str(raw_row.get("queue_ref") or ""),
                        *(str(item) for item in (raw_row.get("source_refs") or [])),
                        *(str(item) for item in file_hints),
                        str(graph.get("graph_ref") if isinstance(graph, dict) else ""),
                    ]
                    if ref
                ],
                MAX_SOLIDITY_DETECTOR_PROOF_REFS,
            )
            row = {
                "detector_slug": _scrub_text(detector, max_chars=160) or detector_key,
                "language": "solidity",
                "status": proof_readiness,
                "proof_readiness": proof_readiness,
                "underlying_proof_readiness": underlying_proof_readiness
                if underlying_proof_readiness != proof_readiness
                else "",
                "execution_evidence": execution_evidence,
                "submission_posture": "NOT_SUBMIT_READY",
                "advisory_only": True,
                "candidate_not_submit_ready": True,
                "promotion_allowed": False,
                "safe_to_treat_as_current": queue_marker_safe,
                "artifact_freshness_status": str(
                    queue_marker_freshness.get("status") or "unknown_freshness_status"
                ),
                "derived_from_stale_artifact": not queue_marker_safe,
                "fixture_smoke_status": fixture_smoke_status,
                "task_id": _scrub_text(raw_row.get("task_id"), max_chars=120),
                "proof_needed": _scrub_text(raw_row.get("proof_needed"), max_chars=260),
                "blockers": blockers,
                "source_refs": [_workspace_ref(ref) or _scrub_text(ref, max_chars=220) for ref in source_refs],
                "file_hints": file_hints,
                "template_ref": template,
                "generated_poc_scaffold_status": "scaffold_only_not_executed",
                "poc_execution_record_status": "ambiguous"
                if ambiguous_manifest_matches
                else "metadata_conflict"
                if manifest_binding_conflicts
                else "present"
                if manifest
                else "missing",
                "execution_manifest_join": manifest_join,
                "execution_manifest_join_key": manifest_join_key,
                "execution_manifest_match_count": len(ambiguous_manifest_matches) if ambiguous_manifest_matches else 1 if manifest else 0,
                "impact_contract_validation": "missing",
                "pre_submit_check_status": "not_run",
                "submit_ready_gate_status": "blocked",
                "next_command": next_command,
                "action_graph": graph or {},
                "execution_manifest": manifest,
                "execution_manifest_binding_conflicts": manifest_binding_conflicts,
                "execution_manifest_matches": [
                    _manifest_match_summary(item) for item in ambiguous_manifest_matches[:8]
                ],
                "fixture_smoke": smoke_record,
                "fixture_smoke_matches": smoke_records[:5],
            }
            row = {key: value for key, value in row.items() if value not in ("", [], {}, None)}
            rows.append(row)

        def _matches(row: dict[str, Any]) -> bool:
            if proof_only and row.get("execution_evidence") != "proved_impact_evidence":
                return False
            if status_filter:
                statuses = {
                    str(row.get("status") or "").lower(),
                    str(row.get("proof_readiness") or "").lower(),
                    str(row.get("execution_evidence") or "").lower(),
                }
                if status_filter not in statuses:
                    return False
            return True

        matched = [row for row in rows if _matches(row)]
        returned = matched[:row_limit]
        readiness_counts: dict[str, int] = {}
        evidence_counts: dict[str, int] = {}
        for row in rows:
            readiness = str(row.get("proof_readiness") or "unknown")
            evidence = str(row.get("execution_evidence") or "unknown")
            readiness_counts[readiness] = readiness_counts.get(readiness, 0) + 1
            evidence_counts[evidence] = evidence_counts.get(evidence, 0) + 1
        fixture_smoke_counts: dict[str, int] = {}
        for row in rows:
            smoke_status = str(row.get("fixture_smoke_status") or "missing")
            fixture_smoke_counts[smoke_status] = fixture_smoke_counts.get(smoke_status, 0) + 1

        base = {
            "schema": SOLIDITY_DETECTOR_PROOF_CONTEXT_SCHEMA,
            "kind": "solidity_detector_proof_context",
            "workspace_path": workspace_label,
            "degraded": False,
            "advisory_only": True,
            "claim_scope": "solidity_detector_fixture_evidence_only",
            "submission_posture": "NOT_SUBMIT_READY",
            "candidate_not_submit_ready": True,
            "promotion_allowed": False,
            "proof_boundary": (
                "Rows are detector-to-proof worklist/evidence-overlay records. "
                "Only execution_evidence=proved_impact_evidence marks local impact proof evidence, and even that is not submission readiness."
            ),
            "claim_guard": (
                "Do NOT infer exploitability, impact, severity, duplicate/OOS clearance, or submission readiness from detector hits, "
                "templates, action graphs, proof queues, or generated PoC scaffolds."
            ),
            "rows": returned,
            "summary": {
                "queue_rows_seen": len(raw_queue_rows),
                "non_solidity_rows_filtered": non_solidity,
                "rows_total": len(rows),
                "rows_matched": len(matched),
                "rows_returned": len(returned),
                "ready_for_foundry_poc_count": sum(1 for row in rows if row.get("proof_readiness") == "ready_for_foundry_poc"),
                "executed_with_manifest_count": sum(1 for row in rows if row.get("proof_readiness") == "executed_with_manifest"),
                "proved_impact_evidence_count": sum(1 for row in rows if row.get("execution_evidence") == "proved_impact_evidence"),
                "current_safe_proved_impact_evidence_count": sum(
                    1
                    for row in rows
                    if row.get("execution_evidence") == "proved_impact_evidence"
                    and row.get("safe_to_treat_as_current") is True
                ),
                "ambiguous_execution_manifest_count": sum(
                    1 for row in rows if row.get("execution_manifest_join") == "ambiguous_execution_manifest_link"
                ),
                "execution_manifest_metadata_conflict_count": sum(
                    1 for row in rows if row.get("execution_evidence") == "execution_manifest_metadata_conflict"
                ),
                "graph_count": len(graphs_by_detector),
                "execution_manifest_count": len(
                    {str(row.get("manifest_ref") or "") for row in manifest_records if row.get("manifest_ref")}
                ),
                "fixture_smoke_passed_count": sum(
                    1 for row in rows if row.get("fixture_smoke_status") == "fixture_smoke_passed"
                ),
                "readiness_counts": dict(sorted(readiness_counts.items())),
                "execution_evidence_counts": dict(sorted(evidence_counts.items())),
                "fixture_smoke_counts": dict(sorted(fixture_smoke_counts.items())),
            },
            "filters": {
                "detector_slug": detector_filter,
                "status": status_filter,
                "proof_only": proof_only,
            },
            "freshness": {
                "detector_artifacts": {
                    "status": "present",
                    "queue_ref": queue_ref,
                    "queue_source": queue_rel,
                    "graph_refs": graph_refs[:MAX_SOLIDITY_DETECTOR_PROOF_REFS],
                    "graph_warning_count": len(graph_warnings),
                    "safe_to_treat_as_current": queue_marker_safe,
                    "freshness_basis": "existing_workspace_detector_artifacts_plus_proof_queue_freshness_marker",
                },
                "proof_obligation_queue_marker": queue_marker_freshness,
            },
            "limits": _limits(),
            "privacy_guards": privacy_guards,
            "source_refs": [
                "tools/detector-hit-action-graph.py",
                "tools/audit-hacker-logic-bridge.py",
                "tools/proof-obligation-queue.py",
                "tools/poc-execution-record.py",
                "reference/poc_templates/",
            ],
        }
        return _finalize(base)

    def vault_solidity_changelog_drift_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded advisory context from the Solidity changelog drift miner."""
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_label = _engage_report_workspace_label(workspace_arg, default="workspace")
        limit = min(MAX_CONTEXT_ITEMS, _clamp_limit(kwargs.get("limit"), default=8))
        privacy_guards = {
            "repo_relative_refs_only": True,
            "workspace_relative_refs_only": True,
            "absolute_local_paths_blocked": True,
            "secret_patterns_blocked": True,
            "raw_source_bodies_not_returned": True,
            "advisory_only": True,
        }

        def _finalize(base: dict[str, Any]) -> dict[str, Any]:
            base.setdefault("schema", SOLIDITY_CHANGELOG_DRIFT_CONTEXT_SCHEMA)
            base.setdefault("kind", "solidity_changelog_drift_context")
            base.setdefault("workspace_path", workspace_label)
            base.setdefault("degraded", False)
            base.setdefault("advisory_only", True)
            base.setdefault("submission_posture", "NOT_SUBMIT_READY")
            base.setdefault("claim_scope", "changelog_source_drift_worklist_only")
            base.setdefault("promotion_allowed", False)
            base.setdefault("does_not_claim_exploitability", True)
            base.setdefault("does_not_claim_impact", True)
            base.setdefault("does_not_claim_severity", True)
            base.setdefault("does_not_claim_duplicate_clearance", True)
            base.setdefault("does_not_claim_oos_clearance", True)
            base.setdefault("does_not_claim_submission_readiness", True)
            base.setdefault("claims", [])
            base.setdefault("verdicts", [])
            base.setdefault("ranked_exposed_call_sites", [])
            base.setdefault("ranked_call_sites", [])
            base.setdefault("privacy_guards", privacy_guards)
            base.setdefault(
                "advisory_boundary",
                "solidity_changelog_drift_worklist_only_not_exploitability_or_submission_readiness",
            )
            base.setdefault(
                "claim_guard",
                "Do NOT infer exploitability, impact, severity, duplicate/OOS clearance, or submission readiness from changelog drift miner rows without project-specific runnable proof and pre-submit review.",
            )
            base["token_estimate"] = _token_estimate(base)
            digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{SOLIDITY_CHANGELOG_DRIFT_CONTEXT_SCHEMA}:solidity_changelog_drift:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        def _empty(error: str, *, reason: str = "") -> dict[str, Any]:
            return _finalize(
                {
                    "error": error,
                    "degraded": True,
                    "degraded_reason": reason or error,
                    "summary": {
                        "claim_count": 0,
                        "verdict_count": 0,
                        "exposed_call_site_count": 0,
                        "call_site_count": 0,
                    },
                    "limits": {"max_claims": limit, "max_call_sites": limit},
                    "source_refs": ["tools/changelog-source-drift-miner.py"],
                }
            )

        if not workspace_arg:
            return _empty("workspace_path_required")
        try:
            workspace = Path(str(workspace_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return _empty("invalid_workspace_path")
        workspace_label = _engage_report_workspace_label(workspace, default=workspace_label)
        if not workspace.is_dir():
            return _empty("workspace_not_found")

        try:
            miner = _load_tool_module("changelog-source-drift-miner")
        except Exception as exc:  # noqa: BLE001 - surface degraded MCP envelope.
            return _empty("miner_unavailable", reason=str(exc))

        mine = getattr(miner, "mine", None)
        if not callable(mine):
            return _empty("miner_missing_mine_callable")
        try:
            payload = mine(workspace, limit=limit)
        except Exception as exc:  # noqa: BLE001 - worklist callable should degrade.
            return _empty("miner_execution_failed", reason=str(exc))
        if not isinstance(payload, dict):
            return _empty("miner_returned_non_object")

        def _safe_rel_ref(value: object) -> str:
            ref = _workspace_ref(value)
            return ref or ""

        def _bounded_claim(claim: object) -> dict[str, Any]:
            if not isinstance(claim, dict):
                return {}
            return {
                "claim_id": _safe_text_item(claim.get("claim_id"), max_chars=80) or "",
                "source_path": _safe_rel_ref(claim.get("source_path")),
                "line": claim.get("line", 0),
                "text": _safe_text_item(claim.get("text"), max_chars=360) or "",
                "keywords": _bounded_string_list(claim.get("keywords"), MAX_CONTEXT_ITEMS, max_chars=40),
                "primitives": _bounded_string_list(claim.get("primitives"), MAX_CONTEXT_ITEMS, max_chars=80),
                "assumption_terms": _bounded_string_list(claim.get("assumption_terms"), MAX_CONTEXT_ITEMS, max_chars=40),
            }

        def _bounded_verdict(verdict: object) -> dict[str, Any]:
            if not isinstance(verdict, dict):
                return {}
            return {
                "claim_id": _safe_text_item(verdict.get("claim_id"), max_chars=80) or "",
                "verdict": _safe_text_item(verdict.get("verdict"), max_chars=80) or "",
                "reason": _safe_text_item(verdict.get("reason"), max_chars=240) or "",
                "consumer_count": verdict.get("consumer_count", 0),
                "exposed_call_site_ids": _bounded_string_list(verdict.get("exposed_call_site_ids"), MAX_CONTEXT_ITEMS, max_chars=80),
            }

        def _bounded_site(site: object) -> dict[str, Any]:
            if not isinstance(site, dict):
                return {}
            file_path = _safe_rel_ref(site.get("file_path"))
            line = site.get("line", 0)
            source_ref = f"{file_path}:{line}" if file_path and line else file_path
            return {
                "rank": site.get("rank", 0),
                "call_site_id": _safe_text_item(site.get("call_site_id"), max_chars=80) or "",
                "claim_id": _safe_text_item(site.get("claim_id"), max_chars=80) or "",
                "verdict": _safe_text_item(site.get("verdict"), max_chars=80) or "",
                "score": site.get("score", 0),
                "source_ref": source_ref,
                "file_path": file_path,
                "line": line,
                "contract": _safe_text_item(site.get("contract"), max_chars=120) or "",
                "function": _safe_text_item(site.get("function"), max_chars=120) or "",
                "signature": _safe_text_item(site.get("signature"), max_chars=220) or "",
                "matched_primitives": _bounded_string_list(site.get("matched_primitives"), MAX_CONTEXT_ITEMS, max_chars=80),
                "matched_assumption_terms": _bounded_string_list(site.get("matched_assumption_terms"), MAX_CONTEXT_ITEMS, max_chars=40),
                "snippet": _safe_text_item(site.get("snippet"), max_chars=360) or "",
                "reason": _safe_text_item(site.get("reason"), max_chars=220) or "",
            }

        claims = [_bounded_claim(row) for row in list(payload.get("claims", []) or [])[:limit]]
        verdicts = [_bounded_verdict(row) for row in list(payload.get("verdicts", []) or [])[:limit]]
        exposed_sites = [
            _bounded_site(row)
            for row in list(payload.get("ranked_exposed_call_sites", []) or [])[:limit]
        ]
        call_sites = [_bounded_site(row) for row in list(payload.get("ranked_call_sites", []) or [])[:limit]]
        stats = payload.get("stats") if isinstance(payload.get("stats"), dict) else {}
        source_refs = ["tools/changelog-source-drift-miner.py"]
        for path in list(payload.get("discovered_changelogs", []) or [])[:MAX_CONTEXT_ITEMS]:
            ref = _safe_rel_ref(path)
            if ref:
                source_refs.append(ref)
        for site in exposed_sites[:MAX_CONTEXT_ITEMS]:
            ref = site.get("source_ref")
            if ref:
                source_refs.append(str(ref))

        return _finalize(
            {
                "miner_schema": _safe_text_item(payload.get("schema"), max_chars=120) or "",
                "claims": claims,
                "verdicts": verdicts,
                "ranked_exposed_call_sites": exposed_sites,
                "ranked_call_sites": call_sites,
                "summary": {
                    "claim_count": stats.get("claim_count", len(payload.get("claims", []) or [])),
                    "verdict_count": len(payload.get("verdicts", []) or []),
                    "exposed_call_site_count": len(payload.get("ranked_exposed_call_sites", []) or []),
                    "call_site_count": len(payload.get("ranked_call_sites", []) or []),
                    "verdict_counts": stats.get("verdict_counts", {}),
                    "changelog_count": stats.get("changelog_count", 0),
                    "solidity_file_count": stats.get("solidity_file_count", 0),
                    "solidity_function_count": stats.get("solidity_function_count", 0),
                },
                "limits": {"max_claims": limit, "max_call_sites": limit},
                "source_refs": _unique_bounded(source_refs, MAX_SOLIDITY_DETECTOR_PROOF_REFS),
            }
        )

    def vault_finding_lineage(self, **kwargs: Any) -> dict[str, Any]:
        """Trace a finding's loop-by-loop history across submissions/ files.

        Inputs:
          * ``finding_name`` (required): substring matched against
            ``Internal name``, filename, and title (case-insensitive).
            Examples: ``LEAD 1``, ``LEAD H-D``, ``LEAD COMMIT-RESUME``.
          * ``audits_root`` (optional): override default ``~/audits`` root.
          * ``engagement`` (optional): scope match to a single engagement dir.

        Output schema: ``auditooor.vault_finding_lineage.v1`` — list of
        matched files with status, lane, loop ids seen, worker ids seen,
        M14-trap mention count, and the ``Surfaced by:`` line. Bounded
        header-only — does NOT return full bodies.
        """
        finding_name = _safe_text_item(kwargs.get("finding_name"), max_chars=120) or ""
        finding_name = finding_name.strip()
        if not finding_name:
            return {"error": "missing_finding_name"}

        audits_root_arg = kwargs.get("audits_root")
        engagement_filter = _safe_text_item(kwargs.get("engagement"), max_chars=80)
        engagement_filter = engagement_filter.lower() if engagement_filter else None

        if audits_root_arg:
            try:
                audits_root = Path(str(audits_root_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                return {"error": "invalid_audits_root"}
        else:
            audits_root = DEFAULT_AUDITS_ROOT.resolve()

        if not audits_root.exists() or not audits_root.is_dir():
            return {"error": "audits_root_not_found"}

        engagement_dirs = sorted(
            p for p in audits_root.iterdir()
            if p.is_dir() and not p.name.startswith(".") and not p.name.startswith("_")
        )

        matches: list[dict[str, Any]] = []
        all_loops: dict[str, int] = {}
        all_workers: dict[str, int] = {}
        all_m14_mentions = 0
        files_scanned = 0
        for eng_dir in engagement_dirs:
            if engagement_filter and engagement_filter not in eng_dir.name.lower():
                continue
            submissions = eng_dir / "submissions"
            if not submissions.exists() or not submissions.is_dir():
                continue
            for lane_dir in ENGAGEMENT_LANE_DIRS:
                lane_path = submissions / lane_dir
                if not lane_path.exists() or not lane_path.is_dir():
                    continue
                for md_file in sorted(lane_path.rglob("*.md")):
                    if md_file.name.startswith(".") or md_file.name.endswith(".bak"):
                        continue
                    if md_file.is_symlink():
                        continue
                    files_scanned += 1
                    try:
                        text = md_file.read_text(encoding="utf-8", errors="replace")
                    except OSError:
                        continue
                    if _has_secret(text[:8000]):
                        continue
                    header = _engagement_extract_header(text)
                    if not _lineage_match(
                        finding_name,
                        internal_name=header.get("internal_name", ""),
                        filename=md_file.name,
                        title=header.get("title", ""),
                    ):
                        continue
                    rel = _engagement_safe_relpath(md_file, audits_root)
                    if rel is None:
                        continue
                    lineage = _lineage_extract_from_header(text)
                    for loop in lineage["loops_seen"]:
                        all_loops[loop] = all_loops.get(loop, 0) + 1
                    for worker in lineage["workers_seen"]:
                        all_workers[worker] = all_workers.get(worker, 0) + 1
                    all_m14_mentions += lineage["m14_trap_mentions"]
                    matches.append(
                        {
                            "audits_relpath": rel,
                            "filename": md_file.name,
                            "engagement": eng_dir.name,
                            "lane": _engagement_lane_classify(lane_dir, md_file.name),
                            "title": header.get("title", ""),
                            "internal_name": header.get("internal_name", ""),
                            "severity": header.get("severity", ""),
                            "status_text": header.get("status_text", ""),
                            "status_class": _engagement_status_classify(
                                header.get("status_text")
                            ),
                            "surfaced_by": lineage["surfaced_by"],
                            "loops_seen": lineage["loops_seen"],
                            "workers_seen": lineage["workers_seen"],
                            "m14_trap_mentions": lineage["m14_trap_mentions"],
                        }
                    )
                    if len(matches) >= MAX_LINEAGE_FILES:
                        break
                if len(matches) >= MAX_LINEAGE_FILES:
                    break

        # Sort matches: paste_ready before staging before others; then by filename.
        lane_order = {
            "paste_ready": 0, "packaged": 1, "staging": 2, "staging_candidate": 3,
            "staging_dropped": 4, "dropped": 5, "llm_review": 6,
        }
        matches.sort(key=lambda m: (lane_order.get(m["lane"], 99), m["audits_relpath"]))

        # Sort the loops summary by numeric value
        def _loop_num(token: str) -> int:
            try:
                return int(token[1:])
            except ValueError:
                return 0

        loop_summary = sorted(all_loops.items(), key=lambda kv: _loop_num(kv[0]))
        worker_summary = sorted(all_workers.items())
        source_refs = _unique_bounded(
            [m["audits_relpath"] for m in matches], MAX_LINEAGE_REFS
        )
        base = {
            "schema": FINDING_LINEAGE_SCHEMA,
            "kind": "finding_lineage",
            "finding_name": finding_name,
            "audits_root_name": audits_root.name,
            "limits": {
                "max_files": MAX_LINEAGE_FILES,
                "max_refs": MAX_LINEAGE_REFS,
                "header_chars_scanned": MAX_LINEAGE_HEADER_CHARS,
                "max_loops": MAX_LINEAGE_LOOPS,
                "max_workers": MAX_LINEAGE_WORKERS,
            },
            "filters": {
                "engagement": engagement_filter or "",
            },
            "privacy_guards": {
                "audits_root_relative_only": True,
                "absolute_paths_blocked": True,
                "header_only_no_body": True,
                "secret_patterns_blocked": True,
                "symlinks_blocked": True,
            },
            "summary": {
                "files_scanned": files_scanned,
                "matches": len(matches),
                "distinct_loops": len(all_loops),
                "distinct_workers": len(all_workers),
                "total_m14_trap_mentions": all_m14_mentions,
            },
            "matches": matches,
            "aggregate": {
                "loops": [{"loop": k, "count": v} for k, v in loop_summary],
                "workers": [{"worker": k, "count": v} for k, v in worker_summary],
            },
            "source_refs": source_refs,
            "advisory_boundary": "Lineage signals are derived from in-file header memory notes; absence of a worker/loop token does NOT prove that worker did not contribute — it only proves no token in the header.",
        }
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "matches": matches,
                "aggregate": base["aggregate"],
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{FINDING_LINEAGE_SCHEMA}:finding_lineage:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    # ------------------------------------------------------------------
    # vault_corpus_lineage helpers (W2.8)
    # ------------------------------------------------------------------

    def _corpus_lineage_safe_rel(self, path: Path) -> str:
        """Return a vault/repo-relative path string for ``path`` (no absolute)."""
        try:
            rel = path.resolve().relative_to(self.repo_root)
            return str(rel)
        except ValueError:
            try:
                rel = path.resolve().relative_to(self.vault_dir)
                return str(rel)
            except ValueError:
                # Fall back to the bare file name; never leak absolute paths.
                return path.name

    def _corpus_lineage_search_record(
        self, record_id: str, corpus_root: Path, manifest_search_dirs: list[Path]
    ) -> dict[str, Any]:
        """Search corpus indexes for ``record_id``. Returns a dict with
        ``found``, ``record_summary``, ``primary_path``, ``alternates``,
        ``missing_manifests``, and ``scanned_paths``.
        """
        result: dict[str, Any] = {
            "found": False,
            "record_summary": None,
            "primary_path": None,
            "alternates": [],
            "missing_manifests": [],
            "scanned_paths": [],
        }
        token = record_id.lower()

        # 1. Walk reference/corpus_mined/*.md headers for matching slug/title.
        if corpus_root.exists() and corpus_root.is_dir():
            for md in sorted(corpus_root.glob("*.md")):
                if md.is_symlink():
                    continue
                rel = self._corpus_lineage_safe_rel(md)
                result["scanned_paths"].append(rel)
                try:
                    text = md.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                head = text[:MAX_CORPUS_LINEAGE_SCAN_BYTES]
                if _has_secret(head[:8000]):
                    continue
                if token not in head.lower():
                    continue
                # Try to extract a record summary block.
                title = ""
                slug = ""
                attack_class = ""
                severity_class = ""
                src_ref = ""
                # Look for a header line that mentions the token.
                low = head.lower()
                idx = low.find(token)
                # Walk backward to nearest markdown heading.
                heading_start = head.rfind("\n#", 0, idx)
                if heading_start == -1:
                    heading_start = 0
                else:
                    heading_start += 1
                heading_end = head.find("\n", heading_start)
                if heading_end == -1:
                    heading_end = min(len(head), heading_start + 200)
                title_line = head[heading_start:heading_end].strip()
                title = title_line.lstrip("# ").strip()[:MAX_CORPUS_LINEAGE_SUMMARY_CHARS]
                slug = record_id
                # Heuristic attack_class / severity scan within a 1KB window
                # around the hit.
                window_start = max(0, idx - 500)
                window_end = min(len(head), idx + 1500)
                window = head[window_start:window_end]
                ac_match = re.search(
                    r"(?i)\b(attack[_\- ]class|class)\s*[:=]\s*([A-Za-z0-9_\-]+)",
                    window,
                )
                if ac_match:
                    attack_class = ac_match.group(2)[:80]
                sev_match = re.search(
                    r"(?i)\b(severity)\s*[:=]\s*([A-Za-z]+)",
                    window,
                )
                if sev_match:
                    severity_class = sev_match.group(2).upper()[:20]
                src_ref = f"{rel}#{record_id}"

                hit_summary = {
                    "title": title,
                    "slug": slug,
                    "attack_class": attack_class,
                    "severity_class": severity_class,
                    "source_ref": src_ref,
                    "path": rel,
                }
                if not result["found"]:
                    result["found"] = True
                    result["record_summary"] = hit_summary
                    result["primary_path"] = rel
                else:
                    if len(result["alternates"]) < MAX_CORPUS_LINEAGE_ALTERNATES:
                        result["alternates"].append(hit_summary)

        # 2. ETL miner registry JSONs may also reference the record id.
        for mdir in manifest_search_dirs:
            if not mdir.exists() or not mdir.is_dir():
                result["missing_manifests"].append(self._corpus_lineage_safe_rel(mdir))
                continue
            for jpath in sorted(mdir.glob("*.json")):
                if jpath.is_symlink():
                    continue
                rel = self._corpus_lineage_safe_rel(jpath)
                result["scanned_paths"].append(rel)
                try:
                    text = jpath.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                head = text[:MAX_CORPUS_LINEAGE_SCAN_BYTES]
                if _has_secret(head[:8000]):
                    continue
                if token not in head.lower():
                    continue
                hit_summary = {
                    "title": "",
                    "slug": record_id,
                    "attack_class": "",
                    "severity_class": "",
                    "source_ref": f"{rel}#{record_id}",
                    "path": rel,
                }
                if not result["found"]:
                    result["found"] = True
                    result["record_summary"] = hit_summary
                    result["primary_path"] = rel
                else:
                    if len(result["alternates"]) < MAX_CORPUS_LINEAGE_ALTERNATES:
                        result["alternates"].append(hit_summary)
        return result

    def _corpus_lineage_walk_etl(
        self, record_id: str, etl_dirs: list[Path], max_runs: int
    ) -> tuple[list[dict[str, Any]], list[dict[str, Any]], list[str]]:
        """Walk ETL miner registry JSONs and miner-output dirs. Returns a
        tuple ``(lineage_etl_entries, miner_runs, scanned_paths)``.
        """
        etl_entries: list[dict[str, Any]] = []
        miner_runs: list[dict[str, Any]] = []
        scanned: list[str] = []
        token = record_id.lower()
        for edir in etl_dirs:
            if not edir.exists() or not edir.is_dir():
                continue
            for jpath in sorted(edir.glob("*.json")):
                if jpath.is_symlink():
                    continue
                if jpath.name.startswith("_"):
                    # Manifests like _manifest.json (aggregate) - still scan.
                    pass
                rel = self._corpus_lineage_safe_rel(jpath)
                scanned.append(rel)
                try:
                    text = jpath.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                head = text[:MAX_CORPUS_LINEAGE_SCAN_BYTES]
                if _has_secret(head[:8000]):
                    continue
                if token not in head.lower():
                    continue
                miner_name = jpath.stem
                miner_script = f"tools/hackerman-etl-from-{miner_name}.py"
                # Try to parse the JSON for richer fields.
                run_id = ""
                input_count = 0
                output_count = 0
                try:
                    data = json.loads(head)
                except (ValueError, TypeError):
                    data = None
                if isinstance(data, dict):
                    run_id = str(data.get("run_id", "") or data.get("miner_run_id", "") or "")[:80]
                    if "input_records_count" in data:
                        try:
                            input_count = int(data.get("input_records_count") or 0)
                        except (TypeError, ValueError):
                            input_count = 0
                    if "output_records_count" in data:
                        try:
                            output_count = int(data.get("output_records_count") or 0)
                        except (TypeError, ValueError):
                            output_count = 0
                etl_entries.append(
                    {
                        "kind": "etl_miner",
                        "name": f"hackerman-etl-from-{miner_name}",
                        "path": miner_script,
                        "manifest_path": rel,
                        "notes": f"Registry hit in {rel}.",
                    }
                )
                if len(miner_runs) < max_runs:
                    miner_runs.append(
                        {
                            "miner_script": miner_script,
                            "miner_run_id": run_id,
                            "input_records_count": input_count,
                            "output_records_count": output_count,
                            "manifest_path": rel,
                        }
                    )
                if len(etl_entries) >= max_runs:
                    break
            if len(etl_entries) >= max_runs:
                break
        return etl_entries, miner_runs, scanned

    def _corpus_lineage_extract_attribution(
        self, record_id: str, case_study_dirs: list[Path]
    ) -> tuple[dict[str, Any], list[dict[str, Any]], list[str]]:
        """Extract attribution and case-study lineage entries.

        Returns ``(attribution, lineage_entries, scanned_paths)``.
        """
        attribution: dict[str, Any] = {
            "primary_source_url": "",
            "secondary_source_urls": [],
            "citation_block": "",
        }
        lineage: list[dict[str, Any]] = []
        scanned: list[str] = []
        token = record_id.lower()
        url_re = re.compile(r"https?://[A-Za-z0-9._~:/?#\[\]@!$&'()*+,;=%-]{6,200}")
        for cdir in case_study_dirs:
            if not cdir.exists() or not cdir.is_dir():
                continue
            for md in sorted(cdir.glob("*.md")):
                if md.is_symlink():
                    continue
                rel = self._corpus_lineage_safe_rel(md)
                scanned.append(rel)
                try:
                    text = md.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                head = text[:MAX_CORPUS_LINEAGE_SCAN_BYTES]
                if _has_secret(head[:8000]):
                    continue
                if token not in head.lower():
                    continue
                # Pull URLs and a citation line.
                urls = []
                for m in url_re.finditer(head):
                    if _has_secret(m.group(0)):
                        continue
                    if _looks_like_private_ref(m.group(0)):
                        continue
                    if m.group(0) not in urls:
                        urls.append(m.group(0))
                    if len(urls) >= MAX_CORPUS_LINEAGE_SECONDARY_URLS + 1:
                        break
                if urls and not attribution["primary_source_url"]:
                    attribution["primary_source_url"] = urls[0][:200]
                    attribution["secondary_source_urls"] = [
                        u[:200] for u in urls[1:MAX_CORPUS_LINEAGE_SECONDARY_URLS + 1]
                    ]
                # Citation block heuristic: first non-empty 'Citation:' line.
                cit_match = re.search(
                    r"(?im)^\s*(citation|cite|attribution)\s*[:\-]\s*(.{4,400})$",
                    head,
                )
                if cit_match and not attribution["citation_block"]:
                    attribution["citation_block"] = cit_match.group(2).strip()[
                        :MAX_CORPUS_LINEAGE_SUMMARY_CHARS
                    ]
                lineage.append(
                    {
                        "kind": "attribution_trail",
                        "name": md.stem,
                        "path": rel,
                        "notes": "Case-study attribution trail.",
                    }
                )
        return attribution, lineage, scanned

    def vault_corpus_lineage(self, **kwargs: Any) -> dict[str, Any]:
        """Trace a corpus record's provenance chain.

        Wave-2 W2.8 callable. Walks corpus indexes, ETL miner registry
        JSONs, and case-study attribution markdown to reconstruct an
        ordered lineage chain (origin -> etl_miner -> corpus_index ->
        attribution_trail). Mirrors :py:meth:`vault_finding_lineage`
        envelope shape but operates on the upstream corpus pipeline
        rather than on workspace submissions.

        Inputs:
          * ``record_id`` (required): regex ``^[A-Za-z0-9._:/-]{8,160}$``.
            Identifies the row in the corpus (filename slug, hackerman
            record id, solodit finding id, pattern slug, or detector
            slug).
          * ``workspace_path`` (optional): carried into ``source_refs``
            for audit trail.
          * ``corpus_root`` (optional): override default
            ``reference/corpus_mined/``.
          * ``include_etl_trace`` (optional, default ``true``): walk ETL
            miner outputs.
          * ``include_source_ref`` (optional, default ``true``): resolve
            attribution and source URLs.
          * ``max_depth`` (optional, default 6, range 1-12): cap on
            lineage walk depth.

        Output schema: ``auditooor.vault_corpus_lineage.v1``.
        """
        import datetime

        ts = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )
        # Allow test-side injection of a frozen UTC for hash-stability
        # assertions; never used in production callers.
        injected_ts = kwargs.get("_frozen_utc")
        if isinstance(injected_ts, str) and injected_ts:
            ts = injected_ts[:64]

        raw_record_id = _safe_text_item(
            kwargs.get("record_id"), max_chars=MAX_CORPUS_LINEAGE_RECORD_ID_LEN + 4
        )
        record_id = (raw_record_id or "").strip()

        include_etl_trace = bool(kwargs.get("include_etl_trace", True))
        include_source_ref = bool(kwargs.get("include_source_ref", True))

        max_depth_arg = kwargs.get("max_depth")
        if max_depth_arg is None or max_depth_arg == "":
            max_depth = MAX_CORPUS_LINEAGE_DEFAULT_DEPTH
        else:
            try:
                max_depth = int(max_depth_arg)
            except (TypeError, ValueError):
                max_depth = MAX_CORPUS_LINEAGE_DEFAULT_DEPTH
        if max_depth < 1:
            max_depth = 1
        if max_depth > MAX_CORPUS_LINEAGE_DEPTH:
            max_depth = MAX_CORPUS_LINEAGE_DEPTH

        workspace_path_raw = kwargs.get("workspace_path") or ""
        workspace_path_text = str(workspace_path_raw or "")[:200]

        privacy_guards = {
            "absolute_paths_blocked": True,
            "header_only_no_body": True,
            "hidden_archive_and_quarantine_paths_blocked": True,
            "secret_patterns_blocked": True,
            "symlinks_blocked": True,
            "vault_relative_paths_only": True,
        }
        limits = {
            "max_depth": max_depth,
            "max_lineage_entries": MAX_CORPUS_LINEAGE_ENTRIES,
            "max_etl_miner_runs": MAX_CORPUS_LINEAGE_MINER_RUNS,
            "max_source_refs": MAX_CORPUS_LINEAGE_REFS,
        }

        def _envelope(
            payload: dict[str, Any], *, degraded_reason: str = ""
        ) -> dict[str, Any]:
            base = {
                "schema": CORPUS_LINEAGE_SCHEMA,
                "kind": "corpus_lineage",
                "record_id": payload.get("record_id", record_id),
                "found": bool(payload.get("found", False)),
                "record_summary": payload.get("record_summary"),
                "lineage_chain": payload.get("lineage_chain", []),
                "etl_miner_runs": payload.get("etl_miner_runs", []),
                "attribution": payload.get(
                    "attribution",
                    {
                        "primary_source_url": "",
                        "secondary_source_urls": [],
                        "citation_block": "",
                    },
                ),
                "degraded": bool(payload.get("degraded", False)),
                "degraded_reason": degraded_reason,
                "limits": limits,
                "include_etl_trace": include_etl_trace,
                "include_source_ref": include_source_ref,
                "workspace_path": workspace_path_text,
                "source_refs": _unique_bounded(
                    payload.get("source_refs", []) or [],
                    MAX_CORPUS_LINEAGE_REFS,
                ),
                "privacy_guards": privacy_guards,
                "generated_at_utc": ts,
                "advisory_boundary": (
                    "Corpus lineage signals are derived from header-only "
                    "scans of corpus index, ETL miner registry, and "
                    "case-study attribution files; absence of a stage in "
                    "lineage_chain does NOT prove the record bypassed that "
                    "stage - it only proves no marker matched in the "
                    "scanned headers."
                ),
            }
            # Stable digest over the canonicalised payload (timestamp included
            # via _frozen_utc support so tests can pin it).
            hash_seed = {
                "record_id": base["record_id"],
                "max_depth": max_depth,
                "include_etl_trace": include_etl_trace,
                "include_source_ref": include_source_ref,
                "generated_at_utc": ts,
                "lineage_chain": base["lineage_chain"],
                "found": base["found"],
            }
            digest = hashlib.sha256(
                _canonical_json(hash_seed).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{CORPUS_LINEAGE_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **base,
            }

        # ---- Input validation ---------------------------------------
        if not record_id:
            return _envelope(
                {
                    "record_id": "",
                    "found": False,
                    "degraded": True,
                    "source_refs": [],
                },
                degraded_reason="missing_record_id",
            )
        if not CORPUS_LINEAGE_RECORD_ID_RE.match(record_id):
            return _envelope(
                {
                    "record_id": record_id[: MAX_CORPUS_LINEAGE_RECORD_ID_LEN],
                    "found": False,
                    "degraded": True,
                    "source_refs": [],
                },
                degraded_reason=(
                    "record_id must match ^[A-Za-z0-9._:/-]{8,160}$"
                ),
            )

        # ---- Resolve corpus_root + supporting dirs ------------------
        corpus_root_arg = kwargs.get("corpus_root")
        if corpus_root_arg:
            try:
                corpus_root = Path(str(corpus_root_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                return _envelope(
                    {
                        "record_id": record_id,
                        "found": False,
                        "degraded": True,
                        "source_refs": [],
                    },
                    degraded_reason="invalid_corpus_root",
                )
        else:
            corpus_root = (self.repo_root / "reference" / "corpus_mined").resolve()

        etl_registry_dir = (
            self.repo_root / "tools" / "audit" / "etl_miner_registry"
        ).resolve()
        agent_outputs_dir = (self.repo_root / "agent_outputs").resolve()
        case_study_dir = (
            self.repo_root / "auditooor-mcp" / "case_study"
        ).resolve()
        # Allow tests / operators to inject extra search dirs (private).
        extra_dirs_arg = kwargs.get("_extra_search_dirs") or []
        extra_dirs: list[Path] = []
        if isinstance(extra_dirs_arg, list):
            for d in extra_dirs_arg[:8]:
                try:
                    extra_dirs.append(Path(str(d)).expanduser().resolve())
                except (OSError, RuntimeError):
                    continue
        extra_case_study_dirs = kwargs.get("_extra_case_study_dirs") or []
        extra_case_dirs: list[Path] = []
        if isinstance(extra_case_study_dirs, list):
            for d in extra_case_study_dirs[:8]:
                try:
                    extra_case_dirs.append(Path(str(d)).expanduser().resolve())
                except (OSError, RuntimeError):
                    continue

        manifest_dirs = [etl_registry_dir, agent_outputs_dir] + extra_dirs
        case_study_dirs = [case_study_dir] + extra_case_dirs

        # ---- Search corpus indexes for the record -------------------
        search_result = self._corpus_lineage_search_record(
            record_id, corpus_root, manifest_dirs
        )
        missing_manifests = list(search_result.get("missing_manifests", []))
        scanned_paths: list[str] = list(search_result.get("scanned_paths", []))

        if not search_result["found"]:
            ref_list = scanned_paths[:MAX_CORPUS_LINEAGE_REFS]
            return _envelope(
                {
                    "record_id": record_id,
                    "found": False,
                    "record_summary": None,
                    "lineage_chain": [],
                    "etl_miner_runs": [],
                    "degraded": bool(missing_manifests),
                    "source_refs": ref_list,
                },
                degraded_reason=(
                    f"record_not_found_in_corpus_indexes"
                    + (
                        ";" + ";".join(
                            f"manifest_not_found:{m}" for m in missing_manifests[:3]
                        )
                        if missing_manifests
                        else ""
                    )
                ),
            )

        record_summary = search_result["record_summary"]
        alternates = search_result.get("alternates", []) or []
        if alternates:
            record_summary = dict(record_summary or {})
            record_summary["alternates"] = alternates

        # ---- Build the lineage chain --------------------------------
        # Level 0 origin: the primary corpus file that matched.
        primary_rel = search_result.get("primary_path") or ""
        lineage_chain: list[dict[str, Any]] = []
        lineage_chain.append(
            {
                "level": 0,
                "kind": "origin",
                "name": Path(primary_rel).stem if primary_rel else record_id,
                "path": primary_rel,
                "commit_sha": "",
                "notes": "Primary corpus index hit; origin row.",
            }
        )

        # Level 1+: optional ETL miner trace.
        etl_entries: list[dict[str, Any]] = []
        miner_runs: list[dict[str, Any]] = []
        etl_scanned: list[str] = []
        if include_etl_trace:
            etl_entries, miner_runs, etl_scanned = self._corpus_lineage_walk_etl(
                record_id, manifest_dirs, MAX_CORPUS_LINEAGE_MINER_RUNS
            )
            scanned_paths.extend(etl_scanned)

        for i, entry in enumerate(etl_entries):
            if len(lineage_chain) >= MAX_CORPUS_LINEAGE_ENTRIES:
                break
            if len(lineage_chain) >= max_depth + 1:
                break
            lineage_chain.append(
                {
                    "level": len(lineage_chain),
                    "kind": entry.get("kind", "etl_miner"),
                    "name": entry.get("name", ""),
                    "path": entry.get("path", ""),
                    "commit_sha": entry.get("commit_sha", ""),
                    "notes": entry.get("notes", ""),
                }
            )

        # corpus_index entry pointing at INDEX.md if available.
        index_md = corpus_root / "INDEX.md"
        if (
            index_md.exists()
            and not index_md.is_symlink()
            and len(lineage_chain) < MAX_CORPUS_LINEAGE_ENTRIES
            and len(lineage_chain) < max_depth + 1
        ):
            index_rel = self._corpus_lineage_safe_rel(index_md)
            lineage_chain.append(
                {
                    "level": len(lineage_chain),
                    "kind": "corpus_index",
                    "name": "reference/corpus_mined/INDEX.md",
                    "path": index_rel,
                    "commit_sha": "",
                    "notes": "Corpus consolidated index.",
                }
            )
            scanned_paths.append(index_rel)

        # Optional attribution / case-study trail.
        attribution: dict[str, Any] = {
            "primary_source_url": "",
            "secondary_source_urls": [],
            "citation_block": "",
        }
        if include_source_ref:
            attr_payload, attr_lineage, attr_scanned = (
                self._corpus_lineage_extract_attribution(record_id, case_study_dirs)
            )
            attribution = attr_payload
            scanned_paths.extend(attr_scanned)
            for entry in attr_lineage:
                if len(lineage_chain) >= MAX_CORPUS_LINEAGE_ENTRIES:
                    break
                if len(lineage_chain) >= max_depth + 1:
                    break
                lineage_chain.append(
                    {
                        "level": len(lineage_chain),
                        "kind": entry.get("kind", "attribution_trail"),
                        "name": entry.get("name", ""),
                        "path": entry.get("path", ""),
                        "commit_sha": "",
                        "notes": entry.get("notes", ""),
                    }
                )

        # Degraded if chain hit max_depth before reaching attribution; or
        # if we encountered missing manifests.
        degraded = False
        degraded_reasons: list[str] = []
        if (
            include_source_ref
            and len(lineage_chain) >= max_depth + 1
            and not any(e["kind"] == "attribution_trail" for e in lineage_chain)
        ):
            degraded = True
            degraded_reasons.append("max_depth_reached_before_attribution")
        for missing in missing_manifests:
            degraded = True
            degraded_reasons.append(f"manifest_not_found:{missing}")

        # Strip record_summary.path internal-only field before returning.
        if isinstance(record_summary, dict) and "path" in record_summary:
            record_summary = {
                k: v for k, v in record_summary.items() if k != "path"
            }

        source_refs = _unique_bounded(
            [s for s in scanned_paths if s], MAX_CORPUS_LINEAGE_REFS
        )
        return _envelope(
            {
                "record_id": record_id,
                "found": True,
                "record_summary": record_summary,
                "lineage_chain": lineage_chain,
                "etl_miner_runs": miner_runs,
                "attribution": attribution,
                "degraded": degraded,
                "source_refs": source_refs,
            },
            degraded_reason=";".join(degraded_reasons),
        )

    def vault_commit_mining_state(self, **kwargs: Any) -> dict[str, Any]:
        """Return commit-mining state for a workspace.

        Inputs:
          * ``workspace_path`` (required): absolute path to a workspace
            (e.g. ``/Users/wolf/audits/spark``).

        Output schema: ``auditooor.vault_commit_mining_state.v1`` — fields:
          * audit_pin_sha, head_sha
          * forward_window_count, backward_window_count, residual_count
          * last_mined_at (ISO8601 timestamp from CLOSEOUT.md or ledger)
          * lanes_triaged[]: list of {lane, sha, verdict, reason}
          * lanes_residual[]: list of {sha, classification, hint}
          * source_artifacts[]: paths to closeout / ledger / mining JSONs

        Reads (in priority order):
          1. ``<ws>/.auditooor/commit_lifecycle_ledger.json`` (Base Azul format)
          2. ``<ws>/mining_rounds/<latest>/CLOSEOUT.md`` (Spark format)
          3. ``<repo-root>/reports/git_commits_mining_<repo>_<date>.json``

        Privacy guards: workspace-relative paths only; no source-tree contents
        embedded; ledger row metadata only (sha + verdict + reason — bounded).
        """
        workspace_path_arg = kwargs.get("workspace_path") or kwargs.get("workspace")
        if not workspace_path_arg:
            return {
                "schema": COMMIT_MINING_STATE_SCHEMA,
                "error": "missing_workspace_path",
            }
        try:
            workspace_path = Path(str(workspace_path_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            return {
                "schema": COMMIT_MINING_STATE_SCHEMA,
                "error": "invalid_workspace_path",
            }
        if not workspace_path.exists() or not workspace_path.is_dir():
            return {
                "schema": COMMIT_MINING_STATE_SCHEMA,
                "error": "workspace_not_found",
                "workspace_path": str(workspace_path),
            }

        result: dict[str, Any] = {
            "schema": COMMIT_MINING_STATE_SCHEMA,
            "workspace": workspace_path.name,
            "workspace_path": str(workspace_path),
            "audit_pin_sha": "",
            "head_sha": "",
            "forward_window_count": 0,
            "backward_window_count": 0,
            "residual_count": 0,
            "last_mined_at": "",
            "lanes_triaged": [],
            "lanes_residual": [],
            "source_artifacts": [],
            "freshness_status": "unknown",
        }

        # Priority 1: structured ledger (Base Azul format).
        ledger_path = workspace_path / ".auditooor" / "commit_lifecycle_ledger.json"
        if ledger_path.exists() and ledger_path.is_file():
            try:
                ledger = json.loads(ledger_path.read_text(errors="replace"))
                if isinstance(ledger, dict):
                    result["audit_pin_sha"] = str(ledger.get("audit_pin_sha", "") or "")[:80]
                    result["head_sha"] = str(ledger.get("head_sha", "") or "")[:80]
                    result["last_mined_at"] = str(ledger.get("last_mined_at", "") or "")[:80]
                    forward = ledger.get("forward_window") or {}
                    backward = ledger.get("backward_window") or {}
                    if isinstance(forward, dict):
                        result["forward_window_count"] = int(forward.get("count") or 0)
                    if isinstance(backward, dict):
                        result["backward_window_count"] = int(backward.get("count") or 0)
                    triaged = ledger.get("lanes_triaged") or []
                    if isinstance(triaged, list):
                        result["lanes_triaged"] = [
                            {
                                "lane": str(row.get("lane", ""))[:80],
                                "sha": str(row.get("sha", ""))[:80],
                                "verdict": str(row.get("verdict", ""))[:40],
                                "reason": str(row.get("reason", ""))[:240],
                            }
                            for row in triaged[:50]
                            if isinstance(row, dict)
                        ]
                    residual = ledger.get("lanes_residual") or []
                    if isinstance(residual, list):
                        result["lanes_residual"] = [
                            {
                                "sha": str(row.get("sha", ""))[:80],
                                "classification": str(row.get("classification", ""))[:40],
                                "hint": str(row.get("hint", ""))[:240],
                            }
                            for row in residual[:50]
                            if isinstance(row, dict)
                        ]
                        result["residual_count"] = len(residual)
                    result["source_artifacts"].append(".auditooor/commit_lifecycle_ledger.json")
                    result["freshness_status"] = "ledger_present"
                    return result
            except (OSError, json.JSONDecodeError, ValueError):
                pass

        # Priority 2: latest mining_rounds CLOSEOUT.md (Spark format).
        mining_rounds = workspace_path / "mining_rounds"
        if mining_rounds.exists() and mining_rounds.is_dir():
            round_dirs = sorted(
                (p for p in mining_rounds.iterdir() if p.is_dir()),
                key=lambda p: p.name,
                reverse=True,
            )
            for round_dir in round_dirs[:1]:
                closeout_path = round_dir / "CLOSEOUT.md"
                if not closeout_path.exists():
                    continue
                try:
                    text = closeout_path.read_text(errors="replace")
                    # Parse audit-pin and HEAD SHAs from the closeout body.
                    pin_match = re.search(r"audit-pin\s+`([0-9a-f]{7,40})`", text, flags=re.IGNORECASE)
                    head_match = re.search(r"HEAD\s+`([0-9a-f]{7,40})`", text, flags=re.IGNORECASE)
                    if pin_match:
                        result["audit_pin_sha"] = pin_match.group(1)
                    if head_match:
                        result["head_sha"] = head_match.group(1)
                    fw_match = re.search(r"Forward window.*?(\d+)\s+commits", text, flags=re.IGNORECASE | re.DOTALL)
                    bw_match = re.search(r"[Bb]ackward window.*?(\d+)\s+commits", text, flags=re.IGNORECASE | re.DOTALL)
                    if fw_match:
                        result["forward_window_count"] = int(fw_match.group(1))
                    if bw_match:
                        result["backward_window_count"] = int(bw_match.group(1))
                    # Parse DROP/HOLD lane verdicts.
                    lane_re = re.compile(
                        r"\|\s*(SPK-T6-[\w-]+|[A-Z][\w-]+-\d+)\s*\|\s*(DROP|HOLD|FILED|ESCALATED)[\w\s-]*\|\s*([^|]+)\|",
                    )
                    triaged = []
                    for m in lane_re.finditer(text):
                        triaged.append(
                            {
                                "lane": m.group(1),
                                "sha": "",
                                "verdict": m.group(2).strip(),
                                "reason": m.group(3).strip()[:240],
                            }
                        )
                    if triaged:
                        result["lanes_triaged"] = triaged[:50]
                    result["last_mined_at"] = round_dir.name
                    result["source_artifacts"].append(
                        f"mining_rounds/{round_dir.name}/CLOSEOUT.md"
                    )
                    result["freshness_status"] = "closeout_md_parsed"
                except OSError:
                    continue

        # Priority 3: workspace's git-commits-mining JSON (auditooor reports/).
        repo_reports = REPO_ROOT / "reports"
        if repo_reports.exists():
            workspace_slug = workspace_path.name
            candidate_jsons = sorted(
                repo_reports.glob(f"git_commits_mining_*{workspace_slug}*_*.json"),
                key=lambda p: p.name,
                reverse=True,
            ) or sorted(
                repo_reports.glob("git_commits_mining_buildonspark-spark_*.json"),
                key=lambda p: p.name,
                reverse=True,
            ) if workspace_slug == "spark" else []
            for jpath in candidate_jsons[:1]:
                try:
                    j = json.loads(jpath.read_text(errors="replace"))
                    if isinstance(j, dict):
                        if not result["audit_pin_sha"]:
                            result["audit_pin_sha"] = str(j.get("audit_pin_sha", ""))[:80]
                        if not result["last_mined_at"]:
                            result["last_mined_at"] = str(j.get("generated_at", ""))[:80]
                        commits = j.get("commits") or j.get("results") or j.get("rows") or []
                        if isinstance(commits, list) and not result["forward_window_count"]:
                            result["forward_window_count"] = len(commits)
                        result["source_artifacts"].append(
                            f"reports/{jpath.name}"
                        )
                except (OSError, json.JSONDecodeError):
                    pass

        if result["freshness_status"] == "unknown":
            result["freshness_status"] = "no_artifacts_found"

        return result

    def _harness_failure_events_path(self, workspace_path: Path | None = None) -> Path:
        """Return path to per-occurrence harness-failure event JSONL.

        Priority order:
          1. workspace_path/.auditooor/harness_failure_events.jsonl
          2. repo_root/reports/harness_failure_events.jsonl
        """
        if workspace_path is not None and workspace_path.is_dir():
            candidate = workspace_path / ".auditooor" / "harness_failure_events.jsonl"
            if candidate.is_file():
                return candidate
        return self.repo_root / DEFAULT_HARNESS_FAILURE_EVENTS_PATH

    def _harness_failure_event_context(self, event: dict[str, Any]) -> dict[str, Any]:
        """Return a bounded safe context dict for a single harness failure event."""
        next_action = event.get("next_action") if isinstance(event.get("next_action"), dict) else {}
        recurrence = event.get("recurrence_window") if isinstance(event.get("recurrence_window"), dict) else {}
        return {
            "event_id": _safe_text_item(event.get("event_id"), max_chars=160) or "",
            "root_cause_id": _safe_text_item(event.get("root_cause_id"), max_chars=90) or "",
            "event_state": _safe_text_item(event.get("event_state"), max_chars=32) or "",
            "occurred_at": _safe_text_item(event.get("occurred_at"), max_chars=40) or "",
            "command": _safe_text_item(event.get("command"), max_chars=240) or "",
            "exit_code": int(event.get("exit_code") or -1),
            "workspace": _safe_text_item(event.get("workspace"), max_chars=160) or "",
            "commit": _safe_text_item(event.get("commit"), max_chars=40) or "",
            "harness_path": _safe_text_item(event.get("harness_path"), max_chars=160) or "",
            "classifier_confidence": float(event.get("classifier_confidence") or -1.0),
            "knowledge_gap_refs": [
                ref for ref in (
                    _safe_text_item(r, max_chars=80) for r in event.get("knowledge_gap_refs", [])
                )
                if ref
            ][:MAX_CONTEXT_ITEMS],
            "next_action_kind": _safe_text_item(next_action.get("kind"), max_chars=64) or "",
            "recurrence_first_seen": _safe_text_item(recurrence.get("first_seen"), max_chars=16) or "",
            "recurrence_last_seen": _safe_text_item(recurrence.get("last_seen"), max_chars=16) or "",
            "recurrence_event_count": int(recurrence.get("event_count") or 0),
            "finalization_status": _safe_text_item(event.get("finalization_status"), max_chars=40) or "",
        }

    def vault_harness_failure_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return recent harness-failure events filtered by poc_class and workspace.

        Inputs:
          * ``workspace_path`` (optional): absolute path to a workspace;
            limits events to those whose ``workspace`` field matches.
          * ``poc_class`` (optional): substring filter applied to ``command``
            and ``harness_path`` fields (e.g. "halmos", "forge", "medusa").
          * ``limit`` (optional): max events returned (default 10, max 50).

        Output schema: ``auditooor.vault_harness_failure_context.v1``

        Source-of-truth: per-occurrence JSONL at
          ``<workspace>/.auditooor/harness_failure_events.jsonl``
          falling back to ``reports/harness_failure_events.jsonl``.

        If the event store does not exist, returns a valid empty envelope —
        never an error.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace")
        poc_class_arg = kwargs.get("poc_class")
        limit = min(MAX_HARNESS_FAILURE_EVENTS, _clamp_limit(kwargs.get("limit", 10), default=10))

        workspace_path: Path | None = None
        workspace_filter: str = ""
        if workspace_arg:
            raw = _safe_workspace_or_brief_path(workspace_arg)
            if raw is not None:
                workspace_path = raw.resolve()
                if workspace_path.is_dir():
                    workspace_filter = workspace_path.name
                else:
                    workspace_path = None

        poc_class_filter: str = ""
        if poc_class_arg:
            raw_poc = _safe_text_item(poc_class_arg, max_chars=120)
            if raw_poc:
                poc_class_filter = raw_poc.lower()

        events_path = self._harness_failure_events_path(workspace_path)
        events_relpath = ""
        try:
            events_relpath = _rel(events_path, self.repo_root)
        except ValueError:
            events_relpath = str(events_path)

        raw_events: list[dict[str, Any]] = []
        store_exists = events_path.is_file() and not _path_has_symlink(events_path, stop_at=self.repo_root)
        if store_exists:
            try:
                text = events_path.read_text(encoding="utf-8")
            except (OSError, UnicodeDecodeError):
                text = ""
            if not _has_secret(text):
                for line in text.splitlines():
                    if not line.strip():
                        continue
                    try:
                        row = json.loads(line)
                    except json.JSONDecodeError:
                        continue
                    if isinstance(row, dict):
                        raw_events.append(row)

        # Filter: workspace match (substring of workspace field)
        if workspace_filter:
            raw_events = [
                e for e in raw_events
                if workspace_filter.lower() in str(e.get("workspace", "")).lower()
            ]

        # Filter: poc_class match (substring of command or harness_path)
        if poc_class_filter:
            raw_events = [
                e for e in raw_events
                if (
                    poc_class_filter in str(e.get("command", "")).lower()
                    or poc_class_filter in str(e.get("harness_path", "")).lower()
                )
            ]

        # Sort: most recent first (occurred_at descending), then by event_id
        raw_events.sort(
            key=lambda e: (str(e.get("occurred_at", "")), str(e.get("event_id", ""))),
            reverse=True,
        )

        items = [self._harness_failure_event_context(e) for e in raw_events[:limit]]

        # Tally state counts over the full (pre-limit) filtered set
        state_counts: dict[str, int] = {}
        root_cause_counts: dict[str, int] = {}
        for e in raw_events:
            state = str(e.get("event_state", "unknown"))
            rc = str(e.get("root_cause_id", "unknown"))
            state_counts[state] = state_counts.get(state, 0) + 1
            root_cause_counts[rc] = root_cause_counts.get(rc, 0) + 1

        source_refs: list[str] = []
        if store_exists and events_relpath:
            safe_ref = _safe_harness_source_ref(events_relpath)
            if safe_ref:
                source_refs.append(safe_ref)
            elif events_relpath.startswith("reports/"):
                source_refs.append(events_relpath)

        base: dict[str, Any] = {
            "schema": HARNESS_FAILURE_CONTEXT_SCHEMA,
            "kind": "harness_failure",
            "store_path": events_relpath,
            "store_exists": store_exists,
            "limits": {
                "max_events": MAX_HARNESS_FAILURE_EVENTS,
            },
            "filters": {
                "workspace_path": str(workspace_path) if workspace_path else "",
                "poc_class": poc_class_filter,
            },
            "privacy_guards": {
                "repo_relative_store_path_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
                "raw_log_contents_not_returned": True,
            },
            "summary": {
                "total_matching": len(raw_events),
                "returned_count": len(items),
                "state_counts": state_counts,
                "root_cause_counts": root_cause_counts,
            },
            "source_refs": source_refs,
            "items": items,
            "advisory_boundary": (
                "Harness failure events record per-occurrence tool/proof failure signals; "
                "use alongside vault_harness_context root-cause records. "
                "This callable is NOT a substitute for direct proof execution."
            ),
        }
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "filters": base["filters"],
                "items": items,
                "source_refs": source_refs,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{HARNESS_FAILURE_CONTEXT_SCHEMA}:harness_failure:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    # ------------------------------------------------------------------
    # vault_triager_pattern_context
    # ------------------------------------------------------------------

    @staticmethod
    def _parse_rejection_classifier_history(text: str) -> list[dict[str, Any]]:
        """Minimal line-by-line parser for rejection_classifier_history.yaml.

        Each top-level YAML list item has a ``timestamp`` key and an optional
        ``top_new_terms`` list of ``{term, weight}`` dicts.  We extract only
        those fields; all others are ignored.  The parser is intentionally
        narrow — it is not a general YAML parser.
        """
        records: list[dict[str, Any]] = []
        current: dict[str, Any] | None = None
        in_top_new_terms = False
        pending_term: str | None = None

        for raw_line in text.splitlines():
            # Strip trailing whitespace only; preserve leading for indent detection.
            line = raw_line.rstrip()
            stripped = line.lstrip()

            # New top-level record
            if stripped.startswith("- timestamp:"):
                if current is not None:
                    records.append(current)
                ts_val = stripped[len("- timestamp:"):].strip().strip("'\"")
                current = {"timestamp": ts_val, "top_new_terms": []}
                in_top_new_terms = False
                pending_term = None
                continue

            if current is None:
                continue

            # Detect "  top_new_terms:" section start
            if stripped == "top_new_terms:":
                in_top_new_terms = True
                pending_term = None
                continue

            # Any other top-level-ish (non-indented or 2-space) key resets in_top_new_terms
            if stripped.startswith("- ") and not in_top_new_terms:
                # sub-list item outside top_new_terms — ignore
                continue

            if in_top_new_terms:
                if stripped.startswith("- term:"):
                    # flush previous
                    if pending_term is not None:
                        current["top_new_terms"].append({"term": pending_term, "weight": 0.0})
                    pending_term = stripped[len("- term:"):].strip()
                    continue
                if stripped.startswith("weight:") and pending_term is not None:
                    try:
                        w = float(stripped[len("weight:"):].strip())
                    except ValueError:
                        w = 0.0
                    current["top_new_terms"].append({"term": pending_term, "weight": w})
                    pending_term = None
                    continue
                # Any key that is not "- term:" or "weight:" while in top_new_terms
                # signals we've left the block — but only if it looks like a real key
                if ":" in stripped and not stripped.startswith("-"):
                    if pending_term is not None:
                        current["top_new_terms"].append({"term": pending_term, "weight": 0.0})
                        pending_term = None
                    in_top_new_terms = False

        if current is not None:
            records.append(current)
        return records

    def vault_triager_pattern_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return top rejection patterns from the triager classifier history.

        Inputs:
          * ``workspace_path`` (required): absolute path to a workspace; used to
            locate ``reference/rejection_classifier_history.yaml`` relative to the
            repo root.
          * ``pattern_class`` (optional): free-text substring filter applied to
            the ``term`` field of each pattern entry.
          * ``limit`` (optional): max patterns returned (default 5, max 50).

        Output schema: ``auditooor.vault_triager_pattern_context.v1``

        Sources:
          * ``reference/rejection_classifier_history.yaml`` for classifier
            vocabulary terms.
          * ``reference/triager_patterns.json`` for structured real triager
            rejection patterns and pre-submit guards.

        If no source file exists, returns a valid empty envelope —
        never an error.
        """
        workspace_arg = kwargs.get("workspace_path") or kwargs.get("workspace")
        pattern_class_arg = kwargs.get("pattern_class")
        limit = min(50, _clamp_limit(kwargs.get("limit", 5), default=5))

        workspace_path: Path | None = None
        if workspace_arg:
            raw = _safe_workspace_or_brief_path(workspace_arg)
            if raw is not None:
                candidate = raw.resolve()
                if candidate.is_dir():
                    workspace_path = candidate

        pattern_class_filter: str = ""
        if pattern_class_arg:
            raw_pc = _safe_text_item(pattern_class_arg, max_chars=200)
            if raw_pc:
                pattern_class_filter = raw_pc.lower()

        # Locate sources: always relative to repo root (workspace-independent)
        history_path = self.repo_root / "reference" / "rejection_classifier_history.yaml"
        structured_path = self.repo_root / "reference" / "triager_patterns.json"
        history_relpath = ""
        structured_relpath = ""
        try:
            history_relpath = _rel(history_path, self.repo_root)
        except ValueError:
            history_relpath = str(history_path)
        try:
            structured_relpath = _rel(structured_path, self.repo_root)
        except ValueError:
            structured_relpath = str(structured_path)

        raw_records: list[dict[str, Any]] = []
        classifier_source_exists = (
            history_path.is_file()
            and not _path_has_symlink(history_path, stop_at=self.repo_root)
        )
        structured_source_exists = (
            structured_path.is_file()
            and not _path_has_symlink(structured_path, stop_at=self.repo_root)
        )
        source_files: list[str] = []

        if classifier_source_exists:
            try:
                text = history_path.read_text(encoding="utf-8")
            except (OSError, UnicodeDecodeError):
                text = ""
            if not _has_secret(text):
                raw_records = self._parse_rejection_classifier_history(text)
                if history_relpath:
                    source_files.append(history_relpath)

        structured_rejection_patterns_all: list[dict[str, Any]] = []
        if structured_source_exists:
            try:
                structured_text = structured_path.read_text(encoding="utf-8")
                structured_data = json.loads(structured_text) if not _has_secret(structured_text) else {}
            except (OSError, UnicodeDecodeError, json.JSONDecodeError):
                structured_data = {}
            if isinstance(structured_data, dict):
                def _pattern_text(value: object, max_chars: int) -> str:
                    text = str(value if value is not None else "").replace("`", "").strip()
                    return _safe_text_item(text, max_chars=max_chars) or ""

                def _pattern_text_list(values: object, limit: int, max_chars: int) -> list[str]:
                    if not isinstance(values, list):
                        return []
                    rows: list[str] = []
                    for value in values:
                        item = _pattern_text(value, max_chars)
                        if item and item.strip(" .,:;"):
                            rows.append(item)
                        if len(rows) >= limit:
                            break
                    return rows

                for raw_pattern in structured_data.get("rejections", []):
                    if not isinstance(raw_pattern, dict):
                        continue
                    pattern_id = _pattern_text(raw_pattern.get("id"), 40)
                    name = _pattern_text(raw_pattern.get("name"), 160)
                    description = _pattern_text(raw_pattern.get("description"), 800)
                    pre_submit_guard = _pattern_text(raw_pattern.get("pre_submit_guard"), 800)
                    severity = _pattern_text(raw_pattern.get("severity"), 40) or "warn"
                    triager_language = _pattern_text_list(raw_pattern.get("triager_language"), 8, 180)
                    triggers = _pattern_text_list(raw_pattern.get("triggers"), 8, 120)
                    examples = _pattern_text_list(raw_pattern.get("examples"), 4, 260)
                    haystack = " ".join(
                        [
                            pattern_id,
                            name,
                            description,
                            pre_submit_guard,
                            severity,
                            " ".join(triager_language),
                            " ".join(triggers),
                            " ".join(examples),
                        ]
                    ).lower()
                    if pattern_class_filter and pattern_class_filter not in haystack:
                        continue
                    structured_rejection_patterns_all.append({
                        "pattern_id": pattern_id,
                        "pattern_name": name,
                        "severity": severity,
                        "description": description,
                        "triager_language": triager_language,
                        "triggers": triggers,
                        "pre_submit_guard": pre_submit_guard,
                        "examples": examples,
                        "source_type": "structured_triager_patterns",
                    })
                if structured_relpath:
                    source_files.append(structured_relpath)

        # Aggregate term → {count, most_recent_iso, representative_reason}
        term_agg: dict[str, dict[str, Any]] = {}
        for record in raw_records:
            ts = record.get("timestamp", "")
            for entry in record.get("top_new_terms", []):
                term = str(entry.get("term", "")).strip()
                if not term:
                    continue
                weight = float(entry.get("weight", 0.0))
                # Only include negatively-weighted terms (rejection-predictive)
                if weight >= 0.0:
                    continue
                if term not in term_agg:
                    term_agg[term] = {
                        "count": 0,
                        "most_recent_iso": "",
                        "representative_reason": f"Rejection-predictive term (weight {weight:.4f})",
                    }
                agg = term_agg[term]
                agg["count"] += 1
                if ts > agg["most_recent_iso"]:
                    agg["most_recent_iso"] = ts
                    agg["representative_reason"] = (
                        f"Rejection-predictive term (weight {weight:.4f})"
                    )

        # Build pattern list: sort by count desc, then term asc
        all_patterns = [
            {
                "pattern": term,
                "count": agg["count"],
                "most_recent_iso": agg["most_recent_iso"],
                "representative_reason": agg["representative_reason"],
            }
            for term, agg in term_agg.items()
        ]
        all_patterns.sort(key=lambda p: (-p["count"], p["pattern"]))

        # Apply optional pattern_class filter
        if pattern_class_filter:
            all_patterns = [
                p for p in all_patterns
                if pattern_class_filter in p["pattern"].lower()
            ]

        top_rejection_patterns = all_patterns[:limit]
        structured_rejection_patterns = structured_rejection_patterns_all[:limit]

        base: dict[str, Any] = {
            "schema": TRIAGER_PATTERN_CONTEXT_SCHEMA,
            "kind": "triager_pattern",
            "source_path": history_relpath,
            "structured_source_path": structured_relpath,
            "source_exists": classifier_source_exists or structured_source_exists,
            "classifier_source_exists": classifier_source_exists,
            "structured_source_exists": structured_source_exists,
            "limits": {
                "max_patterns": 50,
            },
            "filters": {
                "workspace_path": str(workspace_path) if workspace_path else "",
                "pattern_class": pattern_class_filter,
            },
            "privacy_guards": {
                "repo_relative_store_path_only": True,
                "symlinks_blocked": True,
                "secret_patterns_blocked": True,
            },
            "summary": {
                "total_terms_aggregated": len(term_agg),
                "total_matching": len(all_patterns),
                "returned_count": len(top_rejection_patterns),
                "training_records_parsed": len(raw_records),
                "structured_patterns_matching": len(structured_rejection_patterns_all),
                "structured_returned_count": len(structured_rejection_patterns),
            },
            "source_files": source_files,
            "top_rejection_patterns": top_rejection_patterns,
            "structured_rejection_patterns": structured_rejection_patterns,
            "advisory_boundary": (
                "Triager rejection patterns combine classifier vocabulary terms with "
                "structured real-review rejection patterns and pre-submit guards. "
                "Use alongside vault_exploit_context and severity calibration to avoid over-claiming. "
                "This callable is NOT a substitute for manual rubric-match verification."
            ),
        }
        base["token_estimate"] = _token_estimate(
            {
                "summary": base["summary"],
                "filters": base["filters"],
                "top_rejection_patterns": top_rejection_patterns,
                "structured_rejection_patterns": structured_rejection_patterns,
                "source_files": source_files,
            }
        )
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{TRIAGER_PATTERN_CONTEXT_SCHEMA}:triager_pattern:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_external_corpus_search(self, **kwargs: Any) -> dict[str, Any]:
        """Lane 9 (PR #658) — search ingested external corpora for relevant findings.

        Args:
            corpus: zkbugs | solodit | rust | contest | "" (all)
            query: free-text query
            limit: max results (default DEFAULT_LIMIT)

        Returns:
            {schema, results: [{path, slug, snippet, source, score}]}
        """
        corpus = str(kwargs.get("corpus", "") or "")
        query = str(kwargs.get("query", "") or "").strip().lower()
        limit = _clamp_limit(int(kwargs.get("limit", DEFAULT_LIMIT)))
        terms = list(dict.fromkeys(t for t in re.split(r"[^a-z0-9]+", query) if t))

        repo_root = self.repo_root or self.vault_dir.parent
        candidate_dirs = {
            "zkbugs": [
                ("zkbugs", repo_root / ".audit_logs" / "zkbugs_farming"),
            ],
            "solodit": [
                ("solodit", repo_root / "reference" / "corpus_mined"),
                ("solodit", repo_root / "reference" / "corpus_txt"),
            ],
            "rust": [
                ("rust", repo_root / ".audit_logs" / "rust_corpus_mining"),
                ("rust", repo_root / "reference" / "patterns.dsl.r94_solodit_rust"),
            ],
            "contest": [
                ("contest", repo_root / "reference" / "contest_cache"),
            ],
            "": [
                ("solodit", repo_root / "reference" / "corpus_mined"),
                ("solodit", repo_root / "reference" / "corpus_txt"),
                ("zkbugs", repo_root / ".audit_logs" / "zkbugs_farming"),
                ("rust", repo_root / ".audit_logs" / "rust_corpus_mining"),
                ("external-memory", self.vault_dir / "external-memory"),
            ],
        }
        search_dirs = candidate_dirs.get(corpus, candidate_dirs[""])
        stem_lang_map = {
            "sol": "solidity",
            "rs": "rust",
            "go": "go",
            "move": "move",
            "cairo": "cairo",
            "vy": "vyper",
            "circom": "circom",
        }
        framework_hints = {
            "circom": ("circom",),
            "halo2": ("halo2",),
            "cairo": ("cairo", "starknet"),
            "plonky3": ("plonky3",),
            "plonk": ("plonk",),
            "groth16": ("groth16",),
            "bellperson": ("bellperson",),
            "arkworks": ("arkworks",),
            "cosmwasm": ("cosmwasm",),
            "anchor": ("anchor",),
            "solana": ("solana",),
        }

        def _clean_scalar(raw: str) -> str:
            value = raw.strip().strip(",").strip()
            if value.startswith("|"):
                value = value[1:].strip()
            value = value.strip("\"'")
            if value.startswith("[") and value.endswith("]"):
                value = value[1:-1].strip()
            return value

        def _extract_scalar(text: str, *keys: str) -> str:
            for key in keys:
                pattern = re.compile(rf'(?im)^\s*"?{re.escape(key)}"?\s*:\s*(.+?)\s*$')
                match = pattern.search(text)
                if match:
                    value = _clean_scalar(match.group(1))
                    if value:
                        return value
            return ""

        def _extract_title(text: str, path: Path) -> str:
            frontmatter, body = _frontmatter_and_body(text)
            title = _title(path, frontmatter, body)
            return title.strip()

        def _infer_language(path: Path, text: str) -> str:
            explicit = _extract_scalar(text, "language")
            if explicit:
                lang = explicit.lower()
                if lang in LANGUAGE_FILE_EXT_HINTS or lang in ("circom",):
                    return lang
            hay = f"{path.as_posix()}\n{text[:800]}".lower()
            for lang, hints in LANGUAGE_PATH_HINTS.items():
                if any(h in hay for h in hints):
                    return lang
            for suffix, lang in stem_lang_map.items():
                token = f".{suffix}"
                if token in hay:
                    return lang
            return ""

        def _infer_framework(path: Path, text: str, language: str) -> str:
            explicit = _extract_scalar(text, "framework", "platform")
            hay = f"{path.as_posix()}\n{explicit}\n{text[:800]}".lower()
            for framework, hints in framework_hints.items():
                if any(h in hay for h in hints):
                    return framework
            if language in ("circom", "cairo"):
                return language
            return ""

        def _score_hit(path: Path, slug: str, text: str) -> dict[str, Any] | None:
            title = _extract_title(text, path)
            pattern_id = _extract_scalar(text, "pattern_id", "pattern", "id") or slug
            attack_class = _extract_scalar(text, "attack_class", "bug_class", "category", "class")
            language = _infer_language(path, text)
            framework = _infer_framework(path, text, language)
            lower_text = text.lower()
            frontmatter, body = _frontmatter_and_body(text)
            frontmatter_text = " ".join(f"{k} {v}" for k, v in frontmatter.items())
            fields = [
                ("slug", slug.lower(), 6),
                ("path", path.as_posix().lower(), 5),
                ("title", title.lower(), 4),
                ("pattern_id", pattern_id.lower(), 4 if pattern_id else 0),
                ("attack_class", attack_class.lower(), 4 if attack_class else 0),
                ("language", language.lower(), 2 if language else 0),
                ("framework", framework.lower(), 2 if framework else 0),
                ("frontmatter", frontmatter_text.lower(), 2 if frontmatter_text else 0),
                ("body", body.lower(), 1),
            ]
            matched_terms: list[str] = []
            matched_fields: set[str] = set()
            raw_score = 0

            if not terms:
                raw_score = 1
            else:
                for term in terms:
                    term_score = 0
                    for field_name, haystack, weight in fields:
                        if weight <= 0 or not haystack or term not in haystack:
                            continue
                        matched_fields.add(field_name)
                        term_score += weight
                    if term_score > 0:
                        matched_terms.append(term)
                        raw_score += term_score
                if query and query in lower_text:
                    matched_fields.add("phrase")
                    raw_score += max(2, len(terms) * 2)
            if raw_score <= 0:
                return None

            max_term_weight = 30
            denom = max(1, len(terms) * max_term_weight)
            normalized_score = 1.0 if not terms else min(1.0, raw_score / denom)
            snippet_source = body if body.strip() else text
            snippet = snippet_source[:300]
            return {
                "title": title,
                "pattern_id": pattern_id or "",
                "attack_class": attack_class or "",
                "language": language or "",
                "framework": framework or "",
                "score": raw_score,
                "normalized_score": round(normalized_score, 4),
                "term_match_count": len(matched_terms),
                "matched_terms": matched_terms,
                "matched_fields": sorted(matched_fields),
                "snippet": snippet,
            }

        def _safe_repo_hit_path(path: Path) -> str:
            try:
                return path.resolve().relative_to(repo_root.resolve()).as_posix()
            except ValueError:
                return "[redacted-local-path]"

        hits = []
        for corpus_name, d in search_dirs:
            if not d.exists():
                continue
            for ext in ("*.jsonl", "*.json", "*.yaml", "*.md"):
                for f in d.rglob(ext):
                    try:
                        text = f.read_text(errors="replace")
                    except OSError:
                        continue
                    scored = _score_hit(f, f.stem, text)
                    if scored is None:
                        continue
                    hits.append({
                        "path": _safe_repo_hit_path(f),
                        "slug": f.stem,
                        "snippet": scored["snippet"],
                        "source": corpus or "all",
                        "score": scored["score"],
                        "normalized_score": scored["normalized_score"],
                        "term_match_count": scored["term_match_count"],
                        "matched_terms": scored["matched_terms"],
                        "matched_fields": scored["matched_fields"],
                        "corpus": corpus_name,
                        "language": scored["language"],
                        "framework": scored["framework"],
                        "attack_class": scored["attack_class"],
                        "pattern_id": scored["pattern_id"],
                        "title": scored["title"],
                    })
        hits.sort(
            key=lambda r: (
                -int(r["score"]),
                -float(r.get("normalized_score", 0.0)),
                -int(r.get("term_match_count", 0)),
                str(r["path"]),
            )
        )
        return {
            "schema": "auditooor.vault_external_corpus_search.v1",
            "corpus": corpus or "all",
            "query": query,
            "query_terms": terms,
            "results": hits[:limit],
        }

    def vault_llm_calibration(self, **kwargs: Any) -> dict[str, Any]:
        """Lane 12 (PR #658) — return LLM dispatch calibration data.

        Reads existing tools/calibration/llm_calibration_log.jsonl (no parallel
        ledger). Computes per-provider × task_type empirical accuracy.

        Args:
            provider: claude | codex | kimi | minimax | "" (all)
            task_type: filter by task type (or "")
            limit: max recent rows to include (default 5)

        Returns:
            {schema, provider, task_type, n_total, n_decided, recent_tp_rate,
             recommended, recent: [...]}
        """
        provider = str(kwargs.get("provider", "") or "")
        task_type = str(kwargs.get("task_type", "") or "")
        limit = _clamp_limit(int(kwargs.get("limit", 5)))

        repo_root = self.repo_root or self.vault_dir.parent
        log_path = repo_root / "tools" / "calibration" / "llm_calibration_log.jsonl"
        if not log_path.is_file():
            return {
                "schema": "auditooor.vault_llm_calibration.v1",
                "error": "no-calibration-ledger",
                "log_path": str(log_path),
            }

        rows = []
        try:
            for line in log_path.read_text(errors="replace").splitlines():
                if not line.strip() or line.startswith("#"):
                    continue
                try:
                    r = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if provider and r.get("provider") != provider:
                    continue
                if task_type and r.get("task_type") != task_type:
                    continue
                rows.append(r)
        except OSError as exc:
            return {"schema": "auditooor.vault_llm_calibration.v1", "error": f"read error: {exc}"}

        decided = [r for r in rows if str(r.get("verdict", "")).upper() in ("TRUE", "FALSE")]
        tp = sum(1 for r in decided if str(r.get("verdict", "")).upper() == "TRUE")
        rate = round(tp / len(decided), 3) if decided else None
        recommended = bool(decided and len(decided) >= 10 and (rate or 0) >= 0.70)
        return {
            "schema": "auditooor.vault_llm_calibration.v1",
            "provider": provider or "all",
            "task_type": task_type or "all",
            "n_total": len(rows),
            "n_decided": len(decided),
            "recent_tp_rate": rate,
            "recommended": recommended,
            "recent": rows[-limit:],
        }

    def vault_provider_capacity(self, **kwargs: Any) -> dict[str, Any]:
        """Lane B7 (PR #658) — return per-provider capacity from budget + calibration logs.

        Wraps tools/provider-capacity-report.py::_budget_log_summary() directly
        (no subprocess).  Computes headroom_pct and recommended flag from the
        budget log spend vs daily budget config.

        Args:
            provider: filter to single provider string, or "" / omit for all
            limit:    max recent budget-log rows per provider (default 5)

        Returns schema ``auditooor.vault_provider_capacity.v1`` with:
            {schema, provider_filter, rows: [{provider, daily_budget_usd,
             recent_spend_est_usd, headroom_pct, recent_calibration_tp_rate,
             recommended}], advisory_only, source_refs}
        """
        provider_filter = str(kwargs.get("provider", "") or "")
        limit = _clamp_limit(int(kwargs.get("limit", 5)), default=5)

        repo_root = self.repo_root or self.vault_dir.parent
        budget_log_path = repo_root / "tools" / "calibration" / "llm_budget_log.jsonl"
        budget_cfg_path = repo_root / "tools" / "calibration" / "llm_budget.json"
        calib_log_path = repo_root / "tools" / "calibration" / "llm_calibration_log.jsonl"
        model_env_vars = {
            "kimi": ("KIMI_MODEL", "kimi-for-coding"),
            "minimax": ("MINIMAX_MODEL", "MiniMax-M2.7"),
            "anthropic": ("ANTHROPIC_MODEL", "claude-opus-4-5"),
        }
        model_registry = {
            prov: {
                "active_model": os.environ.get(env_name) or default_model,
                "default_model": default_model,
                "model_env_var": env_name,
                "upgrade_note": "provider calibration is model-specific; rerun a mixed advisory calibration slice after changing this model",
            }
            for prov, (env_name, default_model) in model_env_vars.items()
        }

        if not budget_log_path.is_file():
            return {
                "schema": PROVIDER_CAPACITY_SCHEMA,
                "error": "no-budget-log",
                "log_path": str(budget_log_path),
            }

        # --- read budget log ---------------------------------------------------
        budget_rows: list[dict[str, Any]] = []
        try:
            for line in budget_log_path.read_text(errors="replace").splitlines():
                if not line.strip() or line.startswith("#"):
                    continue
                try:
                    r = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if isinstance(r, dict):
                    budget_rows.append(r)
        except OSError as exc:
            return {"schema": PROVIDER_CAPACITY_SCHEMA, "error": f"read error: {exc}"}

        # --- read budget config for daily_budget_usd per provider --------------
        daily_budgets: dict[str, float] = {}
        try:
            cfg = json.loads(budget_cfg_path.read_text(encoding="utf-8"))
            for prov, pdata in (cfg.get("providers") or {}).items():
                if isinstance(pdata, dict) and "daily_budget_usd" in pdata:
                    daily_budgets[str(prov)] = float(pdata["daily_budget_usd"])
        except (OSError, json.JSONDecodeError, ValueError):
            pass

        # --- aggregate by provider ---------------------------------------------
        by_provider: dict[str, dict[str, Any]] = {}
        for row in budget_rows:
            prov = str(row.get("provider") or "unknown")
            if provider_filter and prov != provider_filter:
                continue
            rec = by_provider.setdefault(
                prov,
                {
                    "calls": 0,
                    "successes": 0,
                    "cost_usd_sum": 0.0,
                    "recent_rows": [],
                },
            )
            rec["calls"] += 1
            rec["successes"] += 1 if row.get("success") is True else 0
            rec["cost_usd_sum"] += float(row.get("cost_usd") or 0.0)
            rec["recent_rows"].append(row)

        # --- read calibration log for tp_rate per provider ---------------------
        tp_rates: dict[str, float | None] = {}
        try:
            calib_rows: list[dict[str, Any]] = []
            for line in calib_log_path.read_text(errors="replace").splitlines():
                if not line.strip() or line.startswith("#"):
                    continue
                try:
                    r = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if isinstance(r, dict):
                    calib_rows.append(r)
            for prov in list(by_provider.keys()) + ([provider_filter] if provider_filter else []):
                decided = [r for r in calib_rows if r.get("provider") == prov and str(r.get("verdict", "")).upper() in ("TRUE", "FALSE")]
                if decided:
                    tp = sum(1 for r in decided if str(r.get("verdict", "")).upper() == "TRUE")
                    tp_rates[prov] = round(tp / len(decided), 3)
                else:
                    tp_rates[prov] = None
        except OSError:
            pass

        # --- build rows --------------------------------------------------------
        output_rows: list[dict[str, Any]] = []
        for prov, rec in sorted(by_provider.items()):
            daily = daily_budgets.get(prov)
            spend = round(rec["cost_usd_sum"], 4)
            if daily and daily > 0:
                headroom_pct = round(max(0.0, (daily - spend) / daily) * 100, 1)
            else:
                headroom_pct = None
            tp_rate = tp_rates.get(prov)
            recommended = bool(
                headroom_pct is not None and headroom_pct > 10.0
                and (tp_rate is None or tp_rate >= 0.60)
            )
            output_rows.append(
                {
                    "provider": prov,
                    "active_model": model_registry.get(prov, {}).get("active_model"),
                    "model_env_var": model_registry.get(prov, {}).get("model_env_var"),
                    "daily_budget_usd": daily,
                    "recent_spend_est_usd": spend,
                    "headroom_pct": headroom_pct,
                    "recent_calibration_tp_rate": tp_rate,
                    "recent_calls": rec["calls"],
                    "recent_successes": rec["successes"],
                    "recent_rows": rec["recent_rows"][-limit:],
                    "recommended": recommended,
                }
            )

        source_refs = ["tools/calibration/llm_budget_log.jsonl"]
        if budget_cfg_path.is_file():
            source_refs.append("tools/calibration/llm_budget.json")
        if calib_log_path.is_file():
            source_refs.append("tools/calibration/llm_calibration_log.jsonl")

        base: dict[str, Any] = {
            "schema": PROVIDER_CAPACITY_SCHEMA,
            "provider_filter": provider_filter or "all",
            "rows": output_rows,
            "model_registry": model_registry,
            "advisory_only": True,
            "source_refs": source_refs,
        }
        digest = hashlib.sha256(_canonical_json(base).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{PROVIDER_CAPACITY_SCHEMA}:provider_capacity:{digest[:16]}",
            "context_pack_hash": digest,
            **base,
        }

    def vault_corpus_mining_state(self, **kwargs: Any) -> dict[str, Any]:
        """Lane M-I (PR #658+) — return corpus mining inventory and freshness ledger.

        Invokes ``tools/corpus-mining-state-snapshot.py::build_snapshot()`` directly
        (no subprocess) to produce a live corpus inventory.  Results are NOT cached;
        each call re-probes the filesystem.

        Inputs (all optional):
          * ``workspace_path``: accepted for caller consistency but unused by
            the global snapshot and not echoed in the public payload.

        Output schema: ``auditooor.vault_corpus_mining_state.v1`` — fields:
          * ``snapshot``: the full ``auditooor.corpus_mining_state.v1`` object from
            corpus-mining-state-snapshot.py (corpora[], stale_corpora[],
            generated_at).
          * ``freshness_days_by_corpus``: dict mapping corpus name →
            ``staleness_days`` (float or null).
          * ``gaps``: list of corpus names whose ``staleness_category`` is
            ``"stale"`` (i.e. never mined or > 21 days stale).
          * ``context_pack_id`` and ``context_pack_hash``: always present for
            pr-hygiene-check.py.
        """
        # Import corpus-mining-state-snapshot as a module (no subprocess).
        repo_root = self.repo_root or self.vault_dir.parent
        snapshot_py = repo_root / "tools" / "corpus-mining-state-snapshot.py"
        snap: dict[str, Any] = {}
        if snapshot_py.is_file():
            try:
                import importlib.util as _ilu
                _spec = _ilu.spec_from_file_location("corpus_mining_state_snapshot", snapshot_py)
                if _spec and _spec.loader:
                    _mod = _ilu.module_from_spec(_spec)
                    _spec.loader.exec_module(_mod)  # type: ignore[attr-defined]
                    snap = _mod.build_snapshot()
            except Exception as exc:
                snap = {"error": f"snapshot_import_error: {exc}"}
        else:
            snap = {"error": "corpus-mining-state-snapshot.py not found", "path": str(snapshot_py)}

        # Derive freshness_days_by_corpus and gaps from the snapshot corpora list.
        freshness_by_corpus: dict[str, float | None] = {}
        gaps: list[str] = []
        if isinstance(snap.get("corpora"), list):
            for c in snap["corpora"]:
                name = c.get("corpus", "")
                freshness_by_corpus[name] = c.get("staleness_days")
                if c.get("staleness_category") == "stale":
                    gaps.append(name)

        payload: dict[str, Any] = {
            "schema": CORPUS_MINING_STATE_SCHEMA,
            "kind": "corpus_mining_state",
            "snapshot": snap,
            "freshness_days_by_corpus": freshness_by_corpus,
            "gaps": gaps,
            "gap_count": len(gaps),
        }

        hash_payload = dict(payload)
        snapshot_for_hash = json.loads(json.dumps(snap, sort_keys=True, default=str))
        if isinstance(snapshot_for_hash, dict):
            snapshot_for_hash.pop("generated_at", None)
        hash_payload["snapshot"] = snapshot_for_hash
        digest = hashlib.sha256(_canonical_json(hash_payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{CORPUS_MINING_STATE_SCHEMA}:corpus_mining:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_hacker_brief_for_lane(self, **kwargs: Any) -> dict[str, Any]:
        """W2-B-1 (iter12/13) — return a hacker-mindset brief for a specific hunt lane.

        Thinly wraps ``tools/agent-prompt-hacker-augmenter.py`` (W2-A). If that tool
        has not been shipped yet the callable degrades gracefully: returns a stub brief
        with ``degraded: true`` and ``reason: "augmenter_tool_not_yet_shipped"`` rather
        than crashing.  This lets iter-13 B-2/3/4/5 callables use the same pattern
        without waiting on W2-A.

        Args:
            workspace_path: absolute path to the audit workspace (required).
            lane_id:        hunt lane identifier, e.g. "H1-coop-exit" (required,
                            must match ``[A-Za-z0-9_-]+``).
            files:          optional list of in-scope file paths (workspace-relative
                            or absolute); forwarded to the augmenter via ``--files``.

        Returns (top-level keys):
            context_pack_id, context_pack_hash, lane_id, files, brief_markdown,
            degraded, source_refs, augmenter_tool_version, timestamp_utc.

        Schema: ``auditooor.vault_hacker_brief_for_lane.v1``.
        """
        import datetime
        import subprocess
        import tempfile

        workspace_path_arg = kwargs.get("workspace_path") or ""
        workspace_label = _engage_report_workspace_label(workspace_path_arg, default="workspace")
        lane_id = kwargs.get("lane_id") or ""
        files_arg = kwargs.get("files") or []

        # --- Input validation ---
        if not workspace_path_arg:
            return {
                "context_pack_id": f"{HACKER_BRIEF_FOR_LANE_SCHEMA}:hacker_brief_for_lane:error",
                "context_pack_hash": "",
                "error": "workspace_path is required",
                "degraded": True,
            }
        workspace_path = Path(str(workspace_path_arg)).expanduser().resolve()
        if not workspace_path.is_dir():
            return {
                "context_pack_id": f"{HACKER_BRIEF_FOR_LANE_SCHEMA}:hacker_brief_for_lane:error",
                "context_pack_hash": "",
                "error": f"workspace_path not found: {workspace_label}",
                "degraded": True,
            }
        workspace_label = _engage_report_workspace_label(workspace_path, default=workspace_label)
        if not lane_id or not LANE_ID_RE.match(lane_id):
            return {
                "context_pack_id": f"{HACKER_BRIEF_FOR_LANE_SCHEMA}:hacker_brief_for_lane:error",
                "context_pack_hash": "",
                "error": "lane_id is required and must match [A-Za-z0-9_-]+",
                "degraded": True,
            }
        if not isinstance(files_arg, list):
            files_arg = []
        files: list[str] = [str(f) for f in files_arg if isinstance(f, (str, Path))]
        effective_files: list[str] = files or ["SCOPE.md"]

        def safe_file_label(raw: object) -> str:
            text = str(raw if raw is not None else "").strip()
            if not text:
                return "<external>/unknown"
            try:
                candidate = Path(text).expanduser()
            except (OSError, RuntimeError):
                candidate = Path("")
            rel_text = ""
            if candidate and candidate.is_absolute():
                try:
                    rel_text = candidate.relative_to(workspace_path).as_posix()
                except ValueError:
                    name = _safe_workspace_relpath(candidate.name) or "external"
                    return f"<external>/{name}"
            else:
                rel_text = text
            return _safe_workspace_relpath(rel_text) or "<external>/unknown"

        payload_files = [safe_file_label(f) for f in effective_files]

        def workspace_path_ref(path_value: object, fallback_rel: str) -> str:
            try:
                candidate = Path(str(path_value or "")).expanduser()
                if candidate.is_absolute():
                    try:
                        candidate.resolve().relative_to(workspace_path)
                    except (OSError, ValueError):
                        safe_name = _safe_workspace_relpath(candidate.name) or "hacker_brief.md"
                        return f"generated:{safe_name}"
            except (OSError, RuntimeError):
                pass
            rel = _safe_engage_report_hit_path(path_value, workspace_path) or _safe_workspace_relpath(fallback_rel)
            return f"workspace:{rel}" if rel else "workspace:unknown"

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

        # --- Locate augmenter tool ---
        repo_root = self.repo_root or self.vault_dir.parent
        augmenter_py = repo_root / "tools" / "agent-prompt-hacker-augmenter.py"

        # Workspace state file referenced in source_refs.
        state_file = workspace_path / ".auditooor" / "spark_hunt_loop_state.json"
        source_refs: list[str] = []
        if augmenter_py.is_file():
            source_refs.append("tools/agent-prompt-hacker-augmenter.py")
        if (workspace_path / "engage_report.md").is_file():
            source_refs.append(f"{workspace_path.name}/engage_report.md")
        if state_file.is_file():
            source_refs.append(f"{workspace_path.name}/.auditooor/spark_hunt_loop_state.json")

        # --- Resolve augmenter tool version ---
        augmenter_tool_version = "uncommitted"
        try:
            result = subprocess.run(
                ["git", "-C", str(repo_root), "rev-parse", "HEAD"],
                capture_output=True, text=True, timeout=5,
            )
            if result.returncode == 0:
                augmenter_tool_version = result.stdout.strip()
        except Exception:  # noqa: BLE001
            pass

        # --- Happy path: invoke augmenter ---
        canonical_brief_path = workspace_path / ".auditooor" / "hacker_brief.md"
        generated_brief_path = ""
        if augmenter_py.is_file():
            def run_augmenter(out_path: Path) -> subprocess.CompletedProcess[str]:
                cmd = [
                    sys.executable,
                    str(augmenter_py),
                    "--workspace", str(workspace_path),
                    "--lane-id", lane_id,
                    "--files", ",".join(effective_files),
                    "--out", str(out_path),
                    "--json-out",
                ]
                return subprocess.run(
                    cmd, capture_output=True, text=True, timeout=60,
                )

            try:
                aug_result = run_augmenter(canonical_brief_path)
                if aug_result.returncode != 0 and "PermissionError" in aug_result.stderr:
                    temp_dir = Path(tempfile.gettempdir()) / "auditooor_mcp_hacker_briefs"
                    temp_dir.mkdir(parents=True, exist_ok=True)
                    safe_lane = re.sub(r"[^A-Za-z0-9_-]+", "-", lane_id).strip("-_") or "lane"
                    fallback_brief_path = (
                        temp_dir / f"hacker_brief_{safe_lane}_{timestamp_utc.replace(':', '').replace('-', '')}.md"
                    )
                    aug_result = run_augmenter(fallback_brief_path)
                if aug_result.returncode == 0:
                    output_lines = [line.strip() for line in aug_result.stdout.splitlines() if line.strip()]
                    generated_brief_path = (
                        output_lines[-1]
                        if output_lines
                        else str(canonical_brief_path)
                    )
                    try:
                        brief_path = Path(generated_brief_path).expanduser()
                        brief_markdown = brief_path.read_text(encoding="utf-8")
                    except Exception:  # noqa: BLE001
                        brief_markdown = aug_result.stdout.strip()
                    degraded = False
                    degraded_reason = ""
                else:
                    brief_markdown = (
                        f"# Hacker Brief — {lane_id}\n\n"
                        f"[augmenter returned exit {aug_result.returncode}]\n\n"
                        f"stderr: {aug_result.stderr[:400]}"
                    )
                    degraded = True
                    degraded_reason = f"augmenter_exit_{aug_result.returncode}"
            except Exception as exc:  # noqa: BLE001
                brief_markdown = f"# Hacker Brief — {lane_id}\n\n[augmenter error: {exc}]"
                degraded = True
                degraded_reason = f"augmenter_error: {exc}"
        else:
            # --- Degraded path: augmenter not yet shipped (W2-A pending) ---
            brief_markdown = (
                f"# Hacker Brief — {lane_id} [STUB]\n\n"
                f"> augmenter tool not yet shipped (W2-A pending).\n"
                f"> Workspace: {workspace_label}\n"
                f"> Files in scope: {', '.join(payload_files)}\n\n"
                "## Placeholder\n\n"
                "Run `python3 tools/agent-prompt-hacker-augmenter.py` once W2-A ships "
                "to get the full scope-filtered hacker brief."
            )
            degraded = True
            degraded_reason = "augmenter_tool_not_yet_shipped"

        # iter3 Lane O (2026-05-23): inject Section 0 "Codified rules this
        # lane MUST address" by calling vault_codified_rules_digest with
        # the lane's subtype. The augmenter's existing Section 0 is the
        # L17 verdict-shape contract; this NEW header sits ABOVE it so
        # spawned sub-agents auto-receive R43/R44/R45 (and the rest of
        # the codified rule corpus filtered by lane subtype) without
        # needing to re-read CLAUDE.md.
        try:
            rules_pack = self.vault_codified_rules_digest(
                workspace_path=str(workspace_path),
                lane=lane_id,
            )
            lane_subtype_resolved = str(rules_pack.get("lane_subtype") or "all")
            must_address = list(rules_pack.get("lane_specific_must_address") or [])
            warnings = list(rules_pack.get("routine_violation_warnings") or [])
            digest_records = list(rules_pack.get("digest") or [])
            # Index rule_id -> (name, override_marker, mech_gate) for citation.
            rule_index: dict[str, dict[str, Any]] = {}
            for r in digest_records:
                rid = str(r.get("rule_id") or "").strip().upper()
                if rid:
                    rule_index[rid] = {
                        "name": str(r.get("name") or ""),
                        "override_marker": str(r.get("override_marker") or ""),
                        "mechanical_gate": str(r.get("mechanical_gate") or ""),
                        "severity_scope": str(r.get("severity_scope") or "any"),
                    }
            section0_lines = [
                f"## Section 0 (MCP-injected) - Codified rules this lane MUST address",
                "",
                f"> Lane subtype resolved: `{lane_subtype_resolved}` "
                f"(from lane_id `{lane_id}`)",
                f"> Source: `reference/codified_rules_digest.json` "
                f"(sha256 prefix `{(rules_pack.get('digest_source') or {}).get('source_sha256','')[:12]}`)",
                "",
                "Spawned sub-agents authoring drafts for this lane MUST cite "
                "EACH rule below by ID in their reply, OR add the rule's "
                "override marker (e.g. `<!-- r43-rebuttal: <reason> -->`).",
                "Bare prose mention is not enough; the gates expect the rule "
                "ID literal or the override marker literal.",
                "",
                "| Rule ID | Name | Severity scope | Override marker |",
                "| --- | --- | --- | --- |",
            ]
            for rid in must_address:
                meta = rule_index.get(rid.upper(), {})
                section0_lines.append(
                    f"| {rid} | {meta.get('name','(rule not in digest)')} | "
                    f"{meta.get('severity_scope','any')} | "
                    f"`{meta.get('override_marker','')}` |"
                )
            section0_lines.append("")
            section0_lines.append("### Recent failure modes to avoid (top-5 routine violations)")
            section0_lines.append("")
            for w in warnings[:5]:
                section0_lines.append(
                    f"- **{w.get('rule_id','?')}-{w.get('name','?')}**: "
                    f"{w.get('remediation','').strip()} "
                    f"(override: `{w.get('override_marker','')}`)"
                )
            section0_lines.append("")
            section0_lines.append(
                "> Verify enforcement post-edit with "
                "`bash pre-submit-check.sh <draft.md> --workspace <ws>`."
            )
            section0_lines.append("")
            section0_block = "\n".join(section0_lines)
            brief_markdown = f"{section0_block}\n{brief_markdown.lstrip()}"
            # Add the digest source_ref so it's auditable.
            for ref in ("reference/codified_rules_digest.json",):
                if ref not in source_refs:
                    source_refs.append(ref)
        except Exception as exc:  # noqa: BLE001 - injection must degrade
            # Don't crash the brief on a digest-load problem; just
            # prepend a degraded notice so the operator notices.
            brief_markdown = (
                "## Section 0 (MCP-injected) [DEGRADED]\n\n"
                f"> codified-rules digest injection failed: {exc}\n\n"
                f"{brief_markdown.lstrip()}"
            )

        payload: dict[str, Any] = {
            "schema": HACKER_BRIEF_FOR_LANE_SCHEMA,
            "kind": "hacker_brief_for_lane",
            "lane_id": lane_id,
            "files": payload_files,
            "brief_markdown": brief_markdown,
            "generated_brief_path": workspace_path_ref(generated_brief_path or canonical_brief_path, ".auditooor/hacker_brief.md"),
            "degraded": degraded,
            "degraded_reason": degraded_reason,
            "source_refs": source_refs,
            "augmenter_tool_version": augmenter_tool_version,
            "timestamp_utc": timestamp_utc,
            "workspace_path": workspace_label,
        }

        try:
            helper_payload = self._build_hackerman_brief_payload(
                workspace_path=workspace_path,
                lane_id=lane_id,
                files=effective_files,
                kwargs=kwargs,
            )
        except Exception as exc:  # noqa: BLE001 - optional query index must degrade.
            helper_payload = {
                "degraded": True,
                "reason": f"hackerman_query_error: {exc}",
                "records": [],
                "source_refs": [],
            }
        if isinstance(helper_payload, dict):
            helper_refs = self._safe_hackerman_source_refs(helper_payload.get("source_refs"))
            for ref in helper_refs:
                if ref not in source_refs:
                    source_refs.append(ref)
            records = helper_payload.get("records") if isinstance(helper_payload.get("records"), list) else []
            helper_brief = str(helper_payload.get("brief_markdown") or "").strip()
            if records and helper_brief:
                payload["brief_markdown"] = (
                    f"{payload['brief_markdown'].rstrip()}\n\n"
                    "## Index-Backed Hackerman Corpus\n\n"
                    f"{helper_brief}"
                )
            payload["hackerman_query"] = {
                "schema": helper_payload.get("schema"),
                "context_pack_id": helper_payload.get("context_pack_id", ""),
                "context_pack_hash": helper_payload.get("context_pack_hash", ""),
                "degraded": bool(helper_payload.get("degraded", False)),
                "degraded_reason": helper_payload.get("degraded_reason") or helper_payload.get("reason") or "",
                "target": helper_payload.get("target") or {},
                "total_records_matched": int(helper_payload.get("total_records_matched") or 0),
                "records": records[:10],
                "source_refs": helper_refs,
                "sidecar_gaps": helper_payload.get("sidecar_gaps", [])
                if isinstance(helper_payload.get("sidecar_gaps"), list)
                else [],
            }
            helper_gaps = payload["hackerman_query"]["sidecar_gaps"]
            if helper_gaps:
                payload["sidecar_gaps"] = helper_gaps
            payload["source_refs"] = source_refs

        digest = hashlib.sha256(
            _canonical_json(_hacker_brief_hash_payload(payload)).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{HACKER_BRIEF_FOR_LANE_SCHEMA}:hacker_brief_for_lane:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_lane_cooldown_check(self, **kwargs: Any) -> dict[str, Any]:
        """W2-B-5 (iter15) — check cooldown lanes from spark_hunt_loop_state.json.

        Lets orchestrators decide whether a cooled-down lane's ``trigger_state``
        has changed since cooldown was set, enabling safe re-run decisions.

        Args:
            workspace_path: absolute path to the audit workspace (default:
                ``~/audits/spark``). ``workspace`` is accepted as a
                compatibility alias.
            worktree_path: optional absolute path to the orchestrator worktree
                (e.g. ``/Users/wolf/auditooor-worktrees/dlt-workflow-gaps-main``)
                whose ``.auditooor/spark_hunt_loop_state.json`` is consulted as a
                fallback when ``workspace_path`` has no state file.
            lane_id: optional filter — if given, return only that lane's row.
            state_file: optional override path for the state JSON (default:
                ``<workspace_path>/.auditooor/spark_hunt_loop_state.json``).

        Path search order when ``state_file`` not provided:

          1. ``<workspace_path>/.auditooor/spark_hunt_loop_state.json``
          2. ``<worktree_path>/.auditooor/spark_hunt_loop_state.json``
             (if ``worktree_path`` arg given)
          3. Glob ``/Users/wolf/auditooor-worktrees/*/.auditooor/spark_hunt_loop_state.json``
             (best-effort fallback for service-account / cross-worktree calls)

        Returns (top-level keys):
            context_pack_id, context_pack_hash, schema, kind="lane_cooldown",
            lanes (list), total_cooldowns (int), current_iter (int),
            state_file_path (str), state_file_path_searched (list[str]),
            privacy_guards (dict).

        Each lane object:
            lane_id, since_iter, reason (≤240 chars), trigger_state_summary,
            current_iter, iter_age, staleness_class.

        staleness_class values: "fresh" (age < 5), "stale_5+_iters" (5–9),
        "stale_10+_iters" (10+).

        Graceful empty envelope when state file absent or cooldowns empty.

        Schema: ``auditooor.vault_lane_cooldown_check.v1``.
        """
        import datetime
        import os

        # Track whether workspace_path was explicitly provided. When the caller
        # supplies workspace_path, the cross-worktree glob fallback (step 4
        # below) is suppressed unconditionally - we trust the caller's scope.
        # When workspace_path is NOT supplied, the glob fallback is also gated
        # behind AUDITOOOR_ALLOW_WORKTREE_GLOB_FALLBACK=1 because globbing
        # /Users/wolf/auditooor-worktrees/*/.auditooor/* is environment-leaky
        # (it picks up cooldowns from every co-resident worktree on the host,
        # which breaks hermetic test contexts and concurrent-agent isolation).
        workspace_path_value = kwargs.get("workspace_path") or kwargs.get("workspace")
        workspace_path_explicit = bool(workspace_path_value)
        workspace_path_arg = workspace_path_value or str(Path.home() / "audits" / "spark")
        worktree_path_arg = kwargs.get("worktree_path") or ""
        lane_id_filter = kwargs.get("lane_id") or ""
        state_file_override = kwargs.get("state_file") or ""
        allow_worktree_glob_fallback = (
            os.environ.get("AUDITOOOR_ALLOW_WORKTREE_GLOB_FALLBACK", "") == "1"
        )

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

        # Resolve workspace path
        try:
            workspace = Path(str(workspace_path_arg)).expanduser().resolve()
        except (OSError, RuntimeError):
            workspace = None

        # Resolve worktree path (optional)
        worktree: Path | None = None
        if worktree_path_arg:
            try:
                worktree = Path(str(worktree_path_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                worktree = None

        # Path-search candidate list (in order):
        #   1. explicit state_file override (if set)
        #   2. workspace_path/.auditooor/spark_hunt_loop_state.json
        #   3. worktree_path/.auditooor/spark_hunt_loop_state.json (if given)
        #   4. glob /Users/wolf/auditooor-worktrees/*/.auditooor/spark_hunt_loop_state.json
        #      ONLY when (a) workspace_path was NOT explicitly supplied by the
        #      caller AND (b) AUDITOOOR_ALLOW_WORKTREE_GLOB_FALLBACK=1 is set
        #      in the environment. This keeps test contexts hermetic and
        #      prevents concurrent-agent cooldown leakage across worktrees.
        state_path: Path | None = None
        candidates_tried: list[str] = []

        if state_file_override:
            try:
                cand = Path(str(state_file_override)).expanduser().resolve()
                candidates_tried.append(str(cand))
                if cand.exists() and cand.is_file():
                    state_path = cand
            except (OSError, RuntimeError):
                pass
        else:
            # 1. workspace candidate
            if workspace:
                cand = workspace / ".auditooor" / "spark_hunt_loop_state.json"
                candidates_tried.append(str(cand))
                if cand.exists() and cand.is_file():
                    state_path = cand
            # 2. worktree candidate
            if state_path is None and worktree:
                cand = worktree / ".auditooor" / "spark_hunt_loop_state.json"
                candidates_tried.append(str(cand))
                if cand.exists() and cand.is_file():
                    state_path = cand
            # 3. glob fallback for service-account / cross-worktree.
            #    Hermetic gate: only run when caller did NOT pin workspace_path
            #    AND AUDITOOOR_ALLOW_WORKTREE_GLOB_FALLBACK=1 is set.
            if (
                state_path is None
                and not workspace_path_explicit
                and allow_worktree_glob_fallback
            ):
                glob_root = Path(
                    os.environ.get(
                        "AUDITOOOR_WORKTREE_GLOB_ROOT",
                        "/Users/wolf/auditooor-worktrees",
                    )
                )
                glob_pattern = "*/.auditooor/spark_hunt_loop_state.json"
                if glob_root.exists() and glob_root.is_dir():
                    try:
                        for match in sorted(glob_root.glob(glob_pattern)):
                            candidates_tried.append(str(match))
                            if match.exists() and match.is_file():
                                state_path = match
                                break
                    except (OSError, RuntimeError):
                        pass

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
            "reason_text_truncated_at": 240,
        }

        def _make_empty(error: str | None = None) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": LANE_COOLDOWN_CHECK_SCHEMA,
                "kind": "lane_cooldown",
                "lanes": [],
                "total_cooldowns": 0,
                "current_iter": 0,
                "state_file_path": str(state_path) if state_path else "",
                "state_file_path_searched": list(candidates_tried),
                "workspace_path": str(workspace_path_arg),
                "worktree_path": str(worktree_path_arg) if worktree_path_arg else "",
                "timestamp_utc": timestamp_utc,
                "privacy_guards": privacy_guards,
            }
            if error == "state_file_not_found":
                payload["verdict"] = "pass-no-cooldown-ledger"
                payload["state_file_status"] = "absent"
                payload["degraded"] = False
                payload["degraded_reason"] = ""
                payload["note"] = (
                    "No cooldown ledger exists for this workspace; treat as "
                    "cooldown-clear, not as an MCP lookup failure."
                )
            elif error:
                payload["verdict"] = "error"
                payload["state_file_status"] = "unreadable"
                payload["degraded"] = True
                payload["degraded_reason"] = error
                payload["error"] = error
            else:
                payload["verdict"] = "pass-no-active-cooldowns"
                payload["state_file_status"] = "present"
                payload["degraded"] = False
                payload["degraded_reason"] = ""
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{LANE_COOLDOWN_CHECK_SCHEMA}:lane_cooldown:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        # Guard: state file must exist and be readable
        if state_path is None or not state_path.exists() or not state_path.is_file():
            return _make_empty("state_file_not_found")

        try:
            raw = state_path.read_text(encoding="utf-8", errors="replace")
            state: dict[str, Any] = json.loads(raw)
        except (OSError, json.JSONDecodeError) as exc:
            return _make_empty(f"state_file_read_error: {exc}")

        current_iter: int = int(state.get("iteration", 0))

        # lane_cooldowns may be a dict {lane_id: {...}} or a list [{lane_id: ..., ...}]
        raw_cooldowns = state.get("lane_cooldowns", {})
        if isinstance(raw_cooldowns, dict):
            cooldown_items: list[tuple[str, dict[str, Any]]] = [
                (k, v if isinstance(v, dict) else {})
                for k, v in raw_cooldowns.items()
            ]
        elif isinstance(raw_cooldowns, list):
            cooldown_items = []
            for entry in raw_cooldowns:
                if isinstance(entry, dict):
                    lid = str(entry.get("lane_id", ""))
                    cooldown_items.append((lid, entry))
        else:
            cooldown_items = []

        total_cooldowns = len(cooldown_items)

        def _staleness_class(age: int) -> str:
            if age >= 10:
                return "stale_10+_iters"
            if age >= 5:
                return "stale_5+_iters"
            return "fresh"

        def _trigger_state_summary(reason: str, trigger_state: Any) -> str:
            """Heuristically extract what condition would unblock this lane."""
            # If trigger_state is a dict, list its keys as the unlock conditions
            if isinstance(trigger_state, dict) and trigger_state:
                parts = [f"{k}={v!r}" for k, v in list(trigger_state.items())[:4]]
                return "unblock when: " + "; ".join(parts)
            # Fall back to extracting the last sentence of reason that contains "when" or "re-run"
            for phrase in ("re-run when", "unblock when", "when "):
                idx = reason.lower().find(phrase)
                if idx != -1:
                    fragment = reason[idx:idx + 120].strip()
                    return fragment
            return "(no explicit trigger state found)"

        lanes: list[dict[str, Any]] = []
        for lane_id_key, entry in cooldown_items:
            if lane_id_filter and lane_id_key != lane_id_filter:
                continue
            since_iter = int(entry.get("since_iter", 0))
            raw_reason = str(entry.get("reason", ""))
            # Privacy: truncate and redact secrets from reason
            reason = raw_reason[:240]
            if _has_secret(reason):
                reason = "[redacted: secret pattern detected]"
            trigger_state = entry.get("trigger_state", {})
            iter_age = current_iter - since_iter
            lanes.append({
                "lane_id": lane_id_key,
                "since_iter": since_iter,
                "reason": reason,
                "trigger_state_summary": _trigger_state_summary(reason, trigger_state),
                "current_iter": current_iter,
                "iter_age": iter_age,
                "staleness_class": _staleness_class(iter_age),
            })

        payload: dict[str, Any] = {
            "schema": LANE_COOLDOWN_CHECK_SCHEMA,
            "kind": "lane_cooldown",
            "lanes": lanes,
            "total_cooldowns": total_cooldowns,
            "current_iter": current_iter,
            "state_file_path": str(state_path),
            "state_file_path_searched": list(candidates_tried),
            "workspace_path": str(workspace_path_arg),
            "worktree_path": str(worktree_path_arg) if worktree_path_arg else "",
            "timestamp_utc": timestamp_utc,
            "privacy_guards": privacy_guards,
            "state_file_status": "present",
            "degraded": False,
            "degraded_reason": "",
        }
        if lanes:
            payload["verdict"] = "active-cooldown"
        elif lane_id_filter and total_cooldowns:
            payload["verdict"] = "pass-lane-not-cooled"
        else:
            payload["verdict"] = "pass-no-active-cooldowns"

        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{LANE_COOLDOWN_CHECK_SCHEMA}:lane_cooldown:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_lane_verdict_bus(self, **kwargs: Any) -> dict[str, Any]:
        """M1-2 - read-only MCP wrapper for the M1-1 lane verdict bus CLI.

        Expected M1-1 CLI contract:

            python3 tools/lane-verdict-bus.py consult --workspace <ws> \
                --limit <n> [--candidate-id ID] [--attack-class CLASS] \
                [--filter verdict=DROPPED] --json

        The wrapper preserves the CLI consult schema
        ``auditooor.lane_verdict_bus.consult.v1`` and adds MCP receipt fields.
        If the CLI has not landed yet, the callable returns a degraded empty
        bus envelope with ``verdicts: []`` so dependent dispatch lanes can
        remain fail-soft while M1-1 integrates.
        """
        import subprocess

        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        workspace_raw = str(kwargs.get("workspace_path") or kwargs.get("workspace") or "").strip()
        limit = min(_clamp_limit(kwargs.get("limit"), default=10), MAX_CONTEXT_ITEMS)
        candidate_id = _safe_text_item(kwargs.get("candidate_id"), max_chars=120) or ""
        attack_class = _safe_text_item(kwargs.get("attack_class"), max_chars=120) or ""
        cli_path = self.repo_root / "tools" / "lane-verdict-bus.py"
        source_refs = ["tools/lane-verdict-bus.py", "tools/vault-mcp-server.py"]

        def _filter_args(raw: Any) -> list[str]:
            if raw is None or raw == "":
                return []
            if isinstance(raw, dict):
                items = []
                for key in sorted(raw):
                    value = raw.get(key)
                    if value is None:
                        continue
                    items.append(f"{key}={value}")
                return items
            if isinstance(raw, list):
                return [
                    str(item)
                    for item in raw
                    if item is not None and str(item).strip()
                ]
            return [str(raw)]

        filters = _filter_args(kwargs.get("filter"))

        def _with_receipt(payload: dict[str, Any]) -> dict[str, Any]:
            payload.setdefault("schema", LANE_VERDICT_BUS_CONSULT_SCHEMA)
            payload.setdefault("kind", "lane_verdict_bus")
            if "verdicts" not in payload and isinstance(payload.get("records"), list):
                payload["verdicts"] = list(payload["records"])
            payload.setdefault("verdicts", [])
            if not isinstance(payload.get("verdicts"), list):
                payload["verdicts"] = []
            payload.setdefault("verdicts_returned", len(payload["verdicts"]))
            payload.setdefault("source_refs", source_refs)
            payload.setdefault("generated_at_utc", ts)
            payload.setdefault("mcp_wrapper", "vault_lane_verdict_bus")
            payload.setdefault("m1_1_cli_contract", "tools/lane-verdict-bus.py consult --json")
            payload.setdefault("filters_applied", filters)
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{LANE_VERDICT_BUS_CONSULT_SCHEMA}:vault_lane_verdict_bus:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": LANE_VERDICT_BUS_CONSULT_SCHEMA,
                "kind": "lane_verdict_bus",
                "degraded": True,
                "degraded_reason": reason,
                "verdict": f"degraded-{reason}",
                "workspace_path": workspace_raw,
                "limit": limit,
                "candidate_id": candidate_id,
                "attack_class": attack_class,
                "filters_applied": filters,
                "verdicts": [],
                "verdicts_returned": 0,
                "source_refs": source_refs,
                "generated_at_utc": ts,
                "m1_1_dependency": "tools/lane-verdict-bus.py",
                **extra,
            }
            return _with_receipt(payload)

        if not workspace_raw:
            return _degraded("workspace_path_required")
        try:
            workspace = Path(workspace_raw).expanduser().resolve()
        except (OSError, RuntimeError, ValueError):
            return _degraded("invalid_workspace_path")
        if not cli_path.is_file():
            return _degraded("m1_1_cli_missing", cli_path=str(cli_path))

        cmd = [
            sys.executable,
            str(cli_path),
            "consult",
            "--workspace",
            str(workspace),
            "--limit",
            str(limit),
            "--json",
        ]
        if candidate_id:
            cmd.extend(["--candidate-id", candidate_id])
        if attack_class:
            cmd.extend(["--attack-class", attack_class])
        for item in filters:
            cmd.extend(["--filter", item])

        try:
            proc = subprocess.run(
                cmd,
                cwd=str(self.repo_root),
                capture_output=True,
                text=True,
                timeout=30,
            )
        except subprocess.TimeoutExpired:
            return _degraded("m1_1_cli_timeout", cli_path=str(cli_path))
        except OSError as exc:
            return _degraded(
                "m1_1_cli_exec_error",
                cli_path=str(cli_path),
                error=_safe_text_item(str(exc), max_chars=240) or "",
            )

        if proc.returncode != 0:
            return _degraded(
                "m1_1_cli_nonzero",
                cli_path=str(cli_path),
                returncode=proc.returncode,
                stderr=_safe_text_item(proc.stderr, max_chars=500) or "",
                stdout=_safe_text_item(proc.stdout, max_chars=500) or "",
            )

        try:
            raw_payload = json.loads(proc.stdout or "{}")
        except json.JSONDecodeError as exc:
            return _degraded(
                "m1_1_cli_invalid_json",
                cli_path=str(cli_path),
                error=_safe_text_item(str(exc), max_chars=240) or "",
                stdout=_safe_text_item(proc.stdout, max_chars=500) or "",
            )
        if not isinstance(raw_payload, dict):
            return _degraded("m1_1_cli_payload_not_object", cli_path=str(cli_path))

        payload = dict(raw_payload)
        payload["schema"] = LANE_VERDICT_BUS_CONSULT_SCHEMA
        payload["kind"] = "lane_verdict_bus"
        payload["degraded"] = bool(payload.get("degraded", False))
        payload["workspace_path"] = str(payload.get("workspace_path") or workspace)
        payload["limit"] = limit
        payload["candidate_id"] = candidate_id
        payload["attack_class"] = attack_class
        payload["filters_applied"] = filters
        payload["cli_path"] = str(cli_path)
        return _with_receipt(payload)

    def vault_issue_session_token(self, **kwargs: Any) -> dict[str, Any]:
        """Lane 7 (PR #658) — issue a fresh MCP session token bound to workspace.

        Args:
            workspace_path: absolute path to workspace (default: cwd)
            owner: claude | codex | kimi | minimax | service-account (default claude)
            ttl_seconds: token TTL (default 14400 = 4h; 86400 = 24h for service-account)
            scope: list of allowed scopes (default ['read', 'write', 'remember'])

        Returns:
            {schema, token, sid, owner, workspace, expires_at, ttl_seconds, scope}
        """
        try:
            from auditooor_mcp_token import (
                issue_token, DEFAULT_TTL_SECONDS, SERVICE_ACCOUNT_TTL_SECONDS,
            )
        except ImportError as exc:
            return {"schema": "auditooor.vault_session_token.v1", "error": f"import failed: {exc}"}

        workspace_path = kwargs.get("workspace_path") or os.getcwd()
        owner = kwargs.get("owner", "claude")
        ttl_seconds = kwargs.get("ttl_seconds")
        if ttl_seconds is None:
            ttl_seconds = SERVICE_ACCOUNT_TTL_SECONDS if owner == "service-account" else DEFAULT_TTL_SECONDS
        scope = kwargs.get("scope")

        try:
            token, payload = issue_token(
                workspace_path=workspace_path,
                ttl_seconds=int(ttl_seconds),
                owner=owner,
                scope=scope,
            )
        except ValueError as exc:
            return {"schema": "auditooor.vault_session_token.v1", "error": str(exc)}

        return {
            "schema": "auditooor.vault_session_token.v1",
            "token": token,
            "sid": payload["sid"],
            "owner": payload["owner"],
            "workspace": payload["ws"],
            "issued_at": payload["iat"],
            "expires_at": payload["exp"],
            "ttl_seconds": payload["exp"] - payload["iat"],
            "scope": payload["scope"],
        }

    def vault_verify_session_token(self, **kwargs: Any) -> dict[str, Any]:
        """Lane 7 (PR #658) — verify an MCP session token.

        Args:
            token: the token string
            require_scope: optional scope name to enforce
            require_workspace: optional workspace path to enforce

        Returns:
            {schema, valid, error, payload}
        """
        try:
            from auditooor_mcp_token import verify_token
        except ImportError as exc:
            return {"schema": "auditooor.vault_session_token.v1", "valid": False, "error": f"import failed: {exc}"}

        token = kwargs.get("token", "")
        if not token:
            return {"schema": "auditooor.vault_session_token.v1", "valid": False, "error": "missing token argument"}

        valid, err, payload = verify_token(
            token,
            require_scope=kwargs.get("require_scope"),
            require_workspace=kwargs.get("require_workspace"),
        )
        return {
            "schema": "auditooor.vault_session_token.v1",
            "valid": valid,
            "error": err,
            "payload": payload,
        }

    # ------------------------------------------------------------------
    # W2-B-2 — vault_kill_rubric_context
    # ------------------------------------------------------------------

    def vault_kill_rubric_context(self, **kwargs: Any) -> dict[str, Any]:
        """W2-B-2 (iter13) — surface docs/KILL_RUBRIC_LIBRARY.md rows, optionally filtered.

        Args:
            workspace_path: absolute path to workspace (used to locate repo root;
                defaults to the server's REPO_ROOT if omitted).
            bug_class: optional filter string (case-insensitive substring match against
                the section title, e.g. "AMM", "reentrancy", "oracle").
            contract_type: optional filter string (case-insensitive substring match
                against the "Applies to:" line of each section).

        Returns:
            context_pack_id, context_pack_hash, schema, kind="kill_rubric_context",
            rubric_rows (list), filter (dict), total_sections (int), sections_returned (int),
            source_refs (list), library_found (bool), privacy_guards (dict).

        Each rubric_row:
            id (str), title (str), applies_to (str), checklist (list of str),
            kill_verdict_template (str), motivating_miss (str).

        Graceful empty envelope when KILL_RUBRIC_LIBRARY.md is missing or no rows match.
        Schema: auditooor.vault_kill_rubric_context.v1.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

        workspace_path_arg = kwargs.get("workspace_path")
        bug_class_filter = (kwargs.get("bug_class") or "").strip().lower()
        contract_type_filter = (kwargs.get("contract_type") or "").strip().lower()

        # Resolve repo root from workspace_path or fall back to server REPO_ROOT.
        # The library lives at <repo_root>/docs/KILL_RUBRIC_LIBRARY.md. When
        # workspace_path is an audit workspace (e.g. ~/audits/spark) rather than
        # the auditooor repo root, we fall back to self.repo_root so callers don't
        # need to know the repo root path.
        if workspace_path_arg:
            try:
                ws = Path(str(workspace_path_arg)).expanduser().resolve()
            except (OSError, RuntimeError):
                ws = None
        else:
            ws = None

        # Try workspace_path first, then self.repo_root
        library_path = None
        for candidate_root in ([ws] if ws and ws.exists() else []) + [self.repo_root]:
            candidate = candidate_root / "docs" / "KILL_RUBRIC_LIBRARY.md"
            if candidate.exists():
                library_path = candidate
                break
        if library_path is None:
            library_path = (ws or self.repo_root) / "docs" / "KILL_RUBRIC_LIBRARY.md"

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        def _make_pack(rows: list, found: bool, error: str | None = None) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": KILL_RUBRIC_CONTEXT_SCHEMA,
                "kind": "kill_rubric_context",
                "library_found": found,
                "library_path": str(library_path),
                "filter": {
                    "bug_class": bug_class_filter or None,
                    "contract_type": contract_type_filter or None,
                },
                "total_sections": len(rows),  # after filter
                "sections_returned": len(rows),
                "rubric_rows": rows,
                "source_refs": ["docs/KILL_RUBRIC_LIBRARY.md"],
                "privacy_guards": privacy_guards,
                "generated_at": timestamp_utc,
            }
            if error:
                payload["error"] = error
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{KILL_RUBRIC_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not library_path.exists() or not library_path.is_file():
            return _make_pack([], found=False, error="KILL_RUBRIC_LIBRARY.md not found")

        try:
            raw = library_path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            return _make_pack([], found=False, error=f"read error: {exc}")

        # Parse sections: each starts with "## N. Title"
        section_re = re.compile(r"^## \d+\.\s+(.+)$", re.MULTILINE)
        sections: list[dict[str, Any]] = []
        matches = list(section_re.finditer(raw))
        for i, m in enumerate(matches):
            title = m.group(1).strip()
            start = m.start()
            end = matches[i + 1].start() if i + 1 < len(matches) else len(raw)
            body = raw[start:end]

            # Extract "Applies to:" line
            applies_match = re.search(r"\*\*Applies to:\*\*\s*(.+)", body)
            applies_to = applies_match.group(1).strip() if applies_match else ""

            # Apply filters
            if bug_class_filter and bug_class_filter not in title.lower():
                continue
            if contract_type_filter and contract_type_filter not in applies_to.lower():
                continue

            # Extract checklist items: lines starting with "- [ ] **R-XXX-N:".
            # The separator after the bold tag may be an em-dash (legacy sections
            # 1-13) or a plain hyphen (LANE G7 sections 14+, which avoid em-dashes
            # per the house style); accept either so both parse identically.
            checklist = re.findall(
                r"- \[ \] \*\*(R-[A-Z]+-\d+:[^*]+)\*\*\s*(?:—|-)\s*(.+)", body
            )
            checklist_items = [f"{cid.strip()}: {desc.strip()}" for cid, desc in checklist]

            # Extract kill verdict template (text between ```\nKill verdict and closing ```)
            kill_tpl_match = re.search(r"```\s*\nKill verdict[^\n]*\n(.*?)```", body, re.DOTALL)
            kill_verdict_template = kill_tpl_match.group(0)[:2000] if kill_tpl_match else ""

            # Extract motivating miss line
            miss_match = re.search(r"\*\*Motivating miss:\*\*\s*(.+)", body)
            motivating_miss = miss_match.group(1).strip()[:400] if miss_match else ""

            # Derive section ID prefix from title (e.g. "AMM Rounding" → "R-AMM")
            first_word = re.sub(r"[^A-Z0-9]", "", title.split()[0].upper()) if title.split() else "SEC"
            section_id = f"R-{first_word}" if not re.match(r"^R-", first_word) else first_word

            sections.append({
                "id": section_id,
                "title": title,
                "applies_to": applies_to,
                "checklist": checklist_items,
                "kill_verdict_template": kill_verdict_template,
                "motivating_miss": motivating_miss,
            })

        return _make_pack(sections, found=True)

    # ------------------------------------------------------------------
    # SP-B-1 — vault_bug_family_heatmap (W2 plan 03 §12d)
    # ------------------------------------------------------------------

    def vault_bug_family_heatmap(self, **kwargs: Any) -> dict[str, Any]:
        """SP-B (iter19) — cross-engagement bug-family heatmap.

        Reads:
          reports/cross_workspace_finding_graph.json
          reference/recurring_bug_families.md

        Args:
            workspace_path: optional; if engagement name can be derived from
                the path's basename, that engagement is highlighted.
            engagement_list: optional list of engagement names to restrict the
                heatmap to.

        Returns: schema, kind, heatmap[], top_classes[], engagements_returned[],
        source_refs[], privacy_guards{}, context_pack_id, context_pack_hash.

        Schema: auditooor.vault_bug_family_heatmap.v1.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        workspace_path_arg = kwargs.get("workspace_path")
        engagement_list_arg = kwargs.get("engagement_list")
        if engagement_list_arg is not None and not isinstance(
            engagement_list_arg, (list, tuple)
        ):
            engagement_list_arg = None

        graph_path = self.repo_root / "reports" / "cross_workspace_finding_graph.json"
        families_path = self.repo_root / "reference" / "recurring_bug_families.md"

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        focus_engagement: str | None = None
        if workspace_path_arg:
            try:
                ws = Path(str(workspace_path_arg)).expanduser()
                focus_engagement = ws.name or None
            except (OSError, RuntimeError, ValueError):
                focus_engagement = None

        source_refs: list[str] = []

        def _make_pack(
            heatmap: list,
            top_classes: list,
            engagements: list,
            degraded: bool = False,
            reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": BUG_FAMILY_HEATMAP_SCHEMA,
                "kind": "bug_family_heatmap",
                "heatmap": heatmap,
                "top_classes": top_classes,
                "engagements_returned": engagements,
                "focus_engagement": focus_engagement,
                "source_refs": source_refs,
                "privacy_guards": privacy_guards,
                "degraded": degraded,
                "generated_at": timestamp_utc,
            }
            if reason:
                payload["reason"] = reason
            digest = hashlib.sha256(
                _canonical_json(payload).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{BUG_FAMILY_HEATMAP_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        # Parse the families file
        families: list[str] = []
        per_engagement_in_families: dict[str, set[str]] = {}
        if families_path.exists() and families_path.is_file():
            source_refs.append("reference/recurring_bug_families.md")
            try:
                fraw = families_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                fraw = ""
            # Heatmap table rows look like: | `family-name` | NN | engA, engB |
            row_re = re.compile(
                r"^\|\s*`([a-z][a-z0-9_-]*)`\s*\|\s*\d+\s*\|\s*([^|]+?)\s*\|",
                re.MULTILINE,
            )
            for m in row_re.finditer(fraw):
                fam = m.group(1).strip()
                engs = [
                    e.strip()
                    for e in m.group(2).split(",")
                    if e.strip()
                ]
                families.append(fam)
                for e in engs:
                    per_engagement_in_families.setdefault(e, set()).add(fam)

        # Parse the graph
        graph: dict[str, Any] = {}
        nodes: list[dict[str, Any]] = []
        if graph_path.exists() and graph_path.is_file():
            source_refs.append("reports/cross_workspace_finding_graph.json")
            try:
                graph = json.loads(graph_path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                graph = {}
            nodes_obj = graph.get("nodes")
            if isinstance(nodes_obj, list):
                nodes = nodes_obj

        if not families and not nodes:
            return _make_pack(
                [],
                [],
                [],
                degraded=True,
                reason="both source files missing or unreadable",
            )

        # Engagement set
        ws_in_graph = graph.get("workspaces_scanned") or []
        engagements_universe: list[str] = list(
            dict.fromkeys(
                [str(w) for w in ws_in_graph if isinstance(w, str)]
                + sorted(per_engagement_in_families.keys())
            )
        )
        if engagement_list_arg:
            engagements = [
                e for e in engagements_universe if e in engagement_list_arg
            ]
            if not engagements:
                engagements = list(engagement_list_arg)
        else:
            engagements = engagements_universe[:12]

        # Index nodes by workspace
        node_by_ws: dict[str, list[dict[str, Any]]] = {}
        for n in nodes:
            ws_name = n.get("workspace")
            if isinstance(ws_name, str):
                node_by_ws.setdefault(ws_name, []).append(n)

        heatmap: list[dict[str, Any]] = []
        family_totals: dict[str, int] = {}
        for engagement in engagements:
            ws_nodes = node_by_ws.get(engagement, [])
            seeded_families = per_engagement_in_families.get(engagement, set())
            # Bucket by family
            for family in families:
                count = 0
                exemplars: list[str] = []
                for n in ws_nodes:
                    haystack = " ".join(
                        [
                            str(n.get("title", "")),
                            " ".join(
                                str(p) for p in (n.get("matched_patterns") or [])
                            ),
                            " ".join(
                                str(d) for d in (n.get("matched_detectors") or [])
                            ),
                        ]
                    ).lower()
                    needle = family.lower()
                    # Loose substring match (also try removing dashes)
                    if needle in haystack or needle.replace("-", " ") in haystack:
                        count += 1
                        if len(exemplars) < 3:
                            fid = n.get("finding_id") or ""
                            ttl = (n.get("title") or "")[:80]
                            exemplars.append(f"{fid}:{ttl}".strip(":"))
                # Seed a baseline of 1 if the family was listed for this engagement
                # in recurring_bug_families.md but the graph nodes didn't match.
                # This preserves the "seen-in-engagement" signal.
                if count == 0 and family in seeded_families:
                    count = 1
                if count > 0:
                    heatmap.append(
                        {
                            "engagement": engagement,
                            "bug_family": family,
                            "count": count,
                            "exemplar_finding_refs": exemplars,
                        }
                    )
                    family_totals[family] = family_totals.get(family, 0) + count

        top_classes = [
            {"bug_family": fam, "total": cnt}
            for fam, cnt in sorted(
                family_totals.items(), key=lambda kv: kv[1], reverse=True
            )[:5]
        ]

        return _make_pack(heatmap, top_classes, engagements)

    # ------------------------------------------------------------------
    # SP-B-2 — vault_language_patterns (W2 plan 03 §12d)
    # ------------------------------------------------------------------

    def vault_language_patterns(self, **kwargs: Any) -> dict[str, Any]:
        """SP-B (iter19) — severity-weighted language slice over patterns.dsl.

        Walks active reference/patterns.dsl/**/*.yaml and
        reference/patterns.dsl.*/*.yaml sibling dirs (skipping _held,
        _quarantine, deprecated, graveyard, and promoted archives).
        Returns top_n patterns filtered by language; language is read from
        the YAML 'language' field if present, else inferred from path /
        source / pattern-name hints (default: solidity).

        Args:
            language: one of solidity/rust/go/move/cairo/vyper/all (default all).
            top_n: max patterns to return; default 20, max 100.

        Returns: schema, kind, language, language_summary{}, total_scanned,
        patterns[], source_refs[], privacy_guards{}, context_pack_id,
        context_pack_hash.

        Schema: auditooor.vault_language_patterns.v1.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        language_arg = (kwargs.get("language") or "all").strip().lower()
        if language_arg not in (
            "all",
            "solidity",
            "rust",
            "go",
            "move",
            "cairo",
            "vyper",
        ):
            language_arg = "all"
        try:
            top_n = int(kwargs.get("top_n", DEFAULT_LANG_PATTERNS_TOP_N))
        except (TypeError, ValueError):
            top_n = DEFAULT_LANG_PATTERNS_TOP_N
        top_n = max(1, min(top_n, MAX_LANG_PATTERNS_TOP_N))

        reference_dir = self.repo_root / "reference"
        patterns_dir = reference_dir / "patterns.dsl"
        pattern_dirs: list[Path] = []

        def _is_active_pattern_dir(path: Path) -> bool:
            name = path.name.lower()
            if name == "patterns.dsl":
                return True
            if not name.startswith("patterns.dsl."):
                return False
            inactive_markers = ("deprecated", "graveyard", "promoted")
            return not any(marker in name for marker in inactive_markers)

        if (
            patterns_dir.exists()
            and patterns_dir.is_dir()
            and not patterns_dir.is_symlink()
        ):
            pattern_dirs.append(patterns_dir)
        if reference_dir.exists() and reference_dir.is_dir():
            for sibling in sorted(reference_dir.glob("patterns.dsl.*")):
                if (
                    sibling.is_dir()
                    and not sibling.is_symlink()
                    and _is_active_pattern_dir(sibling)
                ):
                    pattern_dirs.append(sibling)
        source_refs = [
            f"{path.relative_to(self.repo_root).as_posix()}/"
            if path.is_relative_to(self.repo_root)
            else f"{path.as_posix()}/"
            for path in pattern_dirs
        ]

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        def _make_pack(
            patterns_list: list,
            language_summary: dict,
            total_scanned: int,
            degraded: bool = False,
            reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": LANGUAGE_PATTERNS_SCHEMA,
                "kind": "language_patterns",
                "language": language_arg,
                "top_n": top_n,
                "patterns": patterns_list,
                "language_summary": language_summary,
                "total_scanned": total_scanned,
                "patterns_returned": len(patterns_list),
                "source_refs": source_refs,
                "privacy_guards": privacy_guards,
                "degraded": degraded,
                "generated_at": timestamp_utc,
            }
            if reason:
                payload["reason"] = reason
            digest = hashlib.sha256(
                _canonical_json(payload).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{LANGUAGE_PATTERNS_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not pattern_dirs:
            return _make_pack(
                [], {}, 0, degraded=True, reason="patterns.dsl directories missing"
            )

        # Walk YAMLs (skip _held / _quarantine subdirs)
        candidate_files: list[Path] = []
        for pattern_dir in pattern_dirs:
            for yaml_path in pattern_dir.rglob("*.yaml"):
                if yaml_path.is_symlink():
                    continue
                parts = yaml_path.relative_to(pattern_dir).parts
                if any(p in ("_held", "_quarantine") for p in parts):
                    continue
                candidate_files.append(yaml_path)

        def _infer_language(path: Path, body: str) -> str:
            # Explicit yaml field first
            lang_match = re.search(
                r"^language:\s*([a-zA-Z]+)\s*$", body, re.MULTILINE
            )
            if lang_match:
                lang = lang_match.group(1).strip().lower()
                if lang in LANGUAGE_FILE_EXT_HINTS:
                    return lang
            # Path hints
            hay = (str(path) + "\n" + body[:600]).lower()
            for lang, hints in LANGUAGE_PATH_HINTS.items():
                for h in hints:
                    if h in hay:
                        return lang
            return "solidity"

        def _extract_field(body: str, key: str) -> str:
            m = re.search(rf"^{key}:\s*(.+?)\s*$", body, re.MULTILINE)
            return m.group(1).strip() if m else ""

        rows_by_identity: dict[tuple[str, str], dict[str, Any]] = {}
        for yaml_path in candidate_files:
            try:
                body = yaml_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            pattern_id = _extract_field(body, "pattern") or yaml_path.stem
            severity = (_extract_field(body, "severity") or "MEDIUM").upper()
            confidence = (_extract_field(body, "confidence") or "MEDIUM").upper()
            source = _extract_field(body, "source")
            example_count_raw = _extract_field(body, "example_count")
            try:
                example_count = int(example_count_raw) if example_count_raw else 0
            except (TypeError, ValueError):
                example_count = 0
            language = _infer_language(yaml_path, body)

            rel_path = str(
                yaml_path.relative_to(self.repo_root)
            ) if yaml_path.is_relative_to(self.repo_root) else str(yaml_path)

            sev_w = SEVERITY_WEIGHT.get(severity, 1)
            conf_w = CONFIDENCE_WEIGHT.get(confidence, 1)
            score = (sev_w * conf_w) + max(example_count, 0)

            # Brief: first non-blank, non-key comment line after the YAML keys
            brief_lines = []
            for line in body.splitlines():
                s = line.strip()
                if not s:
                    continue
                if s.startswith("#"):
                    cleaned = s.lstrip("#").strip()
                    if cleaned and not cleaned.lower().startswith("auto-migrated"):
                        brief_lines.append(cleaned)
                        if len(brief_lines) >= 2:
                            break
            brief = " ".join(brief_lines)[:240]

            row = {
                "pattern_id": pattern_id,
                "yaml_path": rel_path,
                "language": language,
                "severity_class": severity,
                "confidence": confidence,
                "example_count": example_count,
                "source": source,
                "score": score,
                "brief": brief,
            }
            identity = (language, pattern_id)
            existing = rows_by_identity.get(identity)
            if existing is None:
                rows_by_identity[identity] = row
                continue
            existing_is_canonical = existing["yaml_path"].startswith(
                "reference/patterns.dsl/"
            )
            row_is_canonical = row["yaml_path"].startswith("reference/patterns.dsl/")
            if (row["score"], row_is_canonical) > (
                existing["score"],
                existing_is_canonical,
            ):
                rows_by_identity[identity] = row

        language_summary: dict[str, int] = {}
        all_rows = list(rows_by_identity.values())
        for row in all_rows:
            language = row["language"]
            language_summary[language] = language_summary.get(language, 0) + 1

        rows = [
            row
            for row in all_rows
            if language_arg == "all" or row["language"] == language_arg
        ]

        rows.sort(
            key=lambda r: (r["score"], r["pattern_id"]),
            reverse=True,
        )
        # Pattern_id ascending tiebreak after score desc — stable sort already gives this
        # because we use score desc then pattern_id desc (sorted in reverse).
        # For deterministic alphabetical tiebreak we re-sort:
        rows.sort(key=lambda r: (-r["score"], r["pattern_id"]))
        rows = rows[:top_n]

        return _make_pack(rows, language_summary, len(all_rows))

    # ------------------------------------------------------------------
    # SP-B-3 — vault_dupe_rejection_context (W2 plan 03 §12d)
    # ------------------------------------------------------------------

    def vault_dupe_rejection_context(self, **kwargs: Any) -> dict[str, Any]:
        """SP-B (iter19) — bounded recall of duplicate / rejected outcomes.

        Reads reference/outcomes.jsonl line-by-line, filters rows whose
        outcome / status is in {duplicate, rejected, not_a_bug, oos}, applies
        optional bug_class substring filter and limit, returns the rows plus
        a per-bug-class summary.

        Args:
            workspace_path: optional; restricts to rows whose workspace name
                matches the path basename.
            bug_class: optional substring; case-insensitive match against
                title / tags / class / category fields.
            limit: max rows; default 8, max 24.

        Schema: auditooor.vault_dupe_rejection_context.v1.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        workspace_path_arg = kwargs.get("workspace_path")
        bug_class_arg = (kwargs.get("bug_class") or "").strip().lower()
        try:
            limit = int(kwargs.get("limit", DEFAULT_DUPE_REJECTION_LIMIT))
        except (TypeError, ValueError):
            limit = DEFAULT_DUPE_REJECTION_LIMIT
        limit = max(1, min(limit, MAX_DUPE_REJECTION_LIMIT))

        focus_workspace: str | None = None
        if workspace_path_arg:
            try:
                ws = Path(str(workspace_path_arg)).expanduser()
                focus_workspace = ws.name or None
            except (OSError, RuntimeError, ValueError):
                focus_workspace = None

        outcomes_path = self.repo_root / "reference" / "outcomes.jsonl"

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        def _make_pack(
            rejections: list,
            summary: dict,
            total_in_ledger: int,
            degraded: bool = False,
            reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": DUPE_REJECTION_CONTEXT_SCHEMA,
                "kind": "dupe_rejection_context",
                "rejections": rejections,
                "summary": summary,
                "filter": {
                    "workspace": focus_workspace,
                    "bug_class": bug_class_arg or None,
                    "limit": limit,
                },
                "total_in_ledger": total_in_ledger,
                "rejections_returned": len(rejections),
                "source_refs": ["reference/outcomes.jsonl"],
                "privacy_guards": privacy_guards,
                "degraded": degraded,
                "generated_at": timestamp_utc,
            }
            if reason:
                payload["reason"] = reason
            digest = hashlib.sha256(
                _canonical_json(payload).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{DUPE_REJECTION_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not outcomes_path.exists() or not outcomes_path.is_file():
            return _make_pack(
                [], {"by_bug_class": {}, "total_returned": 0}, 0,
                degraded=True, reason="outcomes.jsonl missing"
            )

        try:
            raw = outcomes_path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            return _make_pack(
                [], {"by_bug_class": {}, "total_returned": 0}, 0,
                degraded=True, reason=f"read error: {exc}"
            )

        rows_filtered: list[dict[str, Any]] = []
        total_seen = 0
        for line in raw.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except json.JSONDecodeError:
                continue
            if not isinstance(obj, dict):
                continue
            total_seen += 1

            status_raw = (
                obj.get("outcome")
                or obj.get("status")
                or obj.get("verdict")
                or ""
            )
            status = str(status_raw).strip().lower().replace("-", "_")
            if status not in DUPE_REJECTION_STATUSES:
                continue

            if focus_workspace:
                ws_name = str(obj.get("workspace") or obj.get("engagement") or "")
                if ws_name and ws_name != focus_workspace:
                    continue

            # bug_class substring search across multiple fields
            if bug_class_arg:
                hay = " ".join(
                    [
                        str(obj.get("bug_class", "")),
                        str(obj.get("class", "")),
                        str(obj.get("category", "")),
                        str(obj.get("title", "")),
                        " ".join(
                            str(t) for t in (obj.get("tags") or [])
                            if isinstance(t, (str, int))
                        ),
                    ]
                ).lower()
                if bug_class_arg not in hay:
                    continue

            bug_class = (
                obj.get("bug_class")
                or obj.get("class")
                or obj.get("category")
                or "unknown"
            )

            rows_filtered.append(
                {
                    "outcome_id": (
                        obj.get("outcome_id")
                        or obj.get("finding_id")
                        or obj.get("id")
                        or ""
                    ),
                    "engagement": (
                        obj.get("workspace")
                        or obj.get("engagement")
                        or ""
                    ),
                    "bug_class": str(bug_class)[:80],
                    "status": status,
                    "rejection_reason": str(
                        obj.get("rejection_reason")
                        or obj.get("fp_reason")
                        or obj.get("reason")
                        or ""
                    )[:400],
                    "triager_quote": str(
                        obj.get("triager_quote") or obj.get("quote") or ""
                    )[:600],
                    "dupe_of": str(obj.get("dupe_of") or "")[:80],
                    "title": str(obj.get("title") or "")[:160],
                    "outcome_date": str(
                        obj.get("outcome_date")
                        or obj.get("date")
                        or ""
                    ),
                    "source_ref": str(
                        obj.get("source") or obj.get("source_path") or ""
                    )[:240],
                }
            )

        # Sort by outcome_date desc; empty dates last
        rows_filtered.sort(
            key=lambda r: (bool(r["outcome_date"]), r["outcome_date"]),
            reverse=True,
        )
        capped = rows_filtered[:limit]

        by_bug_class: dict[str, int] = {}
        for r in rows_filtered:
            by_bug_class[r["bug_class"]] = by_bug_class.get(r["bug_class"], 0) + 1

        summary = {
            "by_bug_class": by_bug_class,
            "total_returned": len(capped),
            "total_filtered": len(rows_filtered),
        }

        return _make_pack(capped, summary, total_seen)

    # ------------------------------------------------------------------
    # SP-INTENT — vault_intent_resolve (W2 plan 09 §4)
    # ------------------------------------------------------------------

    def vault_intent_resolve(self, **kwargs: Any) -> dict[str, Any]:
        """SP-INTENT (iter20) — free-text intent → ranked typed-callable routes.

        Wraps SP-A synonym expansion and a keyword-based router. Tokenizes the
        intent, expands phrases via the synonym map, classifies into one of 5
        routes (recall_finding | recall_exploit | recall_dupe |
        recall_pattern | default), and returns a top_k-bounded list of
        {route, recommended_callable, args, rationale, confidence_score}.

        Args:
            intent: free-text user intent (required).
            workspace_path: optional; passed through to the recommended args.
            top_k: max suggestions to return; default 3, max 8.

        Schema: auditooor.vault_intent_resolve.v1.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        raw_intent = kwargs.get("intent")
        intent = (raw_intent or "").strip() if isinstance(raw_intent, str) else ""
        workspace_path_arg = kwargs.get("workspace_path")
        try:
            top_k = int(kwargs.get("top_k", DEFAULT_INTENT_TOP_K))
        except (TypeError, ValueError):
            top_k = DEFAULT_INTENT_TOP_K
        top_k = max(1, min(top_k, MAX_INTENT_TOP_K))

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        def _make_pack(
            routes: list,
            top_recommendation: dict | None,
            expanded_phrases: list[str],
            synonym_expansion: dict,
            degraded: bool = False,
            reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": INTENT_RESOLVE_SCHEMA,
                "kind": "intent_resolve",
                "intent": intent,
                "expanded_phrases": expanded_phrases,
                "routes": routes,
                "top_recommendation": top_recommendation,
                "synonym_expansion": synonym_expansion,
                "top_k": top_k,
                "source_refs": ["reference/vault_search_synonyms.yaml"],
                "privacy_guards": privacy_guards,
                "degraded": degraded,
                "generated_at": timestamp_utc,
            }
            if reason:
                payload["reason"] = reason
            digest = hashlib.sha256(
                _canonical_json(payload).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{INTENT_RESOLVE_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not intent:
            return _make_pack(
                [], None, [], {"variants": [], "matched_canonicals": []},
                degraded=True, reason="empty_intent",
            )

        # Step 1: synonym expansion (reuse SP-A helpers)
        synonyms_table = _load_search_synonyms()
        variants = _expand_query_with_synonyms(intent, synonyms_table)
        intent_lower = intent.lower()
        matched_canonicals: list[str] = []
        if synonyms_table:
            for canonical in sorted(synonyms_table.keys(), key=lambda s: -len(s)):
                if canonical and canonical.lower() in intent_lower:
                    matched_canonicals.append(canonical)
                    if len(matched_canonicals) >= 5:
                        break

        # Build expanded_phrases — synonym expansions of matched canonicals
        # plus the variants themselves (deduped, capped at 5 groups).
        expanded_phrases: list[str] = []
        seen_phrases: set[str] = set()
        for canonical in matched_canonicals:
            for syn in synonyms_table.get(canonical, []):
                key = syn.lower()
                if key and key not in seen_phrases:
                    seen_phrases.add(key)
                    expanded_phrases.append(syn)
                if len(expanded_phrases) >= 5:
                    break
            if len(expanded_phrases) >= 5:
                break

        synonym_expansion = {
            "variants": variants,
            "matched_canonicals": matched_canonicals,
        }

        # Step 2: keyword-based route classification with scoring.
        # For each route, count keyword hits and longest-match-length.
        scored_routes: list[dict[str, Any]] = []
        for route_name, keywords in INTENT_ROUTE_KEYWORDS.items():
            hits: list[str] = []
            longest_match = 0
            for kw in keywords:
                if kw in intent_lower:
                    hits.append(kw)
                    longest_match = max(longest_match, len(kw))
            if hits:
                # confidence_score: scaled by hit count + longest-match length
                # (longer phrases are more specific). Capped at 1.0.
                base = 0.5 + 0.1 * len(hits)
                bonus = min(0.3, longest_match / 60.0)
                # Strong-priority routes (recall_dupe / recall_pattern /
                # recall_finding) get a small floor bonus when their
                # explicit vocab fires — these are direct user requests for
                # a specific recall lane and should win over generic
                # exploit-keyword overlap.
                if route_name in ("recall_dupe", "recall_pattern", "recall_finding"):
                    bonus += 0.2
                score = min(1.0, base + bonus)
                scored_routes.append(
                    {
                        "route": route_name,
                        "recommended_callable": INTENT_ROUTE_TO_CALLABLE[route_name],
                        "matched_keywords": hits[:6],
                        "confidence_score": round(score, 4),
                        "rationale": (
                            f"Intent keywords {hits[:3]} → {route_name} route"
                        ),
                    }
                )

        # Always include the default fallback route at low confidence.
        # If no specific route fired, give default a slightly higher floor.
        default_score = 0.45 if scored_routes else 0.3
        scored_routes.append(
            {
                "route": "default",
                "recommended_callable": "vault_search",
                "matched_keywords": [],
                "confidence_score": default_score,
                "rationale": (
                    "Generic fallback — vault_search with synonym-expanded query"
                ),
            }
        )

        # Sort by confidence_score desc; cap at top_k.
        scored_routes.sort(key=lambda r: -r["confidence_score"])
        capped = scored_routes[:top_k]

        # Attach args to each route.
        for r in capped:
            route_name = r["route"]
            callable_name = r["recommended_callable"]
            args: dict[str, Any] = {}
            if workspace_path_arg:
                args["workspace_path"] = str(workspace_path_arg)
            if route_name == "recall_dupe":
                # bug_class substring = the intent itself (best-effort)
                args["bug_class"] = intent
                args["limit"] = 8
            elif route_name == "recall_pattern":
                # default to "all"; downstream caller can refine
                args["language"] = "all"
                args["top_n"] = 20
            elif route_name == "recall_exploit":
                args["query"] = intent
                args["limit"] = 5
            elif route_name == "recall_finding":
                args["limit"] = 5
            else:  # default → vault_search
                args["query"] = intent
                args["limit"] = 8
            r["args"] = args

        top_recommendation = capped[0] if capped else None
        return _make_pack(
            capped, top_recommendation, expanded_phrases, synonym_expansion
        )

    # ------------------------------------------------------------------
    # W2-B-4 — vault_remember
    # ------------------------------------------------------------------

    def vault_remember(self, **kwargs: Any) -> dict[str, Any]:
        """W2-B-4 (iter13) — write-back path: persist a memory file and update MEMORY.md index.

        This is the FIRST mutating callable. A valid HMAC-signed token with
        ``remember`` scope is required; the callable rejects any call that
        fails token verification.

        Args:
            scope: one of ``feedback | project | reference | user`` — determines
                filename prefix and MEMORY.md category.
            content: markdown body. **MUST begin with a YAML frontmatter block
                (``---`` ... ``---``) containing the THREE required fields:**

                  - ``name`` (str) — used to derive the memory filename
                  - ``description`` (str) — appears as the MEMORY.md index summary
                  - ``type`` (str) — one of ``feedback | project | reference | user``;
                    must match ``scope`` arg

                Optional fields: ``date``, ``loop``, ``tags``, etc. (ignored).

                Example::

                    ---
                    name: spark_iter_20_state
                    description: Iter 20 state snapshot post FIX-PASS
                    type: project
                    date: 2026-05-10
                    ---
                    Body markdown here ...

            signed_token: HMAC token issued by ``vault_issue_session_token``;
                must carry ``remember`` scope.

        Returns:
            schema, kind="remember", memory_path (str), memory_index_updated (bool),
            schema_validated (bool), scope (str), derived_filename (str),
            context_pack_id, context_pack_hash.

        Rejection responses (token invalid / scope missing / bad frontmatter):
            {schema, kind, accepted: false, error: <reason>, ...}

        Schema: auditooor.vault_remember.v1.
        """
        import datetime
        import re as _re

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

        scope = (kwargs.get("scope") or "").strip()
        content = kwargs.get("content") or ""
        signed_token = kwargs.get("signed_token") or ""

        VALID_SCOPES = {"feedback", "project", "reference", "user"}

        def _reject(reason: str, extra: dict | None = None) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": REMEMBER_SCHEMA,
                "kind": "remember",
                "accepted": False,
                "error": reason,
                "scope": scope or None,
                "generated_at": timestamp_utc,
            }
            if extra:
                payload.update(extra)
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{REMEMBER_SCHEMA}:reject:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        # --- Token verification (mandatory for mutating callable) ---
        if not signed_token:
            return _reject("missing signed_token")

        try:
            verify_token = _auditooor_mcp_token_module().verify_token
        except ImportError as exc:
            return _reject(f"auditooor_mcp_token import failed: {exc}")

        is_valid, token_err, token_payload = verify_token(signed_token, require_scope="remember")
        if not is_valid:
            return _reject(f"token invalid: {token_err}")

        # --- Scope validation ---
        if scope not in VALID_SCOPES:
            return _reject(
                f"invalid scope {scope!r}; must be one of {sorted(VALID_SCOPES)}",
                {"valid_scopes": sorted(VALID_SCOPES)},
            )

        # --- Frontmatter validation ---
        fm_match = _re.match(r"^---\s*\n(.*?)\n---", content, _re.DOTALL)
        if not fm_match:
            return _reject("content must begin with YAML frontmatter block (--- ... ---)")

        fm_body = fm_match.group(1)
        name_match = _re.search(r"^name:\s*(.+)$", fm_body, _re.MULTILINE)
        desc_match = _re.search(r"^description:\s*(.+)$", fm_body, _re.MULTILINE)
        type_match = _re.search(r"^type:\s*(.+)$", fm_body, _re.MULTILINE)

        if not name_match:
            return _reject("frontmatter missing required field: name")
        if not desc_match:
            return _reject("frontmatter missing required field: description")
        if not type_match:
            return _reject(
                "frontmatter missing required field: type "
                "(one of: feedback, project, reference, user)"
            )

        name_val = name_match.group(1).strip()
        desc_val = desc_match.group(1).strip()
        type_val = type_match.group(1).strip().strip("\"'").lower()
        if type_val not in VALID_SCOPES:
            return _reject(
                f"invalid frontmatter type {type_val!r}; "
                f"must be one of {sorted(VALID_SCOPES)}",
                {"valid_scopes": sorted(VALID_SCOPES)},
            )

        # Derive filename from name field: sanitize to [a-z0-9_-]
        derived_filename = _re.sub(r"[^a-z0-9_\-]", "_", name_val.lower()).strip("_") + ".md"

        # --- Resolve target memory directory ---
        # Token's ws field tells us which project this belongs to.
        # Map workspace path → ~/.claude/projects/<slug>/memory/
        ws_path = token_payload.get("ws", "") if token_payload else ""

        # Slug: convert absolute path to the ~/.claude/projects/<slug> convention
        # e.g. /Users/wolf/auditooor-worktrees/dlt-workflow-gaps-main
        # → -Users-wolf-auditooor-worktrees-dlt-workflow-gaps-main
        if ws_path:
            slug = ws_path.replace("/", "-").lstrip("-")
            memory_dir = Path.home() / ".claude" / "projects" / slug / "memory"
        else:
            # Fallback: use this repo root's project slug
            slug = str(self.repo_root).replace("/", "-").lstrip("-")
            memory_dir = Path.home() / ".claude" / "projects" / slug / "memory"

        # Safety: ensure memory_dir is inside ~/.claude/ to prevent path traversal
        claude_base = Path.home() / ".claude"
        try:
            memory_dir.resolve().relative_to(claude_base.resolve())
        except ValueError:
            return _reject(f"resolved memory_dir {memory_dir} is outside ~/.claude/ — rejected")

        # Create if missing
        try:
            memory_dir.mkdir(parents=True, exist_ok=True)
        except OSError as exc:
            return _reject(f"could not create memory directory: {exc}")

        memory_file = memory_dir / derived_filename

        # --- Write memory file ---
        try:
            memory_file.write_text(content, encoding="utf-8")
        except OSError as exc:
            return _reject(f"write failed: {exc}")

        # --- Update MEMORY.md index ---
        memory_index = memory_dir / "MEMORY.md"
        index_updated = False
        link_line = f"- [{desc_val}]({derived_filename})"

        try:
            if memory_index.exists():
                existing = memory_index.read_text(encoding="utf-8")
                # Add line if not already present (idempotent)
                if derived_filename not in existing:
                    updated = existing.rstrip("\n") + "\n" + link_line + "\n"
                    memory_index.write_text(updated, encoding="utf-8")
                    index_updated = True
                else:
                    index_updated = False  # already indexed
            else:
                memory_index.write_text(link_line + "\n", encoding="utf-8")
                index_updated = True
        except OSError:
            # Non-fatal: memory file written, index update failed
            index_updated = False

        payload: dict[str, Any] = {
            "schema": REMEMBER_SCHEMA,
            "kind": "remember",
            "accepted": True,
            "scope": scope,
            "derived_filename": derived_filename,
            "memory_path": str(memory_file),
            "memory_index_updated": index_updated,
            "schema_validated": True,
            "generated_at": timestamp_utc,
        }
        digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
        return {
            "context_pack_id": f"{REMEMBER_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    # ------------------------------------------------------------------
    # PR #658 P0-3 — vault_originality_context
    # ------------------------------------------------------------------
    def vault_originality_context(self, **kwargs: Any) -> dict[str, Any]:
        """PR #658 P0-3 — return prior-disclosure hits from
        ``obsidian-vault/external-audits-extracts/<workspace>/`` filtered by
        keyword presence + ``workspace/<ws>`` tag.

        Replaces raw ``grep`` over 10k+ lines of ``prior_audits/*.txt`` for
        L29 originality checks. Each note in the section is one extracted
        audit finding emitted by ``tools/external-audits-extract-emitter.py``.

        Args:
            workspace_path: required absolute path (e.g. ``/Users/wolf/audits/dydx``).
            keywords: required list[str] — case-insensitive lexical match.
            limit: optional, default 8, max 20.

        Returns: standard envelope (``context_pack_id``, ``context_pack_hash``,
        ``source_refs``, ``privacy_guards``, ``synonym_expansion``) plus
        ``hits`` ordered by score desc and ``workspace`` echo.
        """
        import datetime

        timestamp_utc = datetime.datetime.now(datetime.timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        raw_workspace_path = kwargs.get("workspace_path") or kwargs.get("workspace")
        workspace_path_str = (
            str(raw_workspace_path).strip() if isinstance(raw_workspace_path, str) else ""
        )
        raw_keywords = kwargs.get("keywords") or []
        if isinstance(raw_keywords, str):
            raw_keywords = [raw_keywords]
        keywords = [
            str(k).strip().lower()
            for k in raw_keywords
            if isinstance(k, (str, int)) and str(k).strip()
        ]
        try:
            limit = int(kwargs.get("limit", DEFAULT_ORIGINALITY_LIMIT))
        except (TypeError, ValueError):
            limit = DEFAULT_ORIGINALITY_LIMIT
        limit = max(1, min(limit, MAX_ORIGINALITY_LIMIT))

        privacy_guards: dict[str, Any] = {
            "symlinks_blocked": True,
            "secret_patterns_blocked": True,
        }

        def _make_pack(
            hits: list[dict[str, Any]],
            workspace_name: str,
            synonym_expansion: dict[str, Any],
            degraded: bool = False,
            reason: str | None = None,
        ) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": ORIGINALITY_CONTEXT_SCHEMA,
                "kind": "originality_context",
                "workspace": workspace_name,
                "workspace_path": workspace_path_str,
                "keywords": keywords,
                "limit": limit,
                "hits": hits,
                "synonym_expansion": synonym_expansion,
                "source_refs": [
                    f"vault://external-audits-extracts/{workspace_name}/"
                    if workspace_name
                    else "vault://external-audits-extracts/"
                ],
                "privacy_guards": privacy_guards,
                "degraded": degraded,
                "generated_at": timestamp_utc,
            }
            if reason:
                payload["reason"] = reason
            digest = hashlib.sha256(
                _canonical_json(payload).encode("utf-8")
            ).hexdigest()
            return {
                "context_pack_id": f"{ORIGINALITY_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not workspace_path_str:
            return _make_pack(
                [], "", {"variants": [], "matched_canonicals": []},
                degraded=True, reason="empty_workspace_path",
            )
        if not keywords:
            return _make_pack(
                [], Path(workspace_path_str).name,
                {"variants": [], "matched_canonicals": []},
                degraded=True, reason="empty_keywords",
            )

        workspace_name = Path(workspace_path_str).name
        section_dir = self.vault_dir / "external-audits-extracts" / workspace_name
        if not section_dir.is_dir():
            return _make_pack(
                [], workspace_name,
                {"variants": [], "matched_canonicals": []},
                degraded=True, reason="section_missing",
            )

        # Synonym expansion — reuse SP-A infrastructure. Each keyword is
        # expanded individually; the union of all variants forms the search
        # term set.
        synonyms_table = _load_search_synonyms()
        all_variants: list[str] = []
        seen_variant: set[str] = set()
        matched_canonicals: list[str] = []
        for kw in keywords:
            for v in _expand_query_with_synonyms(kw, synonyms_table):
                v_low = v.lower()
                if v_low and v_low not in seen_variant:
                    seen_variant.add(v_low)
                    all_variants.append(v_low)
            if synonyms_table:
                for canonical in synonyms_table.keys():
                    if canonical.lower() in kw and canonical not in matched_canonicals:
                        matched_canonicals.append(canonical)
        synonym_expansion = {
            "variants": all_variants,
            "matched_canonicals": matched_canonicals,
        }

        # Score each note by total keyword occurrences in body. The
        # workspace tag-filter (frontmatter ``workspace`` / ``tags_csv``)
        # is defence-in-depth: notes are already partitioned by section
        # subdirectory.
        target_tag = f"workspace/{workspace_name}"
        hits: list[dict[str, Any]] = []
        for note_path in sorted(section_dir.rglob("*.md")):
            try:
                if note_path.is_symlink():
                    continue  # privacy_guard: skip symlinks
            except OSError:
                continue
            try:
                text = note_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if _has_secret(text):
                continue  # privacy_guard
            frontmatter, body = _frontmatter_and_body(text)
            ws_field = str(frontmatter.get("workspace", "")).strip()
            tags_csv = str(frontmatter.get("tags_csv", "")).strip()
            tag_strings: list[str] = []
            if tags_csv:
                tag_strings = [t.strip() for t in tags_csv.split(",") if t.strip()]
            else:
                tags_field = frontmatter.get("tags", []) or []
                if isinstance(tags_field, list):
                    tag_strings = [str(t).strip() for t in tags_field]
            if ws_field != workspace_name and target_tag not in tag_strings:
                continue
            body_lower = body.lower()
            score = 0
            matched_terms: list[str] = []
            for term in all_variants:
                count = body_lower.count(term)
                if count > 0:
                    score += count
                    matched_terms.append(term)
            if score <= 0:
                continue
            try:
                relpath = note_path.relative_to(self.vault_dir)
            except ValueError:
                relpath = note_path
            snippet = ""
            for term in matched_terms:
                idx = body_lower.find(term)
                if idx >= 0:
                    start = max(0, idx - 80)
                    end = min(len(body), idx + 200)
                    snippet = body[start:end].strip()
                    break
            if not snippet:
                snippet = body[:240].strip()
            modules_csv = str(frontmatter.get("modules_csv", "")).strip()
            if modules_csv:
                modules_list: list[str] = [
                    m.strip() for m in modules_csv.split(",") if m.strip()
                ]
            else:
                raw_modules = frontmatter.get("modules", []) or []
                modules_list = (
                    [str(m).strip() for m in raw_modules]
                    if isinstance(raw_modules, list)
                    else []
                )
            hits.append({
                "path": str(relpath),
                "audit_id": str(frontmatter.get("audit_id", "")),
                "audit_year": str(frontmatter.get("audit_year", "")),
                "finding_id": str(frontmatter.get("finding_id", "")),
                "finding_severity": str(frontmatter.get("finding_severity", "")),
                "modules": modules_list,
                "status": str(frontmatter.get("status", "")),
                "score": score,
                "matched_terms": matched_terms,
                "snippet": snippet[:480],
                "source_ref": f"vault://{relpath}",
            })
        hits.sort(key=lambda r: (-int(r["score"]), str(r["path"])))
        hits = hits[:limit]

        return _make_pack(hits, workspace_name, synonym_expansion)

    # ------------------------------------------------------------------
    # Wave-4 Track B Phase-A — per-function hacker-mindset brain
    # (3 new callables: vault_function_mindset / vault_function_signature_shape
    # /  vault_attack_class_evidence). Calls into tools/ranker.py +
    # tools/shape-hash.py inline (importlib.util).
    # ------------------------------------------------------------------

    @staticmethod
    def _load_ranker_module() -> Any:
        import importlib.util
        if "_vault_ranker_mod" in sys.modules:
            return sys.modules["_vault_ranker_mod"]
        repo_root = Path(__file__).resolve().parent.parent
        path = repo_root / "tools" / "ranker.py"
        spec = importlib.util.spec_from_file_location("_vault_ranker_mod", path)
        if spec is None or spec.loader is None:
            raise RuntimeError(f"could not load {path}")
        mod = importlib.util.module_from_spec(spec)
        sys.modules["_vault_ranker_mod"] = mod
        spec.loader.exec_module(mod)
        return mod

    @staticmethod
    def _load_shape_hash_module() -> Any:
        import importlib.util
        if "_vault_shape_hash_mod" in sys.modules:
            return sys.modules["_vault_shape_hash_mod"]
        repo_root = Path(__file__).resolve().parent.parent
        path = repo_root / "tools" / "shape-hash.py"
        spec = importlib.util.spec_from_file_location("_vault_shape_hash_mod", path)
        if spec is None or spec.loader is None:
            raise RuntimeError(f"could not load {path}")
        mod = importlib.util.module_from_spec(spec)
        sys.modules["_vault_shape_hash_mod"] = mod
        spec.loader.exec_module(mod)
        return mod

    @staticmethod
    def _load_hackerman_query_module(script_name: str, module_name: str) -> Any:
        import importlib.util
        if module_name in sys.modules:
            return sys.modules[module_name]
        repo_root = Path(__file__).resolve().parent.parent
        path = repo_root / "tools" / script_name
        if not path.is_file():
            raise FileNotFoundError(f"{script_name} not found")
        tools_dir = str(path.parent)
        inserted = False
        if tools_dir not in sys.path:
            sys.path.insert(0, tools_dir)
            inserted = True
        try:
            spec = importlib.util.spec_from_file_location(module_name, path)
            if spec is None or spec.loader is None:
                raise RuntimeError(f"could not load {path}")
            mod = importlib.util.module_from_spec(spec)
            sys.modules[module_name] = mod
            spec.loader.exec_module(mod)
            return mod
        finally:
            if inserted:
                try:
                    sys.path.remove(tools_dir)
                except ValueError:
                    pass

    @staticmethod
    def _safe_hackerman_source_refs(values: object) -> list[str]:
        refs: list[str] = []
        if not isinstance(values, list):
            return refs
        repo_root = Path(__file__).resolve().parent.parent
        for value in values:
            text = str(value if value is not None else "").strip()
            if not text:
                continue
            try:
                path = Path(text).expanduser()
                if path.is_absolute():
                    try:
                        text = path.resolve().relative_to(repo_root).as_posix()
                    except (OSError, ValueError):
                        text = path.name
            except (OSError, RuntimeError):
                pass
            if text.startswith("audit/corpus_tags/") and _is_public_relpath(text):
                if text not in refs:
                    refs.append(text)
                continue
            safe = _safe_source_ref(text)
            if safe and safe not in refs:
                refs.append(safe)
        return refs

    def _hackerman_sidecar_refs_and_gaps(
        self,
        path: Path,
        loaded: bool,
        label: str,
    ) -> tuple[list[str], list[dict[str, str]]]:
        refs = self._safe_hackerman_source_refs([str(path)])
        if loaded:
            return refs, []
        return [], [
            {
                "label": label,
                "path": refs[0] if refs else path.name,
                "reason": "missing" if not path.exists() else "empty_or_unusable",
            }
        ]

    @staticmethod
    def _hackerman_query_paths(kwargs: dict[str, Any]) -> tuple[str, str]:
        repo_root = Path(__file__).resolve().parent.parent
        index_dir = str(kwargs.get("index_dir") or repo_root / "audit" / "corpus_tags" / "index")
        tags_dir = str(kwargs.get("tags_dir") or repo_root / "audit" / "corpus_tags" / "tags")
        return index_dir, tags_dir

