    def vault_audit_deep_manifest_summary(self, **kwargs: Any) -> dict[str, Any]:
        """Surface bounded summary rows from audit-deep manifest report output."""
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        source_ref = "tools/audit-deep-manifest.py"
        limit = _clamp_limit(kwargs.get("limit"), default=DEFAULT_LIMIT)

        def _degraded(reason: str) -> dict[str, Any]:
            payload = {
                "schema": AUDIT_DEEP_MANIFEST_SUMMARY_SCHEMA,
                "kind": "audit_deep_manifest_summary",
                "degraded": True,
                "reason": reason,
                "advisory_only": True,
                "submission_posture": "NOT_SUBMIT_READY",
                "source_count": 0,
                "sources_returned": 0,
                "bridge_groups_count": 0,
                "bridge_groups_returned": 0,
                "sources": [],
                "bridge_outputs": [],
                "source_refs": [source_ref],
                "generated_at_utc": ts,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{AUDIT_DEEP_MANIFEST_SUMMARY_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        explicit = str(kwargs.get("report_path") or "").strip()
        ws_raw = str(kwargs.get("workspace_path") or kwargs.get("workspace") or "").strip()
        if not explicit and not ws_raw:
            return _degraded("workspace_path_required")
        try:
            if explicit:
                rep_path = Path(explicit).expanduser().resolve()
            else:
                ws = Path(ws_raw).expanduser().resolve()
                if not ws.is_dir():
                    return _degraded("workspace_not_found")
                rep_path = ws / ".audit_logs" / "audit_deep_manifest_report.json"
        except (OSError, ValueError):
            return _degraded("invalid_report_path")

        if not rep_path.is_file():
            return _degraded("audit_deep_manifest_report_not_found")
        try:
            data = json.loads(rep_path.read_text(encoding="utf-8"))
        except (OSError, ValueError, json.JSONDecodeError):
            return _degraded("audit_deep_manifest_report_unreadable")
        if not isinstance(data, dict):
            return _degraded("audit_deep_manifest_report_invalid_schema")

        sources_raw = data.get("sources") if isinstance(data.get("sources"), list) else []
        bridge_raw = data.get("bridge_outputs") if isinstance(data.get("bridge_outputs"), dict) else {}
        sources: list[dict[str, Any]] = []
        for src in [row for row in sources_raw if isinstance(row, dict)][:limit]:
            rows = src.get("rows") if isinstance(src.get("rows"), list) else []
            sources.append(
                {
                    "kind": _safe_text_item(src.get("kind"), max_chars=80) or "",
                    "path": self._safe_local_path_label(src.get("path") or ""),
                    "schema": _safe_text_item(src.get("schema"), max_chars=120) or "",
                    "error": _safe_text_item(src.get("error"), max_chars=160) or "",
                    "counts": dict(src.get("counts") or {}),
                    "rows_count": len(rows),
                    "rows_preview": [
                        {
                            "tool": _safe_text_item(row.get("tool"), max_chars=120) or "",
                            "state": _safe_text_item(row.get("state"), max_chars=40) or "",
                            "raw_status": _safe_text_item(row.get("raw_status"), max_chars=40) or "",
                            "detail": _safe_text_item(row.get("detail"), max_chars=240) or "",
                        }
                        for row in rows[:6]
                        if isinstance(row, dict)
                    ],
                }
            )
        bridge_outputs: list[dict[str, Any]] = []
        for bridge_name in sorted(bridge_raw)[:limit]:
            rows = bridge_raw.get(bridge_name)
            if not isinstance(rows, list):
                continue
            bridge_outputs.append(
                {
                    "group": _safe_text_item(bridge_name, max_chars=80) or "",
                    "entries_count": len(rows),
                    "entries": [
                        {
                            "path": self._safe_local_path_label(entry.get("path") or ""),
                            "status": _safe_text_item(entry.get("status"), max_chars=20) or "",
                            "purpose": _safe_text_item(entry.get("purpose"), max_chars=240) or "",
                        }
                        for entry in rows[:6]
                        if isinstance(entry, dict)
                    ],
                }
            )

        payload = {
            "schema": AUDIT_DEEP_MANIFEST_SUMMARY_SCHEMA,
            "kind": "audit_deep_manifest_summary",
            "degraded": False,
            "advisory_only": True,
            "submission_posture": "NOT_SUBMIT_READY",
            "report_path": self._safe_local_path_label(str(rep_path)),
            "tool_schema": _safe_text_item(data.get("schema"), max_chars=120) or "",
            "workspace": self._safe_local_path_label(data.get("workspace") or ""),
            "counts": dict(data.get("counts") or {}),
            "source_count": len(sources_raw) if isinstance(sources_raw, list) else 0,
            "sources_returned": len(sources),
            "bridge_groups_count": len(bridge_raw),
            "bridge_groups_returned": len(bridge_outputs),
            "sources": sources,
            "bridge_outputs": bridge_outputs,
            "source_refs": [source_ref, "tools/audit-deep.sh"],
            "generated_at_utc": ts,
        }
        digest = hashlib.sha256(
            _canonical_json(
                {
                    "schema": AUDIT_DEEP_MANIFEST_SUMMARY_SCHEMA,
                    "report_path": payload["report_path"],
                    "limit": limit,
                    "sources": [row["kind"] for row in sources],
                    "bridge_groups": [row["group"] for row in bridge_outputs],
                }
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{AUDIT_DEEP_MANIFEST_SUMMARY_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_exploit_chain_unifier(self, **kwargs: Any) -> dict[str, Any]:
        """Surface the exploit-chain unifier output.

        DEPRECATED (iter18 NEG-C, removal target 2026-06-30): superseded by
        ``vault_hackerman_chain_candidates`` (37 invocations vs 0). Original
        callable was built for one Wave-9 multi-chain anchor and never reused.
        See ``docs/MCP_CALLABLE_DEPRECATIONS_2026-05-23.md``. Response envelope
        carries a ``deprecation_warning`` field via the ``call()`` wrapper.

        Wave-5 capability lift (W5-M3). ``tools/hackerman-chain-unify.py``
        orders co-located corpus records into precondition / postcondition
        exploit chains and emits ``auditooor.hackerman.chain_unify.v1`` JSON
        with per-chain hop counts and scores. Multi-hop chaining is where the
        largest bounties live, but the unifier output had no MCP recall path.
        This callable gives a session the ranked chains without re-running it.

        Args:
          report_path: explicit path to the chain-unify JSON (required if no
            workspace given). If a workspace is given, resolves
            ``<workspace>/.auditooor/chain_unify.output.json``.
          workspace_path / workspace: local audit workspace.
          min_hops: optional integer floor on ``hop_count``.
          limit: cap on the returned chains.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        limit = _clamp_limit(kwargs.get("limit"), default=DEFAULT_LIMIT)
        try:
            min_hops = int(kwargs.get("min_hops") or 0)
        except (TypeError, ValueError):
            min_hops = 0
        source_ref = "tools/hackerman-chain-unify.py"

        def _degraded(reason: str) -> dict[str, Any]:
            payload = {
                "schema": EXPLOIT_CHAIN_UNIFIER_SCHEMA,
                "kind": "exploit_chain_unifier",
                "degraded": True,
                "reason": reason,
                "total_chains": 0,
                "chains_returned": 0,
                "chains": [],
                "source_refs": [source_ref],
                "generated_at_utc": ts,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{EXPLOIT_CHAIN_UNIFIER_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        explicit = str(kwargs.get("report_path") or "").strip()
        ws_raw = str(kwargs.get("workspace_path") or kwargs.get("workspace") or "").strip()
        try:
            if explicit:
                rep_path = Path(explicit).expanduser().resolve()
            else:
                if not ws_raw:
                    return _degraded("report_path_required")
                ws = Path(ws_raw).expanduser().resolve()
                if not ws.is_dir():
                    return _degraded("workspace_not_found")
                rep_path = ws / ".auditooor" / "chain_unify.output.json"
        except (OSError, ValueError):
            return _degraded("invalid_report_path")

        if not rep_path.is_file():
            return _degraded("chain_unify_output_not_found")
        try:
            data = json.loads(rep_path.read_text(encoding="utf-8"))
        except (OSError, ValueError, json.JSONDecodeError):
            return _degraded("chain_unify_output_unreadable")
        if not isinstance(data, dict):
            return _degraded("chain_unify_output_invalid_schema")

        rows_raw = data.get("chains") if isinstance(data.get("chains"), list) else []
        rows = [r for r in rows_raw if isinstance(r, dict)]
        if min_hops:
            rows = [r for r in rows if int(r.get("hop_count") or 0) >= min_hops]
        bounded: list[dict[str, Any]] = []
        for r in rows[:limit]:
            steps_raw = r.get("steps") if isinstance(r.get("steps"), list) else []
            bounded.append(
                {
                    "chain_id": _safe_text_item(r.get("chain_id"), max_chars=120) or "",
                    "rank": r.get("rank"),
                    "score": r.get("score"),
                    "hop_count": int(r.get("hop_count") or 0),
                    "scope": _safe_text_item(r.get("scope"), max_chars=160) or "",
                    "steps": [
                        _safe_text_item(
                            s.get("record_id") if isinstance(s, dict) else s,
                            max_chars=160,
                        ) or ""
                        for s in steps_raw
                    ][:24],
                }
            )

        payload = {
            "schema": EXPLOIT_CHAIN_UNIFIER_SCHEMA,
            "kind": "exploit_chain_unifier",
            "degraded": False,
            "report_path": self._safe_local_path_label(str(rep_path)),
            "tool_schema": _safe_text_item(data.get("schema"), max_chars=80) or "",
            "source_tag_dir": _safe_text_item(data.get("source_tag_dir"), max_chars=240) or "",
            "total_records_loaded": int(data.get("total_records_loaded") or 0),
            "chainable_steps": int(data.get("chainable_steps") or 0),
            "max_hops": data.get("max_hops"),
            "min_hops_filter": min_hops,
            "total_chains": int(data.get("total_chains") or len(rows_raw)),
            "chains": bounded,
            "chains_returned": len(bounded),
            "source_refs": [source_ref],
            "generated_at_utc": ts,
        }
        digest = hashlib.sha256(
            _canonical_json(
                {
                    "schema": EXPLOIT_CHAIN_UNIFIER_SCHEMA,
                    "report_path": payload["report_path"],
                    "min_hops": min_hops,
                    "limit": limit,
                    "chains": [(c["chain_id"], c["score"]) for c in bounded],
                }
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{EXPLOIT_CHAIN_UNIFIER_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

