    def vault_exploit_queue_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return bounded rows from <ws>/.auditooor/exploit_queue.json.

        Reads the canonical exploit queue written by
        ``tools/exploit-queue.py``.  Returns top-N rows with key fields only
        so MCP consumers can decide what to prove next without loading the
        full queue artifact.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        ws_raw = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_path = Path(str(ws_raw)).expanduser() if ws_raw else None
        limit = min(_clamp_limit(kwargs.get("limit"), default=10), MAX_CONTEXT_ITEMS)

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": EXPLOIT_QUEUE_CONTEXT_SCHEMA,
                "kind": "exploit_queue_context",
                "degraded": True,
                "reason": reason,
                "rows_returned": 0,
                "rows": [],
                "generated_at_utc": ts,
                **extra,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{EXPLOIT_QUEUE_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not workspace_path:
            return _degraded("workspace_path_required")

        queue_path = workspace_path / ".auditooor" / "exploit_queue.json"
        if not queue_path.is_file():
            return _degraded(
                "exploit_queue_not_found",
                hint="Run: python3 tools/exploit-queue.py --workspace <ws>",
                checked_path=str(queue_path),
            )

        try:
            raw = json.loads(queue_path.read_text(encoding="utf-8"))
        except Exception as exc:  # noqa: BLE001
            return _degraded(f"exploit_queue_parse_error: {exc}")

        rows_raw = raw if isinstance(raw, list) else (raw.get("queue") or raw.get("rows") or [])
        rows: list[dict[str, Any]] = [r for r in rows_raw if isinstance(r, dict)]
        bounded: list[dict[str, Any]] = []
        for row in rows[:limit]:
            bounded.append(
                {
                    "lead_id": _safe_text_item(row.get("lead_id"), max_chars=40) or "",
                    "title": _safe_text_item(row.get("title"), max_chars=200) or "",
                    "attack_class": _safe_text_item(row.get("attack_class"), max_chars=80) or "",
                    "likely_severity": _safe_text_item(row.get("likely_severity"), max_chars=20) or "",
                    "severity_confidence": _safe_text_item(row.get("severity_confidence"), max_chars=20) or "",
                    "quality_gate_status": _safe_text_item(row.get("quality_gate_status"), max_chars=40) or "",
                    "learning_route": _safe_text_item(row.get("learning_route"), max_chars=60) or "",
                    "next_command": _safe_text_item(row.get("next_command"), max_chars=300) or "",
                    "priority_score": float(row.get("priority_score") or 0.0),
                    "blockers": [
                        _safe_text_item(b, max_chars=120) or ""
                        for b in (row.get("blockers") or [])[:5]
                    ],
                    "dupe_risk": _safe_text_item(row.get("dupe_risk"), max_chars=20) or "unknown",
                }
            )
        payload = {
            "schema": EXPLOIT_QUEUE_CONTEXT_SCHEMA,
            "kind": "exploit_queue_context",
            "degraded": False,
            "workspace_path": str(workspace_path),
            "queue_path": str(queue_path),
            "total_rows": len(rows),
            "rows_returned": len(bounded),
            "rows": bounded,
            "generated_at_utc": ts,
            "source_refs": [
                "tools/exploit-queue.py",
                f"{workspace_path}/.auditooor/exploit_queue.json",
            ],
        }
        digest = hashlib.sha256(
            _canonical_json(
                {"schema": EXPLOIT_QUEUE_CONTEXT_SCHEMA, "workspace": str(workspace_path), "limit": limit}
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{EXPLOIT_QUEUE_CONTEXT_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_current_to_exploit_conversion_gate_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return a bounded summary of the current-to-exploit conversion gate verdict.

        Reads ``reports/current_to_exploit_conversion_gate.json`` (emitted by
        ``tools/current-to-exploit-conversion-gate.py``).  Returns only the
        gate decision fields - ``start_exploit_conversion_allowed``,
        ``blocked_reasons``, and a bounded gap list - so callers can decide
        whether to start exploit-conversion work without loading the full
        report.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        report_rel = "reports/current_to_exploit_conversion_gate.json"
        report_path = self.repo_root / report_rel
        max_gaps = min(_clamp_limit(kwargs.get("limit"), default=8), MAX_CONTEXT_ITEMS)

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": CURRENT_TO_EXPLOIT_CONVERSION_GATE_CONTEXT_SCHEMA,
                "kind": "current_to_exploit_conversion_gate_context",
                "degraded": True,
                "reason": reason,
                "start_exploit_conversion_allowed": None,
                "blocked_reasons": [],
                "remaining_gaps": [],
                "generated_at_utc": ts,
                **extra,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{CURRENT_TO_EXPLOIT_CONVERSION_GATE_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not report_path.is_file():
            return _degraded(
                "gate_report_not_found",
                hint="Run: python3 tools/current-to-exploit-conversion-gate.py --json",
                checked_path=str(report_path),
            )

        try:
            data = json.loads(report_path.read_text(encoding="utf-8"))
        except Exception as exc:  # noqa: BLE001
            return _degraded(f"gate_report_parse_error: {exc}")

        if not isinstance(data, dict):
            return _degraded("gate_report_not_a_dict")

        allowed = data.get("start_exploit_conversion_allowed")
        blocked_reasons: list[str] = [
            _safe_text_item(r, max_chars=200) or ""
            for r in (data.get("blocked_reasons") or [])[:10]
        ]
        raw_gaps = (data.get("remaining_current_gaps") or [])[:max_gaps]
        bounded_gaps: list[dict[str, Any]] = []
        for g in raw_gaps:
            if isinstance(g, dict):
                bounded_gaps.append(
                    {
                        "id": _safe_text_item(g.get("id"), max_chars=80) or "",
                        "severity": _safe_text_item(g.get("severity"), max_chars=20) or "",
                        "blocked": bool(g.get("blocked")),
                        "note": _safe_text_item(g.get("note"), max_chars=300) or "",
                    }
                )
        deferred: list[dict[str, Any]] = []
        for d in (data.get("deferred_with_reason") or [])[:5]:
            if isinstance(d, dict):
                deferred.append(
                    {
                        "id": _safe_text_item(d.get("id"), max_chars=80) or "",
                        "defer_reason": _safe_text_item(d.get("defer_reason"), max_chars=200) or "",
                    }
                )
        payload = {
            "schema": CURRENT_TO_EXPLOIT_CONVERSION_GATE_CONTEXT_SCHEMA,
            "kind": "current_to_exploit_conversion_gate_context",
            "degraded": False,
            "report_path": report_rel,
            "start_exploit_conversion_allowed": allowed,
            "blocked_reasons": blocked_reasons,
            "remaining_gaps": bounded_gaps,
            "deferred_with_reason": deferred,
            "generated_at_utc": ts,
            "source_refs": [report_rel, "tools/current-to-exploit-conversion-gate.py"],
        }
        digest = hashlib.sha256(
            _canonical_json(
                {
                    "schema": CURRENT_TO_EXPLOIT_CONVERSION_GATE_CONTEXT_SCHEMA,
                    "allowed": allowed,
                    "blocked_reasons": blocked_reasons,
                }
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{CURRENT_TO_EXPLOIT_CONVERSION_GATE_CONTEXT_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_exploit_severity_scope_oracle(self, **kwargs: Any) -> dict[str, Any]:
        """Return a bounded summary of the severity/scope oracle output for a queue row.

        Reads either a path passed via ``oracle_path`` or an inline
        ``oracle_json`` dict.  Returns the key decision fields
        (``selected_severity``, ``scope_status``, ``likely_triager_objections``,
        ``required_proof_upgrades``) so workers can get an advisory severity
        read before drafting.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": EXPLOIT_SEVERITY_SCOPE_ORACLE_SCHEMA,
                "kind": "exploit_severity_scope_oracle",
                "degraded": True,
                "reason": reason,
                "selected_severity": None,
                "scope_status": None,
                "generated_at_utc": ts,
                **extra,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{EXPLOIT_SEVERITY_SCOPE_ORACLE_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        # Accept either an inline JSON dict or a file path.
        oracle_json = kwargs.get("oracle_json")
        oracle_path_raw = kwargs.get("oracle_path") or kwargs.get("path") or ""
        data: dict[str, Any] | None = None
        if isinstance(oracle_json, dict):
            data = oracle_json
        elif oracle_path_raw:
            p = Path(str(oracle_path_raw)).expanduser()
            if not p.is_file():
                return _degraded("oracle_path_not_found", checked_path=str(p))
            try:
                data = json.loads(p.read_text(encoding="utf-8"))
            except Exception as exc:  # noqa: BLE001
                return _degraded(f"oracle_parse_error: {exc}")
        else:
            return _degraded(
                "no_oracle_input",
                hint="Pass oracle_path=<path> or oracle_json=<dict>",
            )

        if not isinstance(data, dict):
            return _degraded("oracle_not_a_dict")

        objections: list[str] = [
            _safe_text_item(o, max_chars=200) or ""
            for o in (data.get("likely_triager_objections") or [])[:8]
        ]
        upgrades: list[str] = [
            _safe_text_item(u, max_chars=200) or ""
            for u in (data.get("required_proof_upgrades") or [])[:8]
        ]
        oos_risks: list[str] = [
            _safe_text_item(r, max_chars=200) or ""
            for r in (data.get("oos_risks") or [])[:5]
        ]
        payload = {
            "schema": EXPLOIT_SEVERITY_SCOPE_ORACLE_SCHEMA,
            "kind": "exploit_severity_scope_oracle",
            "degraded": False,
            "selected_severity": _safe_text_item(data.get("selected_severity"), max_chars=20),
            "confidence": _safe_text_item(data.get("confidence"), max_chars=20),
            "selected_impact": _safe_text_item(data.get("selected_impact"), max_chars=200),
            "scope_status": _safe_text_item(data.get("scope_status"), max_chars=40),
            "likely_triager_objections": objections,
            "required_proof_upgrades": upgrades,
            "oos_risks": oos_risks,
            "dupe_risk": _safe_text_item(data.get("dupe_risk"), max_chars=20),
            "recommended_next_step": _safe_text_item(data.get("recommended_next_step"), max_chars=300),
            "generated_at_utc": ts,
            "source_refs": ["tools/exploit-severity-scope-oracle.py"],
        }
        digest = hashlib.sha256(
            _canonical_json(
                {
                    "schema": EXPLOIT_SEVERITY_SCOPE_ORACLE_SCHEMA,
                    "selected_severity": payload["selected_severity"],
                    "scope_status": payload["scope_status"],
                }
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{EXPLOIT_SEVERITY_SCOPE_ORACLE_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

