    def vault_agent_artifact_mining_context(self, **kwargs: Any) -> dict[str, Any]:
        """Return a bounded summary of an agent-artifact-miner report for a workspace.

        Reads ``<workspace_path>/agent_artifact_mining_report.json`` (written by
        ``tools/agent-artifact-miner.py --workspace <ws> --out
        agent_artifact_mining_report.json``).  Returns ``total_artifacts``,
        ``artifact_type_counts``, ``no_learning_reason``, and a capped sample
        of artifact titles so workers can assess mining yield without loading
        the full report.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        ws_raw = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_path = Path(str(ws_raw)).expanduser() if ws_raw else None
        limit = min(_clamp_limit(kwargs.get("limit"), default=10), MAX_CONTEXT_ITEMS)

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            payload: dict[str, Any] = {
                "schema": AGENT_ARTIFACT_MINING_CONTEXT_SCHEMA,
                "kind": "agent_artifact_mining_context",
                "degraded": True,
                "reason": reason,
                "total_artifacts": 0,
                "artifact_type_counts": {},
                "no_learning_reason": True,
                "artifact_titles_sample": [],
                "generated_at_utc": ts,
                **extra,
            }
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{AGENT_ARTIFACT_MINING_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        if not workspace_path:
            return _degraded("workspace_path_required")

        report_path = workspace_path / "agent_artifact_mining_report.json"
        if not report_path.is_file():
            return _degraded(
                "report_not_found",
                hint=(
                    "Run: python3 tools/agent-artifact-miner.py "
                    "--workspace <ws> --out <ws>/agent_artifact_mining_report.json"
                ),
                checked_path=str(report_path),
            )

        try:
            data = json.loads(report_path.read_text(encoding="utf-8"))
        except Exception as exc:  # noqa: BLE001
            return _degraded(f"report_parse_error: {exc}")

        if not isinstance(data, dict):
            return _degraded("report_not_a_dict")

        artifacts_raw = data.get("artifacts") or []
        artifact_titles_sample: list[str] = [
            _safe_text_item(a.get("title"), max_chars=120) or ""
            for a in (artifacts_raw[:limit] if isinstance(artifacts_raw, list) else [])
        ]
        artifact_type_counts_raw = data.get("artifact_type_counts") or {}
        artifact_type_counts: dict[str, int] = {
            str(k): int(v)
            for k, v in (artifact_type_counts_raw.items() if isinstance(artifact_type_counts_raw, dict) else [])
        }

        payload = {
            "schema": AGENT_ARTIFACT_MINING_CONTEXT_SCHEMA,
            "kind": "agent_artifact_mining_context",
            "degraded": False,
            "workspace_path": str(workspace_path),
            "report_path": str(report_path),
            "total_artifacts": int(data.get("total_artifacts") or 0),
            "no_learning_reason": bool(data.get("no_learning_reason", False)),
            "artifact_type_counts": artifact_type_counts,
            "artifact_titles_sample": artifact_titles_sample,
            "titles_sample_limit": limit,
            "generated_at_utc": ts,
            "source_refs": ["tools/agent-artifact-miner.py"],
        }
        digest = hashlib.sha256(
            _canonical_json(
                {
                    "schema": AGENT_ARTIFACT_MINING_CONTEXT_SCHEMA,
                    "workspace": str(workspace_path),
                    "limit": limit,
                }
            ).encode("utf-8")
        ).hexdigest()
        return {
            "context_pack_id": f"{AGENT_ARTIFACT_MINING_CONTEXT_SCHEMA}:{digest[:16]}",
            "context_pack_hash": digest,
            **payload,
        }

    def vault_agent_learning_context(self, **kwargs: Any) -> dict[str, Any]:
        """Lane K K7 — bounded recall pack over the terminal agent-learning ledger.

        Reads ``<workspace_path>/.auditooor/agent_artifacts/learning_ledger.jsonl``
        (compiled by ``tools/agent-learning-compiler.py``) and returns capped
        rows so a worker can check prior learning before repeating a bug family:
        ``open_objections`` (triager objections / kill reasons still actionable),
        ``recent_kill_reasons``, ``new_hacker_questions``, ``proof_artifacts``,
        ``no_action_summary`` (reason -> count), and ``unclassified_count``.
        Degrades gracefully when the ledger is absent.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        ws_raw = kwargs.get("workspace_path") or kwargs.get("workspace") or ""
        workspace_path = Path(str(ws_raw)).expanduser() if ws_raw else None
        limit = min(_clamp_limit(kwargs.get("limit"), default=8), MAX_CONTEXT_ITEMS)

        def _pack(payload: dict[str, Any]) -> dict[str, Any]:
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{AGENT_LEARNING_CONTEXT_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _degraded(reason: str, **extra: Any) -> dict[str, Any]:
            return _pack(
                {
                    "schema": AGENT_LEARNING_CONTEXT_SCHEMA,
                    "kind": "agent_learning_context",
                    "degraded": True,
                    "reason": reason,
                    "open_objections": [],
                    "recent_kill_reasons": [],
                    "new_hacker_questions": [],
                    "proof_artifacts": [],
                    "lesson_packs": [],
                    "lesson_pack_rows": 0,
                    "no_action_summary": {},
                    "unclassified_count": 0,
                    "ledger_rows": 0,
                    "generated_at_utc": ts,
                    "source_refs": ["tools/agent-learning-compiler.py"],
                    **extra,
                }
            )

        if not workspace_path:
            return _degraded("workspace_path_required")

        ledger_rel = ".auditooor/agent_artifacts/learning_ledger.jsonl"
        ledger_path = workspace_path / ledger_rel
        if not ledger_path.is_file():
            return _degraded(
                "ledger_not_found",
                checked_path=str(ledger_path),
                hint=(
                    "Run: python3 tools/agent-artifact-miner.py --workspace <ws> "
                    "&& python3 tools/agent-learning-compiler.py --workspace <ws>"
                ),
            )

        rows: list[dict[str, Any]] = []
        for raw in ledger_path.read_text(encoding="utf-8", errors="replace").splitlines():
            raw = raw.strip()
            if not raw:
                continue
            try:
                row = json.loads(raw)
            except json.JSONDecodeError:
                continue
            if isinstance(row, dict):
                rows.append(row)

        lesson_pack_rows: list[dict[str, Any]] = []
        ws_slug = re.sub(r"[^A-Za-z0-9_.-]+", "_", workspace_path.name)[:80] or "unknown"
        derived_dir = self.repo_root / "audit" / "corpus_tags" / "derived"
        for lp_path in sorted(derived_dir.glob(f"lesson_pack_{ws_slug}_*.jsonl")):
            try:
                lp_lines = lp_path.read_text(encoding="utf-8", errors="replace").splitlines()
            except OSError:
                continue
            for raw in lp_lines:
                if not raw.strip():
                    continue
                try:
                    row = json.loads(raw)
                except json.JSONDecodeError:
                    continue
                if isinstance(row, dict):
                    lesson_pack_rows.append(row)

        def _kind(row: dict[str, Any]) -> str:
            return str(row.get("terminal_kind") or row.get("kind") or "").strip()

        def _brief(row: dict[str, Any]) -> dict[str, Any]:
            return {
                "artifact_id": _safe_text_item(row.get("artifact_id"), max_chars=120) or "",
                "proposition": _safe_text_item(row.get("proposition"), max_chars=200) or "",
                "primary_for": _safe_text_item(row.get("primary_for"), max_chars=60) or "",
                "evidence_polarity": _safe_text_item(row.get("evidence_polarity"), max_chars=40) or "",
                "reuse_action": _safe_text_item(row.get("reuse_action"), max_chars=60) or "",
                "provenance_ref": _safe_text_item(row.get("provenance_ref"), max_chars=200) or "",
            }

        objections = [_brief(r) for r in rows if _kind(r) == "triager_objection"]
        kill_reasons = [_brief(r) for r in rows if _kind(r) == "kill_reason"]
        hacker_questions = [
            _brief(r) for r in rows if _kind(r) in {"hacker_question", "proof_obligation"}
        ]
        proof_artifacts = [_brief(r) for r in rows if _kind(r) == "proof_artifact"]
        lesson_packs = [
            {
                "packet_id": _safe_text_item(r.get("packet_id"), max_chars=80) or "",
                "source_path": _safe_text_item(r.get("source_path"), max_chars=200) or "",
                "severity": _safe_text_item(r.get("severity"), max_chars=20) or "",
                "lesson_pack_hash": _safe_text_item(r.get("lesson_pack_hash"), max_chars=80) or "",
                "attack_class": _safe_text_item(
                    ((r.get("lesson_pack") or {}).get("selection_keys") or {}).get("attack_class"),
                    max_chars=80,
                ) or "",
                "function_shape": _safe_text_item(
                    ((r.get("lesson_pack") or {}).get("selection_keys") or {}).get("function_shape"),
                    max_chars=80,
                ) or "",
            }
            for r in lesson_pack_rows
        ]
        no_action_summary: dict[str, int] = {}
        unclassified_count = 0
        for row in rows:
            if _kind(row) == "NO_ACTION":
                reason = _safe_text_item(row.get("reason"), max_chars=60) or "unspecified"
                no_action_summary[reason] = no_action_summary.get(reason, 0) + 1
            if not _kind(row):
                unclassified_count += 1

        payload = {
            "schema": AGENT_LEARNING_CONTEXT_SCHEMA,
            "kind": "agent_learning_context",
            "degraded": False,
            "workspace_path": str(workspace_path),
            "ledger_path": str(ledger_path),
            "ledger_rows": len(rows),
            "open_objections": objections[:limit],
            "recent_kill_reasons": kill_reasons[-limit:],
            "new_hacker_questions": hacker_questions[:limit],
            "proof_artifacts": proof_artifacts[:limit],
            "lesson_packs": lesson_packs[-limit:],
            "no_action_summary": dict(sorted(no_action_summary.items())),
            "unclassified_count": unclassified_count,
            "lesson_pack_rows": len(lesson_pack_rows),
            "bound_limit": limit,
            "generated_at_utc": ts,
            "source_refs": [
                "tools/agent-learning-compiler.py",
                "tools/agent-learning-gate.py",
                "tools/worker-delivery-contract.py",
                ledger_rel,
                f"audit/corpus_tags/derived/lesson_pack_{ws_slug}_*.jsonl",
            ],
        }
        return _pack(payload)

    def vault_exploit_narratives_synthesized(self, workspace_path: str = "", **kwargs: Any) -> dict[str, Any]:
        """LIFT-27 followup (2026-05-26) -- bounded recall of synthesized exploit narratives.

        Reads audit/corpus_tags/derived/exploit_narratives_synthesized/<basename(workspace_path)>/*.yaml
        and returns bounded list of narrative fields for hacker-brief enrichment.
        All narratives are tier-3-synthetic-taxonomy-anchored / NOT_SUBMIT_READY.

        Schema: auditooor.vault_exploit_narratives_synthesized.v1.
        """
        ts = _dt.datetime.now(_dt.timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        ws_raw = workspace_path or kwargs.get("workspace") or kwargs.get("workspace_path") or ""
        max_narratives = int(kwargs.get("max_narratives") or 5)
        max_narratives = max(1, min(max_narratives, 50))

        def _pack_result(payload: dict) -> dict:
            digest = hashlib.sha256(_canonical_json(payload).encode("utf-8")).hexdigest()
            return {
                "context_pack_id": f"{EXPLOIT_NARRATIVES_SYNTHESIZED_SCHEMA}:{digest[:16]}",
                "context_pack_hash": digest,
                **payload,
            }

        def _degraded(reason: str, **extra: Any) -> dict:
            return _pack_result({
                "schema": EXPLOIT_NARRATIVES_SYNTHESIZED_SCHEMA,
                "degraded": True,
                "reason": reason,
                "narratives": [],
                "total_available": 0,
                "workspace": str(ws_raw),
                "generated_at_utc": ts,
                **extra,
            })

        if not ws_raw:
            return _degraded("workspace_path_required")

        ws_name = Path(str(ws_raw)).name
        narratives_dir = REPO_ROOT / "audit" / "corpus_tags" / "derived" / "exploit_narratives_synthesized" / ws_name
        if not narratives_dir.is_dir():
            return _degraded(
                "workspace_subdirectory_not_found",
                checked_path=str(narratives_dir),
                hint=(
                    f"Run tools/deepseek-batch-gen-tok-chain-exploit.py "
                    f"--workspace {ws_name} to generate narratives."
                ),
            )

        yaml_files = sorted(narratives_dir.glob("*.yaml"))
        total = len(yaml_files)

        def _yfield(field_name: str, text: str, default: str = "") -> str:
            """Extract a simple scalar YAML field value (single-line)."""
            m = re.search(r"^" + re.escape(field_name) + r":\s*(.+)", text, re.MULTILINE)
            if not m:
                return default
            val = m.group(1).strip()
            if val.startswith(("'", '"')):
                val = val[1:]
            if val.endswith(("'", '"')):
                val = val[:-1]
            return val

        narratives: list[dict] = []
        for yf in yaml_files[:max_narratives]:
            try:
                raw = yf.read_text(encoding="utf-8", errors="replace")
                gct_id = _yfield("chain_template_id", raw) or yf.stem.replace("-narrative", "")
                narratives.append({
                    "gct_id": gct_id,
                    "narrative_id": _yfield("narrative_id", raw),
                    "actor_model": _yfield("actor_model", raw),
                    "commit_point": _yfield("commit_point", raw),
                    "attack_tx_sequence": _yfield("attack_tx_sequence", raw, default="[]"),
                    "defense_bypass_per_kill_condition": _yfield("defense_bypass_per_kill_condition", raw, default="{}"),
                    "honest_caveats": _yfield("honest_caveats", raw),
                    "source_template_id": _yfield("source_task_id", raw) or gct_id,
                    "tier": _yfield("verification_tier", raw, default="tier-3-synthetic-taxonomy-anchored"),
                    "confidence": _yfield("confidence_self_assessment", raw, default="medium"),
                    "submission_posture": _yfield("submission_posture", raw, default="NOT_SUBMIT_READY"),
                })
            except Exception as exc:
                narratives.append({"gct_id": yf.stem, "error": str(exc)})

        return _pack_result({
            "schema": EXPLOIT_NARRATIVES_SYNTHESIZED_SCHEMA,
            "degraded": False,
            "workspace": ws_name,
            "workspace_path": str(ws_raw),
            "narratives_dir": str(narratives_dir),
            "total_available": total,
            "returned": len(narratives),
            "max_narratives": max_narratives,
            "narratives": narratives,
            "advisory_only": True,
            "tier_note": (
                "All narratives are tier-3-synthetic-taxonomy-anchored; "
                "NOT_SUBMIT_READY without V3-grade PoC."
            ),
            "generated_at_utc": ts,
        })

    def vault_daemon_version(self, **_: Any) -> dict[str, Any]:
        """Return the running daemon's code-revision stamp + staleness verdict.

        Schema: ``auditooor.vault_daemon_version.v1``. Lets a caller explicitly
        ask "is the daemon serving current code?" rather than waiting for the
        passive envelope flag injected on every other callable.
        """
        info = self.daemon_version_info()
        info["schema"] = "auditooor.vault_daemon_version.v1"
        return info

    def _inject_staleness_envelope(self, result: dict[str, Any]) -> None:
        """Add degraded:true + daemon_staleness_warning when on-disk is newer.

        No-op when the daemon is current. Does not clobber a caller-set
        ``daemon_staleness_warning``; only raises ``degraded`` to True (never
        downgrades a body that already declared itself degraded).
        """
        info = self.daemon_version_info()
        if not info.get("stale"):
            return
        result.setdefault(
            "daemon_staleness_warning",
            {
                "status": "daemon-stale-restart-required",
                "start_code_stamp": info["start_code_stamp"],
                "current_code_stamp": info["current_code_stamp"],
                "detail": info["detail"],
            },
        )
        # The served body may be pre-fix; surface a top-level degraded flag.
        result["degraded"] = True

    def call(self, name: str, arguments: dict[str, Any] | None = None) -> dict[str, Any]:
        """Dispatch entry point with bounded adoption telemetry wrapper.

        Telemetry kill-switch: `AUDITOOOR_MCP_TELEMETRY_DISABLE=1` skips logging.
        Per-workspace log: `<workspace>/.auditooor/mcp_call_log.jsonl` when a
        workspace_path (or `AUDITOOOR_WORKSPACE` env) is resolvable; otherwise
        falls back to `/tmp/mcp_call_log.jsonl`. Logging failures never raise.

        Phase NEG-B (iter18, 2026-05-23): callables in `_DEPRECATED_CALLABLES`
        get a `deprecation_warning` field injected into their response envelope
        pointing at the canonical sibling. The body is preserved (call-site
        compatibility) and the 30-day cool-off (target 2026-06-30) is honored
        per `docs/MCP_CALLABLE_DEPRECATIONS_2026-05-23.md`.
        """
        args = arguments or {}
        start_ts = _dt.datetime.now(tz=_dt.timezone.utc)
        start_perf = _telemetry_perf_counter_ms()
        result: dict[str, Any] = {"error": "telemetry_pre_dispatch_failure", "tool": name}
        try:
            result = self._dispatch(name, args)
            # Phase NEG-B: inject deprecation_warning on the way out so the
            # method bodies are unchanged. Non-dict responses (none currently
            # but defensive) are passed through unmodified.
            if isinstance(result, dict) and name in _DEPRECATED_CALLABLES:
                meta = _DEPRECATED_CALLABLES[name]
                # Do not clobber an existing key (forward-compatible).
                result.setdefault(
                    "deprecation_warning",
                    {
                        "callable": name,
                        "status": "deprecated",
                        "removal_target": meta["removal_target"],
                        "replacement": meta["replacement"],
                        "reason": meta["reason"],
                        "doc": "docs/MCP_CALLABLE_DEPRECATIONS_2026-05-23.md",
                    },
                )
            # Wave-3 staleness self-check: if the on-disk tool code advanced
            # past the revision this daemon started with, the body above was
            # computed by STALE (pre-merge) code. Signal that to the caller via
            # a degraded envelope without clobbering a real body-level error.
            if isinstance(result, dict):
                try:
                    self._inject_staleness_envelope(result)
                except Exception:
                    # The staleness signal must never break dispatch.
                    pass
            return result
        finally:
            try:
                duration_ms = max(0, _telemetry_perf_counter_ms() - start_perf)
                _record_call_telemetry(
                    callable_name=name,
                    args=args,
                    result=result,
                    duration_ms=duration_ms,
                    ts=start_ts,
                )
            except Exception:
                # Telemetry must never break dispatch.
                pass

