def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--vault-dir", default=str(DEFAULT_VAULT))
    parser.add_argument("--repo-root", default=str(REPO_ROOT))
    parser.add_argument("--self-test", action="store_true")
    parser.add_argument("--call", choices=[tool["name"] for tool in TOOL_SCHEMAS])
    parser.add_argument("--args", default="{}")
    parser.add_argument(
        "--limit",
        type=int,
        help="Convenience alias for --args '{\"limit\": N}' when calling a tool.",
    )
    raw_argv = list(sys.argv[1:] if argv is None else argv)
    args = parser.parse_args(raw_argv)

    if args.self_test:
        return self_test()

    vault_dir, vault_resolution_note = resolve_vault_dir(args.vault_dir, argv=raw_argv)
    if vault_resolution_note:
        print(f"[vault-mcp-server] {vault_resolution_note}", file=sys.stderr)
    vault = VaultQuery(vault_dir, Path(args.repo_root))
    if args.call:
        try:
            call_args = json.loads(args.args)
        except json.JSONDecodeError as exc:
            print(f"invalid --args JSON: {exc}", file=sys.stderr)
            return 2
        if not isinstance(call_args, dict):
            print("invalid --args JSON: expected an object", file=sys.stderr)
            return 2
        if args.limit is not None and "limit" not in call_args:
            call_args["limit"] = args.limit
        print(json.dumps(vault.call(args.call, call_args), indent=2, sort_keys=True))
        return 0
    return serve(vault)


if __name__ == "__main__":
    raise SystemExit(main())
